# ================================
# v187 WF EXPORT-FIRST / SAFE DISPLAY GUARD
# Display-only protection so completed WF results do not crash Streamlit/PyArrow.
# Does NOT alter prediction logic, rules, ranking, member scores, or exported cached data.
# - st.dataframe renders only a preview by default for very large tables
# - duplicate display columns are removed before render
# - object/list/dict columns are stringified for PyArrow safety
# ================================
_V187_ORIG_ST_DATAFRAME = st.dataframe
V187_DISPLAY_ROW_CAP = 250

def _v187_safe_display_df(obj, max_rows: int = V187_DISPLAY_ROW_CAP):
    try:
        if isinstance(obj, pd.DataFrame):
            df = obj.copy()
            if df.columns.duplicated().any():
                df = df.loc[:, ~df.columns.duplicated()].copy()
            # PyArrow can choke on mixed object/list/dict cells; stringify object-like display columns only.
            for c in df.columns:
                try:
                    # PyArrow display is fragile when object columns mix strings/ints/bytes/lists.
                    # Display only: stringify entire object column. Export bytes remain unchanged/cached.
                    if str(df[c].dtype) == 'object':
                        df[c] = df[c].map(lambda x: '' if x is None else str(x))
                except Exception:
                    try:
                        df[c] = df[c].astype(str)
                    except Exception:
                        df[c] = ''
            if len(df) > int(max_rows):
                df = df.head(int(max_rows)).copy()
                df.insert(0, 'v187_DISPLAY_PREVIEW_NOTE', f'Preview first {int(max_rows)} of {len(obj)} rows; use downloads/checkpoint for full data')
            return df
    except Exception:
        pass
    return obj

def _v187_dataframe(obj=None, *args, **kwargs):
    return _V187_ORIG_ST_DATAFRAME(_v187_safe_display_df(obj), *args, **kwargs)

st.dataframe = _v187_dataframe


# ================================
# v188 WF FROZEN DOWNLOAD BYTES / NO-RERUN GUARD
# Streamlit re-runs scripts on many UI actions. These helpers freeze WF export bytes
# immediately after the WF pass completes so download buttons never rebuild WF data.
# No prediction/ranking/member logic is changed.
# ================================
def _v188_unique_cols_df(df: pd.DataFrame) -> pd.DataFrame:
    if df is None or not isinstance(df, pd.DataFrame):
        return pd.DataFrame()
    out = df.copy()
    try:
        out = out.loc[:, ~out.columns.duplicated()].copy()
    except Exception:
        pass
    return out

def _v188_bytes_csv(df: pd.DataFrame) -> bytes:
    try:
        return _v188_unique_cols_df(df).to_csv(index=False).encode("utf-8")
    except Exception as e:
        return ("EXPORT_ERROR," + repr(e) + "\n").encode("utf-8")

def _v188_bytes_txt(df: pd.DataFrame) -> bytes:
    try:
        return _v188_unique_cols_df(df).to_csv(index=False, sep="\t").encode("utf-8")
    except Exception as e:
        return ("EXPORT_ERROR\t" + repr(e) + "\n").encode("utf-8")

def _v188_freeze_wf_exports(summary=None, res=None, pct=None, method_tests=None, single_row_perf=None, stream_diag_df=None):
    exports = {}
    if isinstance(summary, pd.DataFrame):
        exports["lab_summary_csv"] = _v188_bytes_csv(summary)
    if isinstance(res, pd.DataFrame):
        exports["lab_per_event_csv"] = _v188_bytes_csv(res)
        exports["checkpoint_csv"] = _v188_bytes_csv(res)
    if isinstance(pct, pd.DataFrame):
        exports["percentile_csv"] = _v188_bytes_csv(pct)
    if isinstance(method_tests, pd.DataFrame):
        exports["stream_method_tests_csv"] = _v188_bytes_csv(method_tests)
    if isinstance(single_row_perf, pd.DataFrame):
        exports["single_row_perf_csv"] = _v188_bytes_csv(single_row_perf)
    if isinstance(stream_diag_df, pd.DataFrame):
        exports["stream_reduction_csv"] = _v188_bytes_csv(stream_diag_df)
    exports["wf_all_exports_zip"] = _v189_zip_from_exports(exports) if "_v189_zip_from_exports" in globals() else b""
    st.session_state["v188_wf_frozen_exports"] = exports
    st.session_state["v188_wf_exports_ready"] = True
    st.session_state["v151_walkforward_run_active"] = False
    return exports

def _v188_get_export_bytes(key: str, fallback_df=None, txt: bool = False) -> bytes:
    exports = st.session_state.get("v188_wf_frozen_exports", {})
    if isinstance(exports, dict) and key in exports:
        return exports[key]
    if isinstance(fallback_df, pd.DataFrame):
        return _v188_bytes_txt(fallback_df) if txt else _v188_bytes_csv(fallback_df)
    return b""


