# v102 STATE + CADENCE DATE GUARDS
# ================================
def _v102_file_to_bytes(obj):
    """
    Minimal upload/session guard.
    Accepts Streamlit UploadedFile, bytes, bytearray, string/path, or file-like object.
    Fixes rerun/download/reconnect cases where an upload reference becomes a string/path.
    Does NOT change parsing logic.
    """
    if obj is None:
        return b""
    try:
        if isinstance(obj, bytes):
            return obj
        if isinstance(obj, bytearray):
            return bytes(obj)
        if isinstance(obj, str):
            p = Path(obj)
            if p.exists():
                return p.read_bytes()
            return obj.encode("utf-8")
        if isinstance(obj, Path):
            return obj.read_bytes() if obj.exists() else str(obj).encode("utf-8")
        if hasattr(obj, "getvalue"):
            v = obj.getvalue()
            return v if isinstance(v, bytes) else str(v).encode("utf-8")
        if hasattr(obj, "read"):
            try:
                obj.seek(0)
            except Exception:
                pass
            v = obj.read()
            return v if isinstance(v, bytes) else str(v).encode("utf-8")
        return str(obj).encode("utf-8")
    except Exception:
        return str(obj).encode("utf-8")

def _v102_get_upload_name(obj, fallback="uploaded_input"):
    try:
        return str(getattr(obj, "name", obj if isinstance(obj, str) else fallback)).lower()
    except Exception:
        return fallback

def _v102_max_date_from_df(df):
    try:
        if df is None or not hasattr(df, "columns"):
            return None
        date_cols = ["Date", "date", "DrawDate", "draw_date", "LatestDate", "latest_date"]
        col = next((c for c in date_cols if c in df.columns), None)
        if col is None:
            return None
        s = pd.to_datetime(df[col], errors="coerce").dropna()
        if s.empty:
            return None
        return s.max().normalize()
    except Exception:
        return None

def _v102_find_session_date_by_keys(keys):
    for key in keys:
        try:
            obj = st.session_state.get(key)
            d = _v102_max_date_from_df(obj)
            if d is not None:
                return d, key
        except Exception:
            pass
    return None, None

def _v102_resolve_cadence_asof(uploaded_playlist_df=None, history_df=None, manual_asof=None):
    """
    v102 priority:
    1. Uploaded/override playlist Date
    2. Canonical/app daily playlist Date
    3. Loaded history Date
    4. Session history Date
    5. Manual field
    6. Today only as last fallback
    """
    d = _v102_max_date_from_df(uploaded_playlist_df)
    if d is not None:
        return d, "uploaded_playlist"

    playlist_keys = [
        "CANONICAL_DAILY_PLAYLIST",
        "v79_final_daily_play_list",
        "v80_final_box_playlist",
        "v65_daily_optimal_tier_playlist",
        "v645_stream_elimination_playable",
        "v64_final_playlist",
        "daily_playlist",
    ]
    d, key = _v102_find_session_date_by_keys(playlist_keys)
    if d is not None:
        return d, f"daily_playlist:{key}"

    d = _v102_max_date_from_df(history_df)
    if d is not None:
        return d, "loaded_history"

    history_keys = ["history_df", "hist_df", "full_history", "raw_history", "merged_history"]
    d, key = _v102_find_session_date_by_keys(history_keys)
    if d is not None:
        return d, f"history:{key}"

    try:
        if manual_asof:
            d = pd.to_datetime(manual_asof, errors="coerce")
            if pd.notna(d):
                return d.normalize(), "manual_input"
    except Exception:
        pass

    return pd.Timestamp.today().normalize(), "system_today_fallback"



# ================================
# v105 ACTUAL CADENCE AS-OF + DOWNLOAD GUARD
# ================================
def _v103_get_effective_cadence_asof(manual_asof=None, playlist_df=None, history_df=None):
    """
    This is the value used by the actual cadence build/annotation path.
    It is intentionally separate from the visible date_input so the app does not
    silently use today's system date when a dated playlist/history exists.
    """
    try:
        d, src = _v102_resolve_cadence_asof(playlist_df, history_df, manual_asof)
        return pd.to_datetime(d).normalize(), src
    except Exception:
        try:
            if manual_asof:
                return pd.to_datetime(manual_asof).normalize(), "manual_fallback"
        except Exception:
            pass
    return pd.Timestamp.today().normalize(), "system_today_fallback"

def _v103_download_kwargs():
    """
    Avoid expensive reruns when clicking download buttons, when Streamlit supports it.
    """
    return {"on_click": "ignore"}



# ================================
# v105 FORCE PLAYLIST/HISTORY AS-OF FOR CADENCE
# ================================
def _v105_resolve_cadence_asof_strict(playlist_df=None, history_df=None, manual_asof=None, manual_override=False):
    """
    Strict v105 rule:
    - Use playlist latest Date first.
    - Then use history latest Date.
    - Manual/system date is ignored unless manual_override=True.
    This prevents stale session date_input values from contaminating cadence outputs.
    """
    d = _v102_max_date_from_df(playlist_df)
    if d is not None:
        return pd.to_datetime(d).normalize(), "playlist_date"

    # Try canonical/session playlist even if caller didn't pass one.
    for key in [
        "CANONICAL_DAILY_PLAYLIST",
        "v79_final_daily_play_list",
        "v80_final_box_playlist",
        "v65_daily_optimal_tier_playlist",
        "v645_stream_elimination_playable",
        "v64_final_playlist",
        "daily_playlist",
    ]:
        d = _v102_max_date_from_df(st.session_state.get(key))
        if d is not None:
            return pd.to_datetime(d).normalize(), f"daily_playlist:{key}"

    d = _v102_max_date_from_df(history_df)
    if d is not None:
        return pd.to_datetime(d).normalize(), "history_date"

    for key in ["history_df", "hist_df", "full_history", "raw_history", "merged_history"]:
        d = _v102_max_date_from_df(st.session_state.get(key))
        if d is not None:
            return pd.to_datetime(d).normalize(), f"history:{key}"

    if manual_override and manual_asof is not None:
        try:
            d = pd.to_datetime(manual_asof, errors="coerce")
            if pd.notna(d):
                return pd.to_datetime(d).normalize(), "manual_override"
        except Exception:
            pass

    return pd.Timestamp.today().normalize(), "system_today_fallback_no_playlist_or_history"

def _v105_playlist_date_source():
    try:
        k, df = v85_get_daily_playlist()
        if isinstance(df, pd.DataFrame) and not df.empty:
            d = _v102_max_date_from_df(df)
            return k, df, d
    except Exception:
        pass
    return None, None, None



# ================================
# v105 UPLOAD OBJECT SAFETY HELPERS
# ================================
def _v105_upload_bytes(obj):
    """Final guard for secondary upload helpers that may receive UploadedFile, bytes, path, string, or None."""
    if obj is None:
        return b""
    try:
        if isinstance(obj, bytes):
            return obj
        if isinstance(obj, bytearray):
            return bytes(obj)
        if isinstance(obj, Path):
            return obj.read_bytes() if obj.exists() else str(obj).encode("utf-8")
        if isinstance(obj, str):
            p = Path(obj)
            if p.exists():
                return p.read_bytes()
            return obj.encode("utf-8")
        if hasattr(obj, "getvalue"):
            v = obj.getvalue()
            return v if isinstance(v, bytes) else str(v).encode("utf-8")
        if hasattr(obj, "read"):
            try:
                obj.seek(0)
            except Exception:
                pass
            v = obj.read()
            return v if isinstance(v, bytes) else str(v).encode("utf-8")
        return str(obj).encode("utf-8")
    except Exception:
        return str(obj).encode("utf-8")

def _v105_upload_name(obj, fallback="uploaded_input.txt"):
    """Final guard for helpers that still call uploaded_file.name after reruns/reconnects."""
    try:
        nm = getattr(obj, "name", None)
        if nm:
            return str(nm).lower()
        if isinstance(obj, Path):
            return obj.name.lower()
        if isinstance(obj, str):
            p = Path(obj)
            if p.suffix:
                return p.name.lower()
            # String content/path without suffix should still be parseable; default to txt.
            return fallback.lower()
        return fallback.lower()
    except Exception:
        return fallback.lower()

def _v105_cache_cadence_outputs_once():
    """Keep cadence downloads available without forcing rebuild after clicking downloads or switching tabs."""
    try:
        keys = [
            "v92_row_cadence_summary",
            "v92_row_cadence_events",
            "v92_row_cadence_clusters",
            "v92_row_cadence_windows",
            "v92_row_cadence_annotated_playlist",
        ]
        for k in keys:
            v = st.session_state.get(k)
            if isinstance(v, pd.DataFrame) and not v.empty:
                st.session_state[f"v105_cached_{k}"] = v.copy()
    except Exception:
        pass

def _v105_get_cadence_output(key):
    v = st.session_state.get(key)
    if isinstance(v, pd.DataFrame) and not v.empty:
        return v
    v = st.session_state.get(f"v105_cached_{key}")
    if isinstance(v, pd.DataFrame) and not v.empty:
        return v
    return None



# ================================
# v106 RANK / ROW SEPARATION GUARD
# ================================
def _v106_numeric_series(df, col):
    if df is None or col not in getattr(df, "columns", []):
        return None
    return pd.to_numeric(df[col], errors="coerce")

def _v106_validate_rank_row_separation(df: pd.DataFrame, context: str = "data", hard_stop: bool = False) -> dict:
    report = {
        "context": context,
        "rows": int(len(df)) if isinstance(df, pd.DataFrame) else 0,
        "status": "OK",
        "warnings": [],
        "has_StreamRank": isinstance(df, pd.DataFrame) and "StreamRank" in df.columns,
        "has_RowPercentile": isinstance(df, pd.DataFrame) and "RowPercentile" in df.columns,
        "has_SingleRow": isinstance(df, pd.DataFrame) and "SingleRow" in df.columns,
        "has_PlaylistRank": isinstance(df, pd.DataFrame) and "PlaylistRank" in df.columns,
    }
    if not isinstance(df, pd.DataFrame) or df.empty:
        report["status"] = "EMPTY"
        return report

    sr = _v106_numeric_series(df, "StreamRank")
    rp = _v106_numeric_series(df, "RowPercentile")
    single = _v106_numeric_series(df, "SingleRow")
    pr = _v106_numeric_series(df, "PlaylistRank") if "PlaylistRank" in df.columns else _v106_numeric_series(df, "v79_FinalPlayRank")

    def sameish(a, b):
        if a is None or b is None:
            return False
        mask = a.notna() & b.notna()
        if int(mask.sum()) < 10:
            return False
        return bool((a[mask].astype(float).round(8) == b[mask].astype(float).round(8)).all())

    if sameish(sr, rp):
        report["warnings"].append("StreamRank equals RowPercentile across all comparable rows.")
    if sameish(sr, single):
        report["warnings"].append("StreamRank equals SingleRow across all comparable rows.")
    if sameish(rp, single):
        report["warnings"].append("RowPercentile equals SingleRow across all comparable rows; verify SingleRow derivation.")
    if sameish(pr, sr):
        report["warnings"].append("PlaylistRank equals StreamRank across all comparable rows; verify final playlist order.")
    if sameish(pr, single):
        report["warnings"].append("PlaylistRank equals SingleRow across all comparable rows; verify final playlist order.")

    fatal = any(("StreamRank equals RowPercentile" in w) or ("StreamRank equals SingleRow" in w) for w in report["warnings"])
    if fatal:
        report["status"] = "RANK_ROW_COLLAPSE_DETECTED"
        if hard_stop:
            st.error("v106 rank/row regression guard: StreamRank has collapsed into RowPercentile/SingleRow. This invalidates StreamRank-vs-RowPercentile testing.")
            st.json(report)
            st.stop()
    elif report["warnings"]:
        report["status"] = "WARNINGS"
    return report

def _v106_add_true_order_columns(df: pd.DataFrame) -> pd.DataFrame:
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return df
    out = df.copy()
    if "StreamRank" in out.columns:
        out["v106_OrderBy_StreamRank"] = pd.to_numeric(out["StreamRank"], errors="coerce").rank(method="first", ascending=True)
    if "RowPercentile" in out.columns:
        out["v106_OrderBy_RowPercentile"] = pd.to_numeric(out["RowPercentile"], errors="coerce").rank(method="first", ascending=True)
    elif "SingleRow" in out.columns:
        out["v106_OrderBy_RowPercentile"] = pd.to_numeric(out["SingleRow"], errors="coerce").rank(method="first", ascending=True)
    if "PlaylistRank" in out.columns:
        out["v106_OrderBy_FinalPlaylist"] = pd.to_numeric(out["PlaylistRank"], errors="coerce").rank(method="first", ascending=True)
    elif "v79_FinalPlayRank" in out.columns:
        out["v106_OrderBy_FinalPlaylist"] = pd.to_numeric(out["v79_FinalPlayRank"], errors="coerce").rank(method="first", ascending=True)
    return out

def _v106_topn_overlap_report(df: pd.DataFrame, n: int = 40) -> pd.DataFrame:
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return pd.DataFrame()
    out = _v106_add_true_order_columns(df)
    if "StreamKey" not in out.columns:
        return pd.DataFrame()
    if "v106_OrderBy_RowPercentile" not in out.columns or "v106_OrderBy_StreamRank" not in out.columns:
        return pd.DataFrame()
    out["v106_InTopN_StreamRank"] = pd.to_numeric(out["v106_OrderBy_StreamRank"], errors="coerce") <= int(n)
    out["v106_InTopN_RowPercentile"] = pd.to_numeric(out["v106_OrderBy_RowPercentile"], errors="coerce") <= int(n)
    out["v106_InTopN_AgreedBoth"] = out["v106_InTopN_StreamRank"] & out["v106_InTopN_RowPercentile"]
    out["v106_TopN_Source"] = out.apply(
        lambda r: "BOTH_AGREE" if r["v106_InTopN_AgreedBoth"] else (
            "STREAM_ONLY" if r["v106_InTopN_StreamRank"] else (
                "ROWPCT_ONLY" if r["v106_InTopN_RowPercentile"] else "OUTSIDE_TOPN"
            )
        ),
        axis=1,
    )
    return out


















