# ================================
# v121 DEEP COMBO 75 ENGINE
# Isolated add-on. Does not replace baseline prediction logic.
# Offline proof target from full-history mining:
# 234/312 = 75.00% capture, ~36.70 plays/day.
# ================================
def _v121_member(x):
    try:
        if pd.isna(x):
            return ""
    except Exception:
        pass
    s = str(x)
    for tok in re.findall(r"\d+", s):
        if tok in {"3389","3899","3889"}:
            return tok
        if tok in {"25","225","255"}:
            return {"25":"3389","225":"3899","255":"3889"}[tok]
        z = tok.zfill(4)
        if z in {"3389","3899","3889"}:
            return z
    return ""

def _v121_load_any(uploaded):
    if uploaded is None:
        return pd.DataFrame()
    try:
        name = str(getattr(uploaded, "name", "")).lower()
        if name.endswith((".xlsx",".xls")):
            return pd.read_excel(uploaded)
        sep = "\t" if name.endswith(".tsv") else None
        return pd.read_csv(uploaded, sep=sep, engine="python")
    except Exception:
        try:
            return _v108_load_miner_table(uploaded) if "_v108_load_miner_table" in globals() else pd.DataFrame()
        except Exception:
            return pd.DataFrame()

def _v121_digits(x):
    ds = re.findall(r"\d", str(x))
    return ds[-4:] if len(ds) >= 4 else list(str(x).zfill(4)[-4:])

def _v121_add_features(df):
    out = df.copy()

    # v122 daily-column aliases: align real Daily output with mined-rule field names.
    alias_pairs = {
        "seed": "PrevResult",
        "LastResult": "PrevResult",
        "seed_parity_pattern": "seed_parity",
        "seed_highlow_pattern": "seed_highlow",
        "seed_repeat_shape": "seed_shape",
        "rank": "BlindRollingRank",
        "StreamRank": "BlindRollingRank",
    }
    for src, dst in alias_pairs.items():
        if src in out.columns and dst not in out.columns:
            out[dst] = out[src]
    # Preserve original RowPercentile/SingleRow/StreamRank; aliases only fill missing mined fields.
    # Normalize common members.
    for c in ["TrueMember","PredictedMember","Top2_pred","ThirdMember"]:
        if c not in out.columns:
            out[c] = ""
        out[c] = out[c].fillna("").map(_v121_member)

    # Seed / previous result source.
    seed_col = None
    for c in ["PrevResult","Seed","SeedResult","PreviousResult","Result"]:
        if c in out.columns:
            seed_col = c
            break
    if seed_col is None:
        out["PrevResult"] = "0000"
        seed_col = "PrevResult"

    sd = [_v121_digits(x) for x in out[seed_col]]
    sd_int = []
    for row in sd:
        try:
            sd_int.append([int(x) for x in row])
        except Exception:
            sd_int.append([0,0,0,0])
    seed_sums = [sum(x) for x in sd_int]
    out["seed_sum_exact2"] = [str(x) for x in seed_sums]
    out["seed_sum_parity2"] = ["sum_even" if x % 2 == 0 else "sum_odd" for x in seed_sums]
    out["seed_sum_mod5_2"] = [str(x % 5) for x in seed_sums]
    out["seed_sum_end2"] = [str(x % 10) for x in seed_sums]

    def _struct(row):
        counts = sorted([list(row).count(d) for d in set(row)], reverse=True)
        if counts == [4]: return "quad"
        if counts == [3,1]: return "triple"
        if counts == [2,2]: return "double_double"
        if counts == [2,1,1]: return "single_pair"
        return "all_unique"
    out["seed_structure2"] = [_struct(row) for row in sd]

    for d in ["0","2","5","9"]:
        out[f"seed_inc2_{d}"] = ["1" if d in row else "0" for row in sd]

    # If old feature names don't exist, derive common approximations.
    if "seed_sum_bucket" not in out.columns:
        def _sum_bucket(s):
            try: s = int(s)
            except Exception: s = 0
            if s <= 9: return "sum_0_9"
            if s <= 13: return "sum_10_13"
            if s <= 17: return "sum_14_17"
            if s <= 21: return "sum_18_21"
            return "sum_22_plus"
        out["seed_sum_bucket"] = [_sum_bucket(x) for x in seed_sums]

    if "seed_spread_bucket" not in out.columns:
        def _spread_bucket(row):
            try:
                vals = [int(x) for x in row]
                sp = max(vals)-min(vals)
            except Exception:
                sp = 0
            if sp <= 2: return "spread_0_2"
            if sp <= 4: return "spread_3_4"
            if sp <= 6: return "spread_5_6"
            return "spread_7_plus"
        out["seed_spread_bucket"] = [_spread_bucket(row) for row in sd]

    if "seed_parity" not in out.columns:
        out["seed_parity"] = ["".join("E" if int(x)%2==0 else "O" for x in row) for row in sd]
    if "seed_highlow" not in out.columns:
        out["seed_highlow"] = ["".join("H" if int(x)>=5 else "L" for x in row) for row in sd]
    if "seed_shape" not in out.columns:
        out["seed_shape"] = out["seed_structure2"]
    for d in ["0","2","5","9"]:
        old = f"seed_has{d}"
        if old not in out.columns:
            out[old] = out[f"seed_inc2_{d}"]

    out["top1_member2"] = out["PredictedMember"].replace({"3389":"25","3899":"225","3889":"255"})
    out["top2_member2"] = out["Top2_pred"].replace({"3389":"25","3899":"225","3889":"255"})
    out["top3_member2"] = out["ThirdMember"].replace({"3389":"25","3899":"225","3889":"255"})
    out["top12_pair2"] = out["top1_member2"].astype(str) + "_" + out["top2_member2"].astype(str)
    out["top_order2"] = out["top1_member2"].astype(str) + "_" + out["top2_member2"].astype(str) + "_" + out["top3_member2"].astype(str)
    return out

def _v121_parse_rule(rule):
    return [p.strip() for p in str(rule).split(" AND ") if str(p).strip()]

def _v121_rule_mask(df, rule):
    mask = pd.Series(True, index=df.index)
    for part in _v121_parse_rule(rule):
        if "==" not in part:
            mask &= False
            continue
        col, val = part.split("==", 1)
        col = col.strip(); val = val.strip()
        if col not in df.columns:
            mask &= False
        else:
            mask &= df[col].fillna("NA").astype(str).eq(val)
    return mask

def _v121_initial_depth(df):
    # Prefer integrated prior/final depth; fallback to PlayType.
    for c in ["FinalReducedDepth","ReducedDepth","DeepStackDepth","DeepStackDepthPrior","RecommendedDepth"]:
        if c in df.columns:
            return pd.to_numeric(df[c], errors="coerce").fillna(0).astype(int)
    if "DeepStackAction" in df.columns:
        a = df["DeepStackAction"].astype(str).str.upper()
    elif "PlayType" in df.columns:
        a = df["PlayType"].astype(str).str.upper()
    elif "RowPlayType" in df.columns:
        a = df["RowPlayType"].astype(str).str.upper()
    else:
        a = pd.Series("", index=df.index)
    return pd.Series(
        np.where(a.str.contains("TOP3"), 3, np.where(a.str.contains("TOP2"), 2, np.where(a.str.contains("TOP1|PLAY"), 1, 0))),
        index=df.index
    ).astype(int)

def _v121_apply_reduction_stack(df, reduction_rules):
    out = _v121_add_features(df)
    depth = _v121_initial_depth(out).copy()
    log_rows = []
    if reduction_rules is None or not isinstance(reduction_rules, pd.DataFrame) or reduction_rules.empty:
        out["v121_Depth"] = depth
        out["v121_Action"] = np.where(depth==0, "NO_PLAY", np.where(depth==1, "PLAY_TOP1", np.where(depth==2, "PLAY_TOP2", "PLAY_TOP3")))
        return out, pd.DataFrame()

    for idx, r in reduction_rules.iterrows():
        rule = str(r.get("Rule", ""))
        action = str(r.get("ReductionAction", r.get("Action", "")))
        m = re.search(r"(?:SET_DEPTH_|TOP)(\d)", action)
        if not m:
            continue
        new_depth = int(m.group(1))
        mask = _v121_rule_mask(out, rule) & (depth > new_depth)
        affected = int(mask.sum())
        if affected > 0:
            depth.loc[mask] = new_depth
        log_rows.append({
            "Step": int(r.get("ReductionStep", idx+1)) if str(r.get("ReductionStep", idx+1)).replace(".0","").isdigit() else idx+1,
            "Rule": rule,
            "ReductionAction": f"SET_DEPTH_{new_depth}",
            "RowsAffected": affected,
        })

    out["v121_Depth"] = depth
    out["v121_Action"] = np.where(depth==0, "NO_PLAY", np.where(depth==1, "PLAY_TOP1", np.where(depth==2, "PLAY_TOP2", "PLAY_TOP3")))
    return out, pd.DataFrame(log_rows)

def _v121_apply_action_members(df):
    out = df.copy()
    def _members(row):
        d = int(row.get("v121_Depth", 0))
        vals = []
        if d >= 1: vals.append(row.get("PredictedMember",""))
        if d >= 2: vals.append(row.get("Top2_pred",""))
        if d >= 3: vals.append(row.get("ThirdMember",""))
        vals = [str(x) for x in vals if str(x) not in {"", "nan", "None"}]
        return ",".join(vals)
    out["v121_MembersToPlay"] = out.apply(_members, axis=1)
    out["v121_PlayCount"] = out["v121_Depth"].astype(int)
    return out

def _v121_score_if_truth(df):
    out = df.copy()
    if "TrueMember" not in out.columns or out["TrueMember"].fillna("").astype(str).str.len().sum() == 0:
        return pd.DataFrame()
    true = out["TrueMember"].map(_v121_member)
    d = pd.to_numeric(out.get("v121_Depth", 0), errors="coerce").fillna(0).astype(int)
    top1 = out.get("PredictedMember", "").map(_v121_member) if "PredictedMember" in out.columns else pd.Series("", index=out.index)
    top2 = out.get("Top2_pred", "").map(_v121_member) if "Top2_pred" in out.columns else pd.Series("", index=out.index)
    top3 = out.get("ThirdMember", "").map(_v121_member) if "ThirdMember" in out.columns else pd.Series("", index=out.index)
    is_hit = true.isin(["3389","3899","3889"])
    cap = is_hit & (((d>=1)&top1.eq(true)) | ((d>=2)&top2.eq(true)) | ((d>=3)&top3.eq(true)))
    total_hits = int(is_hit.sum())
    captured = int(cap.sum())
    return pd.DataFrame([{
        "Rows": len(out),
        "TotalHits": total_hits,
        "CapturedHits": captured,
        "MissedHits": total_hits-captured,
        "CaptureRate": captured/total_hits if total_hits else None,
        "TotalPlays": int(d.sum()),
        "AvgPlaysPerDay": int(d.sum())/out["Date"].nunique() if "Date" in out.columns and out["Date"].nunique() else None,
        "Top1Rows": int((d==1).sum()),
        "Top2Rows": int((d==2).sum()),
        "Top3Rows": int((d==3).sum()),
        "NoPlayRows": int((d==0).sum()),
    }])


# ================================
# v120 WALK-FORWARD TRUTH EXPORT FIX
# ================================
def _v120_member(x):
    if "_v111_member" in globals():
        try: return _v111_member(x)
        except Exception: pass
    if pd.isna(x): return None
    for tok in re.findall(r"\d+", str(x)):
        z = tok.zfill(4)
        if z in {"3389","3899","3889"}: return z
        if tok in {"25","225","255"}: return {"25":"3389","225":"3899","255":"3889"}[tok]
    return None

def _v120_result_member(x):
    if pd.isna(x): return None
    digs = re.findall(r"\d", str(x))
    if len(digs) < 4: return _v120_member(x)
    z = "".join(sorted("".join(digs)[-4:]))
    if z in {"3389","3899","3889"}: return z
    return _v120_member(x)

def _v120_ranked(row):
    out=[]
    for grp in [["PredictedMember","Top1","Top1_Display"],["Top2_pred","Top2","Top2_Display"],["ThirdMember","Top3","Top3_Display"]]:
        for c in grp:
            if c in row.index:
                m=_v120_member(row.get(c))
                if m and m not in out:
                    out.append(m); break
    for m in ["3389","3899","3889"]:
        if m not in out: out.append(m)
    return out[:3]

def _v120_played(row):
    for c in ["ActualBoxPlay","RecommendedPlay","ActualBoxPlayDisplay","BoxPlayInstruction","BeforeMembers","AfterMembers"]:
        if c in row.index and pd.notna(row.get(c)):
            found=[]
            for tok in re.findall(r"\d+", str(row.get(c))):
                m=_v120_member(tok)
                if m and m not in found: found.append(m)
            if found: return found
    r=_v120_ranked(row)
    pt=str(row.get("PlayType","")).upper() if "PlayType" in row.index else ""
    if "TOP3" in pt: return r[:3]
    if "TOP2" in pt: return r[:2]
    return r[:1]

def _v120_true(row):
    for c in ["TrueMember","WinningMember","ActualMember"]:
        if c in row.index:
            m=_v120_member(row.get(c))
            if m: return m
    for c in ["Result","WinningResult","ActualResult"]:
        if c in row.index:
            m=_v120_result_member(row.get(c))
            if m: return m
    return None

def _v120_fix_truth(df):
    if df is None or not isinstance(df,pd.DataFrame) or df.empty: return pd.DataFrame()
    out=df.copy()
    true_list=[]; t1_list=[]; t2_list=[]; t3_list=[]; miss_list=[]; cap_list=[]; target_list=[]
    for _,row in out.iterrows():
        true=_v120_true(row)
        ranked=_v120_ranked(row)
        played=_v120_played(row)
        t1=int(bool(true and ranked and true==ranked[0]))
        t2=int(bool(true and len(ranked)>1 and true==ranked[1]))
        t3=int(bool(true and len(ranked)>2 and true==ranked[2]))
        cap=int(bool(true and true in set(played)))
        miss=int(bool(true and not cap))
        if not true: target="UNCLASSIFIED_NO_TRUE_MEMBER"
        elif t1 and len(played)>1: target="WASTE"
        elif t1: target="TOP1_WIN"
        elif t2: target="NEEDED"
        elif t3: target="TOP3_WIN"
        else: target="MISS"
        true_list.append(true or "")
        t1_list.append(t1); t2_list.append(t2); t3_list.append(t3); miss_list.append(miss); cap_list.append(cap); target_list.append(target)
    out["TrueMember"]=true_list
    out["Top1_Correct"]=t1_list
    out["Needed_Top2"]=t2_list
    out["Top3_Win"]=t3_list
    out["Miss"]=miss_list
    out["BeforeCaptured"]=cap_list
    out["v120_TargetOutcome"]=target_list
    out["v111_TargetOutcome"]=target_list
    return out

def _v120_audit(df):
    fixed=_v120_fix_truth(df)
    rows=[{"Metric":"rows","Value":len(fixed)}]
    if fixed.empty: return pd.DataFrame(rows)
    rows += [
        {"Metric":"TrueMember_nonblank","Value":int(fixed["TrueMember"].astype(str).str.len().gt(0).sum())},
        {"Metric":"Top1_Correct_sum","Value":int(pd.to_numeric(fixed["Top1_Correct"],errors="coerce").fillna(0).sum())},
        {"Metric":"Needed_Top2_sum","Value":int(pd.to_numeric(fixed["Needed_Top2"],errors="coerce").fillna(0).sum())},
        {"Metric":"Top3_Win_sum","Value":int(pd.to_numeric(fixed["Top3_Win"],errors="coerce").fillna(0).sum())},
        {"Metric":"Miss_sum","Value":int(pd.to_numeric(fixed["Miss"],errors="coerce").fillna(0).sum())},
    ]
    for k,v in fixed["v120_TargetOutcome"].astype(str).value_counts().items():
        rows.append({"Metric":"target__"+str(k),"Value":int(v)})
    return pd.DataFrame(rows)

def _v120_load_src(uploaded=None):
    if uploaded is not None:
        try:
            df=_v108_load_miner_table(uploaded)
            if isinstance(df,pd.DataFrame) and not df.empty: return "uploaded",df
        except Exception: pass
    for k in ["v113_per_event","v112_per_event","v114_per_event","v117_per_event","v119_per_event"]:
        df=st.session_state.get(k)
        if isinstance(df,pd.DataFrame) and not df.empty: return "session:"+k,df
    return "none",pd.DataFrame()


# ================================
# v119 SCHEMA-AWARE TARGET CLASSIFIER HELPERS
# ================================
def _v119_norm(s):
    return re.sub(r"[^a-z0-9]+","",str(s).lower())

def _v119_find(df, names):
    cmap={_v119_norm(c):c for c in df.columns}
    for n in names:
        k=_v119_norm(n)
        if k in cmap: return cmap[k]
    for n in names:
        k=_v119_norm(n)
        for ck,c in cmap.items():
            if k and (k in ck or ck in k): return c
    return None

def _v119_mem(x):
    if "_v111_member" in globals():
        try: return _v111_member(x)
        except Exception: pass
    if pd.isna(x): return None
    for tok in re.findall(r"\d+",str(x)):
        z=tok.zfill(4)
        if z in {"3389","3899","3889"}: return z
        if tok in {"25","225","255"}: return {"25":"3389","225":"3899","255":"3889"}[tok]
    return None

def _v119_bool(x):
    try:
        if pd.isna(x): return 0
        s=str(x).strip().lower()
        if s in {"1","true","yes","y"}: return 1
        if s in {"0","false","no","n",""}: return 0
        return int(float(s))
    except Exception: return 0

def _v119_members_text(x):
    out=[]
    if pd.isna(x): return out
    for tok in re.findall(r"\d+",str(x)):
        m=_v119_mem(tok)
        if m and m not in out: out.append(m)
    return out

def _v119_map(df):
    return {
        "true":_v119_find(df,["TrueMember","WinningMember","ActualMember"]),
        "result":_v119_find(df,["Result","WinningResult","ActualResult"]),
        "top1":_v119_find(df,["PredictedMember","Top1","Top1_Display"]),
        "top2":_v119_find(df,["Top2_pred","Top2","Top2_Display"]),
        "top3":_v119_find(df,["ThirdMember","Top3","Top3_Display"]),
        "top1_correct":_v119_find(df,["Top1_Correct","Top1Correct"]),
        "needed_top2":_v119_find(df,["Needed_Top2","NeededTop2","Top2Needed"]),
        "miss":_v119_find(df,["Miss","IsMiss"]),
        "target":_v119_find(df,["v111_TargetOutcome","v118_TargetLabel","v108_OutcomeGroup","OutcomeGroup"]),
        "play_type":_v119_find(df,["PlayType","RowPlayType"]),
        "play_members":_v119_find(df,["ActualBoxPlay","RecommendedPlay","ActualBoxPlayDisplay","BoxPlayInstruction","BeforeMembers","AfterMembers"]),
        "before_captured":_v119_find(df,["BeforeCaptured"]),
        "after_captured":_v119_find(df,["AfterCaptured"]),
    }

def _v119_true(row, mp):
    for k in ["true","result"]:
        c=mp.get(k)
        if c and c in row.index:
            m=_v119_mem(row.get(c))
            if m: return m
    return None

def _v119_ranked(row, mp):
    out=[]
    for k in ["top1","top2","top3"]:
        c=mp.get(k)
        if c and c in row.index:
            m=_v119_mem(row.get(c))
            if m and m not in out: out.append(m)
    for m in ["3389","3899","3889"]:
        if m not in out: out.append(m)
    return out[:3]

def _v119_current(row, mp):
    c=mp.get("play_members")
    if c and c in row.index:
        mm=_v119_members_text(row.get(c))
        if mm: return mm
    ranked=_v119_ranked(row,mp)
    ptc=mp.get("play_type")
    pt=str(row.get(ptc,"")).upper() if ptc and ptc in row.index else ""
    if "TOP3" in pt: return ranked[:3]
    if "TOP2" in pt: return ranked[:2]
    return ranked[:1]

def _v119_label(row, mp):
    c=mp.get("target")
    if c and c in row.index:
        v=str(row.get(c)).strip()
        if v in {"TOP1_WIN","WASTE","NEEDED","TOP3_WIN","MISS"}: return v
    c1=mp.get("top1_correct"); c2=mp.get("needed_top2"); cm=mp.get("miss")
    if c1 and _v119_bool(row.get(c1))==1: return "WASTE" if len(_v119_current(row,mp))>1 else "TOP1_WIN"
    if c2 and _v119_bool(row.get(c2))==1: return "NEEDED"
    if cm and _v119_bool(row.get(cm))==1: return "MISS"
    bc=mp.get("before_captured"); ac=mp.get("after_captured")
    if bc and ac and bc in row.index and ac in row.index:
        b=_v119_bool(row.get(bc)); a=_v119_bool(row.get(ac))
        if b==1 and a==0: return "HARMED_BY_ACTION"
        if b==0 and a==1: return "RESCUED_BY_ACTION"
    true=_v119_true(row,mp); ranked=_v119_ranked(row,mp); cur=_v119_current(row,mp)
    if true and ranked:
        if true==ranked[0]: return "WASTE" if len(cur)>1 else "TOP1_WIN"
        if len(ranked)>1 and true==ranked[1]: return "NEEDED"
        if len(ranked)>2 and true==ranked[2]: return "TOP3_WIN"
        return "MISS"
    return "UNCLASSIFIED"

def _v119_prepare(df):
    out=df.copy()
    if "_v111_add_bucket_features" in globals():
        try: out=_v111_add_bucket_features(out)
        except Exception: pass
    mp=_v119_map(out)
    out["v119_TargetLabel"]=out.apply(lambda r:_v119_label(r,mp),axis=1)
    audit=pd.DataFrame([{"LogicalField":k,"MappedColumn":v if v else "","Found":bool(v)} for k,v in mp.items()])
    return out.reset_index(drop=True),mp,audit

def _v119_mine(df,min_support=8,min_gap=.05,max_pair=60,max_rules=500):
    work,mp,audit=_v119_prepare(df)
    tm=_v118_traits(work,max_pair) if "_v118_traits" in globals() else pd.DataFrame()
    rows=[]
    if tm.empty: return work,mp,tm,pd.DataFrame(),audit
    y=work["v119_TargetLabel"].astype(str)
    specs=[("WASTE","SUPPRESS_TOP2",.55),("NEEDED","KEEP_TOP2",.35),("NEEDED","SWAP_TOP2_TO_TOP1_REVIEW",.35),("TOP3_WIN","ADD_TOP3",.18),("MISS","REVIEW_SKIP",.45)]
    for trait in tm.columns:
        mask=tm[trait].fillna(False).astype(bool); sup=int(mask.sum())
        if sup<int(min_support): continue
        rest=y[~mask]
        for target,action,minrate in specs:
            hits=int((y[mask]==target).sum()); rate=hits/sup if sup else 0
            rr=int((rest==target).sum())/len(rest) if len(rest) else 0
            gap=rate-rr
            if rate>=minrate and gap>=float(min_gap):
                rows.append({"ActionLabel":action,"TargetGroup":target,"Trait":trait,"Support":sup,"TargetHits":hits,"TargetRate":rate,"RestRate":rr,"Gap":gap})
    rules=pd.DataFrame(rows)
    if not rules.empty:
        pri={"SUPPRESS_TOP2":1,"KEEP_TOP2":2,"SWAP_TOP2_TO_TOP1_REVIEW":3,"ADD_TOP3":4,"REVIEW_SKIP":5}
        rules["Priority"]=rules["ActionLabel"].map(pri).fillna(99)
        rules=rules.sort_values(["Priority","Gap","TargetRate","Support"],ascending=[True,False,False,False]).head(int(max_rules)).reset_index(drop=True)
    return work,mp,tm,rules,audit

def _v119_apply(row,action,mp):
    r=_v119_ranked(row,mp); cur=_v119_current(row,mp)
    if action=="SUPPRESS_TOP2": return r[:1]
    if action=="KEEP_TOP2": return r[:2]
    if action=="SWAP_TOP2_TO_TOP1_REVIEW": return r[1:2] if len(r)>1 else r[:1]
    if action=="ADD_TOP3": return r[:3]
    return cur

def _v119_score(work,mp,tm,rules):
    if rules is None or rules.empty or tm is None or tm.empty: return pd.DataFrame()
    rows=[]
    for _,rule in rules.iterrows():
        trait=str(rule["Trait"]); action=str(rule["ActionLabel"])
        if trait not in tm.columns: continue
        bp=ap=bc=ac=tested=0
        for _,row in work[tm[trait].fillna(False)].iterrows():
            true=_v119_true(row,mp)
            if not true: continue
            cur=_v119_current(row,mp); final=_v119_apply(row,action,mp)
            tested+=1; bp+=len(cur); ap+=len(final); bc+=int(true in set(cur)); ac+=int(true in set(final))
        saved=bp-ap; harm=max(0,bc-ac)
        if saved>0 and harm==0: status="LOCK_CANDIDATE_ZERO_HARM"
        elif action in {"KEEP_TOP2","ADD_TOP3"} and ac>=bc: status="PROTECTIVE_RULE_CANDIDATE"
        elif action=="SWAP_TOP2_TO_TOP1_REVIEW" and ac>bc: status="SWAP_CANDIDATE_REVIEW"
        elif saved>0 and harm<=1 and saved/max(harm,1)>=25: status="REVIEW_LOW_HARM_HIGH_VALUE"
        elif saved>0: status="HOLD_TOO_MUCH_HARM"
        else: status="REVIEW_NO_SAVINGS_OR_PROTECTIVE"
        d=rule.to_dict(); d.update({"EventsTested":tested,"BeforePlays":bp,"AfterPlays":ap,"PlaysSaved":saved,"BeforeCaptured":bc,"AfterCaptured":ac,"WinsHarmed":harm,"WinsGained":max(0,ac-bc),"NetCaptureDelta":ac-bc,"PlaysSavedPerHarmedWin":(saved/harm if harm else None),"NetScore_PlaysMinus25xHarm":saved-(25*harm),"PromotionStatus":status})
        rows.append(d)
    out=pd.DataFrame(rows)
    if out.empty: return out
    order={"LOCK_CANDIDATE_ZERO_HARM":1,"PROTECTIVE_RULE_CANDIDATE":2,"SWAP_CANDIDATE_REVIEW":3,"REVIEW_LOW_HARM_HIGH_VALUE":4,"HOLD_TOO_MUCH_HARM":5,"REVIEW_NO_SAVINGS_OR_PROTECTIVE":6}
    out["StatusOrder"]=out["PromotionStatus"].map(order).fillna(99)
    return out.sort_values(["StatusOrder","NetScore_PlaysMinus25xHarm","AfterCaptured"],ascending=[True,False,False]).drop(columns=["StatusOrder"]).reset_index(drop=True)


# ================================
# v118 FOCUSED SEPARATOR CORRECTION HELPERS
# ================================
def _v118_load(uploaded):
    if uploaded is None: return pd.DataFrame()
    try: return _v108_load_miner_table(uploaded)
    except Exception: return pd.DataFrame()

def _v118_src(keys, uploaded=None):
    up=_v118_load(uploaded)
    if isinstance(up,pd.DataFrame) and not up.empty: return "uploaded", up
    for k in keys:
        x=st.session_state.get(k)
        if isinstance(x,pd.DataFrame) and not x.empty: return "session:"+k, x
    return "none", pd.DataFrame()

def _v118_member(x):
    return _v111_member(x) if "_v111_member" in globals() else None

def _v118_prepare(df):
    out=df.copy()
    if "_v111_compute_correct_outcome_targets" in globals():
        try: out=_v111_compute_correct_outcome_targets(out)
        except Exception: pass
    if "_v111_add_bucket_features" in globals():
        try: out=_v111_add_bucket_features(out)
        except Exception: pass
    return out.reset_index(drop=True)

def _v118_ranked(row):
    if "_v112_ranked_members" in globals():
        try: return _v112_ranked_members(row)
        except Exception: pass
    ranked=[]
    for grp in [["PredictedMember","Top1","Top1_Display"],["Top2_pred","Top2","Top2_Display"],["ThirdMember","Top3","Top3_Display"]]:
        for c in grp:
            if c in row.index:
                m=_v118_member(row.get(c))
                if m and m not in ranked: ranked.append(m); break
    for m in ["3389","3899","3889"]:
        if m not in ranked: ranked.append(m)
    return ranked[:3]

def _v118_current(row):
    if "_v112_current_members" in globals():
        try: return _v112_current_members(row)
        except Exception: pass
    return _v118_ranked(row)[:1]

def _v118_true(row):
    for c in ["TrueMember","WinningMember","ActualMember"]:
        if c in row.index:
            m=_v118_member(row.get(c))
            if m: return m
    return None

def _v118_label(row):
    if "v111_TargetOutcome" in row.index and str(row.get("v111_TargetOutcome")) not in {"","nan","None"}:
        return str(row.get("v111_TargetOutcome"))
    tm=_v118_true(row); r=_v118_ranked(row); cur=_v118_current(row)
    if not tm or not r: return "UNKNOWN"
    if tm==r[0]: return "WASTE" if len(cur)>1 else "TOP1_WIN"
    if len(r)>1 and tm==r[1]: return "NEEDED"
    if len(r)>2 and tm==r[2]: return "TOP3_WIN"
    return "MISS"

def _v118_traits(work, max_pair=60):
    raw={}
    if "_v111_trait_masks" in globals():
        try: raw=_v111_trait_masks(work)
        except Exception: raw={}
    bad=["true","winning","actualmember","top1correct","neededtop2","miss","targetoutcome","outcomegroup","captured"]
    traits={}
    for k,m in raw.items():
        nk=re.sub(r"[^a-z0-9]+","",str(k).lower())
        if any(b in nk for b in bad): continue
        try:
            s=m.fillna(False).astype(bool).reset_index(drop=True)
            if 1<int(s.sum())<len(work): traits[str(k)]=s
        except Exception: pass
    scored=sorted([(min(int(s.sum()),len(work)-int(s.sum())),k) for k,s in traits.items()], reverse=True)
    base=[k for _,k in scored[:int(max_pair)]]
    for i,a in enumerate(base):
        for b in base[i+1:]:
            s=traits[a]&traits[b]
            if 1<int(s.sum())<len(work): traits[f"{a} AND {b}"]=s
    return pd.DataFrame(traits).astype(bool) if traits else pd.DataFrame()

def _v118_mine(df, min_support=8, min_gap=0.05, max_pair=60, max_rules=500):
    work=_v118_prepare(df)
    work["v118_TargetLabel"]=work.apply(_v118_label, axis=1)
    tm=_v118_traits(work, max_pair)
    rows=[]
    if tm.empty: return work,tm,pd.DataFrame()
    specs=[("WASTE","SUPPRESS_TOP2",.55),("NEEDED","KEEP_TOP2",.35),("NEEDED","SWAP_TOP2_TO_TOP1_REVIEW",.35),("TOP3_WIN","ADD_TOP3",.18),("MISS","REVIEW_SKIP",.45)]
    y=work["v118_TargetLabel"].astype(str)
    for trait in tm.columns:
        mask=tm[trait].fillna(False).astype(bool); support=int(mask.sum())
        if support<int(min_support): continue
        rest=y[~mask]
        for target,action,minrate in specs:
            hits=int((y[mask]==target).sum()); rate=hits/support if support else 0
            rr=int((rest==target).sum())/len(rest) if len(rest) else 0
            gap=rate-rr
            if rate>=minrate and gap>=float(min_gap):
                rows.append({"ActionLabel":action,"TargetGroup":target,"Trait":trait,"Support":support,"TargetHits":hits,"TargetRate":rate,"RestRate":rr,"Gap":gap})
    out=pd.DataFrame(rows)
    if out.empty: return work,tm,out
    pri={"SUPPRESS_TOP2":1,"KEEP_TOP2":2,"SWAP_TOP2_TO_TOP1_REVIEW":3,"ADD_TOP3":4,"REVIEW_SKIP":5}
    out["Priority"]=out["ActionLabel"].map(pri).fillna(99)
    return work,tm,out.sort_values(["Priority","Gap","TargetRate","Support"], ascending=[True,False,False,False]).head(int(max_rules)).reset_index(drop=True)

def _v118_apply(row, action):
    r=_v118_ranked(row); cur=_v118_current(row)
    if action=="SUPPRESS_TOP2": return r[:1]
    if action=="KEEP_TOP2": return r[:2]
    if action=="SWAP_TOP2_TO_TOP1_REVIEW": return r[1:2] if len(r)>1 else r[:1]
    if action=="ADD_TOP3": return r[:3]
    return cur

def _v118_score(work, tm, rules):
    if rules is None or rules.empty or tm is None or tm.empty: return pd.DataFrame()
    rows=[]
    for _,rule in rules.iterrows():
        trait=str(rule["Trait"]); action=str(rule["ActionLabel"])
        if trait not in tm.columns: continue
        sub=work[tm[trait].fillna(False)].copy()
        bp=ap=bc=ac=tested=0
        for _,row in sub.iterrows():
            true=_v118_true(row)
            if not true: continue
            cur=_v118_current(row); final=_v118_apply(row, action)
            tested+=1; bp+=len(cur); ap+=len(final); bc+=int(true in set(cur)); ac+=int(true in set(final))
        saved=bp-ap; harm=max(0,bc-ac)
        if saved>0 and harm==0: status="LOCK_CANDIDATE_ZERO_HARM"
        elif action in {"KEEP_TOP2","ADD_TOP3"} and ac>=bc: status="PROTECTIVE_RULE_CANDIDATE"
        elif action=="SWAP_TOP2_TO_TOP1_REVIEW" and ac>bc: status="SWAP_CANDIDATE_REVIEW"
        elif saved>0 and harm<=1 and saved/max(harm,1)>=25: status="REVIEW_LOW_HARM_HIGH_VALUE"
        elif saved>0: status="HOLD_TOO_MUCH_HARM"
        else: status="REVIEW_NO_SAVINGS_OR_PROTECTIVE"
        d=rule.to_dict(); d.update({"EventsTested":tested,"BeforePlays":bp,"AfterPlays":ap,"PlaysSaved":saved,"BeforeCaptured":bc,"AfterCaptured":ac,"WinsHarmed":harm,"WinsGained":max(0,ac-bc),"NetCaptureDelta":ac-bc,"PlaysSavedPerHarmedWin":(saved/harm if harm else None),"NetScore_PlaysMinus25xHarm":saved-(25*harm),"PromotionStatus":status})
        rows.append(d)
    out=pd.DataFrame(rows)
    if out.empty: return out
    order={"LOCK_CANDIDATE_ZERO_HARM":1,"PROTECTIVE_RULE_CANDIDATE":2,"SWAP_CANDIDATE_REVIEW":3,"REVIEW_LOW_HARM_HIGH_VALUE":4,"HOLD_TOO_MUCH_HARM":5,"REVIEW_NO_SAVINGS_OR_PROTECTIVE":6}
    out["StatusOrder"]=out["PromotionStatus"].map(order).fillna(99)
    return out.sort_values(["StatusOrder","NetScore_PlaysMinus25xHarm","AfterCaptured"], ascending=[True,False,False]).drop(columns=["StatusOrder"]).reset_index(drop=True)


# ================================
# v117 PER-EVENT FRESHNESS GUARD
# ================================
def _v117_parse_dates(series):
    try:
        return pd.to_datetime(series, errors="coerce")
    except Exception:
        return pd.Series(dtype="datetime64[ns]")

def _v117_get_latest_date_from_df(df, date_candidates=None):
    if date_candidates is None:
        date_candidates = ["Date", "date", "DrawDate", "draw_date", "SeedDate", "seed_date", "LastDate", "last_date"]
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return None, None
    for c in date_candidates:
        if c in df.columns:
            d = _v117_parse_dates(df[c])
            if d.notna().any():
                return d.max().date(), c
    return None, None

def _v117_get_current_play_date_from_daily(daily_df=None):
    """
    Best-effort current play/date anchor.
    Priority:
    1. Current daily playlist date columns
    2. Uploaded/daily seed date columns
    3. Today
    """
    if isinstance(daily_df, pd.DataFrame) and not daily_df.empty:
        dt, col = _v117_get_latest_date_from_df(
            daily_df,
            ["PlayDate", "play_date", "CurrentPlayDate", "Date", "date", "SeedDate", "seed_date"]
        )
        if dt is not None:
            return dt, "daily_column:" + str(col)
    try:
        return pd.Timestamp.today().date(), "system_today"
    except Exception:
        return None, "unknown"

def _v117_get_per_event_source_for_freshness(uploaded=None):
    """
    Uses same per-event sources as v116, upload fallback only.
    """
    up = pd.DataFrame()
    if uploaded is not None:
        try:
            up = _v108_load_miner_table(uploaded)
        except Exception:
            up = pd.DataFrame()
        if isinstance(up, pd.DataFrame) and not up.empty:
            return "uploaded", up

    for key in ["v113_per_event", "v112_per_event", "v114_per_event", "v117_per_event", "v116_per_event"]:
        df = st.session_state.get(key)
        if isinstance(df, pd.DataFrame) and not df.empty:
            return "session:" + key, df
    return "none", pd.DataFrame()

def _v117_freshness_audit(per_event_df=None, daily_df=None, uploaded_per_event=None, max_age_days=1):
    if per_event_df is None or not isinstance(per_event_df, pd.DataFrame) or per_event_df.empty:
        src, per_event_df = _v117_get_per_event_source_for_freshness(uploaded_per_event)
    else:
        src = "provided_df"

    latest_per_event_date, per_event_date_col = _v117_get_latest_date_from_df(per_event_df)
    current_play_date, current_source = _v117_get_current_play_date_from_daily(daily_df)

    status = "UNKNOWN"
    message = ""
    age_days = None

    if latest_per_event_date is None:
        status = "MISSING_OR_NO_DATE"
        message = "Per-event file is missing or has no recognizable date column. Refresh by running v113 FAST Blind WF or upload the current per-event file."
    elif current_play_date is None:
        status = "UNKNOWN_CURRENT_PLAY_DATE"
        message = "Could not identify current play date. Per-event file date found, but freshness cannot be confirmed."
    else:
        try:
            age_days = int((pd.Timestamp(current_play_date) - pd.Timestamp(latest_per_event_date)).days)
        except Exception:
            age_days = None

        if age_days is None:
            status = "UNKNOWN"
            message = "Could not compare current play date to per-event date."
        elif age_days < 0:
            status = "PER_EVENT_AHEAD_OF_PLAY_DATE"
            message = "Per-event file date is ahead of current play date. Check date/source alignment."
        elif age_days <= int(max_age_days):
            status = "CURRENT"
            message = "Per-event file appears current enough for this run."
        else:
            status = "STALE_REFRESH_RECOMMENDED"
            message = "Per-event file is older than the allowed freshness window. Run v113 FAST Blind WF to refresh proof outputs before locking/promoting rules."

    return pd.DataFrame([{
        "FreshnessStatus": status,
        "Message": message,
        "PerEventSource": src,
        "PerEventLatestDate": str(latest_per_event_date) if latest_per_event_date else "",
        "PerEventDateColumn": str(per_event_date_col) if per_event_date_col else "",
        "CurrentPlayDate": str(current_play_date) if current_play_date else "",
        "CurrentPlayDateSource": str(current_source),
        "AgeDays_CurrentMinusPerEvent": age_days,
        "MaxAllowedAgeDays": int(max_age_days),
        "RefreshNeeded": bool(status in {"MISSING_OR_NO_DATE", "STALE_REFRESH_RECOMMENDED", "UNKNOWN_CURRENT_PLAY_DATE"}),
    }])


# ================================
# v116 HARM-SCORED SUPPRESSION FINALIZER HELPERS
# ================================
def _v116_load_optional(uploaded):
    if uploaded is None:
        return pd.DataFrame()
    try:
        return _v108_load_miner_table(uploaded)
    except Exception:
        return pd.DataFrame()

def _v116_get_source(keys, uploaded=None):
    up = _v116_load_optional(uploaded)
    if isinstance(up, pd.DataFrame) and not up.empty:
        return "uploaded", up
    for key in keys:
        df = st.session_state.get(key)
        if isinstance(df, pd.DataFrame) and not df.empty:
            return "session:" + key, df
    return "none", pd.DataFrame()

def _v116_extract_rule_signature(reason):
    s = str(reason or "").strip()
    if not s:
        return ""
    # reasons look like ACTION | trait | rate=...
    parts = [p.strip() for p in s.split("|")]
    if len(parts) >= 2:
        return parts[1]
    return s[:240]

def _v116_harm_score_from_per_event(per_event):
    """
    True harm scoring from blind per-event output.
    Counts how each applied suppression rule affected capture and plays.
    """
    if per_event is None or not isinstance(per_event, pd.DataFrame) or per_event.empty:
        return pd.DataFrame()

    df = per_event.copy()
    if "ActionApplied" not in df.columns:
        return pd.DataFrame()

    # Focus on actual Top1-only / suppression actions.
    mask = df["ActionApplied"].astype(str).str.contains("TOP1_ONLY|WASTE|FORCE_TOP1", case=False, na=False)
    df = df[mask].copy()
    if df.empty:
        return pd.DataFrame()

    df["RuleSignature"] = df.get("RuleReason", "").map(_v116_extract_rule_signature)
    df = df[df["RuleSignature"].astype(str).str.len() > 0].copy()

    rows = []
    for rule, g in df.groupby("RuleSignature", dropna=False):
        bp = pd.to_numeric(g.get("BeforePlayCount", 0), errors="coerce").fillna(0)
        ap = pd.to_numeric(g.get("AfterPlayCount", 0), errors="coerce").fillna(0)
        bc = pd.to_numeric(g.get("BeforeCaptured", 0), errors="coerce").fillna(0)
        ac = pd.to_numeric(g.get("AfterCaptured", 0), errors="coerce").fillna(0)

        plays_saved = int((bp - ap).sum())
        wins_harmed = int(((bc == 1) & (ac == 0)).sum())
        wins_preserved = int(((bc == 1) & (ac == 1)).sum())
        already_missed = int(((bc == 0) & (ac == 0)).sum())
        wins_rescued = int(((bc == 0) & (ac == 1)).sum())
        affected = int(len(g))

        # Conservative operational score: 1 harmed win costs 25 plays of value.
        net_score = plays_saved - (25 * wins_harmed)
        if plays_saved > 0 and wins_harmed == 0:
            status = "LOCK_CANDIDATE_ZERO_HARM"
        elif plays_saved > 0 and wins_harmed <= 1 and (plays_saved / max(wins_harmed, 1)) >= 25:
            status = "REVIEW_LOW_HARM_HIGH_VALUE"
        elif plays_saved > 0:
            status = "HOLD_TOO_MUCH_HARM"
        else:
            status = "HOLD_NO_SAVINGS"

        rows.append({
            "RuleSignature": str(rule)[:260],
            "EventsAffected": affected,
            "PlaysSaved": plays_saved,
            "WinsHarmed": wins_harmed,
            "WinsPreserved": wins_preserved,
            "AlreadyMissedRows": already_missed,
            "WinsRescued": wins_rescued,
            "PlaysSavedPerHarmedWin": (plays_saved / wins_harmed) if wins_harmed else None,
            "NetScore_PlaysMinus25xHarm": net_score,
            "PromotionStatus": status,
            "Source": "blind_per_event_harm_scored",
        })

    out = pd.DataFrame(rows)
    if out.empty:
        return out
    status_order = {
        "LOCK_CANDIDATE_ZERO_HARM": 1,
        "REVIEW_LOW_HARM_HIGH_VALUE": 2,
        "HOLD_TOO_MUCH_HARM": 3,
        "HOLD_NO_SAVINGS": 4,
    }
    out["StatusOrder"] = out["PromotionStatus"].map(status_order).fillna(99)
    return out.sort_values(["StatusOrder", "NetScore_PlaysMinus25xHarm", "PlaysSaved"], ascending=[True, False, False]).drop(columns=["StatusOrder"]).reset_index(drop=True)

def _v116_locked_rule_list(harm_table, include_low_harm=False):
    if harm_table is None or not isinstance(harm_table, pd.DataFrame) or harm_table.empty:
        return pd.DataFrame()
    keep = ["LOCK_CANDIDATE_ZERO_HARM"]
    if include_low_harm:
        keep.append("REVIEW_LOW_HARM_HIGH_VALUE")
    out = harm_table[harm_table["PromotionStatus"].isin(keep)].copy()
    out["LockedAction"] = "FORCE_TOP1_ONLY"
    out["UseInDailyProduction"] = True
    return out.reset_index(drop=True)

def _v116_full_strategy_validation(per_event):
    if per_event is None or not isinstance(per_event, pd.DataFrame) or per_event.empty:
        return pd.DataFrame()
    df = per_event.copy()
    rows = []
    if "strategy" in df.columns:
        groups = df.groupby("strategy", dropna=False)
    else:
        groups = [("production_preview", df)]
    for strat, g in groups:
        ac = pd.to_numeric(g.get("AfterCaptured", 0), errors="coerce").fillna(0)
        bc = pd.to_numeric(g.get("BeforeCaptured", 0), errors="coerce").fillna(0)
        ap = pd.to_numeric(g.get("AfterPlayCount", 0), errors="coerce").fillna(0)
        bp = pd.to_numeric(g.get("BeforePlayCount", 0), errors="coerce").fillna(0)
        n = len(g)
        rows.append({
            "Strategy": strat,
            "Events": int(n),
            "AfterCaptureCount": int(ac.sum()),
            "AfterCaptureRate": float(ac.mean()) if n else 0,
            "BeforeCaptureCount": int(bc.sum()),
            "BeforeCaptureRate": float(bc.mean()) if n else 0,
            "CaptureDelta": int(ac.sum() - bc.sum()),
            "AfterTotalPlays": int(ap.sum()),
            "BeforeTotalPlays": int(bp.sum()),
            "PlaysSaved": int(bp.sum() - ap.sum()),
            "AfterPlaysPerCapture": float(ap.sum() / ac.sum()) if ac.sum() else None,
            "Meets75PctFullUniverseFloor": bool((float(ac.mean()) if n else 0) >= 0.75),
        })
    return pd.DataFrame(rows).sort_values(["Meets75PctFullUniverseFloor", "AfterTotalPlays"], ascending=[False, True]).reset_index(drop=True)

def _v116_run_instructions_table():
    return pd.DataFrame([
        {"Mode":"Fresh model validation", "RequiredSteps":"Daily Prediction → v113 FAST Blind WF → v114 Promotion Executor → v116 Harm Finalizer", "WhenToUse":"When history/rules changed or you need fresh blind proof."},
        {"Mode":"Daily play generation", "RequiredSteps":"Daily Prediction → v114 Promotion Executor using locked rules → final playlist", "WhenToUse":"After suppression rules are locked. Do not rerun v113 daily."},
        {"Mode":"Recovery if session drops", "RequiredSteps":"Upload v113 per-event + v114 promoted rules directly into v116", "WhenToUse":"Only if Streamlit lost session state."},
    ])


