def _v115_rank_suppression(per_event, rules):
    rows = []
    if isinstance(per_event, pd.DataFrame) and not per_event.empty and "RuleReason" in per_event.columns:
        pe = per_event.copy()
        if "ActionApplied" in pe.columns:
            pe = pe[pe["ActionApplied"].astype(str).str.contains("TOP1_ONLY|WASTE|FORCE_TOP1", case=False, na=False)].copy()
        for reason, g in pe.groupby("RuleReason", dropna=False):
            if not str(reason).strip(): 
                continue
            bp = pd.to_numeric(g.get("BeforePlayCount",0), errors="coerce").fillna(0)
            ap = pd.to_numeric(g.get("AfterPlayCount",0), errors="coerce").fillna(0)
            bc = pd.to_numeric(g.get("BeforeCaptured",0), errors="coerce").fillna(0)
            ac = pd.to_numeric(g.get("AfterCaptured",0), errors="coerce").fillna(0)
            saved = int((bp-ap).sum())
            harm = int(((bc==1)&(ac==0)).sum())
            keep = int(((bc==1)&(ac==1)).sum())
            rows.append({"RuleKey":str(reason)[:240],"Source":"blind_per_event","EventsAffected":int(len(g)),"PlaysSaved":saved,"WinsHarmed":harm,"WinsPreserved":keep,"PlaysSavedPerHarmedWin":(saved/harm if harm else None),"NetScore":saved-(25*harm),"PromotionStatus":"LOCK_CANDIDATE" if saved>0 and harm==0 else ("REVIEW" if saved>0 else "HOLD")})
    if not rows and isinstance(rules, pd.DataFrame) and not rules.empty:
        rr = rules.copy()
        if "v115_Action" not in rr.columns:
            if "v114_Action" in rr.columns:
                rr["v115_Action"] = rr["v114_Action"]
            elif "recommended_action" in rr.columns and "_v114_action" in globals():
                rr["v115_Action"] = rr["recommended_action"].map(_v114_action)
            else:
                rr["v115_Action"] = ""
        rr = rr[rr["v115_Action"].astype(str).str.contains("TOP1_ONLY|WASTE", case=False, na=False)].copy()
        for _, r in rr.iterrows():
            rows.append({"RuleKey":str(r.get("trait",""))[:240],"Source":"rule_stats_only","EventsAffected":int(r.get("support",0) or 0),"PlaysSaved":None,"WinsHarmed":None,"WinsPreserved":None,"PlaysSavedPerHarmedWin":None,"NetScore":float(r.get("gap",0) or 0)*1000+float(r.get("target_rate",0) or 0)*100,"PromotionStatus":"REVIEW_NEEDS_PER_EVENT_HARM","TargetRate":r.get("target_rate",None),"Gap":r.get("gap",None),"Support":r.get("support",None),"Action":r.get("v115_Action","")})
    out = pd.DataFrame(rows)
    return out.sort_values(["PromotionStatus","NetScore"], ascending=[True,False]).reset_index(drop=True) if not out.empty else out

def _v115_regime(per_event):
    if per_event is None or not isinstance(per_event, pd.DataFrame) or per_event.empty:
        return pd.DataFrame()
    df=per_event.copy()
    df["Regime9"]="UNKNOWN9"; df["Regime0"]="UNKNOWN0"
    if "seed_has9" in df.columns: df["Regime9"]=df["seed_has9"].map(lambda x:"HAS9" if str(x) in {"1","1.0","True","true"} else "NO9")
    if "seed_has0" in df.columns: df["Regime0"]=df["seed_has0"].map(lambda x:"HAS0" if str(x) in {"1","1.0","True","true"} else "NO0")
    rows=[]
    for cols in [["Regime9"],["Regime0"],["Regime9","Regime0"]]:
        for key,g in df.groupby(cols, dropna=False):
            if not isinstance(key, tuple): key=(key,)
            cap=pd.to_numeric(g.get("AfterCaptured",0), errors="coerce").fillna(0)
            plays=pd.to_numeric(g.get("AfterPlayCount",0), errors="coerce").fillna(0)
            rows.append({"RegimeType":"+".join(cols),"Regime":"+".join(map(str,key)),"Rows":len(g),"CaptureCount":int(cap.sum()),"CaptureRate":float(cap.mean()) if len(g) else 0,"TotalPlays":int(plays.sum()),"AvgPlaysPerRow":float(plays.mean()) if len(g) else 0})
    return pd.DataFrame(rows)

def _v115_stream_compare(df):
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return pd.DataFrame()
    rows=[]
    for n in [20,25,30,35,40,45,50]:
        sr = pd.to_numeric(df.get("StreamRank",999999), errors="coerce") <= n
        if "SingleRow" in df.columns:
            rr = pd.to_numeric(df["SingleRow"], errors="coerce") <= n
        else:
            rr = pd.to_numeric(df.get("RowPercentile",999999), errors="coerce") <= n
        for method,mask in [("StreamRankTopN",sr),("SingleRowTopN",rr),("AgreementBothTopN",sr&rr),("EitherTopN",sr|rr)]:
            sub=df[mask.fillna(False)]
            pc="v115_FinalPlayCount" if "v115_FinalPlayCount" in sub.columns else ("v114_FinalPlayCount" if "v114_FinalPlayCount" in sub.columns else "AfterPlayCount")
            cc="AfterCaptured" if "AfterCaptured" in sub.columns else None
            rows.append({"N":n,"Method":method,"RowsKept":len(sub),"TotalPlays":int(pd.to_numeric(sub.get(pc,0), errors="coerce").fillna(0).sum()),"CaptureCount":int(pd.to_numeric(sub.get(cc,0), errors="coerce").fillna(0).sum()) if cc else None})
    return pd.DataFrame(rows)

def _v115_cost(daily, cost=1.0):
    if daily is None or not isinstance(daily, pd.DataFrame) or daily.empty: return pd.DataFrame()
    after_col = "v114_FinalPlayCount" if "v114_FinalPlayCount" in daily.columns else "AfterPlayCount"
    before_col = "v114_CurrentPlayCount" if "v114_CurrentPlayCount" in daily.columns else "BeforePlayCount"
    after=int(pd.to_numeric(daily.get(after_col,0), errors="coerce").fillna(0).sum())
    before=int(pd.to_numeric(daily.get(before_col,0), errors="coerce").fillna(0).sum())
    return pd.DataFrame([{"Metric":"RowsPlayed","Value":len(daily)},{"Metric":"BoxPlaysBeforeSuppression","Value":before},{"Metric":"BoxPlaysAfterSuppression","Value":after},{"Metric":"BoxPlaysSaved","Value":before-after},{"Metric":"EstimatedCost","Value":after*float(cost)},{"Metric":"EstimatedSavings","Value":(before-after)*float(cost)}])

def _v115_validation(per_event):
    if per_event is None or not isinstance(per_event,pd.DataFrame) or per_event.empty: return pd.DataFrame()
    rows=[]
    groups=per_event.groupby("strategy", dropna=False) if "strategy" in per_event.columns else [("production_preview",per_event)]
    for strat,g in groups:
        cap=pd.to_numeric(g.get("AfterCaptured",0), errors="coerce").fillna(0)
        plays=pd.to_numeric(g.get("AfterPlayCount",0), errors="coerce").fillna(0)
        rows.append({"Strategy":strat,"Events":len(g),"CaptureCount":int(cap.sum()),"CaptureRate":float(cap.mean()) if len(g) else 0,"TotalPlays":int(plays.sum()),"AvgPlaysPerEvent":float(plays.mean()) if len(g) else 0,"Meets75PctCapture":bool((float(cap.mean()) if len(g) else 0)>=0.75)})
    return pd.DataFrame(rows).sort_values(["Meets75PctCapture","TotalPlays"], ascending=[False,True])


