def _v114_get_rule_source(uploaded=None):
    if uploaded is not None:
        try:
            df = _v108_load_miner_table(uploaded)
            if isinstance(df, pd.DataFrame) and not df.empty:
                return "uploaded_rules", df
        except Exception:
            pass
    for key in ["v113_rules_log","v112_rules_log","v111_correct_separator_scores","v108_miner_scores","v107_separator_scores"]:
        df = st.session_state.get(key)
        if isinstance(df, pd.DataFrame) and not df.empty:
            return "session:" + key, df
    return "none", pd.DataFrame()

def _v114_action(a):
    s = str(a)
    if "TOP1_ONLY" in s or "WASTE" in s:
        return "FORCE_TOP1_ONLY"
    if "TOP1_TOP2_TOP3" in s or "TOP3" in s:
        return "FORCE_TOP1_TOP2_TOP3"
    if "TOP1_TOP2" in s or "NEEDED" in s or "TOP2" in s:
        return "FORCE_TOP1_TOP2"
    if "MISS" in s or "SKIP" in s:
        return "MISS_FLAG_REVIEW"
    return "REVIEW"

def _v114_filter_rules(rules, min_support=8, min_gap=0.05, min_rate=0.20, allow_miss=True, max_rules=300):
    if rules is None or not isinstance(rules, pd.DataFrame) or rules.empty or "recommended_action" not in rules.columns:
        return pd.DataFrame()
    df = rules.copy()
    for c in ["support","gap","target_rate"]:
        if c not in df.columns: df[c] = 0
        df[c] = pd.to_numeric(df[c], errors="coerce").fillna(0)
    df["v114_Action"] = df["recommended_action"].map(_v114_action)
    df = df[df["v114_Action"] != "REVIEW"].copy()
    if not allow_miss:
        df = df[df["v114_Action"] != "MISS_FLAG_REVIEW"].copy()
    df = df[(df["support"] >= int(min_support)) & (df["gap"] >= float(min_gap)) & (df["target_rate"] >= float(min_rate))].copy()
    if df.empty: return df
    pri = {"FORCE_TOP1_ONLY":1,"FORCE_TOP1_TOP2":2,"FORCE_TOP1_TOP2_TOP3":3,"MISS_FLAG_REVIEW":4}
    df["v114_Priority"] = df["v114_Action"].map(pri).fillna(99)
    df = df.sort_values(["v114_Priority","gap","target_rate","support"], ascending=[True,False,False,False])
    if "trait" in df.columns:
        df = df.drop_duplicates(subset=["v114_Action","trait"], keep="first")
    return df.head(int(max_rules)).reset_index(drop=True)

def _v114_ranked(row):
    if "_v112_ranked_members" in globals():
        try: return _v112_ranked_members(row)
        except Exception: pass
    return []

def _v114_current(row):
    if "_v112_current_members" in globals():
        try: return _v112_current_members(row)
        except Exception: pass
    r = _v114_ranked(row)
    return r[:1]

def _v114_rule_passes(row, trait):
    if "_v112_rule_passes" in globals():
        try: return _v112_rule_passes(row, trait)
        except Exception: pass
    parts = [p.strip() for p in str(trait).split(" AND ")]
    for part in parts:
        if "==" in part:
            col, val = part.split("==", 1)
            if col.strip() not in row.index or str(row.get(col.strip())) != val.strip(): return False
        else:
            col = part.strip()
            if col not in row.index: return False
            try:
                if int(float(row.get(col))) != 1: return False
            except Exception:
                if str(row.get(col)).lower() not in {"1","true","yes"}: return False
    return True

def _v114_prepare_daily(df):
    out = df.copy()
    if "_v111_add_bucket_features" in globals():
        try: out = _v111_add_bucket_features(out)
        except Exception: pass
    return out

def _v114_apply_daily(daily, rules, enable_skip=False):
    if daily is None or not isinstance(daily, pd.DataFrame) or daily.empty:
        return pd.DataFrame(), pd.DataFrame()
    work = _v114_prepare_daily(daily)
    rows = []
    for _, row in work.iterrows():
        cur = _v114_current(row)
        ranked = _v114_ranked(row)
        final = list(cur)
        action, reason = "KEEP_EXISTING", ""
        for _, rule in rules.iterrows():
            trait = str(rule.get("trait",""))
            if not trait or not _v114_rule_passes(row, trait): continue
            act = str(rule.get("v114_Action", _v114_action(rule.get("recommended_action",""))))
            reason = f"{act} | {trait} | target={rule.get('target','')} | rate={float(rule.get('target_rate',0)):.3f} | support={int(rule.get('support',0))} | gap={float(rule.get('gap',0)):.3f}"
            action = act
            if act == "FORCE_TOP1_ONLY": final = ranked[:1]
            elif act == "FORCE_TOP1_TOP2": final = ranked[:2]
            elif act == "FORCE_TOP1_TOP2_TOP3": final = ranked[:3]
            elif act == "MISS_FLAG_REVIEW":
                action = "SKIP_PREVIEW" if enable_skip else "MISS_FLAG_REVIEW"
                final = [] if enable_skip else list(cur)
            break
        d = row.to_dict()
        d["v114_CurrentMembersToPlay"] = " + ".join(cur)
        d["v114_CurrentPlayCount"] = len(cur)
        d["v114_FinalMembersToPlay"] = " + ".join(final)
        d["v114_FinalPlayCount"] = len(final)
        d["v114_PlayDelta"] = len(final)-len(cur)
        d["v114_PromotionAction"] = action
        d["v114_PromotionReason"] = reason
        rows.append(d)
    prev = pd.DataFrame(rows)
    return prev, _v114_summary(prev)

def _v114_summary(prev):
    if prev is None or prev.empty: return pd.DataFrame()
    before = int(pd.to_numeric(prev["v114_CurrentPlayCount"], errors="coerce").fillna(0).sum())
    after = int(pd.to_numeric(prev["v114_FinalPlayCount"], errors="coerce").fillna(0).sum())
    rows = [{"metric":"rows","value":len(prev)},{"metric":"current_box_plays","value":before},{"metric":"v114_final_box_plays","value":after},{"metric":"plays_saved","value":before-after}]
    for k,v in prev["v114_PromotionAction"].astype(str).value_counts().items():
        rows.append({"metric":"action__"+k,"value":int(v)})
    return pd.DataFrame(rows)


