# v113 FAST BLIND WALK-FORWARD SEPARATOR LAB
# ================================
def _v113_source(uploaded=None):
    if uploaded is not None:
        return "uploaded:" + str(getattr(uploaded, "name", "file")), _v108_load_miner_table(uploaded)
    if "_v111_get_available_miner_source" in globals():
        return _v111_get_available_miner_source()
    return "none", pd.DataFrame()

def _v113_prepare_matrix(df, max_pair_traits=30):
    work = _v112_prepare_event_table(df)
    work = _v112_sort_events(work)
    raw = _v112_trait_masks_live_safe(work) if "_v112_trait_masks_live_safe" in globals() else {}
    cols = {}
    for name, mask in raw.items():
        try:
            s = mask.fillna(False).astype(bool).reset_index(drop=True)
            if 1 < int(s.sum()) < len(work):
                cols[str(name)] = s
        except Exception:
            pass
    # limit paired traits to prevent lockups
    scored = sorted([(min(int(s.sum()), len(work)-int(s.sum())), n) for n,s in cols.items()], reverse=True)
    base_names = [n for _, n in scored[:int(max_pair_traits)]]
    for i, a in enumerate(base_names):
        for b in base_names[i+1:]:
            s = cols[a] & cols[b]
            if 1 < int(s.sum()) < len(work):
                cols[f"{a} AND {b}"] = s
    tm = pd.DataFrame(cols).astype(bool) if cols else pd.DataFrame()
    return work, tm

def _v113_mine(train_end, work, tm, min_support=8, min_gap=0.05, max_rules=150):
    if train_end <= 0 or tm is None or tm.empty or "v111_TargetOutcome" not in work.columns:
        return pd.DataFrame()
    y = work.iloc[:train_end]["v111_TargetOutcome"].astype(str).reset_index(drop=True)
    x = tm.iloc[:train_end].reset_index(drop=True)
    rows = []
    specs = [
        ("WASTE","FIX_TOP2_WASTE__FORCE_TOP1_ONLY",0.55,1),
        ("NEEDED","FIX_TOP2_NEEDED__FORCE_TOP1_TOP2",0.35,2),
        ("TOP3_WIN","FIX_TOP3_NEEDED__FORCE_TOP1_TOP2_TOP3",0.18,3),
        ("MISS","FIX_MISS_POCKET__SKIP_OR_DOWNRANK_REVIEW",0.45,4),
    ]
    for trait in x.columns:
        mask = x[trait].fillna(False).astype(bool)
        support = int(mask.sum())
        if support < int(min_support) or support == len(x):
            continue
        sy, ry = y[mask], y[~mask]
        for target, action, min_rate, pri in specs:
            h = int((sy == target).sum())
            rate = h / support if support else 0
            rest_rate = int((ry == target).sum()) / len(ry) if len(ry) else 0
            gap = rate - rest_rate
            if rate >= min_rate and gap >= float(min_gap):
                rows.append(dict(target=target, trait=trait, support=support, target_hits=h,
                                 target_rate=rate, rest_rate=rest_rate, gap=gap,
                                 recommended_action=action, priority=pri, train_end=train_end))
    out = pd.DataFrame(rows)
    return out.sort_values(["priority","gap","target_rate","support"], ascending=[True,False,False,False]).head(int(max_rules)).reset_index(drop=True) if not out.empty else out

def _v113_current(row):
    return _v112_current_members(row)

def _v113_ranked(row):
    return _v112_ranked_members(row)

def _v113_true(row):
    return _v112_true_member(row)

def _v113_apply(i, row, rules, tm, stages, enable_skip=False):
    current = _v113_current(row)
    ranked = _v113_ranked(row)
    if rules is None or not isinstance(rules, pd.DataFrame) or rules.empty:
        return current, "KEEP_EXISTING", ""
    allow = []
    if "waste" in stages: allow.append("FIX_TOP2_WASTE__FORCE_TOP1_ONLY")
    if "needed" in stages: allow.append("FIX_TOP2_NEEDED__FORCE_TOP1_TOP2")
    if "top3" in stages: allow.append("FIX_TOP3_NEEDED__FORCE_TOP1_TOP2_TOP3")
    if "miss" in stages: allow.append("FIX_MISS_POCKET__SKIP_OR_DOWNRANK_REVIEW")
    for _, r in rules.iterrows():
        action, trait = str(r.get("recommended_action","")), str(r.get("trait",""))
        if action not in allow or trait not in tm.columns or not bool(tm.iloc[i][trait]):
            continue
        reason = f"{action} | {trait} | rate={float(r.get('target_rate',0)):.3f} | support={int(r.get('support',0))}"
        if action == "FIX_TOP2_WASTE__FORCE_TOP1_ONLY": return ranked[:1], action, reason
        if action == "FIX_TOP2_NEEDED__FORCE_TOP1_TOP2": return ranked[:2], action, reason
        if action == "FIX_TOP3_NEEDED__FORCE_TOP1_TOP2_TOP3": return ranked[:3], action, reason
        if action == "FIX_MISS_POCKET__SKIP_OR_DOWNRANK_REVIEW":
            return ([] if enable_skip else current), ("SKIP_PREVIEW" if enable_skip else "MISS_FLAG_ONLY"), reason
    return current, "KEEP_EXISTING", ""

def _v113_fast_lab(df, train_min=60, retrain_every=5, min_support=8, min_gap=0.05, max_rules=150, max_pair_traits=30, max_events=0, enable_skip=False):
    strategies = {
        "baseline_no_separator": (),
        "waste_only": ("waste",),
        "needed_only": ("needed",),
        "top3_only": ("top3",),
        "waste_plus_needed": ("waste","needed"),
        "waste_needed_top3": ("waste","needed","top3"),
        "full_stack_no_skip": ("waste","needed","top3","miss"),
    }
    work, tm = _v113_prepare_matrix(df, max_pair_traits=max_pair_traits)
    n = len(work) if not max_events else min(len(work), int(max_events))
    cached, last = pd.DataFrame(), None
    per, logs = [], []
    for i in range(n):
        if i >= int(train_min) and (last is None or i - last >= int(retrain_every)):
            cached = _v113_mine(i, work, tm, min_support=min_support, min_gap=min_gap, max_rules=max_rules)
            last = i
            if isinstance(cached, pd.DataFrame) and not cached.empty:
                c = cached.copy(); c["event_index_used_from"] = i; logs.append(c)
        row = work.iloc[i]
        for sname, stages in strategies.items():
            before = _v113_current(row)
            after, action, reason = (before, "BASELINE", "") if sname == "baseline_no_separator" else _v113_apply(i,row,cached,tm,stages,enable_skip and "miss" in stages)
            true = _v113_true(row)
            d = {"event_index":i,"strategy":sname,"train_events_available":i,"rules_cached_from_event":last}
            for c in ["Date","StreamKey","RecommendedStream","State","Game","StreamRank","RowPercentile","SingleRow","PlayType","PredictedMember","Top2_pred","ThirdMember","v111_TargetOutcome"]:
                if c in work.columns: d[c] = row.get(c)
            d.update({"BeforeMembers":" + ".join(before),"AfterMembers":" + ".join(after),
                      "BeforePlayCount":len(before),"AfterPlayCount":len(after),
                      "PlayDelta":len(after)-len(before),"TrueMember":true,
                      "BeforeCaptured":int(true in set(before)) if true else None,
                      "AfterCaptured":int(true in set(after)) if true else None,
                      "ActionApplied":action,"RuleReason":reason})
            per.append(d)
    per = pd.DataFrame(per)
    rules = pd.concat(logs, ignore_index=True) if logs else pd.DataFrame()
    summ = _v112_summary(per)
    queue = _v112_promotion_queue(summ)
    meta = pd.DataFrame([dict(BuildMarker="v113_FAST_BLIND_WF_SEPARATOR_LAB", events_processed=n,
                              traits_precomputed=int(tm.shape[1]) if isinstance(tm,pd.DataFrame) else 0,
                              train_min=train_min, retrain_every=retrain_every, min_support=min_support,
                              min_gap=min_gap, max_rules=max_rules, max_pair_traits=max_pair_traits)])
    return per, rules, summ, queue, meta, pd.DataFrame({"trait": list(tm.columns)}) if isinstance(tm,pd.DataFrame) else pd.DataFrame()


# ================================
# v112 BLIND WALK-FORWARD SEPARATOR LAB
# ================================
V112_FORBIDDEN_TARGET_OR_LEAK_COLS = [
    "TrueMember","WinningMember","ActualMember","Top1_Correct","Needed_Top2",
    "Top2Needed","Needed_Top3","Top3Needed","Top3_Needed","Miss","WinnerSurvived",
    "Captured","v111_TargetOutcome","v111_TargetOutcomeDetail","v108_OutcomeGroup",
    "OutcomeGroup","play_rule_hit"
]

def _v112_norm(s):
    return re.sub(r"[^a-z0-9]+", "", str(s).lower())

def _v112_member(x):
    return _v111_member(x) if "_v111_member" in globals() else None

def _v112_prepare_event_table(df):
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return pd.DataFrame()
    out = df.copy()
    if "_v111_compute_correct_outcome_targets" in globals():
        out = _v111_compute_correct_outcome_targets(out)
    if "_v111_add_bucket_features" in globals():
        out = _v111_add_bucket_features(out)
    return out

def _v112_safe_feature_audit(df):
    cols = list(df.columns) if isinstance(df, pd.DataFrame) else []
    forbid = [_v112_norm(c) for c in V112_FORBIDDEN_TARGET_OR_LEAK_COLS]
    rows = []
    for c in cols:
        n = _v112_norm(c)
        forbidden = any(f == n for f in forbid)
        live_safe = (
            str(c).startswith(("cnt","has","seed_","Row","Stream","v64_","v106_","v111_bucket_"))
            or c in ["sum_bucket","spread_bucket","parity_pattern","highlow_pattern","structure","PlayType",
                     "PredictedMember","Top2_pred","ThirdMember","Margin","Top2RiskScore","Top2Decision",
                     "Top2ToTop1Ratio","ModelConfidenceScore","RowPercentile","SingleRow","StreamRank"]
        )
        rows.append({"column":c,"role":"TARGET_ONLY_DO_NOT_USE_LIVE" if forbidden else ("LIVE_SAFE_FEATURE" if live_safe else "REVIEW_BEFORE_LIVE"),"used_by_v112_miner": bool(live_safe and not forbidden)})
    return pd.DataFrame(rows)

def _v112_sort_events(df):
    out = df.copy()
    date_col = "Date" if "Date" in out.columns else None
    stream_col = "StreamKey" if "StreamKey" in out.columns else ("RecommendedStream" if "RecommendedStream" in out.columns else None)
    out["_v112_date_sort"] = pd.to_datetime(out[date_col], errors="coerce") if date_col else range(len(out))
    out["_v112_stream_sort"] = out[stream_col].astype(str) if stream_col else ""
    return out.sort_values(["_v112_date_sort","_v112_stream_sort"]).reset_index(drop=True)

def _v112_ranked_members(row):
    ranked = []
    for group in [["PredictedMember","Top1","Top1_Display"],["Top2_pred","Top2","Top2_Display"],["ThirdMember","Top3","Top3_Display"]]:
        for col in group:
            if col in row.index:
                m = _v112_member(row.get(col))
                if m and m not in ranked:
                    ranked.append(m); break
    for m in ["3389","3899","3889"]:
        if m not in ranked:
            ranked.append(m)
    return ranked[:3]

def _v112_current_members(row):
    for col in ["ActualBoxPlay","RecommendedPlay","ActualBoxPlayDisplay","BoxPlayInstruction"]:
        if col in row.index and pd.notna(row.get(col)):
            found = []
            for tok in re.findall(r"\d+", str(row.get(col))):
                m = _v112_member(tok)
                if m and m not in found:
                    found.append(m)
            if found:
                return found
    ranked = _v112_ranked_members(row)
    pt = str(row.get("PlayType","")).upper()
    return ranked[:3] if "TOP3" in pt else (ranked[:2] if "TOP2" in pt else ranked[:1])

def _v112_true_member(row):
    for col in ["TrueMember","WinningMember","ActualMember"]:
        if col in row.index:
            m = _v112_member(row.get(col))
            if m:
                return m
    return None

def _v112_trait_masks_live_safe(df):
    traits = {}
    if "_v111_trait_masks" in globals():
        try:
            raw = _v111_trait_masks(df)
        except Exception:
            raw = {}
    else:
        raw = {}
    forbidden = [_v112_norm(c) for c in V112_FORBIDDEN_TARGET_OR_LEAK_COLS]
    for k, mask in raw.items():
        nk = _v112_norm(k)
        if any(f in nk for f in forbidden):
            continue
        traits[k] = mask
    return traits

def _v112_mine_rules_from_train(train_df, min_support=8, min_gap=0.05, max_rules=200):
    if train_df is None or train_df.empty or "v111_TargetOutcome" not in train_df.columns:
        return pd.DataFrame()
    traits = _v112_trait_masks_live_safe(train_df)
    rows = []
    for trait, mask in traits.items():
        mask = mask.fillna(False).astype(bool)
        support = int(mask.sum())
        if support < int(min_support) or support == len(train_df):
            continue
        sub, rest = train_df[mask], train_df[~mask]
        for target, action, min_rate in [
            ("WASTE","FIX_TOP2_WASTE__FORCE_TOP1_ONLY",0.55),
            ("NEEDED","FIX_TOP2_NEEDED__FORCE_TOP1_TOP2",0.35),
            ("TOP3_WIN","FIX_TOP3_NEEDED__FORCE_TOP1_TOP2_TOP3",0.18),
            ("MISS","FIX_MISS_POCKET__SKIP_OR_DOWNRANK_REVIEW",0.45),
        ]:
            h = int((sub["v111_TargetOutcome"] == target).sum())
            r = int((rest["v111_TargetOutcome"] == target).sum())
            rate = h/support if support else 0
            rest_rate = r/len(rest) if len(rest) else 0
            gap = rate - rest_rate
            if rate >= min_rate and gap >= float(min_gap):
                rows.append({"target":target,"trait":trait,"support":support,"target_hits":h,"target_rate":rate,"rest_rate":rest_rate,"gap":gap,"recommended_action":action})
    out = pd.DataFrame(rows)
    if out.empty:
        return out
    priority = {"FIX_TOP2_WASTE__FORCE_TOP1_ONLY":1,"FIX_TOP2_NEEDED__FORCE_TOP1_TOP2":2,"FIX_TOP3_NEEDED__FORCE_TOP1_TOP2_TOP3":3,"FIX_MISS_POCKET__SKIP_OR_DOWNRANK_REVIEW":4}
    out["priority"] = out["recommended_action"].map(priority).fillna(99)
    return out.sort_values(["priority","gap","target_rate","support"], ascending=[True,False,False,False]).head(int(max_rules)).reset_index(drop=True)

def _v112_rule_passes(row, trait):
    parts = [p.strip() for p in str(trait).split(" AND ")]
    for part in parts:
        if "==" in part:
            col, val = part.split("==",1)
            if col.strip() not in row.index or str(row.get(col.strip())) != val.strip():
                return False
        else:
            col = part.strip()
            if col not in row.index:
                return False
            try:
                if int(float(row.get(col))) != 1:
                    return False
            except Exception:
                if str(row.get(col)).lower() not in {"1","true","yes"}:
                    return False
    return True

def _v112_apply_rules(row, rules, stages, enable_skip=False):
    current = _v112_current_members(row)
    ranked = _v112_ranked_members(row)
    if rules is None or rules.empty:
        return current, "KEEP_EXISTING", ""
    allowed = []
    if "waste" in stages: allowed.append("FIX_TOP2_WASTE__FORCE_TOP1_ONLY")
    if "needed" in stages: allowed.append("FIX_TOP2_NEEDED__FORCE_TOP1_TOP2")
    if "top3" in stages: allowed.append("FIX_TOP3_NEEDED__FORCE_TOP1_TOP2_TOP3")
    if "miss" in stages: allowed.append("FIX_MISS_POCKET__SKIP_OR_DOWNRANK_REVIEW")
    for _, r in rules.iterrows():
        action = str(r.get("recommended_action",""))
        if action not in allowed:
            continue
        if _v112_rule_passes(row, str(r.get("trait",""))):
            if action == "FIX_TOP2_WASTE__FORCE_TOP1_ONLY":
                return ranked[:1], action, f"{r.get('trait')} | train_rate={float(r.get('target_rate',0)):.3f}"
            if action == "FIX_TOP2_NEEDED__FORCE_TOP1_TOP2":
                return ranked[:2], action, f"{r.get('trait')} | train_rate={float(r.get('target_rate',0)):.3f}"
            if action == "FIX_TOP3_NEEDED__FORCE_TOP1_TOP2_TOP3":
                return ranked[:3], action, f"{r.get('trait')} | train_rate={float(r.get('target_rate',0)):.3f}"
            if action == "FIX_MISS_POCKET__SKIP_OR_DOWNRANK_REVIEW":
                return ([] if enable_skip else current), ("SKIP_PREVIEW" if enable_skip else "MISS_FLAG_ONLY"), f"{r.get('trait')} | train_rate={float(r.get('target_rate',0)):.3f}"
    return current, "KEEP_EXISTING", ""

def _v112_blind_walk_forward_lab(df, train_min_events=60, min_support=8, min_gap=0.05, max_rules=200, enable_skip=False):
    strategies = {
        "baseline_no_separator": tuple(),
        "waste_only": ("waste",),
        "needed_only": ("needed",),
        "top3_only": ("top3",),
        "miss_flag_only": ("miss",),
        "waste_plus_needed": ("waste","needed"),
        "waste_needed_top3": ("waste","needed","top3"),
        "full_stack_no_skip": ("waste","needed","top3","miss"),
    }
    work = _v112_sort_events(_v112_prepare_event_table(df))
    rows, rule_logs = [], []
    for i in range(len(work)):
        event = work.iloc[i]
        train = work.iloc[:i].copy()
        rules = pd.DataFrame()
        if len(train) >= int(train_min_events):
            rules = _v112_mine_rules_from_train(train, min_support=min_support, min_gap=min_gap, max_rules=max_rules)
            if not rules.empty:
                rr = rules.copy(); rr["event_index"] = i; rule_logs.append(rr)
        for name, stages in strategies.items():
            before = _v112_current_members(event)
            after, action, reason = (before, "BASELINE", "") if name == "baseline_no_separator" else _v112_apply_rules(event, rules, stages, enable_skip=(enable_skip and "miss" in stages))
            tm = _v112_true_member(event)
            d = {"event_index":i,"strategy":name,"train_events_available":len(train)}
            for c in ["Date","StreamKey","RecommendedStream","State","Game","StreamRank","RowPercentile","SingleRow","PlayType","PredictedMember","Top2_pred","ThirdMember","v111_TargetOutcome"]:
                if c in work.columns: d[c] = event.get(c)
            d.update({"BeforeMembers":" + ".join(before),"AfterMembers":" + ".join(after),"BeforePlayCount":len(before),"AfterPlayCount":len(after),"PlayDelta":len(after)-len(before),"TrueMember":tm,"BeforeCaptured":int(tm in set(before)) if tm else None,"AfterCaptured":int(tm in set(after)) if tm else None,"ActionApplied":action,"RuleReason":reason})
            rows.append(d)
    per = pd.DataFrame(rows)
    rules_all = pd.concat(rule_logs, ignore_index=True) if rule_logs else pd.DataFrame()
    return per, rules_all, _v112_summary(per)

def _v112_summary(per):
    if per is None or per.empty: return pd.DataFrame()
    rows = []
    for strat, g in per.groupby("strategy"):
        valid = g[g["AfterCaptured"].notna()].copy()
        n = len(valid); cap = int(valid["AfterCaptured"].sum()) if n else 0; basecap = int(valid["BeforeCaptured"].sum()) if n else 0
        plays = int(pd.to_numeric(valid["AfterPlayCount"], errors="coerce").fillna(0).sum())
        baseplays = int(pd.to_numeric(valid["BeforePlayCount"], errors="coerce").fillna(0).sum())
        rows.append({"strategy":strat,"events_tested":n,"capture_count":cap,"capture_rate":cap/n if n else 0,"baseline_capture_count_same_events":basecap,"capture_delta_vs_baseline":cap-basecap,"total_plays":plays,"baseline_total_plays_same_events":baseplays,"plays_saved_vs_baseline":baseplays-plays,"plays_per_capture":plays/cap if cap else None,"avg_plays_per_event":plays/n if n else None,"top1_only_events":int((pd.to_numeric(valid["AfterPlayCount"], errors="coerce")==1).sum()),"two_play_events":int((pd.to_numeric(valid["AfterPlayCount"], errors="coerce")==2).sum()),"three_play_events":int((pd.to_numeric(valid["AfterPlayCount"], errors="coerce")==3).sum()),"zero_play_events":int((pd.to_numeric(valid["AfterPlayCount"], errors="coerce")==0).sum())})
    return pd.DataFrame(rows).sort_values(["capture_rate","total_plays"], ascending=[False, True]).reset_index(drop=True)

def _v112_promotion_queue(summary):
    if summary is None or summary.empty: return pd.DataFrame()
    rows = []
    for _, r in summary.iterrows():
        status = "BASELINE_REFERENCE" if r["strategy"] == "baseline_no_separator" else ("TESTED_PROMOTION_CANDIDATE" if float(r["capture_rate"]) >= .75 and int(r["plays_saved_vs_baseline"]) >= 0 else "HOLD")
        rows.append({"Status":status,"Strategy":r["strategy"],"CaptureRateFullTestedUniverse":r["capture_rate"],"CaptureCount":r["capture_count"],"EventsTested":r["events_tested"],"TotalPlays":r["total_plays"],"PlaysSavedVsBaseline":r["plays_saved_vs_baseline"],"NextAction":"Review per-event harm before promotion" if status=="TESTED_PROMOTION_CANDIDATE" else "Review/hold"})
    return pd.DataFrame(rows)


# ================================
# v111 CORRECT TARGETS + BUCKET FEATURES + SELF-ACCESS
# ================================
def _v111_to_int01(x):
    try:
        if pd.isna(x):
            return 0
        s = str(x).strip().lower()
        if s in {"1", "true", "yes", "y"}:
            return 1
        if s in {"0", "false", "no", "n", ""}:
            return 0
        return int(float(s))
    except Exception:
        return 0

def _v111_find_col(df, candidates, required=False):
    if "_v108_find_col" in globals():
        return _v108_find_col(df, candidates, required=required)
    nmap = {re.sub(r"[^a-z0-9]+", "", str(c).lower()): c for c in getattr(df, "columns", [])}
    for cand in candidates:
        key = re.sub(r"[^a-z0-9]+", "", str(cand).lower())
        if key in nmap:
            return nmap[key]
    if required:
        raise KeyError(f"Missing required column from {candidates}")
    return None

def _v111_member(x):
    if "_v108_member" in globals():
        return _v108_member(x)
    if pd.isna(x):
        return None
    nums = re.findall(r"\d+", str(x))
    for token in reversed(nums):
        z = token.zfill(4)
        if z in {"3389", "3899", "3889"}:
            return z
        if token in {"25", "225", "255"}:
            return {"25":"3389","225":"3899","255":"3889"}[token]
    return None

def _v111_compute_correct_outcome_targets(df):
    """
    Correctly computes TARGETS separate from feature buckets.
    Keeps existing bucket columns like sum_bucket/spread_bucket as predictors, not labels.
    """
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return pd.DataFrame()
    out = df.copy()

    # Preserve any existing mistaken bucket label but do not trust it as outcome.
    old_outcome = _v111_find_col(out, ["v108_OutcomeGroup", "OutcomeGroup", "outcome_group"], required=False)
    if old_outcome and old_outcome in out.columns:
        out["v111_PreviousOutcomeLabel_Preserved"] = out[old_outcome].astype(str)

    top1_correct_col = _v111_find_col(out, ["Top1_Correct", "top1_correct", "IsTop1Correct"], required=False)
    needed_top2_col = _v111_find_col(out, ["Needed_Top2", "needed_top2", "Top2Needed"], required=False)
    miss_col = _v111_find_col(out, ["Miss", "miss", "IsMiss"], required=False)
    top3_needed_col = _v111_find_col(out, ["Top3_Needed", "Needed_Top3", "top3_needed", "Top3Needed"], required=False)

    win_col = _v111_find_col(out, ["WinningMember", "winning_member", "TrueMember", "ActualMember"], required=False)
    top1_col = _v111_find_col(out, ["PredictedMember", "Top1", "Top1_Display"], required=False)
    top2_col = _v111_find_col(out, ["Top2_pred", "Top2", "Top2_Display"], required=False)
    top3_col = _v111_find_col(out, ["ThirdMember", "Top3", "Top3_Display"], required=False)
    play_col = _v111_find_col(out, ["ActualBoxPlay", "RecommendedPlay", "PlayMembers", "MembersToPlay", "PlayType"], required=False)

    groups = []
    details = []
    for _, r in out.iterrows():
        # Prefer explicit diagnostic columns when present.
        top1_correct = _v111_to_int01(r.get(top1_correct_col)) if top1_correct_col else None
        needed_top2 = _v111_to_int01(r.get(needed_top2_col)) if needed_top2_col else None
        miss = _v111_to_int01(r.get(miss_col)) if miss_col else None
        top3_needed = _v111_to_int01(r.get(top3_needed_col)) if top3_needed_col else None

        if top1_correct == 1:
            # If app played Top2 but Top1 was already right, this is WASTE.
            play_text = str(r.get(play_col, "")) if play_col else ""
            if "TOP2" in play_text.upper() or "+" in play_text:
                groups.append("WASTE")
                details.append("TOP2_WASTE_FROM_TOP1_CORRECT")
            else:
                groups.append("TOP1_WIN")
                details.append("TOP1_WIN")
            continue
        if needed_top2 == 1:
            groups.append("NEEDED")
            details.append("TOP2_NEEDED")
            continue
        if top3_needed == 1:
            groups.append("TOP3_WIN")
            details.append("TOP3_NEEDED")
            continue
        if miss == 1:
            groups.append("MISS")
            details.append("MISS")
            continue

        # Fallback to member comparisons.
        win = _v111_member(r.get(win_col)) if win_col else None
        t1 = _v111_member(r.get(top1_col)) if top1_col else None
        t2 = _v111_member(r.get(top2_col)) if top2_col else None
        t3 = _v111_member(r.get(top3_col)) if top3_col else None
        play_text = str(r.get(play_col, "")) if play_col else ""
        if win is None:
            groups.append("UNCLASSIFIED")
            details.append("NO_WINNER_COLUMN")
        elif t1 == win:
            if "TOP2" in play_text.upper() or "+" in play_text:
                groups.append("WASTE")
                details.append("TOP2_WASTE_FROM_MEMBER_COMPARE")
            else:
                groups.append("TOP1_WIN")
                details.append("TOP1_WIN_FROM_MEMBER_COMPARE")
        elif t2 == win:
            groups.append("NEEDED")
            details.append("TOP2_NEEDED_FROM_MEMBER_COMPARE")
        elif t3 == win:
            groups.append("TOP3_WIN")
            details.append("TOP3_NEEDED_FROM_MEMBER_COMPARE")
        else:
            groups.append("MISS")
            details.append("MISS_FROM_MEMBER_COMPARE")

    out["v111_TargetOutcome"] = groups
    out["v111_TargetOutcomeDetail"] = details
    # For compatibility with v108/v109 scoring functions:
    out["v108_OutcomeGroup"] = out["v111_TargetOutcome"]
    return out

def _v111_add_bucket_features(df):
    """
    Keeps produced buckets as features for gating.
    This is where sum_bucket/spread_bucket/parity/highlow/etc. are retained.
    """
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return pd.DataFrame()
    out = df.copy()

    # Preserve existing v108 traits.
    if "_v108_add_miner_traits" in globals():
        out = _v108_add_miner_traits(out)

    bucket_cols = []
    for c in out.columns:
        lc = str(c).lower()
        if lc in {"sum_bucket", "spread_bucket", "seed_parity_pattern", "seed_highlow_pattern", "seed_repeat_shape", "parity_pattern", "highlow_pattern", "structure"}:
            bucket_cols.append(c)
        elif lc.startswith(("rowbucket", "streamtier", "top2zone", "top2decision", "rowplaytype", "decisionmode")):
            bucket_cols.append(c)

    for c in bucket_cols:
        vals = out[c].astype(str).fillna("")
        for v, n in vals.value_counts().items():
            if v and v.lower() not in {"nan", "none"} and n >= 2:
                safe = re.sub(r"[^A-Za-z0-9_]+", "_", f"v111_bucket_{c}_{v}")[:120]
                out[safe] = vals.eq(v).astype(int)

    # Numeric banding for useful row/model/risk fields.
    for c in ["RowTop1Rate", "RowTop2Rate", "RowTop3Rate", "Top2RiskScore", "Top2ToTop1Ratio", "Margin", "ModelConfidenceScore", "StreamRank", "RowPercentile", "SingleRow"]:
        if c in out.columns:
            vals = pd.to_numeric(out[c], errors="coerce")
            if vals.notna().sum() >= 5:
                try:
                    out[f"v111_{c}_high_q75"] = (vals >= vals.quantile(0.75)).astype(int)
                    out[f"v111_{c}_low_q25"] = (vals <= vals.quantile(0.25)).astype(int)
                except Exception:
                    pass
    return out

def _v111_trait_masks(df):
    """
    Uses v108 masks PLUS v111 bucket/rate masks.
    """
    traits = {}
    if "_v108_trait_masks" in globals():
        try:
            traits.update(_v108_trait_masks(df))
        except Exception:
            pass
    for c in df.columns:
        if str(c).startswith("v111_bucket_") or str(c).startswith("v111_"):
            if c in {"v111_TargetOutcome", "v111_TargetOutcomeDetail", "v111_PreviousOutcomeLabel_Preserved"}:
                continue
            try:
                s = pd.to_numeric(df[c], errors="coerce").fillna(0).astype(int)
                if s.sum() >= 2 and s.sum() < len(df):
                    traits[c] = s.eq(1)
            except Exception:
                pass
    # Limited stacks: combine high-value seed/member buckets with bucket features.
    keys = list(traits.keys())
    high_value = [k for k in keys if any(x in k for x in ["seed_has9","seed_no9","seed_has0","seed_no0","tie_flag","top1_member","top2_member","bucket_sum","bucket_spread","RowTop","Top2Risk","RowPercentile","SingleRow","StreamRank"])]
    high_value = high_value[:80]
    for i in range(len(high_value)):
        for j in range(i + 1, len(high_value)):
            traits[f"{high_value[i]} AND {high_value[j]}"] = traits[high_value[i]] & traits[high_value[j]]
    return traits

def _v111_action(target, rate, support):
    if target in {"TOP1_WIN", "WASTE"} and rate >= 0.60 and support >= 5:
        return "CANDIDATE_TOP1_ONLY"
    if target == "NEEDED" and rate >= 0.30 and support >= 5:
        return "CANDIDATE_TOP1_TOP2_REQUIRED"
    if target == "TOP3_WIN" and rate >= 0.18 and support >= 5:
        return "CANDIDATE_TOP3_REQUIRED"
    if target == "MISS" and rate >= 0.45 and support >= 5:
        return "CANDIDATE_SKIP_OR_DOWNRANK"
    return "REVIEW"

def _v111_score_correct_target_traits(df, min_support=5):
    """
    Scores features against correct outcome targets.
    """
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return pd.DataFrame()
    work = _v111_compute_correct_outcome_targets(df)
    work = _v111_add_bucket_features(work)
    traits = _v111_trait_masks(work)
    targets = ["TOP1_WIN", "WASTE", "NEEDED", "TOP3_WIN", "MISS"]
    rows = []
    total_n = len(work)
    for trait, mask in traits.items():
        mask = mask.fillna(False).astype(bool)
        support = int(mask.sum())
        if support < int(min_support) or support == total_n:
            continue
        sub, rest = work[mask], work[~mask]
        for target in targets:
            h = int((sub["v111_TargetOutcome"] == target).sum())
            r = int((rest["v111_TargetOutcome"] == target).sum())
            rate = h / support if support else 0
            rest_rate = r / len(rest) if len(rest) else 0
            rows.append({
                "target": target,
                "trait": trait,
                "support": support,
                "target_hits": h,
                "target_rate": rate,
                "rest_hits": r,
                "rest_rate": rest_rate,
                "gap": rate - rest_rate,
                "lift_vs_rest": (rate / rest_rate) if rest_rate else None,
                "recommended_action": _v111_action(target, rate, support),
                "BuildMarker": "v111_CORRECT_TARGETS_BUCKET_FEATURES_SELF_ACCESS",
            })
    out = pd.DataFrame(rows)
    if out.empty:
        return out
    return out.sort_values(["recommended_action", "gap", "target_rate", "support"], ascending=[True, False, False, False]).reset_index(drop=True)

def _v111_get_available_miner_source():
    """
    Self-access outputs produced by prior portions of the app.
    No download/reupload required inside the same app.
    """
    # Prefer classified raw data if present.
    for key in ["v108_miner_classified", "v107_separator_classified", "miner_outputs_v6"]:
        obj = st.session_state.get(key)
        if isinstance(obj, pd.DataFrame) and not obj.empty:
            return key, obj
        if isinstance(obj, dict):
            for subkey in ["prepared_df", "work_df"]:
                df = obj.get(subkey)
                if isinstance(df, pd.DataFrame) and not df.empty:
                    return f"{key}.{subkey}", df

    # Fall back to current daily playlist only for preview, not full mining.
    try:
        src, daily = v85_get_daily_playlist()
        if isinstance(daily, pd.DataFrame) and not daily.empty:
            return "current_daily_playlist:" + str(src), daily
    except Exception:
        pass
    return "none", pd.DataFrame()

def _v111_prepare_scores_from_session_or_upload(uploaded_scores=None, uploaded_classified=None, min_support=5):
    """
    No required re-upload: uses session classified data if available.
    Uploads are optional fallback.
    """
    if uploaded_scores is not None:
        try:
            scores = _v108_load_miner_table(uploaded_scores)
            if isinstance(scores, pd.DataFrame) and not scores.empty and "recommended_action" in scores.columns:
                return "uploaded_scores", scores
        except Exception:
            pass
    if uploaded_classified is not None:
        df = _v108_load_miner_table(uploaded_classified)
        scores = _v111_score_correct_target_traits(df, min_support=min_support)
        return "uploaded_classified_recomputed", scores

    src, df = _v111_get_available_miner_source()
    if isinstance(df, pd.DataFrame) and not df.empty:
        scores = _v111_score_correct_target_traits(df, min_support=min_support)
        return "session_recomputed:" + str(src), scores

    return "none", pd.DataFrame()


# ================================
# v110 ROW HISTORY ACTIVATION / AUDIT GUARDS
# ================================
def _v110_row_history_audit(df):
    report = {
        "rows": int(len(df)) if isinstance(df, pd.DataFrame) else 0,
        "status": "UNKNOWN",
        "has_RowPlayTypeReason": False,
        "no_row_history_rows": 0,
        "no_row_history_pct": 0.0,
        "has_RowModelHits": False,
        "rows_with_RowModelHits_gt0": 0,
        "has_RowTopRates": False,
        "ready_for_separator_promotion": False,
        "message": "",
    }
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        report["status"] = "EMPTY"
        report["message"] = "No daily playlist found. Run Daily Prediction and Walk-forward Lab first."
        return report
    n = len(df)
    if "RowPlayTypeReason" in df.columns:
        report["has_RowPlayTypeReason"] = True
        reason = df["RowPlayTypeReason"].astype(str)
        no_hist = reason.str.contains("NO_ROW_HISTORY_YET", case=False, na=False) | reason.str.contains("Run Walk-forward Lab", case=False, na=False)
        report["no_row_history_rows"] = int(no_hist.sum())
        report["no_row_history_pct"] = float(no_hist.mean()) if n else 0.0
    if "RowModelHits" in df.columns:
        report["has_RowModelHits"] = True
        hits = pd.to_numeric(df["RowModelHits"], errors="coerce").fillna(0)
        report["rows_with_RowModelHits_gt0"] = int((hits > 0).sum())
    rate_cols = [c for c in ["RowTop1Rate", "RowTop2Rate", "RowTop3Rate"] if c in df.columns]
    report["has_RowTopRates"] = len(rate_cols) == 3
    if report["no_row_history_rows"] == 0 and report["rows_with_RowModelHits_gt0"] > 0 and report["has_RowTopRates"]:
        report["status"] = "ROW_HISTORY_ACTIVE"
        report["ready_for_separator_promotion"] = True
        report["message"] = "Row history appears active. Separator preview can be evaluated."
    elif report["no_row_history_rows"] > 0:
        report["status"] = "ROW_HISTORY_FALLBACK_ACTIVE"
        report["message"] = "Current playlist still contains NO_ROW_HISTORY_YET fallback rows. Run Walk-forward Lab / row play model before trusting separator promotion."
    else:
        report["status"] = "ROW_HISTORY_INCOMPLETE"
        report["message"] = "Row history fields are incomplete or not populated enough for promotion."
    return report

def _v110_gate_preview_if_needed(daily_df, require_row_history=True):
    audit = _v110_row_history_audit(daily_df)
    if require_row_history and not audit.get("ready_for_separator_promotion", False):
        out = daily_df.copy() if isinstance(daily_df, pd.DataFrame) else pd.DataFrame()
        if isinstance(out, pd.DataFrame) and not out.empty:
            out["v110_RowHistoryGateStatus"] = audit.get("status", "UNKNOWN")
            out["v110_RowHistoryGateMessage"] = audit.get("message", "")
            out["v110_SeparatorAction"] = "BLOCKED_ROW_HISTORY_NOT_ACTIVE"
            out["v110_SeparatorReason"] = audit.get("message", "")
            out["v110_CurrentMembersToPlay"] = ""
            out["v110_CurrentPlayCount"] = 0
            out["v110_PreviewMembersToPlay"] = ""
            out["v110_PreviewPlayCount"] = 0
            out["v110_PlayCountDelta"] = 0
            out["v110_IsPreviewOnly"] = True
        return False, out, pd.DataFrame([audit])
    return True, None, pd.DataFrame([audit])


# ================================
# v109 STAGED SEPARATOR OPTIMIZER HELPERS
# ================================
def _v109_members_from_text(text):
    found = []
    for tok in re.findall(r"\d+", str(text)):
        m = _v108_member(tok) if "_v108_member" in globals() else None
        if m and m not in found:
            found.append(m)
    return found

def _v109_ranked_members_from_row(row):
    ranked = []
    for group in [["PredictedMember","Top1","Top1_Display"], ["Top2_pred","Top2","Top2_Display"], ["ThirdMember","Top3","Top3_Display"]]:
        for col in group:
            if col in row.index:
                m = _v108_member(row.get(col)) if "_v108_member" in globals() else None
                if m and m not in ranked:
                    ranked.append(m); break
    for m in ["3389","3899","3889"]:
        if m not in ranked:
            ranked.append(m)
    return ranked[:3]

def _v109_current_members(row):
    for col in ["ActualBoxPlay","RecommendedPlay","ActualBoxPlayDisplay","BoxPlayInstruction"]:
        if col in row.index and pd.notna(row.get(col)):
            members = _v109_members_from_text(row.get(col))
            if members:
                return members
    ranked = _v109_ranked_members_from_row(row)
    pt = str(row.get("PlayType","")).upper()
    if "TOP3" in pt:
        return ranked[:3]
    if "TOP2" in pt:
        return ranked[:2]
    return ranked[:1]

def _v109_format_members(members):
    return " + ".join([m for m in members if m])

def _v109_stage_priority(action):
    return {"CANDIDATE_TOP1_ONLY":1,"CANDIDATE_TOP1_TOP2_REQUIRED":2,"CANDIDATE_TOP3_REQUIRED":3,"CANDIDATE_SKIP_OR_DOWNRANK":4}.get(str(action),99)

def _v109_rule_passes(row, trait):
    parts = [p.strip() for p in str(trait).split(" AND ")]
    for part in parts:
        if "==" in part:
            col, val = part.split("==",1)
            col, val = col.strip(), val.strip()
            if col not in row.index or str(row.get(col)) != val:
                return False
        else:
            col = part.strip()
            if col not in row.index:
                return False
            try:
                if int(float(row.get(col))) != 1:
                    return False
            except Exception:
                if str(row.get(col)).lower() not in {"1","true","yes"}:
                    return False
    return True

def _v109_filter_rules(scores, min_support=5, min_gap=0.05, min_rate=0.20, max_rules=250):
    if scores is None or not isinstance(scores, pd.DataFrame) or scores.empty or "recommended_action" not in scores.columns:
        return pd.DataFrame()
    df = scores.copy()
    df = df[df["recommended_action"].astype(str).str.startswith("CANDIDATE_")].copy()
    for c in ["support","gap","target_rate"]:
        if c in df.columns:
            df[c] = pd.to_numeric(df[c], errors="coerce")
    df = df[(df["support"] >= int(min_support)) & (df["gap"] >= float(min_gap)) & (df["target_rate"] >= float(min_rate))].copy()
    if df.empty:
        return df
    df["v109_stage_priority"] = df["recommended_action"].map(_v109_stage_priority)
    return df.sort_values(["v109_stage_priority","gap","target_rate","support"], ascending=[True,False,False,False]).head(int(max_rules)).reset_index(drop=True)

def _v109_apply_staged_optimizer(daily_df, scores, min_support=5, min_gap=0.05, min_rate=0.20, max_rules=250, enable_skip_preview=False):
    if daily_df is None or not isinstance(daily_df, pd.DataFrame) or daily_df.empty:
        return pd.DataFrame()
    work = daily_df.copy()
    if "_v108_add_miner_traits" in globals():
        work = _v108_add_miner_traits(work)
    rules = _v109_filter_rules(scores, min_support, min_gap, min_rate, max_rules)
    rows = []
    for _, row in work.iterrows():
        current = _v109_current_members(row)
        ranked = _v109_ranked_members_from_row(row)
        chosen = None
        for _, rule in rules.iterrows():
            if _v109_rule_passes(row, rule.get("trait","")):
                chosen = rule
                break
        action, reason, after = "KEEP_EXISTING", "", list(current)
        if chosen is not None:
            action = str(chosen.get("recommended_action","REVIEW"))
            reason = f"{chosen.get('trait')} | target={chosen.get('target')} | gap={float(chosen.get('gap',0)):.3f} | rate={float(chosen.get('target_rate',0)):.3f} | support={int(chosen.get('support',0))}"
            if action == "CANDIDATE_TOP1_ONLY":
                after = ranked[:1]
            elif action == "CANDIDATE_TOP1_TOP2_REQUIRED":
                after = ranked[:2]
            elif action == "CANDIDATE_TOP3_REQUIRED":
                after = ranked[:3]
            elif action == "CANDIDATE_SKIP_OR_DOWNRANK" and enable_skip_preview:
                after = []
        d = row.to_dict()
        d["v109_CurrentMembersToPlay"] = _v109_format_members(current)
        d["v109_CurrentPlayCount"] = len(current)
        d["v109_SeparatorAction"] = action
        d["v109_SeparatorReason"] = reason
        d["v109_PreviewMembersToPlay"] = _v109_format_members(after)
        d["v109_PreviewPlayCount"] = len(after)
        d["v109_PlayCountDelta"] = len(after) - len(current)
        d["v109_IsPreviewOnly"] = True
        rows.append(d)
    return pd.DataFrame(rows)

def _v109_summary(df):
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return pd.DataFrame()
    before = int(pd.to_numeric(df["v109_CurrentPlayCount"], errors="coerce").fillna(0).sum())
    after = int(pd.to_numeric(df["v109_PreviewPlayCount"], errors="coerce").fillna(0).sum())
    rows = [
        {"metric":"rows","value":int(len(df))},
        {"metric":"current_box_plays","value":before},
        {"metric":"preview_box_plays","value":after},
        {"metric":"plays_saved_preview","value":before-after},
    ]
    for k,v in df["v109_SeparatorAction"].astype(str).value_counts().items():
        rows.append({"metric":"action__"+k,"value":int(v)})
    return pd.DataFrame(rows)


# ================================
# v108 ISOLATED DEEP MINER HELPERS
# ================================
def _v108_miner_bytes(obj):
    if obj is None:
        return b""
    try:
        if isinstance(obj, bytes):
            return obj
        if isinstance(obj, bytearray):
            return bytes(obj)
        if isinstance(obj, str):
            p = Path(obj)
            return p.read_bytes() if p.exists() else obj.encode("utf-8")
        if isinstance(obj, Path):
            return obj.read_bytes() if obj.exists() else str(obj).encode("utf-8")
        if hasattr(obj, "getvalue"):
            v = obj.getvalue()
            return v if isinstance(v, bytes) else str(v).encode("utf-8")
        if hasattr(obj, "read"):
            try:
                obj.seek(0)
            except Exception:
                pass
            v = obj.read()
            return v if isinstance(v, bytes) else str(v).encode("utf-8")
        return str(obj).encode("utf-8")
    except Exception:
        return str(obj).encode("utf-8")

def _v108_miner_name(obj, fallback="miner_input.csv"):
    try:
        nm = getattr(obj, "name", None)
        if nm:
            return str(nm).lower()
        if isinstance(obj, Path):
            return obj.name.lower()
        if isinstance(obj, str):
            p = Path(obj)
            return p.name.lower() if p.suffix else fallback
        return fallback
    except Exception:
        return fallback

def _v108_load_miner_table(uploaded_file):
    import io
    if uploaded_file is None:
        return pd.DataFrame()
    raw = _v108_miner_bytes(uploaded_file)
    name = _v108_miner_name(uploaded_file)
    if name.endswith((".xlsx", ".xls")):
        return pd.read_excel(io.BytesIO(raw))
    text = raw.decode("utf-8", errors="replace")
    for kwargs in [
        dict(sep=None, engine="python"),
        dict(sep="\t"),
        dict(sep=","),
        dict(sep="|", engine="python"),
        dict(sep=";"),
    ]:
        try:
            df = pd.read_csv(io.StringIO(text), **kwargs)
            if isinstance(df, pd.DataFrame) and not df.empty:
                return df
        except Exception:
            continue
    return pd.DataFrame()

def _v108_norm_col(c):
    return re.sub(r"[^a-z0-9]+", "", str(c).lower())

def _v108_find_col(df, candidates, required=False):
    if df is None or not isinstance(df, pd.DataFrame):
        if required:
            raise KeyError("No dataframe supplied")
        return None
    nmap = {_v108_norm_col(c): c for c in df.columns}
    for cand in candidates:
        key = _v108_norm_col(cand)
        if key in nmap:
            return nmap[key]
    for cand in candidates:
        key = _v108_norm_col(cand)
        for nk, orig in nmap.items():
            if key and (key in nk or nk in key):
                return orig
    if required:
        raise KeyError(f"Required column not found. Tried {candidates}. Available: {list(df.columns)}")
    return None

def _v108_member(x):
    if pd.isna(x):
        return None
    s = str(x).strip()
    nums = re.findall(r"\d+", s)
    for token in reversed(nums):
        z = token.zfill(4)
        if z in {"3389", "3899", "3889"}:
            return z
        if token in {"25", "225", "255"}:
            return {"25":"3389","225":"3899","255":"3889"}[token]
    return s if s in {"3389", "3899", "3889"} else None

def _v108_classify_miner_rows(df):
    """
    Isolated classifier for uploaded miner/per-event files only.
    It never writes to app history/session keys used by Daily Prediction.
    """
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return pd.DataFrame()
    out = df.copy()
    og = _v108_find_col(out, ["OutcomeGroup", "outcome_group", "Group", "bucket"], required=False)
    if og:
        out["v108_OutcomeGroup"] = out[og].astype(str).str.upper().replace({
            "WASTE_TOP2":"WASTE", "NEEDED_TOP2":"NEEDED", "MISSED":"MISS", "TOP1":"TOP1_WIN", "TOP3":"TOP3_WIN"
        })
    else:
        win_col = _v108_find_col(out, ["WinningMember", "winning_member", "TrueMember", "ActualMember"], required=False)
        top1_col = _v108_find_col(out, ["Top1", "Top1_Display", "PredictedMember", "top1"], required=False)
        top2_col = _v108_find_col(out, ["Top2", "Top2_pred", "top2"], required=False)
        top3_col = _v108_find_col(out, ["Top3", "ThirdMember", "top3"], required=False)
        play_col = _v108_find_col(out, ["ActualBoxPlay", "RecommendedPlay", "PlayMembers", "MembersToPlay"], required=False)
        hit_col = _v108_find_col(out, ["play_rule_hit", "PlayRuleHit", "WinnerSurvived", "Captured"], required=False)
        groups = []
        if not win_col or not top1_col:
            out["v108_OutcomeGroup"] = "UNCLASSIFIED"
        else:
            for _, r in out.iterrows():
                win = _v108_member(r.get(win_col))
                t1 = _v108_member(r.get(top1_col))
                t2 = _v108_member(r.get(top2_col)) if top2_col else None
                t3 = _v108_member(r.get(top3_col)) if top3_col else None
                play_text = str(r.get(play_col, "")) if play_col else ""
                played = set()
                for tok in re.findall(r"\d+", play_text):
                    m = _v108_member(tok)
                    if m:
                        played.add(m)
                # Fallback: if play text missing, classify by rank relationship only.
                if win is None:
                    groups.append("UNCLASSIFIED")
                elif t1 == win:
                    groups.append("WASTE" if t2 and (t2 in played or "TOP2" in play_text.upper()) else "TOP1_WIN")
                elif t2 == win:
                    groups.append("NEEDED")
                elif t3 == win:
                    groups.append("TOP3_WIN")
                elif hit_col and str(r.get(hit_col)).lower() in {"1","true","yes"}:
                    groups.append("OTHER_CAPTURE")
                else:
                    groups.append("MISS")
            out["v108_OutcomeGroup"] = groups
    return out

def _v108_add_miner_traits(df):
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return pd.DataFrame()
    out = df.copy()
    seed_col = _v108_find_col(out, ["seed", "PrevSeed", "prev_seed", "LastResult"], required=False)
    if seed_col:
        seed_digits = out[seed_col].astype(str).str.replace(r"\D", "", regex=True).str[:4]
        out["v108_seed_has9"] = seed_digits.str.contains("9", na=False).astype(int)
        out["v108_seed_no9"] = (out["v108_seed_has9"] == 0).astype(int)
        out["v108_seed_has0"] = seed_digits.str.contains("0", na=False).astype(int)
        out["v108_seed_no0"] = (out["v108_seed_has0"] == 0).astype(int)
        out["v108_seed_has9_has0"] = ((out["v108_seed_has9"] == 1) & (out["v108_seed_has0"] == 1)).astype(int)
        out["v108_seed_no9_no0"] = ((out["v108_seed_has9"] == 0) & (out["v108_seed_has0"] == 0)).astype(int)
    for cands, name in [
        (["Top1", "PredictedMember", "Top1_Display"], "v108_top1_member"),
        (["Top2", "Top2_pred", "Top2_Display"], "v108_top2_member"),
        (["ThirdMember", "Top3", "Top3_Display"], "v108_top3_member"),
    ]:
        c = _v108_find_col(out, cands, required=False)
        if c:
            out[name] = out[c].map(_v108_member).fillna("")
    tie_col = _v108_find_col(out, ["TieFired", "DeadTie", "Top2Zone", "Top2Decision"], required=False)
    out["v108_tie_flag"] = out[tie_col].astype(str).str.lower().isin(["1","true","yes","tie","dead_tie"]).astype(int) if tie_col else 0
    sr_col = _v108_find_col(out, ["StreamRank"], required=False)
    if sr_col:
        vals = pd.to_numeric(out[sr_col], errors="coerce")
        out["v108_streamrank_band"] = pd.cut(vals, bins=[0,10,20,30,40,50,9999], labels=["SR_1_10","SR_11_20","SR_21_30","SR_31_40","SR_41_50","SR_51_PLUS"], include_lowest=True).astype(str)
    row_col = _v108_find_col(out, ["SingleRowPercentile", "RowPercentile", "SingleRow"], required=False)
    if row_col:
        vals = pd.to_numeric(out[row_col], errors="coerce")
        out["v108_singlerow_band"] = pd.cut(vals, bins=[0,10,20,30,40,50,9999], labels=["ROW_1_10","ROW_11_20","ROW_21_30","ROW_31_40","ROW_41_50","ROW_51_PLUS"], include_lowest=True).astype(str)
    return out

def _v108_trait_masks(df):
    traits = {}
    for col in ["v108_seed_has9","v108_seed_no9","v108_seed_has0","v108_seed_no0","v108_seed_has9_has0","v108_seed_no9_no0","v108_tie_flag"]:
        if col in df.columns:
            traits[col] = df[col].astype(int).eq(1)
    for col in ["v108_top1_member","v108_top2_member","v108_top3_member","v108_streamrank_band","v108_singlerow_band"]:
        if col in df.columns:
            for v, n in df[col].astype(str).value_counts().items():
                if v and v != "nan" and n >= 2:
                    traits[f"{col}=={v}"] = df[col].astype(str).eq(v)
    keys = list(traits.keys())
    for i in range(len(keys)):
        for j in range(i + 1, len(keys)):
            traits[f"{keys[i]} AND {keys[j]}"] = traits[keys[i]] & traits[keys[j]]
    return traits

def _v108_action(target, rate, support):
    if target in {"TOP1_WIN", "WASTE"} and rate >= 0.65 and support >= 5:
        return "CANDIDATE_TOP1_ONLY"
    if target == "NEEDED" and rate >= 0.35 and support >= 5:
        return "CANDIDATE_TOP1_TOP2_REQUIRED"
    if target == "TOP3_WIN" and rate >= 0.20 and support >= 5:
        return "CANDIDATE_TOP3_REQUIRED"
    if target == "MISS" and rate >= 0.50 and support >= 5:
        return "CANDIDATE_SKIP_OR_DOWNRANK"
    return "REVIEW"

def _v108_score_miner_traits(df, min_support=5):
    if df is None or df.empty or "v108_OutcomeGroup" not in df.columns:
        return pd.DataFrame()
    traits = _v108_trait_masks(df)
    targets = ["TOP1_WIN", "WASTE", "NEEDED", "TOP3_WIN", "MISS"]
    rows = []
    for trait, mask in traits.items():
        mask = mask.fillna(False).astype(bool)
        support = int(mask.sum())
        if support < int(min_support) or support == len(df):
            continue
        sub, rest = df[mask], df[~mask]
        for target in targets:
            h = int((sub["v108_OutcomeGroup"] == target).sum())
            r = int((rest["v108_OutcomeGroup"] == target).sum())
            rate = h / support if support else 0
            rest_rate = r / len(rest) if len(rest) else 0
            rows.append({
                "target": target,
                "trait": trait,
                "support": support,
                "target_hits": h,
                "target_rate": rate,
                "rest_hits": r,
                "rest_rate": rest_rate,
                "gap": rate - rest_rate,
                "lift_vs_rest": (rate / rest_rate) if rest_rate else None,
                "recommended_action": _v108_action(target, rate, support),
                "BuildMarker": "v108_DEEP_MINER_ISOLATED_NO_PARSER_TOUCH",
            })
    out = pd.DataFrame(rows)
    return out.sort_values(["gap","target_rate","support"], ascending=[False,False,False]).reset_index(drop=True) if not out.empty else out

def _v108_queue():
    return pd.DataFrame([
        {"Status":"LOCKED_TERM","Item":"SingleRowPercentile definition","Action":"Historical winner-production strength by individual row; distinct from StreamRank/PlaylistRank."},
        {"Status":"LOCKED_GUARD","Item":"Rank/row separation","Action":"Keep StreamRank, SingleRowPercentile, and PlaylistRank visibly separate."},
        {"Status":"CANDIDATE","Item":"Deep Miner separator layer","Action":"Use uploaded per-event/classified file to mine TOP1/WASTE/NEEDED/TOP3/MISS pockets. Preview only."},
        {"Status":"CANDIDATE","Item":"Actual members-to-play clarity","Action":"Expose final members-to-play as primary output after rules are promoted."},
        {"Status":"SOFT_ONLY","Item":"Row/stream cadence","Action":"Caution/tie-breaker only until full replay proves hard suppression safe."},
    ])


# ================================
# v88 DISPLAY-ONLY PLAY VISIBILITY HELPERS
# ================================
# These helpers add obvious ACTUAL PLAY markers for the UI and downloads only.
# They intentionally do not change any prediction, ranking, filtering, scoring,
# stream selection, box member selection, or straight recommendation logic.

def v88_clean_member(value) -> str:
    txt = str(value if value is not None else "").replace("*", "").strip()
    if not txt or txt.lower() in {"nan", "none"}:
        return ""
    return txt.zfill(4) if txt.isdigit() else txt


def v88_box_actual_members(row) -> List[str]:
    play_type = str(row.get("PlayType", row.get("BoxPlayType", ""))).strip()
    top1 = v88_clean_member(row.get("PredictedMember", row.get("Top1_Display", "")))
    top2 = v88_clean_member(row.get("Top2_pred", row.get("Top2_Display", "")))
    top3 = v88_clean_member(row.get("ThirdMember", row.get("Top3_Display", "")))
    members = []
    if play_type == "TOP1_TOP2_TOP3":
        members = [top1, top2, top3]
    elif play_type == "TOP1_TOP2":
        members = [top1, top2]
    elif play_type == "TOP1_ONLY":
        members = [top1]
    else:
        # Preserve prior behavior: if a row is missing PlayType, treat Top1 as the visible play.
        members = [top1]
    return [m for m in members if m]


def v88_add_box_play_markers(df: pd.DataFrame) -> pd.DataFrame:
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return df
    out = df.copy()
    out["PLAY_FLAG"] = "🔴 PLAY"
    out["ActualBoxPlay"] = out.apply(lambda r: " + ".join(v88_box_actual_members(r)), axis=1)
    out["ActualBoxPlayDisplay"] = out["ActualBoxPlay"].apply(
        lambda x: " + ".join([f"🔴 **{p.strip()}**" for p in str(x).split("+") if p.strip()])
    )
    out["BoxPlayInstruction"] = out.apply(
        lambda r: f"🔴 PLAY ONLY: {r['ActualBoxPlay']}" if str(r.get("ActualBoxPlay", "")).strip() else "",
        axis=1,
    )
    return out


def v88_add_straight_play_markers(df: pd.DataFrame) -> pd.DataFrame:
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return df
    out = df.copy()
    rec = pd.to_numeric(out.get("RecommendedStraight", 0), errors="coerce").fillna(0).astype(int)
    out["PLAY_FLAG"] = rec.apply(lambda x: "🔴 PLAY" if int(x) == 1 else "")
    out["ActualStraightPlay"] = out.apply(
        lambda r: str(r.get("StraightPermutation", "")).zfill(4) if int(pd.to_numeric(pd.Series([r.get("RecommendedStraight", 0)]), errors="coerce").fillna(0).iloc[0]) == 1 else "",
        axis=1,
    )
    out["ActualStraightPlayDisplay"] = out.apply(
        lambda r: f"🔴 **{str(r.get('StraightPermutation', '')).zfill(4)}**" if int(pd.to_numeric(pd.Series([r.get("RecommendedStraight", 0)]), errors="coerce").fillna(0).iloc[0]) == 1 else "",
        axis=1,
    )
    out["StraightPlayInstruction"] = out.apply(
        lambda r: f"🔴 PLAY THIS STRAIGHT: {str(r.get('StraightPermutation', '')).zfill(4)}" if int(pd.to_numeric(pd.Series([r.get("RecommendedStraight", 0)]), errors="coerce").fillna(0).iloc[0]) == 1 else "REVIEW ONLY — not a recommended straight play",
        axis=1,
    )
    return out


def v88_play_styler(df: pd.DataFrame, flag_col: str = "PLAY_FLAG"):
    """
    v89 display-only fix: highlight only the actual play cells, not the entire row/table.

    The prior v88 row-level style turned the whole daily playlist red when every visible
    stream was playable. This keeps all diagnostic columns visible while making the
    actual box/straight play columns impossible to miss. No selection/ranking/scoring
    logic is changed here.
    """
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return df

    play_cols = {
        "PLAY_FLAG",
        "ActualBoxPlayDisplay", "ActualBoxPlay", "BoxPlayInstruction",
        "ActualStraightPlayDisplay", "ActualStraightPlay", "StraightPlayInstruction",
    }
    available_play_cols = play_cols.intersection(set(df.columns))
    if not available_play_cols:
        return df

    red_style = (
        "background-color: #b00020; color: white; font-weight: 900; "
        "border: 3px solid #4a000b; font-size: 1.08em;"
    )

    def _cell_style(value, col_name):
        txt = str(value).strip()
        if col_name in available_play_cols and txt and txt.lower() not in {"nan", "none"}:
            if "REVIEW ONLY" in txt.upper():
                return "color: #777; font-style: italic;"
            return red_style
        return ""

    def _style_frame(data):
        styles = pd.DataFrame("", index=data.index, columns=data.columns)
        for col in available_play_cols:
            styles[col] = data[col].apply(lambda v, c=col: _cell_style(v, c))
        return styles

    return df.style.apply(_style_frame, axis=None)

