def _clean_upload_column_name(col) -> str:
    """Normalize upload headers only; does not change downstream app column contracts."""
    c = str(col).replace("\ufeff", "").strip()
    c = re.sub(r"\s+", " ", c)
    return c


def _header_hit_score(cols) -> int:
    aliases = {
        "date", "draw date", "drawdate", "time", "draw time", "state", "st", "game",
        "streamkey", "stream key", "result", "results", "winning numbers", "winning_numbers",
        "winningnumbers", "number", "numbers", "seed", "prevseed", "winningmember",
        "truemember", "trait_stack", "winner_member", "winner_rate", "support", "stack_size"
    }
    return sum(1 for c in cols if _clean_upload_column_name(c).lower().replace("_", " ") in aliases)


def _looks_like_data_row(cols) -> bool:
    text = " | ".join(str(c) for c in cols)
    has_date = bool(re.search(r"\b\d{1,2}[/-]\d{1,2}[/-]\d{2,4}\b|\b\d{4}[/-]\d{1,2}[/-]\d{1,2}\b", text))
    has_pick4 = bool(re.search(r"(?<!\d)\d\D*\d\D*\d\D*\d(?!\d)", text))
    return has_date and has_pick4


def load_upload(uploaded_file, header: Optional[int] = "infer") -> pd.DataFrame:
    """
    Robust upload reader for CSV/TXT/TSV app inputs.

    Fix scope: parsing only. It deliberately returns a DataFrame for the existing
    normalize_history / ensure_truth / ensure_library paths without altering any
    scoring, stream reduction, lab, daily, or straight-play behavior.
    """
    raw = _v102_file_to_bytes(uploaded_file)
    name = _v102_get_upload_name(uploaded_file)

    # v146 loader repair:
    # Some Streamlit sessions can expose an internal file id/UUID as the apparent
    # upload name even though the real file is present in the sidebar. Do not fail
    # only because that displayed/internal name has no extension. Keep extension-
    # based priority when available; otherwise sniff the actual bytes. Parsing only.
    if name.endswith(".csv"):
        seps = [",", "\t", "|", ";"]
    elif name.endswith(".tsv"):
        seps = ["\t", ",", "|", ";"]
    elif name.endswith(".txt"):
        seps = ["\t", ",", "|", ";"]
    else:
        try:
            sample = raw[:12000].decode("utf-8", errors="replace") if isinstance(raw, (bytes, bytearray)) else str(raw)[:12000]
        except Exception:
            sample = ""
        if "\t" in sample:
            seps = ["\t", ",", "|", ";"]
        elif "|" in sample and sample.count("|") > sample.count(","):
            seps = ["|", "\t", ",", ";"]
        elif "," in sample:
            seps = [",", "\t", "|", ";"]
        else:
            seps = ["\t", ",", "|", ";"]

    candidates = []
    for sep in seps:
        for hdr in [0, None]:
            try:
                df = pd.read_csv(
                    io.BytesIO(raw),
                    sep=sep,
                    header=hdr,
                    dtype=str,
                    low_memory=False,
                    encoding="utf-8-sig",
                    on_bad_lines="skip",
                )
                if df is None or df.empty:
                    continue
                df = df.dropna(how="all").copy()
                if hdr is None:
                    df.columns = [f"col_{i}" for i in range(df.shape[1])]
                else:
                    df.columns = [_clean_upload_column_name(c) for c in df.columns]
                df = df.loc[:, ~pd.Index(df.columns).astype(str).str.startswith("Unnamed")].copy()
                hits = _header_hit_score(df.columns)
                penalty = 50 if hdr == 0 and hits == 0 and _looks_like_data_row(df.columns) else 0
                score = (hits * 100) + (df.shape[1] * 10) + min(len(df), 10) - penalty
                candidates.append((score, hits, df.shape[1], len(df), df))
            except Exception:
                continue

    if candidates:
        candidates.sort(key=lambda x: (x[0], x[1], x[2], x[3]), reverse=True)
        return candidates[0][4]

    try:
        df = pd.read_csv(io.BytesIO(raw), sep=None, engine="python", dtype=str, encoding="utf-8-sig", on_bad_lines="skip")
        df.columns = [_clean_upload_column_name(c) for c in df.columns]
        return df.dropna(how="all").copy()
    except Exception:
        df = pd.read_csv(io.BytesIO(raw), sep="\t", header=None, dtype=str, encoding="utf-8-sig", low_memory=False, on_bad_lines="skip")
        df.columns = [f"col_{i}" for i in range(df.shape[1])]
        return df.dropna(how="all").copy()


def extract_pick4_digits(x) -> str:
    if x is None:
        return ""
    s = str(x)
    m = re.search(r"(\d)\D+(\d)\D+(\d)\D+(\d)", s)
    if m:
        return "".join(m.groups())
    m2 = re.search(r"(?<!\d)(\d{4})(?!\d)", s)
    if m2:
        return m2.group(1)
    digits = re.findall(r"\d", s)
    if len(digits) >= 4:
        return "".join(digits[:4])
    return ""


def box_key(s: str) -> str:
    s = extract_pick4_digits(s) or str(s)
    return "".join(sorted(re.sub(r"\D", "", s).zfill(4)[-4:]))


def normalize_member(x) -> str:
    if x is None:
        return ""
    s = str(x).strip().replace("'", "")
    s = re.sub(r"\D", "", s)
    if s in {"25", "389", "3389"}:
        return "3389"
    if s in {"225", "3899"}:
        return "3899"
    if s in {"255", "3889"}:
        return "3889"
    return s.zfill(4) if s else ""


def result_to_core389_member(result4: str) -> str:
    b = box_key(result4)
    return b if b in set(MEMBERS) else ""


def canonical_stream(state: str, game: str) -> str:
    return f"{str(state).strip()} | {str(game).strip()}"



def ensure_streamkey_columns(df: pd.DataFrame, context: str = "data") -> pd.DataFrame:
    """v82: guarantee StreamKey exists whenever possible, without changing existing StreamKey values."""
    out = df.copy()
    out.columns = [str(c).strip() for c in out.columns]
    if "StreamKey" in out.columns:
        out["StreamKey"] = out["StreamKey"].astype(str).str.strip()
        return out

    lower = {str(c).strip().lower(): c for c in out.columns}
    state_col = lower.get("state")
    game_col = lower.get("game")

    # Some exports split draw time/session from game. Include it only when Game does not already carry timing.
    time_col = None
    for cand in ["drawtime", "draw_time", "time", "period", "session", "draw", "daypart"]:
        if cand in lower:
            time_col = lower[cand]
            break

    if state_col is not None and game_col is not None:
        game_text = out[game_col].astype(str).str.strip()
        if time_col is not None:
            time_text = out[time_col].astype(str).str.strip()
            # Avoid duplicating time if already embedded in game label.
            needs_time = ~game_text.str.lower().str.contains("morning|midday|day|evening|night|noon|pm|am|10pm|1:50|7:50", regex=True, na=False)
            game_text = game_text.where(~needs_time, game_text + " " + time_text)
        out["StreamKey"] = out[state_col].astype(str).str.strip() + " | " + game_text.astype(str).str.strip()
        return out

    raise ValueError(f"Could not auto-build StreamKey for {context}. Need StreamKey, or State + Game columns.")

