def v83_is_nonempty_df(x) -> bool:
    return isinstance(x, pd.DataFrame) and not x.empty

def v83_first_nonempty_session_df(keys: List[str]) -> Tuple[Optional[str], Optional[pd.DataFrame]]:
    """Return first non-empty DataFrame from session_state. Prevents straight tabs from using empty placeholders."""
    for key in keys:
        val = st.session_state.get(key)
        if v83_is_nonempty_df(val):
            return key, val.copy()
    return None, None

def v84_score_playlist_candidate(df: pd.DataFrame) -> int:
    """Score whether a session_state DataFrame looks like a daily playlist for straight generation."""
    if not v83_is_nonempty_df(df):
        return -999
    cols = set(map(str, df.columns))
    score = 0
    for c in ["StreamKey", "seed", "PredictedMember", "Top2_pred", "PlayType"]:
        if c in cols:
            score += 10
    for c in ["StreamRank", "RowPercentile", "SingleRow", "RecommendedStream", "UniversalFamilyScore"]:
        if c in cols:
            score += 4
    if "Result" in cols and "TrueMember" in cols:
        score -= 10
    return score

def v84_find_best_playlist_anywhere() -> Tuple[Optional[str], Optional[pd.DataFrame]]:
    """Fallback: scan all session_state objects for the best playlist-like non-empty DataFrame."""
    best_key, best_df, best_score = None, None, -999
    for key, val in st.session_state.items():
        if not v83_is_nonempty_df(val):
            continue
        score = v84_score_playlist_candidate(val)
        if score > best_score:
            best_key, best_df, best_score = key, val.copy(), score
    if best_score >= 30:
        return best_key, best_df
    return None, None

def v83_get_straight_source_playlist(v64_use_ensemble_for_straights: bool = True) -> Tuple[Optional[str], Optional[pd.DataFrame]]:
    """Best available daily playlist source for straight generation."""
    keys = [
        "v80_final_box_playlist",
        "v79_final_daily_play_list",
        "v79_final_play_this_today",
        "v65_daily_optimal_tier_playlist",
        "v645_stream_elimination_playable",
        "v64_final_playlist",
        "v64_ensemble_marked",
        "daily_playlist",
        "playlist",
        "daily_final_playlist",
        "final_playlist",
    ]
    key, df = v83_first_nonempty_session_df(keys)
    if df is not None and v84_score_playlist_candidate(df) >= 30:
        return key, df
    return v84_find_best_playlist_anywhere()

