def v85_promote_canonical_outputs() -> None:
    """Canonical downstream handoff. Safe to call repeatedly after any tab creates outputs."""
    daily_keys = [
        "v80_final_box_playlist",
        "v79_final_daily_play_list",
        "v65_daily_optimal_tier_playlist",
        "v645_stream_elimination_playable",
        "v64_final_playlist",
        "v64_ensemble_marked",
        "daily_playlist",
    ]
    for key in daily_keys:
        val = st.session_state.get(key)
        if isinstance(val, pd.DataFrame) and not val.empty:
            st.session_state["CANONICAL_DAILY_PLAYLIST"] = val.copy()
            st.session_state["v85_canonical_daily_source"] = key
            break

    lab_keys = [
        "lab_results",
        "v65_optimal_tier_per_event",
        "v648_full312_straight_per_event",
        "v643_final_straight_per_event",
        "straight_backtest_events",
    ]
    for key in lab_keys:
        val = st.session_state.get(key)
        if isinstance(val, pd.DataFrame) and not val.empty:
            st.session_state["CANONICAL_LAB_RESULTS"] = val.copy()
            st.session_state["v85_canonical_lab_source"] = key
            break

def v85_get_daily_playlist() -> Tuple[Optional[str], Optional[pd.DataFrame]]:
    v85_promote_canonical_outputs()
    df = st.session_state.get("CANONICAL_DAILY_PLAYLIST")
    if isinstance(df, pd.DataFrame) and not df.empty:
        return st.session_state.get("v85_canonical_daily_source", "CANONICAL_DAILY_PLAYLIST"), df.copy()
    return None, None

def v85_get_lab_results() -> Tuple[Optional[str], Optional[pd.DataFrame]]:
    v85_promote_canonical_outputs()
    df = st.session_state.get("CANONICAL_LAB_RESULTS")
    if isinstance(df, pd.DataFrame) and not df.empty:
        return st.session_state.get("v85_canonical_lab_source", "CANONICAL_LAB_RESULTS"), df.copy()
    return None, None


def _norm_col_key(c: str) -> str:
    return re.sub(r"[^a-z0-9]", "", str(c).strip().lower())


def _find_col(df: pd.DataFrame, aliases: List[str]) -> Optional[str]:
    wanted = {_norm_col_key(a) for a in aliases}
    for c in df.columns:
        if _norm_col_key(c) in wanted:
            return c
    return None


def _split_streamkey(value: str) -> Tuple[str, str]:
    s = str(value).strip()
    if "|" in s:
        a, b = s.split("|", 1)
        return a.strip(), b.strip()
    parts = re.split(r"\s+-\s+|\s{2,}", s, maxsplit=1)
    if len(parts) == 2:
        return parts[0].strip(), parts[1].strip()
    return "", s


def _v183_parse_raw_history_lines_from_df(df_raw: pd.DataFrame) -> pd.DataFrame:
    """
    v183 WF loader repair: parse raw LotteryPost-style history lines when the
    WF reader produced a 1-column/unrecognized dataframe. Parsing only; no
    scoring/ranking/member logic changed.
    Supported examples:
      Fri, Feb 20, 2026<TAB>Wisconsin<TAB>Pick 4 Midday<TAB>8-5-7-7
      2026-02-20<TAB>Wisconsin<TAB>Pick 4 Midday<TAB>8577
    """
    if df_raw is None or not isinstance(df_raw, pd.DataFrame) or df_raw.empty:
        return pd.DataFrame()

    rows = []

    # Include column labels too, because pd.read_csv(header=0) can accidentally
    # consume the first raw history row as headers.
    possible_lines = []
    try:
        possible_lines.append("\t".join(str(c) for c in df_raw.columns if str(c).strip() and not str(c).startswith("Unnamed")))
    except Exception:
        pass

    for _, r in df_raw.iterrows():
        vals = [str(x).strip() for x in list(r.values) if str(x).strip() and str(x).strip().lower() != "nan"]
        if not vals:
            continue
        possible_lines.append("\t".join(vals))

    date_re = re.compile(
        r"^(?P<date>(?:Mon|Tue|Wed|Thu|Fri|Sat|Sun),\s+[A-Za-z]{3,9}\s+\d{1,2},\s+\d{4}|\d{4}[-/]\d{1,2}[-/]\d{1,2}|\d{1,2}[-/]\d{1,2}[-/]\d{2,4})\s*[\t,| ]+",
        re.I,
    )

    for line in possible_lines:
        line = str(line).replace("\ufeff", "").strip()
        if not line:
            continue

        # Prefer clean tab/pipe/csv-ish splitting.
        parts = [p.strip() for p in re.split(r"\t+|\s*\|\s*", line) if p.strip()]
        if len(parts) < 4:
            # Raw line may have date containing commas; capture date first, then
            # split the remaining text from the right by the pick-4 result.
            m = date_re.search(line)
            if not m:
                continue
            date_txt = m.group("date").strip()
            rest = line[m.end():].strip(" \t,|")
            rm = re.search(r"(\d\D+\d\D+\d\D+\d|\b\d{4}\b)\s*$", rest)
            if not rm:
                continue
            result_txt = rm.group(1)
            left = rest[:rm.start()].strip(" \t,|")
            # State and game are best separated by tabs/pipe. If not present,
            # split on 2+ spaces; final fallback keeps full left as game.
            left_parts = [p.strip() for p in re.split(r"\t+|\s*\|\s*|\s{2,}", left) if p.strip()]
            if len(left_parts) >= 2:
                state_txt = left_parts[0]
                game_txt = " ".join(left_parts[1:])
            else:
                state_txt = ""
                game_txt = left
        else:
            date_txt, state_txt, game_txt = parts[0], parts[1], parts[2]
            result_txt = parts[3]

        result4 = extract_pick4_digits(result_txt)
        if not result4:
            continue
        dt = pd.to_datetime(date_txt, errors="coerce")
        if pd.isna(dt):
            continue
        state_txt = str(state_txt).strip()
        game_txt = str(game_txt).strip()
        if not state_txt or not game_txt:
            continue
        rows.append({
            "Date": dt,
            "State": state_txt,
            "Game": game_txt,
            "Results": result_txt,
            "Result": result4,
        })

    if not rows:
        return pd.DataFrame()

    out = pd.DataFrame(rows)
    out["Box"] = out["Result"].apply(box_key)
    out["StreamKey"] = out.apply(lambda r: canonical_stream(r["State"], r["Game"]), axis=1)
    out["Core389Member"] = out["Result"].apply(result_to_core389_member)
    out = out.drop_duplicates(["Date", "StreamKey", "Result"]).sort_values(["StreamKey", "Date"]).reset_index(drop=True)
    return out


def normalize_history(df_raw: pd.DataFrame) -> pd.DataFrame:
    df = df_raw.copy()
    df.columns = [_clean_upload_column_name(c) for c in df.columns]
    df = df.dropna(how="all").copy()
    df = df.loc[:, ~pd.Index(df.columns).astype(str).str.startswith("Unnamed")].copy()

    date_col = _find_col(df, ["Date", "Draw Date", "DrawDate", "Draw_Date"])
    state_col = _find_col(df, ["State", "ST", "Jurisdiction"])
    game_col = _find_col(df, ["Game", "Game Name", "Draw", "Draw Time", "DrawTime", "Session", "Period"])
    stream_col = _find_col(df, ["StreamKey", "Stream Key", "Stream", "State Game", "State_Game"])
    result_col = _find_col(df, [
        "Results", "Result", "Winning Numbers", "Winning_Numbers", "WinningNumbers",
        "Number", "Numbers", "Pick4", "Pick 4", "Draw Result", "DrawResult"
    ])

    # v183: WF lab must accept the same raw LotteryPost-style history text that
    # the daily side can use. This is a parser-only fallback before failing.
    if date_col is None or result_col is None or ((state_col is None or game_col is None) and stream_col is None):
        raw_parsed = _v183_parse_raw_history_lines_from_df(df)
        if isinstance(raw_parsed, pd.DataFrame) and not raw_parsed.empty:
            return raw_parsed

    # Headerless history remains supported: Date, State, Game, Results in first 4 fields.
    if date_col is None or result_col is None or ((state_col is None or game_col is None) and stream_col is None):
        if df.shape[1] >= 4:
            cols = list(df.columns)
            date_col = date_col or cols[0]
            state_col = state_col or cols[1]
            game_col = game_col or cols[2]
            result_col = result_col or cols[3]
        elif df.shape[1] >= 3 and stream_col is not None:
            cols = list(df.columns)
            date_col = date_col or cols[0]
            result_col = result_col or cols[-1]
        else:
            raise ValueError("History file must contain Date + Result plus either StreamKey or State + Game columns.")

    if stream_col is not None and (state_col is None or game_col is None):
        tmp = df[stream_col].apply(_split_streamkey)
        state_vals = tmp.apply(lambda x: x[0])
        game_vals = tmp.apply(lambda x: x[1])
    else:
        state_vals = df[state_col].astype(str) if state_col is not None else ""
        game_vals = df[game_col].astype(str) if game_col is not None else ""

    out = pd.DataFrame({
        "Date": df[date_col],
        "State": state_vals,
        "Game": game_vals,
        "Results": df[result_col],
    })

    out["Date"] = pd.to_datetime(out["Date"], errors="coerce")
    out["State"] = out["State"].astype(str).str.strip()
    out["Game"] = out["Game"].astype(str).str.strip()
    out["Result"] = out["Results"].apply(extract_pick4_digits)
    out = out[out["Date"].notna() & out["Result"].str.len().eq(4)].copy()
    if out.empty:
        raw_parsed = _v183_parse_raw_history_lines_from_df(df)
        if isinstance(raw_parsed, pd.DataFrame) and not raw_parsed.empty:
            return raw_parsed
        raise ValueError("History upload parsed, but no valid Pick 4 rows were found. Check Date/State/Game/Result columns or delimiter.")
    out["Box"] = out["Result"].apply(box_key)
    out["StreamKey"] = out.apply(lambda r: canonical_stream(r["State"], r["Game"]), axis=1)
    out["Core389Member"] = out["Result"].apply(result_to_core389_member)
    out = out.sort_values(["StreamKey", "Date"]).reset_index(drop=True)
    return out



def ensure_truth(df_raw: pd.DataFrame) -> pd.DataFrame:
    df = df_raw.copy()
    df.columns = [_clean_upload_column_name(c) for c in df.columns]
    df = df.dropna(how="all").copy()
    df = df.loc[:, ~pd.Index(df.columns).astype(str).str.startswith("Unnamed")].copy()

    # Canonicalize common truth/export aliases without changing downstream contracts.
    true_col = _find_col(df, ["WinningMember", "TrueMember", "WinnerMember", "winner_member", "Member", "Core389Member"])
    if true_col is None:
        raise ValueError("FULL TRUTH file must contain WinningMember or TrueMember.")
    df["TrueMember"] = df[true_col].apply(normalize_member)

    seed_col = _find_col(df, ["seed", "PrevSeed", "feat_seed", "Seed", "Previous Result", "PreviousResult", "LastResult"])
    if seed_col is not None:
        df["seed"] = df[seed_col].astype(str)
    elif "seed" not in df.columns:
        df["seed"] = ""

    # Preserve existing StreamKey values when present; otherwise build it when possible.
    try:
        df = ensure_streamkey_columns(df, "truth/lab file")
    except Exception:
        # Truth files used only for member scoring may not always include stream fields.
        pass

    return df


def ensure_library(df_raw: pd.DataFrame) -> pd.DataFrame:
    df = df_raw.copy()
    df.columns = [_clean_upload_column_name(c) for c in df.columns]
    alias_map = {}
    for target, aliases in {
        "trait_stack": ["trait_stack", "trait stack", "TraitStack"],
        "winner_member": ["winner_member", "winner member", "WinningMember", "TrueMember"],
        "winner_rate": ["winner_rate", "winner rate", "WinRate", "Rate"],
        "support": ["support", "Support", "Hits"],
        "stack_size": ["stack_size", "stack size", "StackSize"],
    }.items():
        col = _find_col(df, aliases)
        if col is not None and col != target:
            alias_map[col] = target
    if alias_map:
        df = df.rename(columns=alias_map)
    required = ["trait_stack", "winner_member", "winner_rate", "support", "stack_size"]
    missing = [c for c in required if c not in df.columns]
    if missing:
        raise ValueError(f"Promoted separator library missing required columns: {missing}")
    df["winner_member"] = df["winner_member"].apply(normalize_member)
    df["winner_rate"] = pd.to_numeric(df["winner_rate"], errors="coerce").fillna(0.0)
    return df


def digits4(seed: str) -> List[int]:
    s = extract_pick4_digits(seed)
    if len(s) != 4:
        s = re.sub(r"\D", "", str(seed)).zfill(4)[-4:]
    return [int(ch) for ch in s] if len(s) == 4 else [0, 0, 0, 0]


def repeat_shape(d: List[int]) -> str:
    counts = sorted(pd.Series(d).value_counts().tolist(), reverse=True)
    if counts == [1, 1, 1, 1]:
        return "all_unique"
    if counts == [2, 1, 1]:
        return "one_pair"
    if counts == [2, 2]:
        return "two_pair"
    if counts == [3, 1]:
        return "triple"
    if counts == [4]:
        return "quad"
    return "other"


def structure_4(d: List[int]) -> str:
    counts = sorted(pd.Series(d).value_counts().tolist(), reverse=True)
    if counts == [4]:
        return "AAAA"
    if counts == [3, 1]:
        return "AAAB"
    if counts == [2, 2]:
        return "AABB"
    if counts == [2, 1, 1]:
        return "AABC"
    return "ABCD"


def sum_bucket(v: int) -> str:
    if v <= 13:
        return "sum_10_13"
    if v <= 17:
        return "sum_14_17"
    if v <= 21:
        return "sum_18_21"
    return "sum_22_plus"


def spread_bucket(v: int) -> str:
    if v <= 2:
        return "spread_0_2"
    if v <= 4:
        return "spread_3_4"
    if v <= 6:
        return "spread_5_6"
    return "spread_7_plus"


def consec_links_count(d: List[int]) -> int:
    u = sorted(set(d))
    return sum(1 for a, b in zip(u, u[1:]) if b - a == 1)


def enrich_seed_features(df: pd.DataFrame, seed_col: str = "seed") -> pd.DataFrame:
    out = df.copy()
    if seed_col not in out.columns:
        out[seed_col] = ""

    ds = out[seed_col].apply(digits4)
    sums = [sum(d) for d in ds]
    spreads = [max(d) - min(d) for d in ds]

    out["seed_sum"] = sums
    out["seed_spread"] = spreads
    out["seed_even_cnt"] = [sum(1 for x in d if x % 2 == 0) for d in ds]
    out["seed_high_cnt"] = [sum(1 for x in d if x >= 5) for d in ds]
    out["seed_low_cnt"] = [sum(1 for x in d if x <= 4) for d in ds]
    out["seed_has9"] = [1 if 9 in d else 0 for d in ds]
    out["seed_has0"] = [1 if 0 in d else 0 for d in ds]
    out["seed_parity_pattern"] = ["".join("E" if x % 2 == 0 else "O" for x in d) for d in ds]
    out["seed_highlow_pattern"] = ["".join("H" if x >= 5 else "L" for x in d) for d in ds]
    out["seed_repeat_shape"] = [repeat_shape(d) for d in ds]
    out["seed"] = out[seed_col].astype(str).apply(lambda x: extract_pick4_digits(x) or re.sub(r"\D", "", str(x)).zfill(4)[-4:])

    # Critical compatibility layer for the promoted separator library.
    # The promoted library uses unprefixed trait names like cnt0, has0, high, low,
    # parity_pattern, highlow_pattern, structure, sum_bucket, spread_bucket.
    # These are generated from the current seed so daily and lab rule matching actually fires.
    for digit in range(10):
        out[f"cnt{digit}"] = [d.count(digit) for d in ds]
        out[f"has{digit}"] = [1 if digit in d else 0 for d in ds]

    out["even"] = out["seed_even_cnt"]
    out["odd"] = [4 - int(v) for v in out["seed_even_cnt"]]
    out["high"] = out["seed_high_cnt"]
    out["low"] = out["seed_low_cnt"]
    out["parity_pattern"] = out["seed_parity_pattern"]
    out["highlow_pattern"] = out["seed_highlow_pattern"]
    out["structure"] = [structure_4(d) for d in ds]
    out["unique"] = [len(set(d)) for d in ds]
    out["max_rep"] = [max(pd.Series(d).value_counts().tolist()) for d in ds]
    out["consec_links"] = [consec_links_count(d) for d in ds]
    out["pair"] = [1 if max(pd.Series(d).value_counts().tolist()) >= 2 else 0 for d in ds]
    out["sum_bucket"] = [sum_bucket(int(v)) for v in sums]
    out["spread_bucket"] = [spread_bucket(int(v)) for v in spreads]

    return out


def deep_mine_separators(df: pd.DataFrame, min_rate: float = 0.76, min_support: int = 5) -> pd.DataFrame:
    mined: List[Dict] = []
    trait_cols = [
        c for c in df.columns
        if any(k in c.lower() for k in [
            "pair_has_", "adj_ord_has_", "parity_pattern", "highlow_pattern",
            "repeat_shape", "palindrome", "consec", "mirror", "sum_bucket",
            "spread_bucket", "has", "cnt", "seed_sum", "seed_spread"
        ])
    ]

    for col in trait_cols:
        vals = df[col].astype(str).fillna("").unique()
        for val in vals:
            if val in ["", "nan", "None"]:
                continue
            subset = df[df[col].astype(str) == val]
            if len(subset) < min_support:
                continue
            for m in MEMBERS:
                rate = (subset["TrueMember"] == m).sum() / len(subset)
                if rate >= min_rate:
                    mined.append({
                        "pair": "TRUTH_MINED",
                        "trait_stack": f"{col}={val}",
                        "winner_member": m,
                        "winner_rate": rate,
                        "support": int((subset["TrueMember"] == m).sum()),
                        "pair_gap": 0.0,
                        "stack_size": 1,
                    })

    for i, col1 in enumerate(trait_cols[:25]):
        for col2 in trait_cols[i + 1:i + 20]:
            vals1 = list(df[col1].astype(str).fillna("").unique())[:12]
            vals2 = list(df[col2].astype(str).fillna("").unique())[:12]
            for v1 in vals1:
                for v2 in vals2:
                    if v1 in ["", "nan"] or v2 in ["", "nan"]:
                        continue
                    subset = df[(df[col1].astype(str) == v1) & (df[col2].astype(str) == v2)]
                    if len(subset) < min_support:
                        continue
                    for m in MEMBERS:
                        rate = (subset["TrueMember"] == m).sum() / len(subset)
                        if rate >= min_rate + 0.05:
                            mined.append({
                                "pair": "TRUTH_MINED",
                                "trait_stack": f"{col1}={v1} && {col2}={v2}",
                                "winner_member": m,
                                "winner_rate": rate,
                                "support": int((subset["TrueMember"] == m).sum()),
                                "pair_gap": 0.0,
                                "stack_size": 2,
                            })

    if not mined:
        return pd.DataFrame(columns=["pair", "trait_stack", "winner_member", "winner_rate", "support", "pair_gap", "stack_size"])
    return pd.DataFrame(mined).drop_duplicates(subset=["trait_stack", "winner_member"]).reset_index(drop=True)


def _val_equal(a, b) -> bool:
    sa = str(a).strip()
    sb = str(b).strip()
    if sa == sb:
        return True
    try:
        fa = float(sa)
        fb = float(sb)
        return abs(fa - fb) < 1e-9
    except Exception:
        return False


def apply_rules(row: pd.Series, rules_df: pd.DataFrame, trait_weight: float) -> Tuple[Dict[str, float], List[str]]:
    boosts = {m: 0.0 for m in MEMBERS}
    fired: List[str] = []

    for _, r in rules_df.iterrows():
        stack_text = str(r.get("trait_stack", ""))
        if not stack_text or stack_text.lower() == "nan":
            continue

        # Support both current promoted-library format "a=b && c=d"
        # and older pipe-delimited stacked formats.
        stack = [s.strip() for s in re.split(r"\s*&&\s*|\|", stack_text) if s.strip()]
        matched = True

        for cond in stack:
            if "=" not in cond:
                matched = False
                break
            col, val = [x.strip() for x in cond.split("=", 1)]
            if col not in row.index or not _val_equal(row.get(col, ""), val):
                matched = False
                break

        if matched:
            winner = normalize_member(r.get("winner_member"))
            if winner in boosts:
                boost = float(r.get("winner_rate", 1.0)) * trait_weight
                boosts[winner] += boost
                fired.append(f"{winner}+{boost:.2f}:{stack_text}")
    return boosts, fired


def v22_pick(
    row: pd.Series,
    rules_df: pd.DataFrame,
    trait_weight: float,
    min_margin: float,
    enable_margin_swap: bool = False,
    top2_zone_ratio: float = 0.90,
    top2_zone_margin: float = 5.0,
    top2_risk_threshold: int = 3,
) -> Dict:
    """
    v39 decision layer:
    - Preserve v34/v36 scoring and strict score ranking.
    - Top1 is highest score; Top2 is second-highest score.
    - No third-choice hijack.
    - FIRST gate: evaluate deep Top2-risk traits only if row is already in a Top2 zone.
    """
    boosts, fired = apply_rules(row, rules_df, trait_weight)
    sorted_scores = sorted(boosts.items(), key=lambda x: x[1], reverse=True)

    top = sorted_scores[0][0]
    second = sorted_scores[1][0]
    margin = float(sorted_scores[0][1]) - float(sorted_scores[1][1])
    top1_score = float(sorted_scores[0][1])
    top2_score = float(sorted_scores[1][1])
    ratio = (top2_score / top1_score) if top1_score > 0 else 0.0
    seed = str(row.get("seed", ""))

    margin_swap = 0
    if enable_margin_swap and margin < float(min_margin):
        danger_seed = (
            ("0" in seed and "9" in seed)
            or len(set(seed)) <= 2
            or "00" in seed
            or "88" in seed
            or "99" in seed
        )
        if danger_seed:
            top, second = second, top
            margin_swap = 1
            fired.append("MARGIN_SWAP_TOP1_TOP2_ONLY")

    is_top2_zone = (ratio >= float(top2_zone_ratio)) or (margin <= float(top2_zone_margin))

    risk_score = 0
    risk_reasons = []

    if is_top2_zone:
        if ratio >= float(top2_zone_ratio):
            risk_score += 3
            risk_reasons.append("ratio>=zone")

        if margin <= float(top2_zone_margin):
            risk_score += 3
            risk_reasons.append("margin<=zone")

        if (
            str(row.get("sum_bucket", "")) == "sum_22_plus"
            and str(row.get("spread_bucket", "")) == "spread_3_4"
            and int(float(row.get("seed_has9", 0) or 0)) == 0
        ):
            risk_score += 2
            risk_reasons.append("sum22_spread34_no9")

        if (
            top == "3889"
            and str(row.get("structure", "")) == "AABC"
            and int(float(row.get("seed_has9", 0) or 0)) == 1
        ):
            risk_score += 2
            risk_reasons.append("3889_AABC_has9")

        score_pair = f"{top}>{second}"
        if (
            score_pair == "3899>3889"
            and str(row.get("sum_bucket", "")) == "sum_10_13"
            and int(float(row.get("consec_links", 0) or 0)) == 1
        ):
            risk_score += 2
            risk_reasons.append("3899_3889_sum10_consec1")

        if (
            str(row.get("parity_pattern", "")) == "EOOO"
            and int(float(row.get("pair", 0) or 0)) == 1
        ):
            risk_score += 1
            risk_reasons.append("EOOO_pair")

        if (
            str(row.get("highlow_pattern", "")) == "HLLH"
            and int(float(row.get("seed_has0", 0) or 0)) == 0
        ):
            risk_score += 1
            risk_reasons.append("HLLH_no0")

    top2_decision = "TOP2_REQUIRED" if (is_top2_zone and risk_score >= int(top2_risk_threshold)) else "TOP1_SAFE"

    return {
        "PredictedMember": top,
        "Top2_pred": second,
        "Margin": round(margin, 3),
        "Top2ToTop1Ratio": round(ratio, 4),
        "Top2Zone": int(is_top2_zone),
        "Top2RiskScore": int(risk_score),
        "Top2Decision": top2_decision,
        "Top2RiskReasons": "|".join(risk_reasons),
        "DecisionMode": "STRICT_SCORE_RANK" if margin_swap == 0 else "MARGIN_SWAP_TOP1_TOP2_ONLY",
        "MarginSwap": margin_swap,
        "Fired_Rules": " | ".join(fired[:20]),
        "GATED_TOP3": 0,
        "score_3389": boosts["3389"],
        "score_3899": boosts["3899"],
        "score_3889": boosts["3889"],
    }


def build_live_seed_rows(hist: pd.DataFrame, top_streams: Optional[List[str]] = None) -> pd.DataFrame:
    rows = []
    for stream, g in hist.groupby("StreamKey"):
        g = g.sort_values("Date")
        if g.empty:
            continue
        last = g.iloc[-1]
        rows.append({
            "StreamKey": stream,
            "Date": last["Date"],
            "seed": last["Result"],
            "LastResult": last["Result"],
            "State": last["State"],
            "Game": last["Game"],
        })
    out = pd.DataFrame(rows)
    if out.empty:
        return out
    if top_streams is not None:
        out = out[out["StreamKey"].isin(top_streams)].copy()
    return enrich_seed_features(out, "seed")


def build_lab_event_rows(hist: pd.DataFrame, include_full_universe: bool = False) -> pd.DataFrame:
    """
    Build walk-forward rows from real uploaded history only.

    include_full_universe=False preserves the older winner-event-only lab behavior.
    include_full_universe=True includes every stream transition in the selected date range:
    Core389 winner events plus non-Core389 events. Non-Core389 events are not counted
    as member misses; they are evaluated as non-winner play/cost opportunities.
    """
    rows = []
    for stream, g in hist.groupby("StreamKey"):
        g = g.sort_values("Date").reset_index(drop=True)
        for i in range(1, len(g)):
            true_member = result_to_core389_member(g.loc[i, "Result"])
            is_core_event = int(bool(true_member))
            if include_full_universe or true_member:
                rows.append({
                    "StreamKey": stream,
                    "Date": g.loc[i, "Date"],
                    "seed": g.loc[i - 1, "Result"],
                    "TrueMember": true_member if true_member else "",
                    "Result": g.loc[i, "Result"],
                    "Core389WinnerEvent": is_core_event,
                    "NonCore389Event": int(not is_core_event),
                    "WalkForwardUniverse": "FULL_UNIVERSE" if include_full_universe else "WINNER_EVENTS_ONLY",
                })
    out = pd.DataFrame(rows)
    if out.empty:
        return empty_lab_results_frame()
    return enrich_seed_features(out, "seed")

def v147_filter_history_by_date_range(hist: pd.DataFrame, start_date=None, end_date=None) -> pd.DataFrame:
    if hist is None or not isinstance(hist, pd.DataFrame) or hist.empty or "Date" not in hist.columns:
        return hist
    out = hist.copy()
    out["Date"] = pd.to_datetime(out["Date"], errors="coerce")
    out = out[out["Date"].notna()].copy()
    if start_date is not None:
        start_ts = pd.to_datetime(start_date, errors="coerce")
        if pd.notna(start_ts):
            out = out[out["Date"] >= start_ts.normalize()].copy()
    if end_date is not None:
        end_ts = pd.to_datetime(end_date, errors="coerce")
        if pd.notna(end_ts):
            out = out[out["Date"] <= end_ts.normalize() + pd.Timedelta(days=1) - pd.Timedelta(microseconds=1)].copy()
    return out


def stream_reduction(hist: pd.DataFrame, window_days: int, prune_pct: int) -> Tuple[pd.DataFrame, List[str]]:
    max_date = hist["Date"].max()
    cutoff = max_date - pd.Timedelta(days=int(window_days))
    win = hist[hist["Date"] >= cutoff].copy()
    grp = win.groupby("StreamKey").agg(
        draws=("Result", "size"),
        core389_hits=("Core389Member", lambda s: int((s != "").sum())),
        last_date=("Date", "max"),
    ).reset_index()
    # v82 numeric safety: mixed TXT/CSV uploads can make aggregate columns object dtype.
    grp["core389_hits"] = pd.to_numeric(grp["core389_hits"], errors="coerce").fillna(0)
    grp["draws"] = pd.to_numeric(grp["draws"], errors="coerce").fillna(0)
    denom = grp["draws"].where(grp["draws"] != 0)
    grp["hit_density"] = (grp["core389_hits"] / denom).fillna(0.0)
    grp["hit_density"] = pd.to_numeric(grp["hit_density"], errors="coerce").fillna(0.0)
    thresh = grp["hit_density"].quantile(prune_pct / 100.0) if len(grp) else 0.0
    grp["kept"] = (grp["hit_density"] >= thresh).astype(int)
    grp["rank"] = pd.to_numeric(grp["hit_density"], errors="coerce").fillna(0.0).rank(ascending=False, method="first").astype(int)
    grp["StreamRank"] = grp["rank"]
    grp = grp.sort_values(["kept", "hit_density", "core389_hits"], ascending=[False, False, False]).reset_index(drop=True)
    kept_streams = grp[grp["kept"] == 1]["StreamKey"].tolist()
    return grp, kept_streams



def v152_build_historical_stream_advisory(hist: pd.DataFrame, target_dates, window_days: int, prune_pct: int) -> pd.DataFrame:
    """
    v152: Blind historical stream-reduction advisory builder.

    This recomputes stream_reduction using only history BEFORE each target date,
    then returns advisory fields for every stream/date. It does NOT filter rows.
    kept_streams is preserved only as KeptStreamFlag/advisory metadata so all 78
    streams remain visible and scorable for each historical date.
    """
    if hist is None or not isinstance(hist, pd.DataFrame) or hist.empty or "Date" not in hist.columns:
        return pd.DataFrame()
    h = hist.copy()
    h["Date"] = pd.to_datetime(h["Date"], errors="coerce")
    h = h[h["Date"].notna()].copy()
    if h.empty:
        return pd.DataFrame()
    dates = pd.to_datetime(pd.Series(list(target_dates)), errors="coerce").dropna().dt.normalize().drop_duplicates().sort_values().tolist()
    parts = []
    for d in dates:
        prior = h[h["Date"] < d].copy()
        if prior.empty:
            continue
        try:
            diag, kept = stream_reduction(prior, int(window_days), int(prune_pct))
            # v191 canonical WF enrichment:
            # Match Daily Prediction path exactly: stream_reduction -> assign_stream_tiers -> add_stream_selection_flags.
            # This restores StreamRank / RowPercentile / SingleRow / RowBucket10 / StreamTier /
            # RecommendedByTopN / RecommendedByRowPct / RecommendedStream BEFORE downstream v64/v152 audit layers.
            # These are audit/playlist dictionary fields only; no member scores, rules, or predictions are changed here.
            if isinstance(diag, pd.DataFrame) and not diag.empty:
                diag = assign_stream_tiers(diag)
                diag = add_stream_selection_flags(diag, recommended_top_n, row_pct_cutoff)
        except Exception:
            continue
        if diag is None or not isinstance(diag, pd.DataFrame) or diag.empty or "StreamKey" not in diag.columns:
            continue
        dd = diag.copy()
        dd["Date"] = pd.to_datetime(d)
        dd["KeptStreamFlag"] = dd.get("kept", 0)
        dd["KeptStreamAdvisory"] = dd["KeptStreamFlag"].map(lambda x: "KEEP_ADVISORY" if int(float(x or 0)) == 1 else "DOWNRANK_ADVISORY")
        parts.append(dd)
    if not parts:
        return pd.DataFrame()
    adv = pd.concat(parts, ignore_index=True)
    adv["Date"] = pd.to_datetime(adv["Date"], errors="coerce").dt.normalize()
    adv["StreamKey"] = adv["StreamKey"].astype(str)
    return adv


def v152_apply_daily_hybrid_movement(full_rows: pd.DataFrame) -> pd.DataFrame:
    """
    v152: Calculate the same visible hybrid movement fields for every historical
    daily 78-stream playlist. This is analysis/ranking presentation only; it does
    not remove streams or alter member scoring rules.
    """
    if full_rows is None or not isinstance(full_rows, pd.DataFrame) or full_rows.empty:
        return full_rows
    out = full_rows.copy()
    if "Date" not in out.columns:
        return out
    out["Date"] = pd.to_datetime(out["Date"], errors="coerce")
    parts = []
    for d, g in out.groupby(out["Date"].dt.normalize(), sort=True):
        gg = g.copy()
        try:
            ranked = _v141_build_verification_play_table(gg)
            if ranked is None or not isinstance(ranked, pd.DataFrame) or ranked.empty:
                ranked = gg
        except Exception:
            ranked = gg
        if "StreamRank_COMPARE_FIRST" not in ranked.columns:
            ranked["StreamRank_COMPARE_FIRST"] = pd.to_numeric(ranked.get("StreamRank", ranked.get("rank", pd.Series(range(1, len(ranked)+1), index=ranked.index))), errors="coerce")
        if "PctRank_COMPARE_FIRST" not in ranked.columns:
            ranked["PctRank_COMPARE_FIRST"] = pd.to_numeric(ranked.get("SingleRow", ranked.get("RowPercentile", ranked.get("StreamRank_COMPARE_FIRST", pd.Series(range(1, len(ranked)+1), index=ranked.index)))), errors="coerce")
        if "HybridRank_COMPARE_FIRST" not in ranked.columns:
            # Fallback only if the visible hybrid table builder could not run.
            ranked["HybridRank_COMPARE_FIRST"] = pd.to_numeric(ranked.get("PlayOrder", ranked.get("StreamRank_COMPARE_FIRST", pd.Series(range(1, len(ranked)+1), index=ranked.index))), errors="coerce")
        ranked["v152_StreamRank"] = pd.to_numeric(ranked["StreamRank_COMPARE_FIRST"], errors="coerce")
        ranked["v152_PctRank"] = pd.to_numeric(ranked["PctRank_COMPARE_FIRST"], errors="coerce")
        ranked["v152_HybridRank"] = pd.to_numeric(ranked["HybridRank_COMPARE_FIRST"], errors="coerce")
        ranked["v152_MovementVsStream"] = ranked["v152_HybridRank"] - ranked["v152_StreamRank"]
        ranked["v152_MovementBucket"] = ranked["v152_MovementVsStream"].map(_v146_bucket_movement if "_v146_bucket_movement" in globals() else lambda x: "unknown")
        ranked["v152_DatePlaylistRows"] = len(ranked)
        ranked["v152_Full78PlaylistFlag"] = int(len(ranked) >= 78)
        parts.append(ranked)
    if not parts:
        return out
    final = pd.concat(parts, ignore_index=True)
    return final

def assign_stream_tiers(stream_df: pd.DataFrame) -> pd.DataFrame:
    out = stream_df.copy()
    if out.empty:
        return out
    n = len(out)
    out = out.sort_values(["StreamRank"], ascending=True).reset_index(drop=True)
    out["RowPercentile"] = ((out["StreamRank"] / n) * 100).round(2)
    out["SingleRow"] = out["StreamRank"].astype(int)
    out["RowBucket10"] = (((out["StreamRank"] - 1) // max(1, int(n / 10))) + 1).clip(1, 10)
    out["StreamTier"] = pd.cut(
        out["RowPercentile"],
        bins=[-0.01, 25, 50, 75, 100],
        labels=["A_TOP25", "B_26_50", "C_51_75", "D_76_100"],
    ).astype(str)
    return out




