def build_row_play_model(single_row_perf: Optional[pd.DataFrame], min_hits: int, top3_threshold: float, top2_threshold: float, top1_threshold: float, low_top2_threshold: float = 0.35) -> pd.DataFrame:
    source_rows = []
    if single_row_perf is not None and not single_row_perf.empty:
        for _, r in single_row_perf.iterrows():
            try:
                source_rows.append((int(r["SingleRow"]), int(r["rows"]), int(r["top1"]), int(r["top2_captured"]), int(r["top3_captured"])))
            except Exception:
                continue
    else:
        source_rows = [(k, *v) for k, v in FALLBACK_ROW_PLAY_COUNTS.items()]

    rows = []
    for row_num, total, top1, top2, top3 in source_rows:
        if total <= 0:
            continue

        top1_rate = top1 / total
        top2_rate = top2 / total
        top3_rate = top3 / total
        row_volatility = top2_rate + top3_rate

        # v46 stability upgrade:
        # - Restore protection on volatile rows that v45 trimmed too aggressively.
        # - Keep Top3 controlled: it still requires historical row support.
        # - Suppress Top2 only when Top1 is truly dominant and the row is not volatile.
        if total < int(min_hits):
            play_type = "TOP1_TOP2"
            reason = "LOW_SAMPLE_CONSERVATIVE"
        elif total >= int(min_hits) and top3 > 0 and top3_rate >= float(top3_threshold):
            play_type = "TOP1_TOP2_TOP3"
            reason = "ROW_TOP3_RATE_V46_CONTROLLED"
        elif total >= int(min_hits) and top3 > 0 and row_volatility >= 0.50 and top2_rate >= 0.20:
            play_type = "TOP1_TOP2_TOP3"
            reason = "V46_VOLATILE_ROW_TOP3_PROTECT"
        elif row_volatility >= 0.50:
            play_type = "TOP1_TOP2"
            reason = "V46_HIGH_VOLATILITY_TOP2_PROTECT"
        elif (
            top2_rate < float(low_top2_threshold)
            and top1_rate >= float(top1_threshold)
            and row_volatility < 0.40
        ):
            play_type = "TOP1_ONLY"
            reason = "V46_STRONG_TOP1_SUPPRESS_TOP2"
        elif top2_rate >= float(top2_threshold) and top2 >= top1:
            play_type = "TOP1_TOP2"
            reason = "ROW_TOP2_HEAVY"
        elif top1_rate >= float(top1_threshold) and top2 == 0 and top3 == 0:
            play_type = "TOP1_ONLY"
            reason = "ROW_TOP1_DOMINANT"
        else:
            play_type = "TOP1_TOP2"
            reason = "ROW_DEFAULT_TOP2"

        rows.append({
            "SingleRow": row_num,
            "RowModelHits": total,
            "RowModelTop1": top1,
            "RowModelTop2": top2,
            "RowModelTop3": top3,
            "RowTop1Rate": round(top1_rate, 4),
            "RowTop2Rate": round(top2_rate, 4),
            "RowTop3Rate": round(top3_rate, 4),
            "RowVolatilityRate": round(row_volatility, 4),
            "RowLowTop2Threshold": float(low_top2_threshold),
            "RowPlayType": play_type,
            "RowPlayTypeReason": reason,
        })
    return pd.DataFrame(rows).sort_values("SingleRow").reset_index(drop=True)


def apply_row_playtype_model(df: pd.DataFrame, row_model_df: Optional[pd.DataFrame], enabled: bool) -> pd.DataFrame:
    out = df.copy()
    if out.empty:
        return out
    if not enabled or row_model_df is None or row_model_df.empty or "SingleRow" not in out.columns:
        out["RowPlayType"] = ""
        out["RowPlayTypeReason"] = "row_model_disabled"
        return out

    cols = ["SingleRow","RowModelHits","RowModelTop1","RowModelTop2","RowModelTop3","RowTop1Rate","RowTop2Rate","RowTop3Rate","RowVolatilityRate","RowLowTop2Threshold","RowPlayType","RowPlayTypeReason"]
    out = out.merge(row_model_df[cols], on="SingleRow", how="left")
    out["RowPlayType"] = out["RowPlayType"].fillna("TOP1_TOP2")
    out["RowPlayTypeReason"] = out["RowPlayTypeReason"].fillna("row_unseen_default_top2")
    out["PlayType"] = out["RowPlayType"]
    return out


def add_rare_top3_and_universal_scores(
    df: pd.DataFrame,
    enable_top3_rescue: bool,
    top3_rescue_min_score: int,
    w_model: float,
    w_row: float,
    w_density: float,
    w_outlier: float,
) -> pd.DataFrame:
    out = df.copy()
    if out.empty:
        return out

    # Third member = the omitted member from the strict Top1/Top2 pair.
    def _third(row):
        top1 = str(row.get("PredictedMember", ""))
        top2 = str(row.get("Top2_pred", ""))
        rest = [m for m in MEMBERS if m not in {top1, top2}]
        return rest[0] if rest else ""

    out["ThirdMember"] = out.apply(_third, axis=1)

    danger_rows = {56, 44, 17, 50, 58, 24, 30, 2}
    danger_parity = {"EOEO", "OOOO", "OEEE", "EOOE"}
    danger_highlow = {"LLLH", "HHLL", "HLLH"}

    out["Top3RescueScore"] = 0
    out["Top3RescueReasons"] = ""

    reasons_col = []
    scores = []
    for _, r in out.iterrows():
        score = 0
        reasons = []

        row_num = int(float(r.get("SingleRow", 0) or 0))
        if row_num in danger_rows:
            score += 2
            reasons.append("danger_row")

        if str(r.get("ThirdMember", "")) == "3889":
            score += 2
            reasons.append("third_3889")

        if str(r.get("parity_pattern", "")) in danger_parity:
            score += 1
            reasons.append("danger_parity")

        if str(r.get("highlow_pattern", "")) in danger_highlow:
            score += 1
            reasons.append("danger_highlow")

        if str(r.get("sum_bucket", "")) == "sum_18_21":
            score += 1
            reasons.append("sum_18_21")

        if str(r.get("StreamTier", "")) in {"B_26_50", "C_51_75"}:
            score += 1
            reasons.append("mid_tier_miss_zone")

        scores.append(score)
        reasons_col.append("|".join(reasons))

    out["Top3RescueScore"] = scores
    out["Top3RescueReasons"] = reasons_col
    out["Top3Rescue"] = ((out["Top3RescueScore"] >= int(top3_rescue_min_score)) & bool(enable_top3_rescue)).astype(int)

    # Universal score: normalized to 0-100 and family-comparable.
    # Family apps can use the same column names and weights.
    score_cols = [c for c in ["score_3389", "score_3899", "score_3889"] if c in out.columns]
    if score_cols:
        out["ModelConfidenceRaw"] = out[score_cols].max(axis=1)
        max_model = pd.to_numeric(out["ModelConfidenceRaw"], errors="coerce").max()
        out["ModelConfidenceScore"] = (pd.to_numeric(out["ModelConfidenceRaw"], errors="coerce") / max_model * 100).fillna(0) if max_model and max_model > 0 else 0
    else:
        out["ModelConfidenceScore"] = 0

    out["RowStrengthScore"] = (100 - _v186_wf_num_series(out, "RowPercentile", 100)).clip(0, 100).fillna(0)

    dens = _v186_wf_num_series(out, "hit_density", 0).fillna(0)
    max_dens = dens.max()
    out["FamilyHitDensityScore"] = (dens / max_dens * 100) if max_dens and max_dens > 0 else 0

    out["MissOutlierRiskScore"] = (out["Top3RescueScore"] * 10).clip(0, 100)

    total_weight = float(w_model) + float(w_row) + float(w_density) + float(w_outlier)
    if total_weight <= 0:
        total_weight = 1.0

    out["UniversalFamilyScore"] = (
        (out["ModelConfidenceScore"] * float(w_model))
        + (out["RowStrengthScore"] * float(w_row))
        + (out["FamilyHitDensityScore"] * float(w_density))
        - (out["MissOutlierRiskScore"] * float(w_outlier))
    ) / total_weight
    out["UniversalFamilyScore"] = out["UniversalFamilyScore"].round(2)

    return out


def apply_play_recommendation(df: pd.DataFrame, play_policy: str) -> pd.DataFrame:
    out = df.copy()
    if out.empty:
        return out

    if "PlayType" not in out.columns or out["PlayType"].isna().all() or (out["PlayType"].astype(str).str.len() == 0).all():
        if play_policy.startswith("Full capture"):
            out["PlayType"] = "TOP1_TOP2"
        elif play_policy.startswith("Top2 risk"):
            out["PlayType"] = out["Top2Decision"].apply(lambda x: "TOP1_TOP2" if str(x) == "TOP2_REQUIRED" else "TOP1_ONLY")
        else:
            out["PlayType"] = "TOP1_ONLY"
        if "Top3Rescue" in out.columns:
            out.loc[out["Top3Rescue"] == 1, "PlayType"] = "TOP1_TOP2_TOP3"

    def _bold_play(row):
        top1 = str(row.get("PredictedMember", ""))
        top2 = str(row.get("Top2_pred", ""))
        top3 = str(row.get("ThirdMember", ""))
        if row["PlayType"] == "TOP1_TOP2_TOP3":
            parts = [f"**{top1}**", f"**{top2}**", f"**{top3}**"]
        elif row["PlayType"] == "TOP1_TOP2":
            parts = [f"**{top1}**", f"**{top2}**"]
        else:
            parts = [f"**{top1}**"]
        return " + ".join([p for p in parts if p and p != "****"])

    out["RecommendedPlay"] = out.apply(_bold_play, axis=1)
    out["Top1_Display"] = out["PredictedMember"].apply(lambda x: f"**{x}**")
    out["Top2_Display"] = out.apply(lambda r: f"**{r['Top2_pred']}**" if r["PlayType"] in ["TOP1_TOP2", "TOP1_TOP2_TOP3"] else str(r["Top2_pred"]), axis=1)
    out["Top3_Display"] = out.apply(lambda r: f"**{r['ThirdMember']}**" if r["PlayType"] == "TOP1_TOP2_TOP3" else str(r.get("ThirdMember", "")), axis=1)
    # v88 display-only columns: make actual box plays unmistakable in UI/downloads.
    out = v88_add_box_play_markers(out)
    return out


def add_stream_selection_flags(df: pd.DataFrame, recommended_top_n: int, row_pct_cutoff: int) -> pd.DataFrame:
    out = df.copy()
    if out.empty:
        return out
    out["RecommendedByTopN"] = (pd.to_numeric(out["StreamRank"], errors="coerce") <= int(recommended_top_n)).astype(int)
    out["RecommendedByRowPct"] = (pd.to_numeric(out["RowPercentile"], errors="coerce") <= int(row_pct_cutoff)).astype(int)
    out["RecommendedStream"] = ((out["RecommendedByTopN"] == 1) | (out["RecommendedByRowPct"] == 1)).astype(int)
    return out


def summarize_policy(df: pd.DataFrame, mask, label: str, play_policy: str) -> Dict:
    sub = df[mask].copy()
    total = len(sub)
    if total == 0:
        return {
            "method": label, "rows": 0, "winner_events": 0, "non_core_events": 0,
            "top1": 0, "top2_captured": 0, "top3_captured": 0,
            "captured": 0, "miss": 0, "capture_pct": 0.0,
            "plays": 0, "plays_per_capture": None, "plays_per_winner_event": None
        }

    if "Core389WinnerEvent" in sub.columns:
        winner_mask = pd.to_numeric(sub["Core389WinnerEvent"], errors="coerce").fillna(0).astype(int).eq(1)
    else:
        winner_mask = pd.Series(True, index=sub.index)
    winner_events = int(winner_mask.sum())
    non_core_events = int(total - winner_events)
    winner_sub = sub[winner_mask].copy()

    top1 = int(pd.to_numeric(winner_sub.get("Top1_Correct", 0), errors="coerce").fillna(0).sum()) if winner_events else 0
    top2_all = int(pd.to_numeric(winner_sub.get("Needed_Top2", 0), errors="coerce").fillna(0).sum()) if winner_events else 0

    if "PlayType" in sub.columns:
        # Cost is operational across every evaluated row. Capture is evaluated only against true Core389 winner events.
        if winner_events:
            top2_captured = int(((pd.to_numeric(winner_sub["Needed_Top2"], errors="coerce").fillna(0).astype(int) == 1) & (winner_sub["PlayType"].isin(["TOP1_TOP2", "TOP1_TOP2_TOP3"]))).sum())
            top3_captured = int(((pd.to_numeric(winner_sub["Miss"], errors="coerce").fillna(0).astype(int) == 1) & (winner_sub["PlayType"] == "TOP1_TOP2_TOP3")).sum())
        else:
            top2_captured = 0
            top3_captured = 0
        plays = int((sub["PlayType"] == "TOP1_ONLY").sum() + 2*(sub["PlayType"] == "TOP1_TOP2").sum() + 3*(sub["PlayType"] == "TOP1_TOP2_TOP3").sum())
    elif play_policy.startswith("Full capture"):
        top2_captured = top2_all
        top3_captured = 0
        plays = total * 2
    elif play_policy.startswith("Top2 risk"):
        top2_captured = int(((pd.to_numeric(winner_sub.get("Needed_Top2", 0), errors="coerce").fillna(0).astype(int) == 1) & (winner_sub.get("Top2Decision", "") == "TOP2_REQUIRED")).sum()) if winner_events else 0
        top3_captured = 0
        plays = total + int((sub.get("Top2Decision", "") == "TOP2_REQUIRED").sum())
    else:
        top2_captured = 0
        top3_captured = 0
        plays = total

    captured = top1 + top2_captured + top3_captured
    miss = max(0, winner_events - captured)
    return {
        "method": label,
        "rows": total,
        "winner_events": winner_events,
        "non_core_events": non_core_events,
        "top1": top1,
        "top2_captured": top2_captured,
        "top3_captured": top3_captured,
        "captured": captured,
        "miss": miss,
        "capture_pct": round((captured / winner_events * 100), 2) if winner_events else 0.0,
        "plays": int(plays),
        "plays_per_capture": round((plays / captured), 3) if captured else None,
        "plays_per_winner_event": round((plays / winner_events), 3) if winner_events else None,
    }

def build_stream_method_tests(res: pd.DataFrame, play_policy: str) -> Tuple[pd.DataFrame, pd.DataFrame]:
    if res.empty or "StreamRank" not in res.columns:
        return pd.DataFrame(), pd.DataFrame()

    work = res.copy()
    work["StreamRank"] = pd.to_numeric(work["StreamRank"], errors="coerce")
    max_rank = int(work["StreamRank"].max()) if work["StreamRank"].notna().any() else 0
    rows = []

    rows.append(summarize_policy(work, work["StreamRank"].notna(), "ALL_STREAMS", play_policy))

    for n in [10, 15, 20, 25, 30, 40, 50, 60]:
        if n <= max_rank:
            rows.append(summarize_policy(work, work["StreamRank"] <= n, f"TOP_{n}_STREAM_ROWS", play_policy))

    for pct in [10, 15, 20, 25, 30, 40, 50, 60, 70, 80]:
        cutoff = max(1, int(round(max_rank * pct / 100)))
        rows.append(summarize_policy(work, work["StreamRank"] <= cutoff, f"ROW_PERCENTILE_TOP_{pct}", play_policy))

    if "StreamTier" in work.columns:
        for tier in ["A_TOP25", "B_26_50", "C_51_75", "D_76_100"]:
            rows.append(summarize_policy(work, work["StreamTier"] == tier, f"STREAM_TIER_{tier}", play_policy))

    method_df = pd.DataFrame(rows)

    single_rows = []
    for rnk, g in work.groupby("StreamRank", dropna=True):
        single_rows.append(summarize_policy(g, pd.Series([True] * len(g), index=g.index), f"SINGLE_ROW_{int(rnk)}", play_policy))
    single_df = pd.DataFrame(single_rows)
    if not single_df.empty:
        single_df["SingleRow"] = single_df["method"].str.replace("SINGLE_ROW_", "", regex=False).astype(int)
        single_df = single_df.sort_values("SingleRow")
    return method_df, single_df


def unique_straight_permutations(member: str) -> List[str]:
    member = normalize_member(member)
    if member not in MEMBERS:
        return []
    return sorted({"".join(p) for p in permutations(member, 4)})


def duplicate_position_pattern(perm: str) -> str:
    counts = pd.Series(list(str(perm))).value_counts().to_dict()
    dup_digits = [d for d, c in counts.items() if c > 1]
    if not dup_digits:
        return "none"
    d = sorted(dup_digits)[0]
    positions = [str(i + 1) for i, ch in enumerate(str(perm)) if ch == d]
    return "-".join(positions)


def ordered_pairs_4(perm: str) -> List[str]:
    s4 = str(perm).zfill(4)[-4:]
    return [s4[0:2], s4[1:3], s4[2:4]]


def build_straight_training_events(hist: pd.DataFrame) -> pd.DataFrame:
    rows = []
    for stream, g in hist.groupby("StreamKey"):
        g = g.sort_values("Date").reset_index(drop=True)
        for i in range(1, len(g)):
            member = result_to_core389_member(g.loc[i, "Result"])
            if member in MEMBERS:
                rows.append({
                    "StreamKey": stream,
                    "Date": g.loc[i, "Date"],
                    "seed": g.loc[i - 1, "Result"],
                    "TrueMember": member,
                    "StraightResult": extract_pick4_digits(g.loc[i, "Result"]),
                    "Result": extract_pick4_digits(g.loc[i, "Result"]),
                })
    events = pd.DataFrame(rows)
    if events.empty:
        return events
    events = enrich_seed_features(events, "seed")
    events["DupPattern"] = events["StraightResult"].apply(duplicate_position_pattern)
    events["Pair12"] = events["StraightResult"].astype(str).str[0:2]
    events["Pair23"] = events["StraightResult"].astype(str).str[1:3]
    events["Pair34"] = events["StraightResult"].astype(str).str[2:4]
    for pos in range(4):
        events[f"pos{pos+1}"] = events["StraightResult"].astype(str).str[pos]
    return events


def _rate_with_support(df: pd.DataFrame, numerator_mask, min_support: int = 1) -> Tuple[float, int]:
    support = int(len(df))
    if support < int(min_support) or support <= 0:
        return 0.0, support
    return float(pd.Series(numerator_mask).sum()) / support, support


def straight_member_score(row: pd.Series, member: str) -> float:
    member = normalize_member(member)
    score_cols = {m: float(row.get(f"score_{m}", 0) or 0) for m in MEMBERS}
    max_score = max(score_cols.values()) if score_cols else 0.0
    if max_score > 0 and member in score_cols:
        return max(0.0, min(1.0, score_cols[member] / max_score))
    if member == str(row.get("PredictedMember", "")):
        return 1.0
    if member == str(row.get("Top2_pred", "")):
        return 0.65
    if member == str(row.get("ThirdMember", "")):
        return 0.35
    return 0.0


def straight_eligible_members(
    row: pd.Series,
    top2_ratio_min: float,
    top2_margin_max: float,
    top2_volatility_min: float,
    top3_margin_max: float,
    top3_volatility_min: float,
) -> List[Dict[str, str]]:
    out = []
    top1 = normalize_member(row.get("PredictedMember", ""))
    top2 = normalize_member(row.get("Top2_pred", ""))
    top3 = normalize_member(row.get("ThirdMember", ""))
    play_type = str(row.get("PlayType", ""))
    ratio = float(row.get("Top2ToTop1Ratio", 0) or 0)
    margin = float(row.get("Margin", 9999) or 9999)
    risk = int(float(row.get("Top2RiskScore", 0) or 0))
    vol = float(row.get("RowVolatilityRate", 0) or 0)
    top3_rescue = int(float(row.get("Top3Rescue", 0) or 0))

    if top1 in MEMBERS:
        out.append({"StraightMember": top1, "StraightMemberSource": "TOP1", "StraightEligibilityReason": "TOP1_ALWAYS_ELIGIBLE"})

    top2_ok = (
        top2 in MEMBERS
        and top2 != top1
        and play_type in {"TOP1_TOP2", "TOP1_TOP2_TOP3"}
        and (
            risk > 0
            or ratio >= float(top2_ratio_min)
            or margin <= float(top2_margin_max)
            or vol >= float(top2_volatility_min)
        )
    )
    if top2_ok:
        reasons = []
        if risk > 0: reasons.append("top2_risk")
        if ratio >= float(top2_ratio_min): reasons.append("ratio")
        if margin <= float(top2_margin_max): reasons.append("weak_margin")
        if vol >= float(top2_volatility_min): reasons.append("row_volatility")
        out.append({"StraightMember": top2, "StraightMemberSource": "TOP2", "StraightEligibilityReason": "|".join(reasons)})

    top3_ok = (
        top3 in MEMBERS
        and top3 not in {top1, top2}
        and play_type == "TOP1_TOP2_TOP3"
        and top3_rescue == 1
        and vol >= float(top3_volatility_min)
        and (margin <= float(top3_margin_max) or risk > 0)
    )
    if top3_ok:
        reasons = ["top3_rescue", "row_volatility"]
        if margin <= float(top3_margin_max): reasons.append("weak_margin")
        if risk > 0: reasons.append("top2_risk")
        out.append({"StraightMember": top3, "StraightMemberSource": "TOP3", "StraightEligibilityReason": "|".join(reasons)})

    return out


def score_straight_permutation(row: pd.Series, member: str, perm: str, events: pd.DataFrame) -> Dict:
    member = normalize_member(member)
    perm = str(perm).zfill(4)[-4:]
    stream = str(row.get("StreamKey", ""))
    member_events = events[events["TrueMember"] == member].copy()
    stream_member_events = member_events[member_events["StreamKey"] == stream].copy()
    trait_events = member_events[
        (member_events["sum_bucket"].astype(str) == str(row.get("sum_bucket", "")))
        & (member_events["spread_bucket"].astype(str) == str(row.get("spread_bucket", "")))
    ].copy()
    seed_shape_events = member_events[
        (member_events["parity_pattern"].astype(str) == str(row.get("parity_pattern", "")))
        & (member_events["highlow_pattern"].astype(str) == str(row.get("highlow_pattern", "")))
    ].copy()
    exact_seed_events = member_events[member_events["seed"].astype(str) == str(row.get("seed", ""))].copy()

    pos_rates = []
    pos_supports = []
    for i, digit in enumerate(perm):
        r_global, s_global = _rate_with_support(member_events, member_events[f"pos{i+1}"].astype(str) == digit, 1)
        r_stream, s_stream = _rate_with_support(stream_member_events, stream_member_events[f"pos{i+1}"].astype(str) == digit, 2)
        r_trait, s_trait = _rate_with_support(trait_events, trait_events[f"pos{i+1}"].astype(str) == digit, 3)
        weighted = (0.55 * r_global) + (0.30 * r_stream) + (0.15 * r_trait)
        pos_rates.append(weighted)
        pos_supports.append(s_global + s_stream + s_trait)
    position_score = sum(pos_rates) / 4 if pos_rates else 0.0

    pair_rates = []
    pair_supports = []
    pair_cols = ["Pair12", "Pair23", "Pair34"]
    for pair, col in zip(ordered_pairs_4(perm), pair_cols):
        r_global, s_global = _rate_with_support(member_events, member_events[col].astype(str) == pair, 1)
        r_stream, s_stream = _rate_with_support(stream_member_events, stream_member_events[col].astype(str) == pair, 2)
        r_seedshape, s_seedshape = _rate_with_support(seed_shape_events, seed_shape_events[col].astype(str) == pair, 3)
        weighted = (0.55 * r_global) + (0.25 * r_stream) + (0.20 * r_seedshape)
        pair_rates.append(weighted)
        pair_supports.append(s_global + s_stream + s_seedshape)
    ordered_pair_score = sum(pair_rates) / 3 if pair_rates else 0.0

    exact_perm_rate, exact_seed_support = _rate_with_support(exact_seed_events, exact_seed_events["StraightResult"].astype(str) == perm, 1)
    trait_perm_rate, trait_support = _rate_with_support(trait_events, trait_events["StraightResult"].astype(str) == perm, 3)
    seedshape_perm_rate, seedshape_support = _rate_with_support(seed_shape_events, seed_shape_events["StraightResult"].astype(str) == perm, 3)
    seed_transition_score = (0.50 * exact_perm_rate) + (0.30 * trait_perm_rate) + (0.20 * seedshape_perm_rate)

    dup = duplicate_position_pattern(perm)
    dup_rate_global, dup_support_global = _rate_with_support(member_events, member_events["DupPattern"].astype(str) == dup, 1)
    dup_rate_stream, dup_support_stream = _rate_with_support(stream_member_events, stream_member_events["DupPattern"].astype(str) == dup, 2)
    repeat_placement_score = (0.70 * dup_rate_global) + (0.30 * dup_rate_stream)

    first_rate, first_support = _rate_with_support(stream_member_events, stream_member_events["pos1"].astype(str) == perm[0], 2)
    last_rate, last_support = _rate_with_support(stream_member_events, stream_member_events["pos4"].astype(str) == perm[3], 2)
    stream_order_score = (first_rate + last_rate) / 2 if (first_support + last_support) > 0 else 0.0

    recent = stream_member_events.sort_values("Date").tail(20)
    recent_rate, recent_support = _rate_with_support(recent, recent["StraightResult"].astype(str) == perm, 1)
    recent_front_rate, recent_front_support = _rate_with_support(recent, recent["pos1"].astype(str) == perm[0], 2)
    recent_back_rate, recent_back_support = _rate_with_support(recent, recent["pos4"].astype(str) == perm[3], 2)
    recent_order_score = (0.50 * recent_rate) + (0.25 * recent_front_rate) + (0.25 * recent_back_rate)

    member_confidence = straight_member_score(row, member)
    total_score = (
        (member_confidence * 0.25)
        + (position_score * 0.25)
        + (ordered_pair_score * 0.20)
        + (seed_transition_score * 0.15)
        + (stream_order_score * 0.10)
        + (recent_order_score * 0.05)
    )

    evidence_support = int(sum(pos_supports) + sum(pair_supports) + exact_seed_support + trait_support + seedshape_support + dup_support_global + dup_support_stream + first_support + last_support + recent_support + recent_front_support + recent_back_support)

    return {
        "StraightPermutation": perm,
        "MemberConfidenceScore": round(member_confidence * 100, 2),
        "PositionScore": round(position_score * 100, 2),
        "OrderedPairScore": round(ordered_pair_score * 100, 2),
        "SeedTransitionScore": round(seed_transition_score * 100, 2),
        "StreamOrderScore": round(stream_order_score * 100, 2),
        "RecentOrderScore": round(recent_order_score * 100, 2),
        "RepeatPlacementScore": round(repeat_placement_score * 100, 2),
        "StraightConfidenceScore": round(total_score * 100, 2),
        "EvidenceSupport": evidence_support,
        "DupPattern": dup,
        "StraightScoreFormula": "25% member + 25% position + 20% ordered_pair + 15% seed_transition + 10% stream_order + 5% recent_order",
    }


def build_straight_playlist(
    playlist: pd.DataFrame,
    hist: pd.DataFrame,
    recommended_only: bool,
    top2_ratio_min: float,
    top2_margin_max: float,
    top2_volatility_min: float,
    top3_margin_max: float,
    top3_volatility_min: float,
    max_straights_per_stream: int,
) -> Tuple[pd.DataFrame, pd.DataFrame]:
    events = build_straight_training_events(hist)
    if playlist is None or playlist.empty or events.empty:
        empty = pd.DataFrame()
        return empty, empty

    base = playlist.copy()
    if recommended_only and "RecommendedStream" in base.columns:
        base = base[pd.to_numeric(base["RecommendedStream"], errors="coerce").fillna(0).astype(int) == 1].copy()

    rows = []
    for _, row in base.iterrows():
        eligible = straight_eligible_members(row, top2_ratio_min, top2_margin_max, top2_volatility_min, top3_margin_max, top3_volatility_min)
        for em in eligible:
            member = em["StraightMember"]
            for perm in unique_straight_permutations(member):
                score = score_straight_permutation(row, member, perm, events)
                rows.append({
                    "PlaylistRank": row.get("PlaylistRank", ""),
                    "RecommendedStream": row.get("RecommendedStream", ""),
                    "StreamRank": row.get("StreamRank", ""),
                    "RowPercentile": row.get("RowPercentile", ""),
                    "SingleRow": row.get("SingleRow", ""),
                    "StreamTier": row.get("StreamTier", ""),
                    "StreamKey": row.get("StreamKey", ""),
                    "State": row.get("State", ""),
                    "Game": row.get("Game", ""),
                    "seed": row.get("seed", ""),
                    "LastResult": row.get("LastResult", ""),
                    "BoxPlayType": row.get("PlayType", ""),
                    "BoxRecommendedPlay": row.get("RecommendedPlay", ""),
                    "PredictedMember": row.get("PredictedMember", ""),
                    "Top2_pred": row.get("Top2_pred", ""),
                    "ThirdMember": row.get("ThirdMember", ""),
                    "StraightMember": member,
                    "StraightMemberSource": em["StraightMemberSource"],
                    "StraightEligibilityReason": em["StraightEligibilityReason"],
                    "Margin": row.get("Margin", ""),
                    "Top2ToTop1Ratio": row.get("Top2ToTop1Ratio", ""),
                    "Top2RiskScore": row.get("Top2RiskScore", ""),
                    "Top3Rescue": row.get("Top3Rescue", ""),
                    "RowVolatilityRate": row.get("RowVolatilityRate", ""),
                    **score,
                })

    straight = pd.DataFrame(rows)
    if straight.empty:
        return straight, pd.DataFrame()

    straight = straight.sort_values(
        ["RecommendedStream", "PlaylistRank", "StraightConfidenceScore", "EvidenceSupport"],
        ascending=[False, True, False, False]
    ).reset_index(drop=True)
    straight["OverallStraightRank"] = straight.index + 1
    straight["StreamStraightRank"] = straight.groupby("StreamKey")["StraightConfidenceScore"].rank(method="first", ascending=False).astype(int)
    straight["RecommendedStraight"] = (straight["StreamStraightRank"] <= int(max_straights_per_stream)).astype(int)
    straight["RecommendedStraightDisplay"] = straight.apply(lambda r: f"**{r['StraightPermutation']}**" if int(r["RecommendedStraight"]) == 1 else str(r["StraightPermutation"]), axis=1)
    # v88 display-only columns: make actual straight plays unmistakable in UI/downloads.
    straight = v88_add_straight_play_markers(straight)

    summary = straight.groupby("StreamKey", dropna=False).agg(
        eligible_members=("StraightMember", lambda series: ",".join(sorted(set(map(str, series))))),
        total_candidate_straights=("StraightPermutation", "count"),
        recommended_straights=("RecommendedStraight", "sum"),
        best_straight=("StraightPermutation", "first"),
        best_confidence=("StraightConfidenceScore", "first"),
        box_play_type=("BoxPlayType", "first"),
        box_play=("BoxRecommendedPlay", "first"),
        stream_rank=("StreamRank", "first"),
        row_percentile=("RowPercentile", "first"),
    ).reset_index()
    summary = summary.sort_values(["stream_rank", "best_confidence"], ascending=[True, False]).reset_index(drop=True)
    return straight, summary



# ================================
# v64.2 STRAIGHT PLAY BACKTEST
# Uses existing v47 straight ranking logic; does not alter box/member picks.
# ================================

def v642_event_playlist_from_lab_row(row: pd.Series) -> pd.DataFrame:
    """Convert one lab/per-event row into the playlist shape expected by build_straight_playlist."""
    d = row.to_dict()
    if "PlaylistRank" not in d:
        d["PlaylistRank"] = d.get("rank", d.get("StreamRank", ""))
    if "LastResult" not in d:
        d["LastResult"] = d.get("seed", "")
    if "seed" not in d:
        d["seed"] = d.get("LastResult", "")
    if "State" not in d:
        stream = str(d.get("StreamKey", ""))
        d["State"] = stream.split("|")[0].strip() if "|" in stream else ""
    if "Game" not in d:
        stream = str(d.get("StreamKey", ""))
        d["Game"] = stream.split("|", 1)[1].strip() if "|" in stream else ""
    if "RecommendedStream" not in d:
        d["RecommendedStream"] = 1
    return pd.DataFrame([d])

def v642_run_straight_backtest(
    lab_df: pd.DataFrame,
    hist: pd.DataFrame,
    recommended_only: bool,
    use_ensemble_only: bool,
    max_events: int,
    straight_depth: int,
    top2_ratio_min: float,
    top2_margin_max: float,
    top2_volatility_min: float,
    top3_margin_max: float,
    top3_volatility_min: float,
) -> Tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    if lab_df is None or lab_df.empty:
        return pd.DataFrame(), pd.DataFrame(), pd.DataFrame()

    events = lab_df.copy()

    if recommended_only and "RecommendedStream" in events.columns:
        events = events[pd.to_numeric(events["RecommendedStream"], errors="coerce").fillna(0).astype(int).eq(1)].copy()

    if use_ensemble_only:
        # Apply the same v64 agreement layer to historical lab rows.
        events = v64_final_play_list(events, st.session_state.get("v64_agreement_threshold_for_backtest", V64_DEFAULT_AGREEMENT_THRESHOLD))

    if max_events and int(max_events) > 0:
        events = events.head(int(max_events)).copy()

    rows = []
    for idx, ev in events.iterrows():
        true_result = extract_pick4_digits(ev.get("Result", ""))
        true_member = normalize_member(ev.get("TrueMember", result_to_core389_member(true_result)))
        one = v642_event_playlist_from_lab_row(ev)

        # Rank all eligible straight candidates; depth is evaluated afterward.
        ranked, _summary = build_straight_playlist(
            one,
            hist,
            recommended_only=False,
            top2_ratio_min=top2_ratio_min,
            top2_margin_max=top2_margin_max,
            top2_volatility_min=top2_volatility_min,
            top3_margin_max=top3_margin_max,
            top3_volatility_min=top3_volatility_min,
            max_straights_per_stream=max(24, int(straight_depth)),
        )

        if ranked is None or ranked.empty:
            rows.append({
                "EventIndex": idx,
                "Date": ev.get("Date", ""),
                "StreamKey": ev.get("StreamKey", ""),
                "seed": ev.get("seed", ev.get("LastResult", "")),
                "Result": true_result,
                "TrueMember": true_member,
                "PredictedMember": ev.get("PredictedMember", ""),
                "Top2_pred": ev.get("Top2_pred", ""),
                "ThirdMember": ev.get("ThirdMember", ""),
                "PlayType": ev.get("PlayType", ""),
                "StraightHit": 0,
                "StraightHitRank": None,
                "StraightCapturedAtDepth": 0,
                "Reason": "NO_STRAIGHT_CANDIDATES",
            })
            continue

        ranked["StraightPermutation"] = ranked["StraightPermutation"].astype(str).str.zfill(4)
        hit_rows = ranked[ranked["StraightPermutation"].eq(str(true_result).zfill(4))].copy()

        if hit_rows.empty:
            hit_rank = None
            hit_score = None
            hit_member = None
            hit_source = None
            reason = "TRUE_STRAIGHT_NOT_IN_ELIGIBLE_SET"
            hit = 0
        else:
            hr = hit_rows.sort_values("StreamStraightRank").iloc[0]
            hit_rank = int(hr["StreamStraightRank"])
            hit_score = hr.get("StraightConfidenceScore", None)
            hit_member = hr.get("StraightMember", "")
            hit_source = hr.get("StraightMemberSource", "")
            reason = "HIT_IN_RANKED_LIST"
            hit = 1

        rows.append({
            "EventIndex": idx,
            "Date": ev.get("Date", ""),
            "StreamKey": ev.get("StreamKey", ""),
            "seed": ev.get("seed", ev.get("LastResult", "")),
            "Result": true_result,
            "TrueMember": true_member,
            "PredictedMember": ev.get("PredictedMember", ""),
            "Top2_pred": ev.get("Top2_pred", ""),
            "ThirdMember": ev.get("ThirdMember", ""),
            "PlayType": ev.get("PlayType", ""),
            "RecommendedPlay": ev.get("RecommendedPlay", ""),
            "StreamRank": ev.get("StreamRank", ""),
            "RowPercentile": ev.get("RowPercentile", ""),
            "SingleRow": ev.get("SingleRow", ""),
            "RecommendedStream": ev.get("RecommendedStream", ""),
            "v64_AgreementScore": ev.get("v64_AgreementScore", ""),
            "v64_AgreedMethods": ev.get("v64_AgreedMethods", ""),
            "StraightHit": hit,
            "StraightHitRank": hit_rank,
            "StraightHitMember": hit_member,
            "StraightHitMemberSource": hit_source,
            "StraightHitScore": hit_score,
            "StraightCapturedAtDepth": 1 if (hit_rank is not None and int(hit_rank) <= int(straight_depth)) else 0,
            "Reason": reason,
        })

    per_event = pd.DataFrame(rows)
    total = len(per_event)
    ranked_hits = int(per_event["StraightHit"].sum()) if total else 0
    depth_hits = int(per_event["StraightCapturedAtDepth"].sum()) if total else 0

    summary = pd.DataFrame([{
        "Build": BUILD_MARKER,
        "events_tested": total,
        "recommended_only": recommended_only,
        "use_ensemble_only": use_ensemble_only,
        "straight_depth": int(straight_depth),
        "straight_ranked_hits": ranked_hits,
        "straight_ranked_hit_pct": round((ranked_hits / total * 100) if total else 0, 2),
        "straight_captured_at_depth": depth_hits,
        "straight_capture_at_depth_pct": round((depth_hits / total * 100) if total else 0, 2),
        "estimated_straight_plays": int(total * int(straight_depth)),
        "plays_per_straight_capture": round((total * int(straight_depth)) / depth_hits, 3) if depth_hits else None,
    }])

    depth_rows = []
    if total:
        for d in range(1, 25):
            cnt = int(per_event["StraightHitRank"].apply(lambda x: pd.notna(x) and int(x) <= d).sum())
            depth_rows.append({
                "Depth": d,
                "HitsAtOrAboveDepth": cnt,
                "HitPct": round(cnt / total * 100, 2),
                "EstimatedPlays": total * d,
                "Events": total,
            })
    depth_df = pd.DataFrame(depth_rows)

    return per_event, summary, depth_df


# ================================
# v64.3 FINAL-LIST ANALYTICS + CACHED STRAIGHT BACKTEST
# Downstream only: does not alter v47 member/box engine.
# ================================

def v643_final_list_single_row_test(lab_df: pd.DataFrame, threshold: int) -> pd.DataFrame:
    """v192 safe final-list summary.
    Downstream report only. It must never crash/rerun/block completed WF exports.
    """
    def _safe_num_group(g, col, default=0.0):
        try:
            if isinstance(g, pd.DataFrame) and col in g.columns:
                return pd.to_numeric(g[col], errors="coerce").fillna(default)
            if isinstance(g, pd.DataFrame):
                return pd.Series([default] * len(g), index=g.index, dtype=float)
        except Exception:
            pass
        return pd.Series(dtype=float)

    if lab_df is None or not isinstance(lab_df, pd.DataFrame) or lab_df.empty:
        return pd.DataFrame()
    try:
        marked = v64_apply_ensemble(lab_df.copy(), threshold)
    except Exception as e:
        return pd.DataFrame([{"v192_ReportStatus": "SKIPPED_v64_apply_ensemble_error", "Error": repr(e)}])
    try:
        final = marked[marked["v64_FinalPlayable"].astype(int).eq(1)].copy() if "v64_FinalPlayable" in marked.columns else marked.copy()
    except Exception:
        final = marked.copy()
    if final.empty or "SingleRow" not in final.columns:
        return pd.DataFrame()

    rows = []
    try:
        grouped = final.groupby("SingleRow", dropna=False)
    except Exception as e:
        return pd.DataFrame([{"v192_ReportStatus": "SKIPPED_groupby_error", "Error": repr(e)}])

    for row_num, g in grouped:
        if not isinstance(g, pd.DataFrame) or g.empty:
            continue
        total = len(g)
        top1 = int(_safe_num_group(g, "Top1_Correct", 0).sum())
        needed_top2 = int(_safe_num_group(g, "Needed_Top2", 0).sum())
        miss = int(_safe_num_group(g, "Miss", 0).sum())
        top3_rescue = int(_safe_num_group(g, "Top3Rescue", 0).sum())
        captured = top1 + needed_top2 + top3_rescue
        try:
            play_series = g["PlayType"].astype(str) if "PlayType" in g.columns else pd.Series([""] * len(g), index=g.index)
            plays = int((play_series.eq("TOP1_ONLY")).sum() + 2 * (play_series.eq("TOP1_TOP2")).sum() + 3 * (play_series.eq("TOP1_TOP2_TOP3")).sum())
        except Exception:
            plays = 0
        rows.append({
            "SingleRow": row_num,
            "EventsInFinalList": total,
            "Top1": top1,
            "NeededTop2": needed_top2,
            "Top3Rescue": top3_rescue,
            "Miss": miss,
            "Captured": captured,
            "CapturePct": round(captured / total * 100, 2) if total else 0,
            "Top1Pct": round(top1 / total * 100, 2) if total else 0,
            "Plays": plays,
            "PlaysPerCapture": round(plays / captured, 3) if captured else None,
            "AvgAgreementScore": round(_safe_num_group(g, "v64_AgreementScore", 0).mean(), 3) if total else 0,
            "AvgUniversalFamilyScore": round(_safe_num_group(g, "UniversalFamilyScore", 0).mean(), 3) if total else 0,
            "AvgModelConfidenceScore": round(_safe_num_group(g, "ModelConfidenceScore", 0).mean(), 3) if total else 0,
        })
    out = pd.DataFrame(rows)
    if out.empty:
        return out
    return out.sort_values(["CapturePct", "Top1Pct", "EventsInFinalList"], ascending=[False, False, False]).reset_index(drop=True)

def v645_safe_numeric_series(df: pd.DataFrame, col: str, default: float = 0.0) -> pd.Series:
    if df is None or df.empty:
        return pd.Series(dtype=float)
    if col in df.columns:
        return pd.to_numeric(df[col], errors="coerce").fillna(default)
    return pd.Series([default] * len(df), index=df.index, dtype=float)

def v643_top1_confidence_subset(lab_or_daily_df: pd.DataFrame, threshold: int) -> pd.DataFrame:
    if lab_or_daily_df is None or lab_or_daily_df.empty:
        return pd.DataFrame()
    marked = v64_apply_ensemble(lab_or_daily_df.copy(), threshold)
    final = marked[marked["v64_FinalPlayable"].astype(int).eq(1)].copy()
    if final.empty:
        return final

    margin = v645_safe_numeric_series(final, "Margin", 0)
    ratio = v645_safe_numeric_series(final, "Top2ToTop1Ratio", 1)
    row_top1 = v645_safe_numeric_series(final, "RowTop1Rate", 0)
    row_top2 = v645_safe_numeric_series(final, "RowTop2Rate", 1)
    agreement = v645_safe_numeric_series(final, "v64_AgreementScore", 0)
    model_conf = v645_safe_numeric_series(final, "ModelConfidenceScore", 0) if "ModelConfidenceScore" in final.columns else v645_safe_numeric_series(final, "ModelConfidenceRaw", 0)

    final["v643_Top1ConfidenceScore"] = (
        agreement * 15
        + row_top1 * 35
        + (1 - ratio.clip(lower=0, upper=1)) * 25
        + (margin.rank(pct=True).fillna(0) * 15)
        + (model_conf.rank(pct=True).fillna(0) * 10)
        - row_top2 * 10
    ).round(3)

    final["v643_Top1ConfidenceFlag"] = (
        (agreement.ge(3))
        & (row_top1.ge(0.50))
        & (ratio.le(0.50))
        & (margin.ge(20))
    ).astype(int)

    # Conservative list: if not perfect, still return ranked candidates for review.
    out = final.sort_values(["v643_Top1ConfidenceFlag", "v643_Top1ConfidenceScore", "v64_AgreementScore", "Margin"], ascending=[False, False, False, False]).reset_index(drop=True)
    return out

def v643_run_cached_final_straight_backtest(
    lab_df: pd.DataFrame,
    hist: pd.DataFrame,
    threshold: int,
    straight_depth: int,
    recommended_only: bool,
    top2_ratio_min: float,
    top2_margin_max: float,
    top2_volatility_min: float,
    top3_margin_max: float,
    top3_volatility_min: float,
    max_events: int = 0,
) -> Tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    if lab_df is None or lab_df.empty:
        return pd.DataFrame(), pd.DataFrame(), pd.DataFrame()

    events = lab_df.copy()
    if recommended_only and "RecommendedStream" in events.columns:
        events = events[pd.to_numeric(events["RecommendedStream"], errors="coerce").fillna(0).astype(int).eq(1)].copy()

    marked = v64_apply_ensemble(events, threshold)
    final = marked[marked["v64_FinalPlayable"].astype(int).eq(1)].copy()

    if max_events and int(max_events) > 0:
        final = final.head(int(max_events)).copy()

    if final.empty:
        return pd.DataFrame(), pd.DataFrame([{
            "Build": BUILD_MARKER,
            "events_tested": 0,
            "note": "No events passed final ensemble list"
        }]), pd.DataFrame()

    # Cache the straight training event table once, then score per event from the same cached table.
    training_events = build_straight_training_events(hist)
    st.session_state["v643_cached_straight_events"] = training_events

    rows = []
    for idx, ev in final.iterrows():
        true_result = extract_pick4_digits(ev.get("Result", ""))
        true_member = normalize_member(ev.get("TrueMember", result_to_core389_member(true_result)))
        one = v642_event_playlist_from_lab_row(ev) if "v642_event_playlist_from_lab_row" in globals() else pd.DataFrame([ev.to_dict()])

        if training_events is None or training_events.empty:
            ranked = pd.DataFrame()
        else:
            # Equivalent to build_straight_playlist, but uses cached training_events.
            cand_rows = []
            for _, row in one.iterrows():
                eligible = straight_eligible_members(row, top2_ratio_min, top2_margin_max, top2_volatility_min, top3_margin_max, top3_volatility_min)
                for em in eligible:
                    member = em["StraightMember"]
                    for perm in unique_straight_permutations(member):
                        score = score_straight_permutation(row, member, perm, training_events)
                        cand_rows.append({
                            "StraightMember": member,
                            "StraightMemberSource": em["StraightMemberSource"],
                            "StraightEligibilityReason": em["StraightEligibilityReason"],
                            **score,
                        })
            ranked = pd.DataFrame(cand_rows)
            if not ranked.empty:
                ranked = ranked.sort_values(["StraightConfidenceScore", "EvidenceSupport"], ascending=[False, False]).reset_index(drop=True)
                ranked["StreamStraightRank"] = ranked.index + 1

        if ranked is None or ranked.empty:
            rows.append({
                "EventIndex": idx,
                "Date": ev.get("Date", ""),
                "StreamKey": ev.get("StreamKey", ""),
                "seed": ev.get("seed", ev.get("LastResult", "")),
                "Result": true_result,
                "TrueMember": true_member,
                "PredictedMember": ev.get("PredictedMember", ""),
                "Top2_pred": ev.get("Top2_pred", ""),
                "ThirdMember": ev.get("ThirdMember", ""),
                "PlayType": ev.get("PlayType", ""),
                "v64_AgreementScore": ev.get("v64_AgreementScore", ""),
                "v64_AgreedMethods": ev.get("v64_AgreedMethods", ""),
                "StraightHit": 0,
                "StraightHitRank": None,
                "StraightCapturedAtDepth": 0,
                "Reason": "NO_STRAIGHT_CANDIDATES",
            })
            continue

        ranked["StraightPermutation"] = ranked["StraightPermutation"].astype(str).str.zfill(4)
        hit_rows = ranked[ranked["StraightPermutation"].eq(str(true_result).zfill(4))].copy()
        if hit_rows.empty:
            hit_rank, hit_score, hit_member, hit_source = None, None, None, None
            hit, reason = 0, "TRUE_STRAIGHT_NOT_IN_ELIGIBLE_SET"
        else:
            hr = hit_rows.sort_values("StreamStraightRank").iloc[0]
            hit_rank = int(hr["StreamStraightRank"])
            hit_score = hr.get("StraightConfidenceScore", None)
            hit_member = hr.get("StraightMember", "")
            hit_source = hr.get("StraightMemberSource", "")
            hit, reason = 1, "HIT_IN_RANKED_LIST"

        rows.append({
            "EventIndex": idx,
            "Date": ev.get("Date", ""),
            "StreamKey": ev.get("StreamKey", ""),
            "seed": ev.get("seed", ev.get("LastResult", "")),
            "Result": true_result,
            "TrueMember": true_member,
            "PredictedMember": ev.get("PredictedMember", ""),
            "Top2_pred": ev.get("Top2_pred", ""),
            "ThirdMember": ev.get("ThirdMember", ""),
            "PlayType": ev.get("PlayType", ""),
            "RecommendedPlay": ev.get("RecommendedPlay", ""),
            "StreamRank": ev.get("StreamRank", ""),
            "RowPercentile": ev.get("RowPercentile", ""),
            "SingleRow": ev.get("SingleRow", ""),
            "v64_AgreementScore": ev.get("v64_AgreementScore", ""),
            "v64_AgreedMethods": ev.get("v64_AgreedMethods", ""),
            "UniversalFamilyScore": ev.get("UniversalFamilyScore", ""),
            "StraightHit": hit,
            "StraightHitRank": hit_rank,
            "StraightHitMember": hit_member,
            "StraightHitMemberSource": hit_source,
            "StraightHitScore": hit_score,
            "StraightCapturedAtDepth": 1 if (hit_rank is not None and int(hit_rank) <= int(straight_depth)) else 0,
            "Reason": reason,
        })

    per_event = pd.DataFrame(rows)
    total = len(per_event)
    ranked_hits = int(per_event["StraightHit"].sum()) if total else 0
    depth_hits = int(per_event["StraightCapturedAtDepth"].sum()) if total else 0
    summary = pd.DataFrame([{
        "Build": BUILD_MARKER,
        "Mode": "Final ensemble list + cached straight training events",
        "AgreementThreshold": int(threshold),
        "events_tested": total,
        "straight_depth": int(straight_depth),
        "straight_ranked_hits": ranked_hits,
        "straight_ranked_hit_pct": round((ranked_hits / total * 100) if total else 0, 2),
        "straight_captured_at_depth": depth_hits,
        "straight_capture_at_depth_pct": round((depth_hits / total * 100) if total else 0, 2),
        "estimated_straight_plays": int(total * int(straight_depth)),
        "plays_per_straight_capture": round((total * int(straight_depth)) / depth_hits, 3) if depth_hits else None,
        "cached_training_events": 0 if training_events is None else len(training_events),
    }])

    depth_rows = []
    if total:
        for d in range(1, 25):
            cnt = int(per_event["StraightHitRank"].apply(lambda x: pd.notna(x) and int(x) <= d).sum())
            depth_rows.append({
                "Depth": d,
                "HitsAtOrAboveDepth": cnt,
                "HitPct": round(cnt / total * 100, 2),
                "EstimatedPlays": total * d,
                "Events": total,
            })
    depth_df = pd.DataFrame(depth_rows)
    return per_event, summary, depth_df


# ================================
# v64.5 STREAM ELIMINATION TEST
# Full-312 denominator first. Member uncertainty does NOT eliminate streams.
# ================================

V645_FULL_UNIVERSE_TOTAL = 312
V645_MIN_FULL_CAPTURE_PCT = 75.0
V645_MIN_FULL_CAPTURE_COUNT = 234
V645_DEFAULT_ROW_CAPTURE_FLOOR = 75.0

def v645_row_coverage_table(lab_df: pd.DataFrame) -> pd.DataFrame:
    if lab_df is None or lab_df.empty or "SingleRow" not in lab_df.columns:
        return pd.DataFrame()

    rows = []
    work = lab_df.copy()
    # v147: if the Walk-forward Lab is running full universe, preserve old v64.5/v64.6
    # row-coverage behavior by using only actual Core389 winner events for coverage math.
    if "Core389WinnerEvent" in work.columns:
        work = work[pd.to_numeric(work["Core389WinnerEvent"], errors="coerce").fillna(0).astype(int).eq(1)].copy()
    work["SingleRow"] = pd.to_numeric(work["SingleRow"], errors="coerce")
    work = work[work["SingleRow"].notna()].copy()

    for row_num, g in work.groupby("SingleRow", dropna=False):
        events = len(g)
        top1 = int(pd.to_numeric(g.get("Top1_Correct", 0), errors="coerce").fillna(0).sum())
        needed_top2 = int(pd.to_numeric(g.get("Needed_Top2", 0), errors="coerce").fillna(0).sum())
        top3_rescue = int(pd.to_numeric(g.get("Top3Rescue", 0), errors="coerce").fillna(0).sum()) if "Top3Rescue" in g.columns else 0
        miss = int(pd.to_numeric(g.get("Miss", 0), errors="coerce").fillna(0).sum())
        captured = top1 + needed_top2 + top3_rescue
        playtype = g.get("PlayType", pd.Series([""] * len(g))).astype(str)
        plays = int((playtype.eq("TOP1_ONLY")).sum() + 2 * (playtype.eq("TOP1_TOP2")).sum() + 3 * (playtype.eq("TOP1_TOP2_TOP3")).sum())

        rows.append({
            "SingleRow": int(row_num),
            "WinnersFromFull312": events,
            "Full312WinnerSharePct": round(events / V645_FULL_UNIVERSE_TOTAL * 100, 2),
            "CapturedFromFull312": captured,
            "Full312CapturePct": round(captured / V645_FULL_UNIVERSE_TOTAL * 100, 2),
            "RowSubsetCapturePct": round(captured / events * 100, 2) if events else 0,
            "Top1Wins": top1,
            "NeededTop2": needed_top2,
            "Top3RescueWins": top3_rescue,
            "Misses": miss,
            "OperationalPlays": plays,
            "PlaysPerCapture": round(plays / captured, 3) if captured else None,
            "AvgStreamRank": round(pd.to_numeric(g.get("StreamRank", 0), errors="coerce").fillna(0).mean(), 3),
            "AvgRowPercentile": round(pd.to_numeric(g.get("RowPercentile", 0), errors="coerce").fillna(0).mean(), 3),
            "AvgUniversalFamilyScore": round(pd.to_numeric(g.get("UniversalFamilyScore", 0), errors="coerce").fillna(0).mean(), 3),
        })

    out = pd.DataFrame(rows)
    if out.empty:
        return out
    out = out.sort_values(["WinnersFromFull312", "CapturedFromFull312", "RowSubsetCapturePct"], ascending=[False, False, False]).reset_index(drop=True)
    out["CoverageOrder"] = out.index + 1
    out["CumulativeWinnersFrom312"] = out["WinnersFromFull312"].cumsum()
    out["CumulativeWinnerPctOf312"] = (out["CumulativeWinnersFrom312"] / V645_FULL_UNIVERSE_TOTAL * 100).round(2)
    out["CumulativeCapturedFrom312"] = out["CapturedFromFull312"].cumsum()
    out["CumulativeCapturePctOf312"] = (out["CumulativeCapturedFrom312"] / V645_FULL_UNIVERSE_TOTAL * 100).round(2)
    out["Meets75PctCumulativeCoverage"] = out["CumulativeWinnersFrom312"].ge(V645_MIN_FULL_CAPTURE_COUNT).astype(int)
    return out

def v645_rows_needed_for_capture(row_table: pd.DataFrame, min_full_capture_pct: float = V645_MIN_FULL_CAPTURE_PCT) -> list:
    if row_table is None or row_table.empty:
        return []
    target = int(round(V645_FULL_UNIVERSE_TOTAL * float(min_full_capture_pct) / 100.0))
    ordered = row_table.sort_values(["CoverageOrder"]).copy()
    keep = []
    total = 0
    for _, r in ordered.iterrows():
        keep.append(int(r["SingleRow"]))
        total += int(r["WinnersFromFull312"])
        if total >= target:
            break
    return keep

def v645_apply_stream_elimination(df: pd.DataFrame, row_table: pd.DataFrame, min_full_capture_pct: float = V645_MIN_FULL_CAPTURE_PCT, row_subset_capture_floor: float = V645_DEFAULT_ROW_CAPTURE_FLOOR, use_row_subset_floor: bool = False) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    if df is None or df.empty or row_table is None or row_table.empty:
        return pd.DataFrame(), pd.DataFrame(), pd.DataFrame()

    keep_rows = set(v645_rows_needed_for_capture(row_table, min_full_capture_pct))
    policy = row_table.copy()
    policy["v645_RowSelectedByFull312Coverage"] = policy["SingleRow"].astype(int).isin(keep_rows).astype(int)

    if use_row_subset_floor:
        ok_subset_rows = set(policy[pd.to_numeric(policy["RowSubsetCapturePct"], errors="coerce").fillna(0).ge(float(row_subset_capture_floor))]["SingleRow"].astype(int).tolist())
        keep_rows = keep_rows.intersection(ok_subset_rows)
        policy["v645_RowSelectedAfterSubsetFloor"] = policy["SingleRow"].astype(int).isin(keep_rows).astype(int)
    else:
        policy["v645_RowSelectedAfterSubsetFloor"] = policy["v645_RowSelectedByFull312Coverage"]

    out = df.copy()
    out["SingleRow"] = pd.to_numeric(out.get("SingleRow", -1), errors="coerce").fillna(-1).astype(int)
    out["v645_StreamElim_RowKept"] = out["SingleRow"].isin(keep_rows).astype(int)
    out["v645_StreamElimReason"] = out["v645_StreamElim_RowKept"].map({
        1: "KEEP:row_needed_for_full312_75pct_coverage",
        0: "ELIMINATE_OR_REVIEW:row_outside_full312_coverage_plan",
    })

    playtype = out.get("PlayType", pd.Series([""] * len(out))).astype(str)
    out["v645_MemberUncertaintyAction"] = playtype.map({
        "TOP1_ONLY": "MEMBER:Top1 only",
        "TOP1_TOP2": "MEMBER:Play Top1+Top2",
        "TOP1_TOP2_TOP3": "MEMBER:Play all 3 members",
    }).fillna("MEMBER:Use existing v47 recommendation")

    final = out[out["v645_StreamElim_RowKept"].eq(1)].copy()

    if "Top1_Correct" in out.columns:
        selected_events = len(final)
        selected_captured = int(
            pd.to_numeric(final.get("Top1_Correct", 0), errors="coerce").fillna(0).sum()
            + pd.to_numeric(final.get("Needed_Top2", 0), errors="coerce").fillna(0).sum()
            + (pd.to_numeric(final.get("Top3Rescue", 0), errors="coerce").fillna(0).sum() if "Top3Rescue" in final.columns else 0)
        )
        selected_winners = selected_events
    else:
        selected_events = len(final)
        selected_captured = None
        selected_winners = None

    summary = pd.DataFrame([{
        "Build": BUILD_MARKER,
        "Purpose": "Stream elimination only; member uncertainty never eliminates streams.",
        "FullUniverseTotal": V645_FULL_UNIVERSE_TOTAL,
        "RequiredMinimumFullCapturePct": float(min_full_capture_pct),
        "RequiredMinimumWinnersFrom312": int(round(V645_FULL_UNIVERSE_TOTAL * float(min_full_capture_pct) / 100.0)),
        "RowsKeptCount": len(keep_rows),
        "RowsKept": ",".join(map(str, sorted(keep_rows))),
        "InputRows": len(out),
        "FinalPlayableRows": selected_events,
        "HistoricalWinnersFrom312InKeptRows": selected_winners,
        "HistoricalWinnerCoveragePctOf312": round((selected_winners / V645_FULL_UNIVERSE_TOTAL * 100), 2) if selected_winners is not None else None,
        "HistoricalCapturedFrom312InKeptRows": selected_captured,
        "HistoricalCapturePctOf312": round((selected_captured / V645_FULL_UNIVERSE_TOTAL * 100), 2) if selected_captured is not None else None,
        "SubsetCapturePct_LabelledSecondary": round((selected_captured / selected_events * 100), 2) if selected_events and selected_captured is not None else None,
        "UseRowSubsetCaptureFloor": bool(use_row_subset_floor),
        "RowSubsetCaptureFloorPct": float(row_subset_capture_floor),
    }])

    return out, final, summary

def v645_build_daily_stream_elimination_from_lab_and_daily(lab_df: pd.DataFrame, daily_df: pd.DataFrame, min_full_capture_pct: float, row_subset_capture_floor: float, use_row_subset_floor: bool):
    row_table = v645_row_coverage_table(lab_df)
    marked, final, summary = v645_apply_stream_elimination(daily_df, row_table, min_full_capture_pct=min_full_capture_pct, row_subset_capture_floor=row_subset_capture_floor, use_row_subset_floor=use_row_subset_floor)
    return row_table, marked, final, summary


# ================================
# v64.6 EXCLUDED-ROW 3889-ONLY RESCUE
# ================================

def v646_excluded_row_3889_rescue_backtest(lab_df: pd.DataFrame, row_table: pd.DataFrame, min_full_capture_pct: float, min_misses_per_row: int = 2, min_3889_miss_share: float = 0.75):
    if lab_df is None or lab_df.empty or row_table is None or row_table.empty:
        return pd.DataFrame(), pd.DataFrame(), pd.DataFrame()

    keep_rows = set(v645_rows_needed_for_capture(row_table, min_full_capture_pct))
    work = lab_df.copy()
    work["SingleRow"] = pd.to_numeric(work.get("SingleRow", -1), errors="coerce").fillna(-1).astype(int)
    true_col = "TrueMember" if "TrueMember" in work.columns else ("winning_member" if "winning_member" in work.columns else None)
    work["TrueMember_norm"] = work[true_col].astype(str).str.zfill(4) if true_col else ""
    top3_series = pd.to_numeric(work.get("Top3Rescue", 0), errors="coerce").fillna(0).astype(int) if "Top3Rescue" in work.columns else 0
    work["BaseCaptured"] = (
        pd.to_numeric(work.get("Top1_Correct", 0), errors="coerce").fillna(0).astype(int)
        | pd.to_numeric(work.get("Needed_Top2", 0), errors="coerce").fillna(0).astype(int)
        | top3_series
    ).astype(int)
    work["ExcludedByV645RowPlan"] = (~work["SingleRow"].isin(keep_rows)).astype(int)
    work["WouldRecoverWith3889Only"] = ((work["ExcludedByV645RowPlan"].eq(1)) & (work["BaseCaptured"].eq(0)) & (work["TrueMember_norm"].eq("3889"))).astype(int)

    rows = []
    excluded = work[work["ExcludedByV645RowPlan"].eq(1)].copy()
    for row_num, g in excluded.groupby("SingleRow"):
        excluded_events = len(g)
        base_misses = int((g["BaseCaptured"].eq(0)).sum())
        miss_3889 = int(((g["BaseCaptured"].eq(0)) & (g["TrueMember_norm"].eq("3889"))).sum())
        miss_3389 = int(((g["BaseCaptured"].eq(0)) & (g["TrueMember_norm"].eq("3389"))).sum())
        miss_3899 = int(((g["BaseCaptured"].eq(0)) & (g["TrueMember_norm"].eq("3899"))).sum())
        recovered = int(g["WouldRecoverWith3889Only"].sum())
        share = (miss_3889 / base_misses) if base_misses else 0
        rows.append({
            "SingleRow": int(row_num),
            "ExcludedHistoricalEventsFrom312": excluded_events,
            "BaseMissesInExcludedRow": base_misses,
            "Misses3889": miss_3889,
            "Misses3389": miss_3389,
            "Misses3899": miss_3899,
            "3889MissShareOfRowMisses": round(share, 4),
            "RecoveredBy3889Only": recovered,
            "ExtraPlaysIfRescueAllEventsInRow": excluded_events,
            "PlaysPerRecoveredWinner": round(excluded_events / recovered, 3) if recovered else None,
            "EligibleRescueRow": int(base_misses >= int(min_misses_per_row) and share >= float(min_3889_miss_share)),
        })

    by_row = pd.DataFrame(rows)
    if by_row.empty:
        summary = pd.DataFrame([{"Build": BUILD_MARKER, "FullUniverseTotal": V645_FULL_UNIVERSE_TOTAL, "RecoveredFull312Winners": 0}])
        return work, by_row, summary

    eligible_rows = set(by_row[by_row["EligibleRescueRow"].eq(1)]["SingleRow"].astype(int).tolist())
    work["v646_Excluded3889RescueEligibleRow"] = work["SingleRow"].isin(eligible_rows).astype(int)
    work["v646_3889OnlyRescuePlay"] = ((work["ExcludedByV645RowPlan"].eq(1)) & (work["v646_Excluded3889RescueEligibleRow"].eq(1))).astype(int)
    work["v646_3889OnlyRecovered"] = ((work["v646_3889OnlyRescuePlay"].eq(1)) & (work["WouldRecoverWith3889Only"].eq(1))).astype(int)

    base_captured = int(work["BaseCaptured"].sum())
    rescue_extra_plays = int(work["v646_3889OnlyRescuePlay"].sum())
    rescue_recovered = int(work["v646_3889OnlyRecovered"].sum())
    final_captured = base_captured + rescue_recovered

    summary = pd.DataFrame([{
        "Build": BUILD_MARKER,
        "FullUniverseTotal": V645_FULL_UNIVERSE_TOTAL,
        "BaseCapturedFromFull312": base_captured,
        "BaseCapturePctOf312": round(base_captured / V645_FULL_UNIVERSE_TOTAL * 100, 2),
        "StreamEliminationCoverageTargetPct": float(min_full_capture_pct),
        "RowsKeptByMainPlan": len(keep_rows),
        "ExcludedRowsTested": int(by_row.shape[0]),
        "Eligible3889RescueRows": ",".join(map(str, sorted(eligible_rows))),
        "Eligible3889RescueRowCount": len(eligible_rows),
        "Extra3889OnlyRescuePlays": rescue_extra_plays,
        "RecoveredFull312Winners": rescue_recovered,
        "FinalCapturedFromFull312AfterRescue": final_captured,
        "FinalCapturePctOf312AfterRescue": round(final_captured / V645_FULL_UNIVERSE_TOTAL * 100, 2),
        "Full312CaptureGainPctPoints": round((final_captured - base_captured) / V645_FULL_UNIVERSE_TOTAL * 100, 2),
        "ExtraPlaysPerRecoveredWinner": round(rescue_extra_plays / rescue_recovered, 3) if rescue_recovered else None,
        "RescueRule": f"Excluded rows only; play 3889 only if row has >= {min_misses_per_row} misses and >= {min_3889_miss_share:.0%} of misses are 3889",
    }])

    by_row = by_row.sort_values(["EligibleRescueRow", "RecoveredBy3889Only", "3889MissShareOfRowMisses", "BaseMissesInExcludedRow"], ascending=[False, False, False, False]).reset_index(drop=True)
    return work, by_row, summary

def v646_daily_excluded_3889_rescue_list(daily_df: pd.DataFrame, rescue_by_row: pd.DataFrame, marked_df: pd.DataFrame) -> pd.DataFrame:
    if daily_df is None or daily_df.empty or rescue_by_row is None or rescue_by_row.empty:
        return pd.DataFrame()
    eligible_rows = set(rescue_by_row[rescue_by_row["EligibleRescueRow"].eq(1)]["SingleRow"].astype(int).tolist())
    if not eligible_rows:
        return pd.DataFrame()
    source = marked_df.copy() if marked_df is not None and isinstance(marked_df, pd.DataFrame) and not marked_df.empty else daily_df.copy()
    source["SingleRow"] = pd.to_numeric(source.get("SingleRow", -1), errors="coerce").fillna(-1).astype(int)
    if "v645_StreamElim_RowKept" in source.columns:
        out = source[(source["v645_StreamElim_RowKept"].eq(0)) & (source["SingleRow"].isin(eligible_rows))].copy()
    else:
        out = source[source["SingleRow"].isin(eligible_rows)].copy()
    if out.empty:
        return out
    out["v646_RescuePlay"] = "3889_ONLY"
    out["v646_RescueReason"] = "Excluded row has historical 3889 miss bias"
    out["v646_RecommendedRescueMember"] = "3889"
    return out


# ================================
# v64.7 TOP-N CONSENSUS ANALYSIS
# Tests historical containment against full 312 first.
# Methods available historically: StreamRank, SingleRow, RowPercentile rank-equivalent.
# ================================

V647_DEFAULT_DEPTHS = [5, 10, 15, 20, 25, 30, 40, 50, 60, 70, 80]

def v647_safe_num(df: pd.DataFrame, col: str, default: float = 9999.0) -> pd.Series:
    if df is None or df.empty:
        return pd.Series(dtype=float)
    if col in df.columns:
        return pd.to_numeric(df[col], errors="coerce").fillna(default)
    return pd.Series([default] * len(df), index=df.index, dtype=float)

def v647_rowpct_equivalent_rank(df: pd.DataFrame) -> pd.Series:
    if df is None or df.empty:
        return pd.Series(dtype=float)
    # RowPercentile is percentile position. Convert back to a row-like rank using max observed SingleRow/StreamRank.
    max_rank = int(max(
        1,
        pd.to_numeric(df.get("SingleRow", pd.Series([1])), errors="coerce").max(),
        pd.to_numeric(df.get("StreamRank", pd.Series([1])), errors="coerce").max(),
    ))
    row_pct = v647_safe_num(df, "RowPercentile", 9999.0)
    return ((row_pct / 100.0) * max_rank).apply(lambda x: int(max(1, round(float(x)))))

def v647_base_captured_series(df: pd.DataFrame) -> pd.Series:
    if df is None or df.empty:
        return pd.Series(dtype=int)
    top1 = pd.to_numeric(df.get("Top1_Correct", 0), errors="coerce").fillna(0).astype(int)
    top2 = pd.to_numeric(df.get("Needed_Top2", 0), errors="coerce").fillna(0).astype(int)
    top3 = pd.to_numeric(df.get("Top3Rescue", 0), errors="coerce").fillna(0).astype(int) if "Top3Rescue" in df.columns else 0
    return (top1 | top2 | top3).astype(int)

def v647_consensus_analysis(lab_df: pd.DataFrame, depths: list = None) -> tuple[pd.DataFrame, pd.DataFrame]:
    if lab_df is None or lab_df.empty:
        return pd.DataFrame(), pd.DataFrame()
    depths = depths or V647_DEFAULT_DEPTHS
    work = lab_df.copy()
    work["v647_StreamRankValue"] = v647_safe_num(work, "StreamRank", 9999).astype(int)
    work["v647_SingleRowValue"] = v647_safe_num(work, "SingleRow", 9999).astype(int)
    work["v647_RowPctEquivalentRank"] = v647_rowpct_equivalent_rank(work).astype(int)
    work["v647_BaseCaptured"] = v647_base_captured_series(work)

    total = V645_FULL_UNIVERSE_TOTAL if "V645_FULL_UNIVERSE_TOTAL" in globals() else len(work)
    rows = []
    for depth in depths:
        depth = int(depth)
        stream_flag = work["v647_StreamRankValue"].le(depth).astype(int)
        row_flag = work["v647_SingleRowValue"].le(depth).astype(int)
        pct_flag = work["v647_RowPctEquivalentRank"].le(depth).astype(int)

        consensus_count = stream_flag + row_flag + pct_flag
        for required in [1, 2, 3]:
            selected = consensus_count.ge(required)
            selected_events = int(selected.sum())
            captured = int(work.loc[selected, "v647_BaseCaptured"].sum())
            top1 = int(pd.to_numeric(work.loc[selected].get("Top1_Correct", 0), errors="coerce").fillna(0).sum()) if selected_events else 0
            needed_top2 = int(pd.to_numeric(work.loc[selected].get("Needed_Top2", 0), errors="coerce").fillna(0).sum()) if selected_events else 0
            top3 = int(pd.to_numeric(work.loc[selected].get("Top3Rescue", 0), errors="coerce").fillna(0).sum()) if ("Top3Rescue" in work.columns and selected_events) else 0
            rows.append({
                "Build": BUILD_MARKER,
                "DepthTopN": depth,
                "MethodsRequired": required,
                "MethodsTested": "StreamRank<=N + SingleRow<=N + RowPercentileEquivalentRank<=N",
                "FullUniverseTotal": total,
                "SelectedWinnerEventsFrom312": selected_events,
                "WinnerCoveragePctOf312": round(selected_events / total * 100, 2) if total else 0,
                "CapturedFrom312InsideSelection": captured,
                "CapturePctOf312InsideSelection": round(captured / total * 100, 2) if total else 0,
                "SubsetCapturePct_LabelledSecondary": round(captured / selected_events * 100, 2) if selected_events else None,
                "Top1InsideSelection": top1,
                "NeededTop2InsideSelection": needed_top2,
                "Top3RescueInsideSelection": top3,
            })

        # Store event-level flags for common depths.
        work[f"v647_Depth{depth}_StreamRankTopN"] = stream_flag
        work[f"v647_Depth{depth}_SingleRowTopN"] = row_flag
        work[f"v647_Depth{depth}_RowPctEqTopN"] = pct_flag
        work[f"v647_Depth{depth}_ConsensusCount"] = consensus_count

    summary = pd.DataFrame(rows)
    return work, summary

def v647_mark_daily_consensus(daily_df: pd.DataFrame, depth: int = 10) -> pd.DataFrame:
    if daily_df is None or daily_df.empty:
        return pd.DataFrame()
    out = daily_df.copy()
    out["v647_StreamRankValue"] = v647_safe_num(out, "StreamRank", 9999).astype(int)
    out["v647_SingleRowValue"] = v647_safe_num(out, "SingleRow", 9999).astype(int)
    out["v647_RowPctEquivalentRank"] = v647_rowpct_equivalent_rank(out).astype(int)
    depth = int(depth)
    out["v647_StreamRankTopN"] = out["v647_StreamRankValue"].le(depth).astype(int)
    out["v647_SingleRowTopN"] = out["v647_SingleRowValue"].le(depth).astype(int)
    out["v647_RowPctEqTopN"] = out["v647_RowPctEquivalentRank"].le(depth).astype(int)
    out["v647_ConsensusCount"] = out[["v647_StreamRankTopN", "v647_SingleRowTopN", "v647_RowPctEqTopN"]].sum(axis=1)
    out["v647_ConsensusLabel"] = out["v647_ConsensusCount"].map({
        3: "3_OF_3_TOPN_CONSENSUS",
        2: "2_OF_3_TOPN_CONSENSUS",
        1: "1_OF_3_TOPN_ONLY",
        0: "NO_TOPN_CONSENSUS",
    })
    return out.sort_values(["v647_ConsensusCount", "PlaylistRank" if "PlaylistRank" in out.columns else "v647_StreamRankValue"], ascending=[False, True]).reset_index(drop=True)


# ================================
# v64.8 FULL-312 STRAIGHT DEPTH + RESCUE DIAGNOSTICS
# Timeout fix: cache straight training events once and reuse for all 312 rows.
# ================================

def v648_score_event_straights_cached(
    ev: pd.Series,
    training_events: pd.DataFrame,
    top2_ratio_min: float = 0.65,
    top2_margin_max: float = 30.0,
    top2_volatility_min: float = 0.35,
    top3_margin_max: float = 12.0,
    top3_volatility_min: float = 0.50,
) -> pd.DataFrame:
    one = v642_event_playlist_from_lab_row(ev) if "v642_event_playlist_from_lab_row" in globals() else pd.DataFrame([ev.to_dict()])
    if training_events is None or training_events.empty or one is None or one.empty:
        return pd.DataFrame()
    cand_rows = []
    for _, row in one.iterrows():
        eligible = straight_eligible_members(
            row,
            top2_ratio_min=top2_ratio_min,
            top2_margin_max=top2_margin_max,
            top2_volatility_min=top2_volatility_min,
            top3_margin_max=top3_margin_max,
            top3_volatility_min=top3_volatility_min,
        )
        for em in eligible:
            member = str(em.get("StraightMember", "")).zfill(4)
            for perm in unique_straight_permutations(member):
                score = score_straight_permutation(row, member, perm, training_events)
                cand_rows.append({
                    "StraightMember": member,
                    "StraightMemberSource": em.get("StraightMemberSource", ""),
                    "StraightEligibilityReason": em.get("StraightEligibilityReason", ""),
                    **score,
                })
    ranked = pd.DataFrame(cand_rows)
    if ranked.empty:
        return ranked
    ranked = ranked.sort_values(
        ["StraightConfidenceScore", "EvidenceSupport", "StraightPermutation"],
        ascending=[False, False, True],
    ).reset_index(drop=True)
    ranked["StreamStraightRank"] = ranked.index + 1
    return ranked

def v648_full312_straight_depth_backtest(
    lab_df: pd.DataFrame,
    hist: pd.DataFrame,
    top2_ratio_min: float = 0.65,
    top2_margin_max: float = 30.0,
    top2_volatility_min: float = 0.35,
    top3_margin_max: float = 12.0,
    top3_volatility_min: float = 0.50,
    max_depth: int = 36,
    max_events: int = 0,
) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    if lab_df is None or lab_df.empty:
        return pd.DataFrame(), pd.DataFrame([{"Build": BUILD_MARKER, "Reason": "No lab rows available"}]), pd.DataFrame()
    if hist is None or hist.empty:
        return pd.DataFrame(), pd.DataFrame([{"Build": BUILD_MARKER, "Reason": "No history loaded"}]), pd.DataFrame()

    events = lab_df.copy()
    if max_events and int(max_events) > 0:
        events = events.head(int(max_events)).copy()

    training_events = st.session_state.get("v648_cached_straight_training_events")
    if training_events is None or not isinstance(training_events, pd.DataFrame) or training_events.empty:
        training_events = build_straight_training_events(hist)
        st.session_state["v648_cached_straight_training_events"] = training_events

    rows = []
    max_depth = int(max(1, min(int(max_depth), 36)))

    progress = st.progress(0, text="Starting cached full-312 straight backtest...")
    total_events = len(events)

    for pos, (idx, ev) in enumerate(events.iterrows(), start=1):
        if pos == 1 or pos % 10 == 0 or pos == total_events:
            progress.progress(min(pos / max(total_events, 1), 1.0), text=f"Scoring straight event {pos}/{total_events} with cached training table...")

        true_result = extract_pick4_digits(ev.get("Result", ""))
        true_member = normalize_member(ev.get("TrueMember", result_to_core389_member(true_result)))
        ranked = v648_score_event_straights_cached(
            ev,
            training_events,
            top2_ratio_min=top2_ratio_min,
            top2_margin_max=top2_margin_max,
            top2_volatility_min=top2_volatility_min,
            top3_margin_max=top3_margin_max,
            top3_volatility_min=top3_volatility_min,
        )

        if ranked is None or ranked.empty:
            rows.append({
                "EventIndex": idx,
                "Date": ev.get("Date", ""),
                "StreamKey": ev.get("StreamKey", ""),
                "seed": ev.get("seed", ev.get("LastResult", "")),
                "Result": true_result,
                "TrueMember": true_member,
                "PredictedMember": ev.get("PredictedMember", ""),
                "Top2_pred": ev.get("Top2_pred", ""),
                "ThirdMember": ev.get("ThirdMember", ""),
                "PlayType": ev.get("PlayType", ""),
                "BoxCaptured": int(pd.to_numeric(pd.Series([ev.get("Top1_Correct", 0)]), errors="coerce").fillna(0).iloc[0]) | int(pd.to_numeric(pd.Series([ev.get("Needed_Top2", 0)]), errors="coerce").fillna(0).iloc[0]) | int(pd.to_numeric(pd.Series([ev.get("Top3Rescue", 0)]), errors="coerce").fillna(0).iloc[0] if "Top3Rescue" in ev.index else 0),
                "StraightHitRank": None,
                "StraightHit": 0,
                "Reason": "NO_STRAIGHT_CANDIDATES",
            })
            continue

        ranked["StraightPermutation"] = ranked["StraightPermutation"].astype(str).str.zfill(4)
        hit_rows = ranked[ranked["StraightPermutation"].eq(str(true_result).zfill(4))].copy()
        if hit_rows.empty:
            hit_rank = None
            hit_score = None
            hit_member = None
            hit_source = None
            reason = "TRUE_STRAIGHT_NOT_IN_ELIGIBLE_SET"
            hit = 0
        else:
            hr = hit_rows.sort_values("StreamStraightRank").iloc[0]
            hit_rank = int(hr["StreamStraightRank"])
            hit_score = hr.get("StraightConfidenceScore", None)
            hit_member = hr.get("StraightMember", "")
            hit_source = hr.get("StraightMemberSource", "")
            reason = "HIT_IN_RANKED_LIST"
            hit = 1

        box_captured = int(pd.to_numeric(pd.Series([ev.get("Top1_Correct", 0)]), errors="coerce").fillna(0).iloc[0]) | int(pd.to_numeric(pd.Series([ev.get("Needed_Top2", 0)]), errors="coerce").fillna(0).iloc[0]) | int(pd.to_numeric(pd.Series([ev.get("Top3Rescue", 0)]), errors="coerce").fillna(0).iloc[0] if "Top3Rescue" in ev.index else 0)

        rows.append({
            "EventIndex": idx,
            "Date": ev.get("Date", ""),
            "StreamKey": ev.get("StreamKey", ""),
            "seed": ev.get("seed", ev.get("LastResult", "")),
            "Result": true_result,
            "TrueMember": true_member,
            "PredictedMember": ev.get("PredictedMember", ""),
            "Top2_pred": ev.get("Top2_pred", ""),
            "ThirdMember": ev.get("ThirdMember", ""),
            "PlayType": ev.get("PlayType", ""),
            "RecommendedPlay": ev.get("RecommendedPlay", ""),
            "StreamRank": ev.get("StreamRank", ""),
            "RowPercentile": ev.get("RowPercentile", ""),
            "SingleRow": ev.get("SingleRow", ""),
            "BoxCaptured": box_captured,
            "StraightHit": hit,
            "StraightHitRank": hit_rank,
            "StraightHitMember": hit_member,
            "StraightHitMemberSource": hit_source,
            "StraightHitScore": hit_score,
            "Reason": reason,
        })

    progress.progress(1.0, text="Cached full-312 straight backtest complete.")

    per_event = pd.DataFrame(rows)
    total = len(per_event)
    full_total = V645_FULL_UNIVERSE_TOTAL if "V645_FULL_UNIVERSE_TOTAL" in globals() else total
    ranked_hits = int(per_event["StraightHit"].sum()) if total else 0

    depth_rows = []
    for d in range(1, max_depth + 1):
        hits = int(per_event["StraightHitRank"].apply(lambda x: pd.notna(x) and int(x) <= d).sum()) if total else 0
        depth_rows.append({
            "Build": BUILD_MARKER,
            "StraightDepth": d,
            "StraightHitsFromFull312": hits,
            "StraightHitPctOf312": round(hits / full_total * 100, 2) if full_total else 0,
            "EventsTested": total,
            "EstimatedStraightPlays": total * d,
            "PlaysPerStraightHit": round((total * d) / hits, 3) if hits else None,
        })
    depth_df = pd.DataFrame(depth_rows)

    summary = pd.DataFrame([{
        "Build": BUILD_MARKER,
        "Mode": "Timeout-safe cached full-312 straight depth backtest",
        "FullUniverseTotal": full_total,
        "EventsTested": total,
        "RankedStraightHitsAnywhere": ranked_hits,
        "RankedStraightHitPctOf312": round(ranked_hits / full_total * 100, 2) if full_total else 0,
        "MaxDepthTested": max_depth,
        "CachedTrainingEvents": 0 if training_events is None else len(training_events),
        "Note": "Depth curve below shows how many straight plays per event are needed to reach x/312.",
    }])

    return per_event, summary, depth_df

def v648_excluded_rescue_empty_reason(daily_df: pd.DataFrame, marked_df: pd.DataFrame, by_row: pd.DataFrame) -> pd.DataFrame:
    if by_row is None or not isinstance(by_row, pd.DataFrame) or by_row.empty:
        return pd.DataFrame([{
            "ReasonCode": "NO_HISTORICAL_RESCUE_ROWS",
            "Explanation": "No historical excluded rows met the current 3889 miss-bias settings.",
            "EligibleHistoricalRows": "",
            "EligibleRowsPresentToday": 0,
            "EligibleExcludedRowsPresentToday": 0,
        }])

    eligible_rows = set(by_row[by_row.get("EligibleRescueRow", 0).eq(1)]["SingleRow"].astype(int).tolist()) if "EligibleRescueRow" in by_row.columns else set()
    if not eligible_rows:
        return pd.DataFrame([{
            "ReasonCode": "SETTINGS_TOO_STRICT",
            "Explanation": "Historical rows exist, but none met the current Min Misses / Min 3889 Share settings.",
            "EligibleHistoricalRows": "",
            "EligibleRowsPresentToday": 0,
            "EligibleExcludedRowsPresentToday": 0,
        }])

    source = marked_df.copy() if marked_df is not None and isinstance(marked_df, pd.DataFrame) and not marked_df.empty else (daily_df.copy() if daily_df is not None and isinstance(daily_df, pd.DataFrame) else pd.DataFrame())
    if source.empty or "SingleRow" not in source.columns:
        return pd.DataFrame([{
            "ReasonCode": "NO_DAILY_PLAYLIST_OR_NO_SINGLEROW",
            "Explanation": "Daily playlist is missing or does not include SingleRow, so daily excluded rescue cannot be evaluated.",
            "EligibleHistoricalRows": ",".join(map(str, sorted(eligible_rows))),
            "EligibleRowsPresentToday": 0,
            "EligibleExcludedRowsPresentToday": 0,
        }])

    source["SingleRow"] = pd.to_numeric(source["SingleRow"], errors="coerce").fillna(-1).astype(int)
    present_today = source[source["SingleRow"].isin(eligible_rows)].copy()
    if present_today.empty:
        return pd.DataFrame([{
            "ReasonCode": "ELIGIBLE_ROWS_NOT_PRESENT_TODAY",
            "Explanation": "3889 rescue rows exist historically, but none appear in today's daily playlist.",
            "EligibleHistoricalRows": ",".join(map(str, sorted(eligible_rows))),
            "EligibleRowsPresentToday": 0,
            "EligibleExcludedRowsPresentToday": 0,
        }])

    if "v645_StreamElim_RowKept" in source.columns:
        excluded_today = present_today[present_today["v645_StreamElim_RowKept"].eq(0)].copy()
        if excluded_today.empty:
            return pd.DataFrame([{
                "ReasonCode": "ELIGIBLE_ROWS_PRESENT_BUT_NOT_EXCLUDED",
                "Explanation": "Eligible 3889 rescue rows are present today, but they are already kept by the main stream plan, so no excluded-row rescue is needed.",
                "EligibleHistoricalRows": ",".join(map(str, sorted(eligible_rows))),
                "EligibleRowsPresentToday": len(present_today),
                "EligibleExcludedRowsPresentToday": 0,
            }])
        return pd.DataFrame([{
            "ReasonCode": "ELIGIBLE_EXCLUDED_ROWS_PRESENT",
            "Explanation": "Eligible excluded rows are present today; the rescue list should populate.",
            "EligibleHistoricalRows": ",".join(map(str, sorted(eligible_rows))),
            "EligibleRowsPresentToday": len(present_today),
            "EligibleExcludedRowsPresentToday": len(excluded_today),
        }])

    return pd.DataFrame([{
        "ReasonCode": "STREAM_ELIMINATION_MARKS_MISSING",
        "Explanation": "Eligible rows are present, but v645_StreamElim_RowKept is missing. Run/refresh the v64.5 stream-elimination section first.",
        "EligibleHistoricalRows": ",".join(map(str, sorted(eligible_rows))),
        "EligibleRowsPresentToday": len(present_today),
        "EligibleExcludedRowsPresentToday": None,
    }])


# ================================
# v64.9 DAILY SINGLE-ROW PLAYLIST + CHUNKED FULL312 STRAIGHT
# ================================

def v649_daily_by_single_row_capture(daily_df: pd.DataFrame, single_row_perf: pd.DataFrame = None, lab_df: pd.DataFrame = None) -> pd.DataFrame:
    if daily_df is None or daily_df.empty or "SingleRow" not in daily_df.columns:
        return pd.DataFrame()

    d = daily_df.copy()
    d["SingleRow"] = pd.to_numeric(d["SingleRow"], errors="coerce").fillna(-1).astype(int)

    if single_row_perf is None or not isinstance(single_row_perf, pd.DataFrame) or single_row_perf.empty:
        if lab_df is not None and isinstance(lab_df, pd.DataFrame) and not lab_df.empty:
            single_row_perf = v645_row_coverage_table(lab_df) if "v645_row_coverage_table" in globals() else pd.DataFrame()
        else:
            single_row_perf = st.session_state.get("v645_row_coverage_table", pd.DataFrame())

    if single_row_perf is None or not isinstance(single_row_perf, pd.DataFrame) or single_row_perf.empty:
        out = d.copy()
        out["v649_SingleRowRankReason"] = "No single-row performance table available; run Lab first."
        return out

    sr = single_row_perf.copy()
    if "SingleRow" not in sr.columns:
        return d
    sr["SingleRow"] = pd.to_numeric(sr["SingleRow"], errors="coerce").fillna(-1).astype(int)

    # Normalize column names from either single_row_performance.csv or v645 row table.
    rename_map = {}
    if "rows" in sr.columns and "RowHistoricalEvents" not in sr.columns:
        rename_map["rows"] = "RowHistoricalEvents"
    if "captured" in sr.columns and "RowCaptured" not in sr.columns:
        rename_map["captured"] = "RowCaptured"
    if "miss" in sr.columns and "RowMisses" not in sr.columns:
        rename_map["miss"] = "RowMisses"
    if "capture_pct" in sr.columns and "RowSubsetCapturePct" not in sr.columns:
        rename_map["capture_pct"] = "RowSubsetCapturePct"
    if "plays_per_capture" in sr.columns and "RowPlaysPerCapture" not in sr.columns:
        rename_map["plays_per_capture"] = "RowPlaysPerCapture"
    if "WinnersFromFull312" in sr.columns and "RowHistoricalEvents" not in sr.columns:
        rename_map["WinnersFromFull312"] = "RowHistoricalEvents"
    if "CapturedFromFull312" in sr.columns and "RowCaptured" not in sr.columns:
        rename_map["CapturedFromFull312"] = "RowCaptured"
    if "Misses" in sr.columns and "RowMisses" not in sr.columns:
        rename_map["Misses"] = "RowMisses"
    sr = sr.rename(columns=rename_map)

    keep_cols = ["SingleRow"] + [c for c in [
        "RowHistoricalEvents", "RowCaptured", "RowMisses", "RowSubsetCapturePct",
        "RowPlaysPerCapture", "CumulativeWinnersFrom312", "CumulativeWinnerPctOf312",
        "CumulativeCapturedFrom312", "CumulativeCapturePctOf312",
        "Top1Wins", "NeededTop2", "Top3RescueWins"
    ] if c in sr.columns]

    merged = d.merge(sr[keep_cols], on="SingleRow", how="left")
    for c in ["RowHistoricalEvents", "RowCaptured", "RowMisses", "RowSubsetCapturePct"]:
        if c not in merged.columns:
            merged[c] = 0
        merged[c] = pd.to_numeric(merged[c], errors="coerce").fillna(0)

    merged = merged.sort_values(
        ["RowCaptured", "RowSubsetCapturePct", "RowHistoricalEvents", "PlaylistRank" if "PlaylistRank" in merged.columns else "StreamRank"],
        ascending=[False, False, False, True],
    ).reset_index(drop=True)
    merged.insert(0, "v649_SingleRowDailyRank", merged.index + 1)
    merged["v649_SingleRowPlayReason"] = (
        "SingleRow " + merged["SingleRow"].astype(str)
        + " | row captured " + merged["RowCaptured"].astype(int).astype(str)
        + "/" + merged["RowHistoricalEvents"].astype(int).astype(str)
        + " (" + merged["RowSubsetCapturePct"].round(2).astype(str) + "% subset)"
    )
    return merged

def v649_straight_depth_from_per_event(per_event: pd.DataFrame, max_depth: int = 36) -> tuple[pd.DataFrame, pd.DataFrame]:
    if per_event is None or not isinstance(per_event, pd.DataFrame) or per_event.empty:
        return pd.DataFrame(), pd.DataFrame()
    total_processed = len(per_event)
    full_total = V645_FULL_UNIVERSE_TOTAL if "V645_FULL_UNIVERSE_TOTAL" in globals() else total_processed
    rows = []
    max_depth = int(max(1, min(int(max_depth), 36)))
    for d in range(1, max_depth + 1):
        hits = int(per_event["StraightHitRank"].apply(lambda x: pd.notna(x) and int(x) <= d).sum()) if "StraightHitRank" in per_event.columns else 0
        rows.append({
            "Build": BUILD_MARKER,
            "StraightDepth": d,
            "StraightHitsFromFull312": hits,
            "StraightHitPctOf312": round(hits / full_total * 100, 2) if full_total else 0,
            "EventsProcessed": total_processed,
            "FullUniverseTotal": full_total,
            "EstimatedStraightPlaysOnProcessedEvents": total_processed * d,
            "ProjectedStraightPlaysIfAll312": full_total * d,
            "PlaysPerStraightHit_Processed": round((total_processed * d) / hits, 3) if hits else None,
        })
    depth = pd.DataFrame(rows)
    summary = pd.DataFrame([{
        "Build": BUILD_MARKER,
        "Mode": "Chunked/resumable full-312 straight backtest",
        "FullUniverseTotal": full_total,
        "EventsProcessed": total_processed,
        "RemainingEvents": max(full_total - total_processed, 0),
        "RankedStraightHitsAnywhereProcessed": int(per_event.get("StraightHit", pd.Series(dtype=int)).sum()) if "StraightHit" in per_event.columns else 0,
        "MaxDepthTested": max_depth,
        "Important": "Use Process Next Batch until EventsProcessed reaches 312. This avoids Streamlit timeout.",
    }])
    return summary, depth

def v649_process_next_straight_batch(
    lab_df: pd.DataFrame,
    hist: pd.DataFrame,
    batch_size: int = 10,
    max_depth: int = 36,
) -> tuple[pd.DataFrame, pd.DataFrame, pd.DataFrame]:
    if lab_df is None or lab_df.empty:
        return pd.DataFrame(), pd.DataFrame(), pd.DataFrame()
    if hist is None or hist.empty:
        return pd.DataFrame(), pd.DataFrame(), pd.DataFrame()

    start = int(st.session_state.get("v649_chunked_straight_next_pos", 0) or 0)
    batch_size = int(max(1, min(int(batch_size), 50)))
    end = min(start + batch_size, len(lab_df))
    batch = lab_df.iloc[start:end].copy()

    if batch.empty:
        per_event = st.session_state.get("v649_chunked_straight_events", pd.DataFrame())
        summary, depth = v649_straight_depth_from_per_event(per_event, max_depth=max_depth)
        return per_event, summary, depth

    # Uses v64.8 scorer, but on a small batch to avoid timeout.
    per_batch, _, _ = v648_full312_straight_depth_backtest(
        batch,
        hist,
        max_depth=max_depth,
        max_events=0,
    )

    existing = st.session_state.get("v649_chunked_straight_events", pd.DataFrame())
    if existing is not None and isinstance(existing, pd.DataFrame) and not existing.empty:
        combined = pd.concat([existing, per_batch], ignore_index=True)
    else:
        combined = per_batch.copy()

    st.session_state["v649_chunked_straight_events"] = combined
    st.session_state["v649_chunked_straight_next_pos"] = end

    summary, depth = v649_straight_depth_from_per_event(combined, max_depth=max_depth)
    st.session_state["v649_chunked_straight_summary"] = summary
    st.session_state["v649_chunked_straight_depth_curve"] = depth
    return combined, summary, depth


# ================================
# v65 OPTIMAL TIER MODEL
# Full-312 first. Consensus is a ranking signal, not a hard filter.
# ================================

V65_TIER1_SIZES = [5, 10, 15, 20, 25]
V65_TIER2_SIZES = [10, 15, 20, 25, 30, 35, 40]
V65_TOTAL_SIZES = [40, 45, 50, 55, 60, 65, 70, 75, 80]

def v65_num(df: pd.DataFrame, col: str, default: float = 0.0) -> pd.Series:
    if df is None or df.empty:
        return pd.Series(dtype=float)
    if col in df.columns:
        return pd.to_numeric(df[col], errors="coerce").fillna(default)
    return pd.Series([default] * len(df), index=df.index, dtype=float)

def v65_get_row_perf(lab_df: pd.DataFrame = None) -> pd.DataFrame:
    rp = st.session_state.get("v645_row_coverage_table", pd.DataFrame())
    if rp is not None and isinstance(rp, pd.DataFrame) and not rp.empty:
        return rp
    if lab_df is not None and isinstance(lab_df, pd.DataFrame) and not lab_df.empty and "v645_row_coverage_table" in globals():
        return v645_row_coverage_table(lab_df)
    return pd.DataFrame()

def v65_scored(df: pd.DataFrame, lab_df: pd.DataFrame = None) -> pd.DataFrame:
    if df is None or df.empty:
        return pd.DataFrame()
    out = df.copy()
    out["SingleRow"] = pd.to_numeric(out.get("SingleRow", -1), errors="coerce").fillna(-1).astype(int)
    out["StreamRank"] = pd.to_numeric(out.get("StreamRank", out.get("rank", 9999)), errors="coerce").fillna(9999.0)
    out["RowPercentile"] = pd.to_numeric(out.get("RowPercentile", 100), errors="coerce").fillna(100.0)

    rp = v65_get_row_perf(lab_df)
    if rp is not None and isinstance(rp, pd.DataFrame) and not rp.empty and "SingleRow" in rp.columns:
        sr = rp.copy()
        sr["SingleRow"] = pd.to_numeric(sr["SingleRow"], errors="coerce").fillna(-1).astype(int)
        # Support both v645 table and single_row_performance exports.
        if "CapturedFromFull312" in sr.columns:
            sr["v65_RowCaptured"] = pd.to_numeric(sr["CapturedFromFull312"], errors="coerce").fillna(0)
        elif "captured" in sr.columns:
            sr["v65_RowCaptured"] = pd.to_numeric(sr["captured"], errors="coerce").fillna(0)
        else:
            sr["v65_RowCaptured"] = 0

        if "WinnersFromFull312" in sr.columns:
            sr["v65_RowEvents"] = pd.to_numeric(sr["WinnersFromFull312"], errors="coerce").fillna(0)
        elif "rows" in sr.columns:
            sr["v65_RowEvents"] = pd.to_numeric(sr["rows"], errors="coerce").fillna(0)
        else:
            sr["v65_RowEvents"] = 0

        if "RowSubsetCapturePct" in sr.columns:
            sr["v65_RowSubsetCapturePct"] = pd.to_numeric(sr["RowSubsetCapturePct"], errors="coerce").fillna(0)
        elif "capture_pct" in sr.columns:
            sr["v65_RowSubsetCapturePct"] = pd.to_numeric(sr["capture_pct"], errors="coerce").fillna(0)
        else:
            sr["v65_RowSubsetCapturePct"] = 0

        out = out.merge(sr[["SingleRow", "v65_RowCaptured", "v65_RowEvents", "v65_RowSubsetCapturePct"]].drop_duplicates("SingleRow"), on="SingleRow", how="left")

    for col in ["v65_RowCaptured", "v65_RowEvents", "v65_RowSubsetCapturePct"]:
        if col not in out.columns:
            out[col] = 0
        out[col] = pd.to_numeric(out[col], errors="coerce").fillna(0)

    out["v65_ConsensusCount"] = (
        out["StreamRank"].le(25).astype(int)
        + out["SingleRow"].le(25).astype(int)
        + out["RowPercentile"].le(25).astype(int)
    )
    max_row_cap = max(float(out["v65_RowCaptured"].max()), 1.0)
    max_stream = max(float(out["StreamRank"].max()), 1.0)
    out["v65_OptimalTierScore"] = (
        (out["v65_ConsensusCount"] / 3.0) * 45.0
        + (out["v65_RowCaptured"] / max_row_cap) * 30.0
        + (1.0 - ((out["StreamRank"] - 1.0) / max(max_stream - 1.0, 1.0))) * 15.0
        + (1.0 - out["RowPercentile"] / 100.0) * 10.0
    ).round(4)
    return out.sort_values(["v65_OptimalTierScore", "v65_ConsensusCount", "v65_RowCaptured", "StreamRank"], ascending=[False, False, False, True]).reset_index(drop=True)

def v65_policy_capture(row: pd.Series, policy: str):
    pred = str(row.get("PredictedMember", row.get("Top1_Display", ""))).replace("*", "").strip().zfill(4)
    top2 = str(row.get("Top2_pred", row.get("Top2_Display", ""))).replace("*", "").strip().zfill(4)
    third = str(row.get("ThirdMember", row.get("Top3_Display", ""))).replace("*", "").strip().zfill(4)
    true = str(row.get("TrueMember", "")).zfill(4)
    if policy == "SKIP":
        return 0, 0, "SKIP"
    if policy == "TOP1":
        return int(true == pred), 1, pred
    if policy == "TOP1_TOP2":
        plays = list(dict.fromkeys([p for p in [pred, top2] if p and p != "0000"]))
        return int(true in plays), len(plays), " + ".join(plays)
    if policy == "TOP1_TOP2_TOP3":
        plays = list(dict.fromkeys([p for p in [pred, top2, third] if p and p != "0000"]))
        return int(true in plays), len(plays), " + ".join(plays)
    return 0, 0, "SKIP"

def v65_test_plan(scored: pd.DataFrame, tier1: int, tier2: int, total: int, tier3_policy: str):
    if scored is None or scored.empty:
        return pd.DataFrame(), {}
    df = scored.copy().reset_index(drop=True)
    df["v65_OptimalRank"] = df.index + 1
    tier1, tier2, total = int(tier1), int(tier2), int(total)

    policies, tiers = [], []
    for rank in df["v65_OptimalRank"]:
        if rank <= tier1:
            policies.append("TOP1"); tiers.append("TIER1_TOP1_ONLY")
        elif rank <= tier1 + tier2:
            policies.append("TOP1_TOP2"); tiers.append("TIER2_TOP1_TOP2")
        elif rank <= total:
            policies.append(tier3_policy); tiers.append(f"TIER3_{tier3_policy}")
        else:
            policies.append("SKIP"); tiers.append("SKIP")
    df["v65_Tier"] = tiers
    df["v65_Policy"] = policies

    caps, plays, labels = [], [], []
    for _, row in df.iterrows():
        c, p, lab = v65_policy_capture(row, row["v65_Policy"])
        caps.append(c); plays.append(p); labels.append(lab)
    df["v65_Captured"] = caps
    df["v65_PlayCount"] = plays
    df["v65_PlayedMembers"] = labels

    full_total = V645_FULL_UNIVERSE_TOTAL if "V645_FULL_UNIVERSE_TOTAL" in globals() else len(df)
    captured = int(df["v65_Captured"].sum())
    total_plays = int(df["v65_PlayCount"].sum())
    summary = {
        "Build": BUILD_MARKER,
        "FullUniverseTotal": full_total,
        "Tier1Top1OnlySize": tier1,
        "Tier2Top1Top2Size": tier2,
        "TotalStreamsPlayed": int((df["v65_Policy"] != "SKIP").sum()),
        "Tier3Policy": tier3_policy,
        "CapturedFrom312": captured,
        "CapturePctOf312": round(captured / full_total * 100, 2) if full_total else 0,
        "TotalPlays": total_plays,
        "PlaysPerCapturedWin": round(total_plays / captured, 3) if captured else None,
        "Tier1Wins": int(((df["v65_Tier"] == "TIER1_TOP1_ONLY") & (df["v65_Captured"] == 1)).sum()),
        "Tier2Wins": int(((df["v65_Tier"] == "TIER2_TOP1_TOP2") & (df["v65_Captured"] == 1)).sum()),
        "Tier3Wins": int((df["v65_Tier"].astype(str).str.startswith("TIER3") & (df["v65_Captured"] == 1)).sum()),
    }
    return df, summary

def v65_grid_search(lab_df: pd.DataFrame, min_capture_pct: float = 75.0):
    if lab_df is None or lab_df.empty:
        return pd.DataFrame(), pd.DataFrame(), pd.DataFrame()
    scored = v65_scored(lab_df, lab_df)
    rows = []
    plan_cache = {}
    for total in V65_TOTAL_SIZES:
        for tier1 in V65_TIER1_SIZES:
            for tier2 in V65_TIER2_SIZES:
                if tier1 + tier2 > total:
                    continue
                for tier3 in ["TOP1", "TOP1_TOP2", "SKIP"]:
                    per, summ = v65_test_plan(scored, tier1, tier2, total, tier3)
                    rows.append(summ)
                    plan_cache[(tier1, tier2, total, tier3)] = per
    grid = pd.DataFrame(rows)
    grid = grid.sort_values(["CapturePctOf312", "PlaysPerCapturedWin", "TotalPlays"], ascending=[False, True, True]).reset_index(drop=True)

    viable = grid[grid["CapturePctOf312"].ge(float(min_capture_pct))].copy()
    if not viable.empty:
        viable = viable.sort_values(["PlaysPerCapturedWin", "TotalPlays", "CapturedFrom312"], ascending=[True, True, False]).reset_index(drop=True)
        best = viable.iloc[0]
    else:
        best = grid.iloc[0]
    key = (int(best["Tier1Top1OnlySize"]), int(best["Tier2Top1Top2Size"]), int(best["TotalStreamsPlayed"]), str(best["Tier3Policy"]))
    best_per = plan_cache.get(key, pd.DataFrame())
    return pd.DataFrame([best.to_dict()]), grid, best_per

def v65_daily_playlist(daily_df: pd.DataFrame, summary_df: pd.DataFrame, lab_df: pd.DataFrame = None):
    if daily_df is None or daily_df.empty:
        return pd.DataFrame()
    scored = v65_scored(daily_df, lab_df).reset_index(drop=True)
    scored["v65_OptimalRank"] = scored.index + 1
    if summary_df is None or not isinstance(summary_df, pd.DataFrame) or summary_df.empty:
        tier1, tier2, total, tier3 = 10, 25, 60, "TOP1"
    else:
        row = summary_df.iloc[0]
        tier1 = int(row.get("Tier1Top1OnlySize", 10))
        tier2 = int(row.get("Tier2Top1Top2Size", 25))
        total = int(row.get("TotalStreamsPlayed", 60))
        tier3 = str(row.get("Tier3Policy", "TOP1"))

    tiers, policies, labels, counts = [], [], [], []
    for _, r in scored.iterrows():
        rank = int(r["v65_OptimalRank"])
        if rank <= tier1:
            pol, tier = "TOP1", "TIER1_TOP1_ONLY"
        elif rank <= tier1 + tier2:
            pol, tier = "TOP1_TOP2", "TIER2_TOP1_TOP2"
        elif rank <= total:
            pol, tier = tier3, f"TIER3_{tier3}"
        else:
            pol, tier = "SKIP", "SKIP"
        _, pc, lab = v65_policy_capture(r, pol)
        tiers.append(tier); policies.append(pol); labels.append(lab); counts.append(pc)
    scored["v65_Tier"] = tiers
    scored["v65_Policy"] = policies
    scored["v65_PlayedMembers"] = labels
    scored["v65_PlayCount"] = counts
    scored["v65_PlayDecision"] = scored["v65_Tier"] + " | " + scored["v65_PlayedMembers"].astype(str)
    return scored


# ================================
# v79 FINAL DAILY PLAY PRIORITY + ROWPCT STRAIGHT RECOMMENDATIONS
# ================================

V79_ROWPCT_STRAIGHT_LOOKUP = {
    "0-10": {1: [1], 2: [1, 9], 3: [1, 9, 13], 4: [1, 9, 13, 2], 5: [1, 9, 13, 2, 4]},
    "10-20": {1: [1], 2: [1, 13], 3: [1, 13, 10], 4: [1, 13, 10, 3], 5: [1, 13, 10, 3, 7]},
    "20-30": {1: [1], 2: [1, 3], 3: [1, 3, 2], 4: [1, 3, 2, 12], 5: [1, 3, 2, 12, 13]},
    "30-40": {1: [1], 2: [1, 13], 3: [1, 13, 14], 4: [1, 13, 14, 12], 5: [1, 13, 14, 12, 3]},
    "40-50": {1: [1], 2: [1, 2], 3: [1, 2, 13], 4: [1, 2, 13, 8], 5: [1, 2, 13, 8, 12]},
    "50-60": {1: [1], 2: [1, 13], 3: [1, 13, 7], 4: [1, 13, 7, 11], 5: [1, 13, 7, 11, 25]},
    "60-70": {1: [1], 2: [1, 13], 3: [1, 13, 2], 4: [1, 13, 2, 7], 5: [1, 13, 2, 7, 15]},
    "70-80": {1: [1], 2: [1, 13], 3: [1, 13, 15], 4: [1, 13, 15, 2], 5: [1, 13, 15, 2, 3]},
    "80-90": {1: [1], 2: [1, 2], 3: [1, 2, 25], 4: [1, 2, 25, 13], 5: [1, 2, 25, 13, 24]},
    "90-100": {1: [1], 2: [1, 13], 3: [1, 13, 3], 4: [1, 13, 3, 5], 5: [1, 13, 3, 5, 6]},
}

def v79_rowpct_band(value) -> str:
    try:
        v = float(value)
    except Exception:
        return "90-100"
    if v <= 10: return "0-10"
    if v <= 20: return "10-20"
    if v <= 30: return "20-30"
    if v <= 40: return "30-40"
    if v <= 50: return "40-50"
    if v <= 60: return "50-60"
    if v <= 70: return "60-70"
    if v <= 80: return "70-80"
    if v <= 90: return "80-90"
    return "90-100"

def v79_lookup_table() -> pd.DataFrame:
    rows = []
    for band, depth_map in V79_ROWPCT_STRAIGHT_LOOKUP.items():
        for depth, ranks in depth_map.items():
            rows.append({"RowPercentileBand": band, "StraightDepthMode": depth, "RecommendedStraightRanks": ",".join(map(str, ranks))})
    return pd.DataFrame(rows)

def v79_prepare_final_daily_play_list(daily_df: pd.DataFrame, row_perf: Optional[pd.DataFrame] = None, lab_df: Optional[pd.DataFrame] = None) -> pd.DataFrame:
    """Final daily list for actual play order: all streams remain visible, but sorted by historically best SingleRow first."""
    if daily_df is None or not isinstance(daily_df, pd.DataFrame) or daily_df.empty:
        return pd.DataFrame()
    out = daily_df.copy()
    out["SingleRow"] = pd.to_numeric(out.get("SingleRow", -1), errors="coerce").fillna(-1).astype(int)

    sr = row_perf if isinstance(row_perf, pd.DataFrame) and not row_perf.empty else None
    if sr is None and lab_df is not None and isinstance(lab_df, pd.DataFrame) and not lab_df.empty:
        try:
            sr = v645_row_coverage_table(lab_df)
        except Exception:
            sr = None
    if sr is None or not isinstance(sr, pd.DataFrame) or sr.empty or "SingleRow" not in sr.columns:
        out["v79_FinalPlayRank"] = range(1, len(out) + 1)
        out["v79_FinalPlayTier"] = "NO_ROW_HISTORY_YET"
        out["v79_FinalPlayReason"] = "Run Walk-forward Lab to activate SingleRow historical play order."
        out["v79_BoxPlayPriorityScore"] = pd.to_numeric(out.get("UniversalFamilyScore", 0), errors="coerce").fillna(0)
        return out

    sr = sr.copy()
    sr["SingleRow"] = pd.to_numeric(sr["SingleRow"], errors="coerce").fillna(-1).astype(int)
    if "CoverageOrder" not in sr.columns:
        # highest-producing rows first if no explicit CoverageOrder exists
        sort_cols = [c for c in ["WinnersFromFull312", "CapturedFromFull312", "RowSubsetCapturePct"] if c in sr.columns]
        if sort_cols:
            sr = sr.sort_values(sort_cols, ascending=[False] * len(sort_cols)).reset_index(drop=True)
        sr["CoverageOrder"] = sr.index + 1

    keep_cols = ["SingleRow"] + [c for c in [
        "CoverageOrder", "WinnersFromFull312", "CapturedFromFull312", "Full312WinnerSharePct",
        "Full312CapturePct", "RowSubsetCapturePct", "CumulativeWinnersFrom312", "CumulativeWinnerPctOf312",
        "CumulativeCapturedFrom312", "CumulativeCapturePctOf312", "OperationalPlays", "PlaysPerCapture",
        "Top1Wins", "NeededTop2", "Top3RescueWins", "Misses"
    ] if c in sr.columns]
    out = out.merge(sr[keep_cols], on="SingleRow", how="left")
    out["CoverageOrder"] = pd.to_numeric(out.get("CoverageOrder", 9999), errors="coerce").fillna(9999)
    out["RowSubsetCapturePct"] = pd.to_numeric(out.get("RowSubsetCapturePct", 0), errors="coerce").fillna(0)
    out["WinnersFromFull312"] = pd.to_numeric(out.get("WinnersFromFull312", 0), errors="coerce").fillna(0)
    out["UniversalFamilyScore"] = pd.to_numeric(out.get("UniversalFamilyScore", 0), errors="coerce").fillna(0)
    out["RecommendedStream"] = pd.to_numeric(out.get("RecommendedStream", 0), errors="coerce").fillna(0).astype(int)
    out["v64_FinalPlayable"] = pd.to_numeric(out.get("v64_FinalPlayable", out["RecommendedStream"]), errors="coerce").fillna(out["RecommendedStream"]).astype(int)

    out["v79_BoxPlayPriorityScore"] = (
        (10000 - out["CoverageOrder"].clip(upper=9999))
        + (out["RecommendedStream"] * 250)
        + (out["v64_FinalPlayable"] * 500)
        + out["UniversalFamilyScore"]
    ).round(3)
    out["v79_FinalPlayTier"] = out.apply(lambda r: "PLAY_PRIMARY" if int(r.get("v64_FinalPlayable", 0)) == 1 or int(r.get("RecommendedStream", 0)) == 1 else "VISIBLE_REVIEW", axis=1)
    out["v79_FinalPlayReason"] = (
        "SingleRow " + out["SingleRow"].astype(str)
        + " | historical coverage order " + out["CoverageOrder"].astype(int).astype(str)
        + " | row winners " + out["WinnersFromFull312"].astype(int).astype(str) + "/312"
        + " | UniversalFamilyScore " + out["UniversalFamilyScore"].round(2).astype(str)
    )
    out = out.sort_values(["v79_FinalPlayTier", "CoverageOrder", "RecommendedStream", "v64_FinalPlayable", "UniversalFamilyScore", "StreamRank"], ascending=[True, True, False, False, False, True]).reset_index(drop=True)
    out.insert(0, "v79_FinalPlayRank", out.index + 1)
    return out

def v79_straight_environment_mode(row: pd.Series) -> str:
    """v80: deterministic straight scores rank candidates first; this mode only chooses final row-depth."""
    try:
        vol = float(row.get("RowVolatilityRate", 0) or 0)
    except Exception:
        vol = 0.0
    try:
        margin = float(row.get("Margin", 9999) or 9999)
    except Exception:
        margin = 9999.0
    try:
        risk = int(float(row.get("Top2RiskScore", 0) or 0))
    except Exception:
        risk = 0
    play_type = str(row.get("BoxPlayType", row.get("PlayType", "")))
    rescue = int(float(row.get("Top3Rescue", 0) or 0)) if str(row.get("Top3Rescue", "")).strip() not in {"", "nan", "None"} else 0
    reasons = f"{row.get('Top3RescueReasons', '')}|{row.get('RowPlayTypeReason', '')}"

    if play_type == "TOP1_ONLY" and vol < 0.40 and margin > 25 and risk == 0 and rescue == 0:
        return "STABLE"
    if play_type == "TOP1_TOP2_TOP3" or vol >= 0.60 or risk >= 6 or rescue == 1 or "danger_row" in reasons:
        return "VOLATILE"
    if vol >= 0.45 or margin <= 15 or risk > 0:
        return "BALANCED"
    return "BALANCED"


def v79_depth_for_environment(mode: str, stable_depth: int = 1, balanced_depth: int = 2, volatile_depth: int = 3) -> int:
    if str(mode) == "STABLE":
        return max(1, min(5, int(stable_depth)))
    if str(mode) == "VOLATILE":
        return max(1, min(5, int(volatile_depth)))
    return max(1, min(5, int(balanced_depth)))


def v79_apply_rowpct_straight_recommendations(straight_df: pd.DataFrame, depth_mode: int = 3, display_top_n: int = 10) -> pd.DataFrame:
    """v80 behavior under the existing v79 function name for compatibility.

    Sequence:
    1) straight_df already contains deterministic seed/position/pair/member scoring and StreamStraightRank.
    2) this function classifies the environment as STABLE/BALANCED/VOLATILE.
    3) RowPercentileBand lookup is applied LAST as the cost-control selector.
    """
    if straight_df is None or not isinstance(straight_df, pd.DataFrame) or straight_df.empty:
        return pd.DataFrame()
    out = straight_df.copy()
    out["RowPercentileBand"] = out.get("RowPercentile", "").apply(v79_rowpct_band)
    out["StreamStraightRank"] = pd.to_numeric(out.get("StreamStraightRank", 9999), errors="coerce").fillna(9999).astype(int)

    # v80 dynamic depth defaults. The sidebar depth_mode remains a cap/fallback.
    out["v80_StraightEnvironmentMode"] = out.apply(v79_straight_environment_mode, axis=1)
    out["v80_DynamicStraightDepth"] = out["v80_StraightEnvironmentMode"].apply(
        lambda m: v79_depth_for_environment(m, stable_depth=1, balanced_depth=2, volatile_depth=max(3, int(depth_mode)))
    )

    out["v79_RecommendedStraightRanksForBand"] = out.apply(
        lambda r: ",".join(map(str, V79_ROWPCT_STRAIGHT_LOOKUP.get(str(r["RowPercentileBand"]), {}).get(int(r["v80_DynamicStraightDepth"]), [1]))),
        axis=1,
    )
    out["v79_RowPctStraightDepthMode"] = out["v80_DynamicStraightDepth"]

    def _is_recommended(r):
        ranks = V79_ROWPCT_STRAIGHT_LOOKUP.get(str(r["RowPercentileBand"]), {}).get(int(r["v80_DynamicStraightDepth"]), [1])
        return int(r["StreamStraightRank"]) in set(map(int, ranks))

    out["v79_RowPctRecommendedStraight"] = out.apply(lambda r: int(_is_recommended(r)), axis=1)
    out["v79_StraightDisplayTopN"] = (out["StreamStraightRank"] <= int(display_top_n)).astype(int)
    out["RecommendedStraight"] = out["v79_RowPctRecommendedStraight"]
    out["RecommendedStraightDisplay"] = out.apply(lambda r: f"**{r['StraightPermutation']}**" if int(r["RecommendedStraight"]) == 1 else str(r["StraightPermutation"]), axis=1)
    # v88 display-only columns: make actual straight plays unmistakable in UI/downloads.
    out = v88_add_straight_play_markers(out)
    out["v79_StraightPlayReason"] = out.apply(
        lambda r: f"{r['v80_StraightEnvironmentMode']} mode: deterministic rank first; RowPctBand {r['RowPercentileBand']} recommends straight-list rank(s) {r['v79_RecommendedStraightRanksForBand']}; this candidate is rank {int(r['StreamStraightRank'])}",
        axis=1,
    )
    return out

