def v87_resolve_uploaded_file(uploaded_file, key: str):
    """Return the active Streamlit UploadedFile for an uploader key.

    This is intentionally limited to upload resolution only. Some Streamlit
    reruns can show a file inside the uploader widget while the local return
    variable is temporarily None. The rest of the app should not interpret that
    as missing history/truth/library data, so this resolver falls back to the
    canonical session_state value for the same widget key.
    """
    if uploaded_file is not None:
        return uploaded_file
    try:
        val = st.session_state.get(key, None)
    except Exception:
        return uploaded_file
    if val is None:
        return uploaded_file
    if isinstance(val, (list, tuple)):
        return val[0] if val else uploaded_file
    if hasattr(val, "getvalue") and hasattr(val, "name"):
        return val
    return uploaded_file

