# ================================
# v64 ENSEMBLE AGREEMENT LAYER
# Runs downstream of v47. It marks agreement; it does not change member picks.
# ================================

V64_STREAM_RANK_MAX = 20
V64_ROW_PERCENTILE_MAX = 25.0
V64_CLUSTER_BUCKET_MAX = 3
V64_TRAIT_SCORE_MIN = 40.0
V64_DEFAULT_AGREEMENT_THRESHOLD = 2

def v64_row_capture_lookup() -> Dict[int, float]:
    df = st.session_state.get("row_single_perf")
    out = {}
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return out
    if "SingleRow" not in df.columns or "capture_pct" not in df.columns:
        return out
    for _, r in df.iterrows():
        try:
            out[int(float(r["SingleRow"]))] = float(r["capture_pct"])
        except Exception:
            continue
    return out



def _v186_wf_num_series(df: pd.DataFrame, col: str, default=0.0) -> pd.Series:
    """
    v186 WF repair: return a Series aligned to df.index even when optional WF audit
    columns such as RowPercentile/RowBucket10/hit_density have not been created yet.
    This prevents scalar fallback crashes without changing member scoring rules.
    """
    if df is None or not isinstance(df, pd.DataFrame):
        return pd.Series(dtype=float)
    if col in df.columns:
        return pd.to_numeric(df[col], errors="coerce")
    return pd.Series([default] * len(df), index=df.index)

def _v186_wf_num_first(df: pd.DataFrame, cols, default=0.0) -> pd.Series:
    if df is None or not isinstance(df, pd.DataFrame):
        return pd.Series(dtype=float)
    for col in cols:
        if col in df.columns:
            return pd.to_numeric(df[col], errors="coerce")
    return pd.Series([default] * len(df), index=df.index)

def v64_apply_ensemble(df: pd.DataFrame, threshold: int = V64_DEFAULT_AGREEMENT_THRESHOLD) -> pd.DataFrame:
    if df is None or df.empty:
        return pd.DataFrame()
    out = df.copy()

    stream_rank = _v186_wf_num_series(out, "StreamRank", 9999).fillna(9999)
    row_pct = _v186_wf_num_series(out, "RowPercentile", 9999).fillna(9999)
    row_bucket = _v186_wf_num_series(out, "RowBucket10", 9999).fillna(9999)
    model_conf = _v186_wf_num_first(out, ["ModelConfidenceScore", "ModelConfidenceRaw"], 0).fillna(0)
    density = _v186_wf_num_series(out, "hit_density", 0).fillna(0)

    out["v64_Method_StreamRank_Top20"] = stream_rank.le(V64_STREAM_RANK_MAX).astype(int)
    out["v64_Method_RowPercentile_Top25"] = row_pct.le(V64_ROW_PERCENTILE_MAX).astype(int)

    # Cluster/group method: row bucket <=3 corresponds to the high-signal grouped front zone.
    out["v64_Method_Grouped_RowBucketTop3"] = row_bucket.le(V64_CLUSTER_BUCKET_MAX).astype(int)

    # Trait method: independent seed/rule strength proxy from existing v47 outputs.
    # This does not rescore members; it only checks whether the seed/member engine fired strong evidence.
    fired = out.get("Fired_Rules", pd.Series([""] * len(out))).astype(str)
    strong_rule_count = fired.apply(lambda s: 0 if not s.strip() else len([x for x in s.split("|") if x.strip()]))
    out["v64_StrongRuleCount"] = strong_rule_count
    out["v64_Method_TraitEvidence"] = ((model_conf.ge(V64_TRAIT_SCORE_MIN)) | (strong_rule_count.ge(5)) | (density.gt(0))).astype(int)

    method_cols = [
        "v64_Method_StreamRank_Top20",
        "v64_Method_RowPercentile_Top25",
        "v64_Method_Grouped_RowBucketTop3",
        "v64_Method_TraitEvidence",
    ]
    out["v64_AgreementScore"] = out[method_cols].sum(axis=1)

    def _methods(row):
        names = []
        if row["v64_Method_StreamRank_Top20"]: names.append("StreamRankTop20")
        if row["v64_Method_RowPercentile_Top25"]: names.append("RowPctTop25")
        if row["v64_Method_Grouped_RowBucketTop3"]: names.append("GroupedBucketTop3")
        if row["v64_Method_TraitEvidence"]: names.append("TraitEvidence")
        return ",".join(names)

    out["v64_AgreedMethods"] = out.apply(_methods, axis=1)
    out["v64_FinalPlayable"] = out["v64_AgreementScore"].ge(int(threshold)).astype(int)
    out["v64_EnsembleReason"] = out.apply(
        lambda r: f"PLAY:agreement_{int(r['v64_AgreementScore'])}_of_4" if int(r["v64_FinalPlayable"]) == 1
        else f"REVIEW_ONLY:agreement_{int(r['v64_AgreementScore'])}_of_4",
        axis=1,
    )

    # Keep full list but sort final agreement group first, then v47 ranking.
    sort_cols = [c for c in ["v64_FinalPlayable", "v64_AgreementScore", "RecommendedStream", "UniversalFamilyScore", "StreamRank"] if c in out.columns]
    if sort_cols:
        asc = [False, False] + [False] * max(0, len(sort_cols)-2)
        if "StreamRank" in sort_cols:
            asc[sort_cols.index("StreamRank")] = True
        out = out.sort_values(sort_cols, ascending=asc).reset_index(drop=True)
    return out

def v64_final_play_list(df: pd.DataFrame, threshold: int = V64_DEFAULT_AGREEMENT_THRESHOLD) -> pd.DataFrame:
    marked = v64_apply_ensemble(df, threshold)
    if marked.empty:
        return marked
    return marked[marked["v64_FinalPlayable"].astype(int).eq(1)].copy()

def v64_ensemble_summary(marked: pd.DataFrame, final: pd.DataFrame, threshold: int) -> pd.DataFrame:
    if marked is None or marked.empty:
        return pd.DataFrame()
    return pd.DataFrame([{
        "Build": BUILD_MARKER,
        "AgreementThreshold": int(threshold),
        "FullRowsVisible": len(marked),
        "FinalPlayableRows": 0 if final is None else len(final),
        "Method1": f"StreamRank <= {V64_STREAM_RANK_MAX}",
        "Method2": f"RowPercentile <= {V64_ROW_PERCENTILE_MAX}",
        "Method3": f"RowBucket10 <= {V64_CLUSTER_BUCKET_MAX}",
        "Method4": f"TraitEvidence: ModelConfidence >= {V64_TRAIT_SCORE_MIN} OR strong rules",
        "Important": "Ensemble is downstream only; v47 member/box picks are unchanged.",
    }])



# ================================
# v78 CACHED FULL-312 LAST-MEMBER STRAIGHT LAB
# Downstream only. Does not modify Daily Prediction, Walk-forward Lab, box picks, streams, or members.
# ================================

def v78_prior_member_context(lab_df: pd.DataFrame) -> pd.DataFrame:
    if lab_df is None or lab_df.empty:
        return pd.DataFrame()
    df = lab_df.copy()
    df["_v78_date"] = pd.to_datetime(df.get("Date", pd.Series([None] * len(df))), errors="coerce")
    df["_v78_order"] = range(len(df))
    df = df.sort_values(["_v78_date", "_v78_order"]).copy()
    last_stream, last_state, last_row = {}, {}, {}
    records = {}
    for idx, r in df.iterrows():
        stream = str(r.get("StreamKey", ""))
        state = str(r.get("State", ""))
        if not state and "|" in stream:
            state = stream.split("|", 1)[0].strip()
        rownum = str(r.get("SingleRow", ""))
        sh = last_stream.get(stream, [])
        sth = last_state.get(state, [])
        rh = last_row.get(rownum, [])
        records[idx] = {
            "Last1_Stream_Member": sh[-1] if sh else "",
            "Last2_Stream_Members": ",".join(sh[-2:]),
            "Last1_State_Member": sth[-1] if sth else "",
            "Last2_State_Members": ",".join(sth[-2:]),
            "Last1_Row_Member": rh[-1] if rh else "",
            "Last2_Row_Members": ",".join(rh[-2:]),
        }
        true_member = normalize_member(r.get("TrueMember", result_to_core389_member(r.get("Result", ""))))
        if true_member in MEMBERS:
            last_stream.setdefault(stream, []).append(true_member)
            last_state.setdefault(state, []).append(true_member)
            last_row.setdefault(rownum, []).append(true_member)
    return pd.DataFrame.from_dict(records, orient="index")


def v78_base_members(row: pd.Series, mode: str) -> list:
    top1 = normalize_member(row.get("PredictedMember", ""))
    top2 = normalize_member(row.get("Top2_pred", ""))
    top3 = normalize_member(row.get("ThirdMember", ""))
    play_type = str(row.get("PlayType", ""))
    decision = str(row.get("Top2Decision", ""))
    ratio = float(row.get("Top2ToTop1Ratio", 0) or 0)
    margin = float(row.get("Margin", 9999) or 9999)
    risk = int(float(row.get("Top2RiskScore", 0) or 0))
    vol = float(row.get("RowVolatilityRate", 0) or 0)
    top3_rescue = int(float(row.get("Top3Rescue", 0) or 0))
    reasons = str(row.get("Top3RescueReasons", ""))

    if mode == "ALWAYS_TOP1":
        return [(top1, "TOP1")]
    if mode == "ALWAYS_TOP2":
        return [(top2, "TOP2")] if top2 in MEMBERS else []
    if mode == "BOX_PLAY_MEMBERS":
        out = [(top1, "BOX_TOP1")] if top1 in MEMBERS else []
        if play_type in {"TOP1_TOP2", "TOP1_TOP2_TOP3"} and top2 in MEMBERS and top2 != top1:
            out.append((top2, "BOX_TOP2"))
        if play_type == "TOP1_TOP2_TOP3" and top3 in MEMBERS and top3 not in {top1, top2}:
            out.append((top3, "BOX_TOP3"))
        return out
    if mode == "TOP1_ONLY_ROWS_ONLY":
        return [(top1, "TOP1_ONLY_ROW")] if play_type == "TOP1_ONLY" and top1 in MEMBERS else []
    if mode == "LOW_VOL_TOP1":
        return [(top1, "LOW_VOL_TOP1")] if vol <= 0.25 and risk == 0 and ratio <= 0.35 and top1 in MEMBERS else []
    if mode == "STRONG_MARGIN_TOP1":
        return [(top1, "STRONG_MARGIN_TOP1")] if margin >= 50 and risk == 0 and ratio <= 0.35 and top1 in MEMBERS else []
    if mode == "TOP2_REQUIRED_USE_TOP2":
        return [(top2, "TOP2_REQUIRED_SIGNAL")] if (decision == "TOP2_REQUIRED" or risk >= 3 or ratio >= 0.80) and top2 in MEMBERS else []
    if mode == "3889_RESCUE_USE_3889":
        return [("3889", "3889_RESCUE_SIGNAL")] if top3 == "3889" and top3_rescue == 1 and "third_3889" in reasons else []
    if mode == "SINGLE_BEST_SIGNAL":
        if play_type == "TOP1_ONLY" and risk == 0 and top1 in MEMBERS:
            return [(top1, "BEST_TOP1_ONLY")]
        if vol <= 0.25 and risk == 0 and ratio <= 0.35 and top1 in MEMBERS:
            return [(top1, "BEST_LOW_VOL_TOP1")]
        if margin >= 50 and risk == 0 and ratio <= 0.35 and top1 in MEMBERS:
            return [(top1, "BEST_STRONG_MARGIN_TOP1")]
        if (decision == "TOP2_REQUIRED" or risk >= 3 or ratio >= 0.80) and top2 in MEMBERS:
            return [(top2, "BEST_TOP2_REQUIRED")]
        if top3 == "3889" and top3_rescue == 1 and "third_3889" in reasons:
            return [("3889", "BEST_3889_RESCUE")]
    return []


def v78_apply_last_member_signal(row: pd.Series, candidates: list, signal_mode: str) -> list:
    if signal_mode == "NONE":
        return candidates
    if not candidates:
        return []
    last2 = "LAST2" in signal_mode
    if "STREAM" in signal_mode:
        col = "Last2_Stream_Members" if last2 else "Last1_Stream_Member"
    elif "ROW" in signal_mode:
        col = "Last2_Row_Members" if last2 else "Last1_Row_Member"
    elif "STATE" in signal_mode:
        col = "Last2_State_Members" if last2 else "Last1_State_Member"
    else:
        return candidates
    prior = {normalize_member(x) for x in str(row.get(col, "")).split(",") if normalize_member(x) in MEMBERS}
    if not prior:
        return []
    include_only = signal_mode.startswith("INCLUDE_ONLY")
    exclude = signal_mode.startswith("EXCLUDE")
    out = []
    for member, src in candidates:
        member = normalize_member(member)
        if include_only and member in prior:
            out.append((member, src + "+" + signal_mode))
        elif exclude and member not in prior:
            out.append((member, src + "+" + signal_mode))
    return out


def v78_precompute_event_member_ranks(work: pd.DataFrame, hist: pd.DataFrame, max_depth: int) -> dict:
    events_cache = build_straight_training_events(hist)
    cache = {}
    if events_cache is None or events_cache.empty:
        return cache
    total = len(work) * len(MEMBERS)
    prog = st.progress(0, text=f"v78 precomputing straight ranks 0/{total}")
    done = 0
    for idx, row in work.iterrows():
        for member in MEMBERS:
            rows = []
            for perm in unique_straight_permutations(member):
                score = score_straight_permutation(row, member, perm, events_cache)
                rows.append({"StraightMember": member, "StraightPermutation": str(perm).zfill(4), **score})
            df = pd.DataFrame(rows)
            if not df.empty:
                df = df.sort_values(["StraightConfidenceScore", "EvidenceSupport"], ascending=[False, False]).reset_index(drop=True)
                df["MemberRank"] = df.index + 1
            cache[(idx, member)] = df
            done += 1
            if done % 50 == 0 or done == total:
                prog.progress(done / max(total, 1), text=f"v78 precomputing straight ranks {done}/{total}")
    prog.empty()
    return cache


def v78_full312_last_member_straight_test(lab_df: pd.DataFrame, hist: pd.DataFrame, base_modes: list, signal_modes: list, max_depth: int = 5):
    if lab_df is None or lab_df.empty or hist is None or hist.empty:
        return pd.DataFrame(), pd.DataFrame(), pd.DataFrame()
    full_total = len(lab_df)
    work = lab_df.copy()
    work["EventIndex"] = range(len(work))
    ctx = v78_prior_member_context(work)
    for c in ctx.columns:
        work[c] = ctx.reindex(work.index)[c].fillna("")
    max_depth = int(max_depth)
    base_modes = list(base_modes or ["ALWAYS_TOP1"])
    signal_modes = list(signal_modes or ["NONE"])

    rank_cache = v78_precompute_event_member_ranks(work, hist, max_depth)
    if not rank_cache:
        return pd.DataFrame(), pd.DataFrame(), pd.DataFrame()

    total_jobs = len(base_modes) * len(signal_modes) * len(work)
    prog = st.progress(0, text=f"v78 evaluating signal modes 0/{total_jobs}")
    detail = []
    done = 0
    for base_mode in base_modes:
        for signal_mode in signal_modes:
            mode = f"{base_mode}__{signal_mode}"
            for idx, row in work.iterrows():
                true_straight = extract_pick4_digits(row.get("Result", ""))
                true_member = normalize_member(row.get("TrueMember", result_to_core389_member(true_straight)))
                candidates = v78_apply_last_member_signal(row, v78_base_members(row, base_mode), signal_mode)
                parts = []
                for member, src in candidates:
                    r = rank_cache.get((idx, normalize_member(member)), pd.DataFrame())
                    if r is not None and not r.empty:
                        tmp = r.copy()
                        tmp["StraightMemberSource"] = src
                        parts.append(tmp)
                if parts:
                    ranked = pd.concat(parts, ignore_index=True).sort_values(["StraightConfidenceScore", "EvidenceSupport"], ascending=[False, False]).reset_index(drop=True)
                    ranked["StraightRank"] = ranked.index + 1
                    ranked = ranked[ranked["StraightRank"] <= max_depth].copy()
                else:
                    ranked = pd.DataFrame()
                common = {
                    "Mode": mode, "BaseMode": base_mode, "LastMemberSignalMode": signal_mode,
                    "EventIndex": idx, "Date": row.get("Date", ""), "StreamKey": row.get("StreamKey", ""),
                    "State": row.get("State", ""), "SingleRow": row.get("SingleRow", ""),
                    "TrueStraight": true_straight, "TrueMember": true_member,
                    "PredictedMember": row.get("PredictedMember", ""), "Top2_pred": row.get("Top2_pred", ""),
                    "ThirdMember": row.get("ThirdMember", ""), "PlayType": row.get("PlayType", ""),
                    "Top2Decision": row.get("Top2Decision", ""), "Top2RiskScore": row.get("Top2RiskScore", ""),
                    "Top2ToTop1Ratio": row.get("Top2ToTop1Ratio", ""), "RowVolatilityRate": row.get("RowVolatilityRate", ""),
                    "Last1_Stream_Member": row.get("Last1_Stream_Member", ""), "Last2_Stream_Members": row.get("Last2_Stream_Members", ""),
                    "Last1_Row_Member": row.get("Last1_Row_Member", ""), "Last2_Row_Members": row.get("Last2_Row_Members", ""),
                    "Last1_State_Member": row.get("Last1_State_Member", ""), "Last2_State_Members": row.get("Last2_State_Members", ""),
                }
                if ranked.empty:
                    detail.append({**common, "CandidateCount": 0, "SelectedMembers": "", "StraightHitRank": None, "StraightHit": 0, "HitMember": "", "HitMemberSource": "", "Reason": "NO_CANDIDATES"})
                else:
                    hits = ranked[ranked["StraightPermutation"].astype(str).str.zfill(4).eq(str(true_straight).zfill(4))]
                    if hits.empty:
                        hit_rank, hit_member, hit_src, hit = None, "", "", 0
                    else:
                        h = hits.sort_values("StraightRank").iloc[0]
                        hit_rank, hit_member, hit_src, hit = int(h["StraightRank"]), h.get("StraightMember", ""), h.get("StraightMemberSource", ""), 1
                    detail.append({**common, "CandidateCount": int(len(ranked)), "SelectedMembers": ",".join(sorted(set(ranked["StraightMember"].astype(str)))), "StraightHitRank": hit_rank, "StraightHit": hit, "HitMember": hit_member, "HitMemberSource": hit_src, "Reason": "HIT" if hit else "MISS"})
                done += 1
                if done % 100 == 0 or done == total_jobs:
                    prog.progress(done / max(total_jobs, 1), text=f"v78 evaluating signal modes {done}/{total_jobs}")
    prog.empty()
    detail_df = pd.DataFrame(detail)
    summary_rows, depth_rows = [], []
    for mode, g in detail_df.groupby("Mode", dropna=False):
        played = int((g["CandidateCount"] > 0).sum())
        for d in range(1, max_depth + 1):
            hits_d = int(g["StraightHitRank"].apply(lambda x: pd.notna(x) and int(x) <= d).sum())
            plays_d = played * d
            depth_rows.append({"Mode": mode, "Depth": d, "FullUniverseTotal": full_total, "PlayedEvents": played, "NoSignalEventsCountedMissed": full_total - played, "HitsAtDepth_FromFull312": hits_d, "HitPctOfFull312": round(hits_d/full_total*100, 2), "HitPctOfPlayedEvents": round(hits_d/played*100, 2) if played else 0, "EstimatedStraightPlays": plays_d, "CostAt25c": round(plays_d*0.25, 2), "PlaysPerHit": round(plays_d/hits_d, 3) if hits_d else None})
        top1 = int(g["StraightHitRank"].apply(lambda x: pd.notna(x) and int(x) <= 1).sum())
        top3 = int(g["StraightHitRank"].apply(lambda x: pd.notna(x) and int(x) <= min(3, max_depth)).sum())
        top5 = int(g["StraightHitRank"].apply(lambda x: pd.notna(x) and int(x) <= min(5, max_depth)).sum())
        anyhit = int(g["StraightHit"].sum())
        summary_rows.append({"Build": BUILD_MARKER, "Mode": mode, "BaseMode": str(g["BaseMode"].iloc[0]), "LastMemberSignalMode": str(g["LastMemberSignalMode"].iloc[0]), "FullUniverseTotal": full_total, "PlayedEvents": played, "NoSignalEventsCountedMissed": full_total-played, "Top1StraightHits_FromFull312": top1, "Top1StraightPctOfFull312": round(top1/full_total*100, 2), "Top3StraightHits_FromFull312": top3, "Top3StraightPctOfFull312": round(top3/full_total*100, 2), "Top5StraightHits_FromFull312": top5, "Top5StraightPctOfFull312": round(top5/full_total*100, 2), "AnyRankedHit_FromFull312": anyhit, "AnyRankedHitPctOfFull312": round(anyhit/full_total*100, 2), "Top5EstimatedStraightPlays": played*min(5,max_depth), "Top5CostAt25c": round(played*min(5,max_depth)*0.25, 2), "AvgCandidatesPerPlayedEvent": round(g["CandidateCount"].sum()/played, 3) if played else 0})
    summary_df = pd.DataFrame(summary_rows)
    if not summary_df.empty:
        summary_df = summary_df.sort_values(["Top5StraightHits_FromFull312", "Top5EstimatedStraightPlays", "Top1StraightHits_FromFull312"], ascending=[False, True, False])
    return detail_df, summary_df, pd.DataFrame(depth_rows)


# ================================
# v140 DATE / STALENESS PANEL OVERRIDE
# Prediction date is based only on uploaded history timeline.
# ================================
def _v140_prediction_dates_from_history(hist: pd.DataFrame):
    if hist is None or not isinstance(hist, pd.DataFrame) or hist.empty:
        return None, None
    date_col = next((c for c in ["Date", "date", "DrawDate", "draw_date"] if c in hist.columns), None)
    if date_col is None:
        return None, None
    dates = pd.to_datetime(hist[date_col], errors="coerce").dropna()
    if dates.empty:
        return None, None
    latest = dates.max().normalize()
    return latest, latest + pd.Timedelta(days=1)

def _v140_render_date_staleness_panel(hist: pd.DataFrame):
    latest, pred = _v140_prediction_dates_from_history(hist)
    st.subheader("v140 Date / Staleness Check")
    if latest is None:
        st.warning("No valid date column was found in uploaded history. Prediction-date safety check cannot run.")
        return

    c1, c2, c3, c4 = st.columns(4)
    c1.metric("Most Recent History Date", latest.date().isoformat())
    c2.metric("Playlist / Prediction Date", pred.date().isoformat())
    c3.metric("Calendar Date Used?", "NO")
    c4.metric("Rule", "history max + 1")

    st.caption("For mock-play/backtesting, the app ignores today's real calendar date. If history ends 2026-02-20, the playlist date is 2026-02-21.")

    support_rows = []
    for label, obj in [
        ("FULL TRUTH intelligence file", truth_file if "truth_file" in globals() else None),
        ("Promoted separator library", lib_file if "lib_file" in globals() else None),
    ]:
        support_rows.append({
            "SupportFile": label,
            "UploadStatus": "UPLOADED" if obj is not None else "NOT UPLOADED",
            "StalenessClock": "history-timeline based",
            "Yellow": "60 history-days",
            "Orange": "90 history-days",
            "Red": "180 history-days",
            "Action": "Rebuild support files in separate support-file builder when refreshed history is ready."
        })
    st.dataframe(pd.DataFrame(support_rows), use_container_width=True, hide_index=True)



