V141_SINGLE_ROW_WINNER_COUNTS = {1:6,2:9,3:4,4:6,5:7,6:7,7:5,8:4,9:4,10:5,11:3,12:3,13:1,14:8,15:4,16:2,17:5,18:3,19:3,20:4,21:5,22:2,23:3,24:12,25:5,26:5,27:2,28:4,29:5,30:9,31:1,32:6,33:4,34:6,35:2,36:4,37:3,38:2,39:2,40:0,41:5,42:3,43:3,44:4,45:4,46:3,47:5,48:2,49:2,50:6,51:3,52:5,53:2,54:1,55:9,56:6,57:2,58:6,59:1,60:6,61:0,62:4,63:2,64:5,65:6,66:6,67:3,68:3,69:7,70:2,71:4,72:2,73:1,74:4,75:2,76:5,77:0,78:3}
V141_DUE_PRESSURE = {60:317,69:223,65:94,50:147}

def _v141_num(df, col, default=0.0):
    if col in df.columns: return pd.to_numeric(df[col], errors="coerce").fillna(default)
    return pd.Series(default, index=df.index)

def _v141_bool01(df, col):
    if col not in df.columns: return pd.Series(0, index=df.index, dtype=int)
    s = df[col]
    if getattr(s, "dtype", None) == bool: return s.astype(int)
    return s.astype(str).str.strip().str.lower().isin(["1","true","yes","y","play"]).astype(int)

def _v141_scale_high(s):
    s = pd.to_numeric(s, errors="coerce").astype(float)
    if s.notna().sum() == 0: return pd.Series(0.0, index=s.index)
    lo, hi = s.min(), s.max()
    if pd.isna(lo) or pd.isna(hi) or hi == lo: return pd.Series(0.5, index=s.index)
    return ((s-lo)/(hi-lo)).fillna(0.0)

def _v141_scale_low(s): return 1.0 - _v141_scale_high(s)

def _v141_member_tokens(x):
    found=[]
    for tok in re.findall(r"\d+", str(x)):
        z=tok.zfill(4)
        if z in {"3389","3899","3889"} and z not in found: found.append(z)
        elif tok in {"25","225","255"}:
            z={"25":"3389","225":"3899","255":"3889"}[tok]
            if z not in found: found.append(z)
    return found

def _v141_clean_member(x):
    t=_v141_member_tokens(x)
    return t[0] if t else ""

def _v141_actual_members_from_row(row):
    for c in ["ActualBoxPlay","ActualBoxPlayDisplay","BoxPlayInstruction","RecommendedPlay","v130_MembersToPlay","v128_MembersToPlay","v127_MembersToPlay","v124_MembersToPlay","v121_MembersToPlay","MembersToPlay"]:
        if c in row.index:
            t=_v141_member_tokens(row.get(c,""))
            if t: return t
    depth=None
    for c in ["ActualPlayCount","PlayCount","v130_PlayCount","v128_PlayCount","v127_PlayCount","v124_PlayCount","v121_PlayCount","v130_Depth","v128_Depth","v127_Depth","v124_Depth","v121_Depth"]:
        if c in row.index:
            try:
                depth=int(float(row.get(c))); break
            except Exception: pass
    if depth is None:
        txt=" ".join(str(row.get(c,"")) for c in ["FinalAction","v130_Action","v128_Action","v127_Action","v124_Action","v121_Action","PlayType","RecommendedPlay","ActualBoxPlay","BoxPlayInstruction"] if c in row.index).upper()
        depth=3 if "TOP3" in txt else 2 if "TOP2" in txt else 1 if ("TOP1" in txt or "PLAY" in txt) else 0
    ranked=[]
    for c in ["Top1_Display","PredictedMember","Top1","Top2_Display","Top2_pred","Top2","Top3_Display","ThirdMember","Top3"]:
        if c in row.index:
            m=_v141_clean_member(row.get(c,""))
            if m and m not in ranked: ranked.append(m)
    return ranked[:max(0,int(depth or 0))]

def _v141_prediction_dates_from_history(hist):
    if hist is None or not isinstance(hist, pd.DataFrame) or hist.empty: return None, None
    date_col=next((c for c in ["Date","date","DrawDate","draw_date"] if c in hist.columns), None)
    if date_col is None: return None, None
    d=pd.to_datetime(hist[date_col], errors="coerce").dropna()
    if d.empty: return None, None
    latest=d.max().normalize()
    return latest, latest+pd.Timedelta(days=1)

def _v141_render_date_staleness_panel(hist):
    latest,pred=_v141_prediction_dates_from_history(hist)
    st.subheader("v141 Date / Staleness Check")
    if latest is None:
        st.warning("No valid history date found. Prediction-date check cannot run."); return
    c1,c2,c3,c4=st.columns(4)
    c1.metric("Most Recent History Date", latest.date().isoformat())
    c2.metric("Playlist / Prediction Date", pred.date().isoformat())
    c3.metric("Calendar Date Used?", "NO")
    c4.metric("Rule", "history max + 1")
    st.caption("Prediction date is based on uploaded history timeline only. Today's real date is ignored for mock play/backtesting.")
    rows=[]
    for label,obj in [("FULL TRUTH intelligence file", truth_file if "truth_file" in globals() else None), ("Promoted separator library", lib_file if "lib_file" in globals() else None)]:
        rows.append({"SupportFile":label,"UploadStatus":"UPLOADED" if obj is not None else "NOT UPLOADED","StalenessClock":"history-timeline based","Yellow":"60 history-days","Orange":"90 history-days","Red":"180 history-days","Action":"Use separate support-file builder when refreshed history is ready."})
    st.dataframe(pd.DataFrame(rows), use_container_width=True, hide_index=True)

def _v141_build_verification_play_table(playlist):
    if playlist is None or not isinstance(playlist, pd.DataFrame) or playlist.empty: return pd.DataFrame()
    out=playlist.copy()
    out["OldPlaylistRank"]=out["PlaylistRank"] if "PlaylistRank" in out.columns else range(1,len(out)+1)
    out["OldStreamRank"]=out["StreamRank"] if "StreamRank" in out.columns else (out["SingleRow"] if "SingleRow" in out.columns else out["OldPlaylistRank"])
    top1=_v141_num(out,"Top1_score",_v141_num(out,"ModelConfidenceScore",0))
    gap=_v141_num(out,"gap",_v141_num(out,"Margin",0))
    ratio=_v141_num(out,"ratio",_v141_num(out,"Top2ToTop1Ratio",0))
    top23=_v141_num(out,"Top2_score",0)+_v141_num(out,"Top3_score",0)
    s25=_v141_num(out,"score_3889",0)+_v141_num(out,"final_3889",0)+_v141_num(out,"boost_3889",0)+_v141_num(out,"rules_3889",0)
    s225=_v141_num(out,"score_3899",0)+_v141_num(out,"final_3899",0)+_v141_num(out,"boost_3899",0)+_v141_num(out,"rules_3899",0)
    s3389=_v141_num(out,"score_3389",0)+_v141_num(out,"final_3389",0)+_v141_num(out,"boost_3389",0)+_v141_num(out,"rules_3389",0)
    out["DynamicScore_v141"]=1.15*_v141_scale_low(top1)+1.00*_v141_scale_low(gap)+0.85*_v141_scale_high(ratio)+0.70*_v141_scale_high(top23)+0.45*_v141_scale_high(s25)+0.35*_v141_scale_high(s225)+0.20*_v141_scale_low(s3389)+0.25*_v141_bool01(out,"RecommendedStream")+0.20*_v141_bool01(out,"RecommendedByTopN")+0.20*_v141_bool01(out,"RecommendedByRowPct")+0.15*_v141_bool01(out,"Top3Rescue")+0.10*(1-_v141_bool01(out,"GATED_TOP3"))
    out["DynamicRank_v141"]=out["DynamicScore_v141"].rank(method="first", ascending=False).astype(int)
    sr=pd.to_numeric(out["SingleRow"], errors="coerce") if "SingleRow" in out.columns else pd.to_numeric(out["OldStreamRank"], errors="coerce")
    out["SingleRowWinnerCount_v141"]=sr.map(lambda x: V141_SINGLE_ROW_WINNER_COUNTS.get(int(x),0) if pd.notna(x) else 0)
    out["SingleRowWinnerPct_v141"]=out["SingleRowWinnerCount_v141"]/312.0
    out["SingleRowHistoricalRank_v141"]=out["SingleRowWinnerCount_v141"].rank(method="first", ascending=False).astype(int)
    out["DuePressureValue_v141"]=sr.map(lambda x: V141_DUE_PRESSURE.get(int(x),0) if pd.notna(x) else 0).fillna(0)
    out["DuePressureRank_v141"]=out["DuePressureValue_v141"].rank(method="first", ascending=False).astype(int)
    out["HybridScore_v141"]=0.50*out["DynamicRank_v141"]+0.35*out["SingleRowHistoricalRank_v141"]+0.15*out["DuePressureRank_v141"]
    out["HybridFinalRank_v141"]=out["HybridScore_v141"].rank(method="first", ascending=True).astype(int)
    out["MovementVsOldStreamRank_v141"]=pd.to_numeric(out["OldStreamRank"], errors="coerce")-pd.to_numeric(out["HybridFinalRank_v141"], errors="coerce")
    out["MovementLabel_v141"]=out["MovementVsOldStreamRank_v141"].map(lambda x: f"UP {int(x)}" if pd.notna(x) and x>0 else (f"DOWN {abs(int(x))}" if pd.notna(x) and x<0 else "SAME"))
    members=out.apply(_v141_actual_members_from_row, axis=1)
    out["ActualMembersToPlay"]=members.map(lambda xs:" + ".join(xs))
    out["ActualPlayCount"]=members.map(len).astype(int)
    out["Action"]=np.where(out["ActualPlayCount"].eq(0),"NO PLAY",np.where(out["ActualPlayCount"].eq(1),"TOP1",np.where(out["ActualPlayCount"].eq(2),"TOP2","TOP3")))
    out["RowCostDisplay"]=(out["ActualPlayCount"]*0.25).map(lambda x:f"${x:,.2f}")
    out=out.sort_values("HybridFinalRank_v141").copy()
    out["PlayOrder"]=range(1,len(out)+1)
    out["RunningPlayTotal"]=out["ActualPlayCount"].cumsum()
    out["RunningCostDisplay"]=(out["RunningPlayTotal"]*0.25).map(lambda x:f"${x:,.2f}")
    out["BudgetMarkerReached"]=out["RunningPlayTotal"].map(lambda t:"$50" if t>=200 else "$40" if t>=160 else "$35" if t>=140 else "$30" if t>=120 else "$25" if t>=100 else "$20" if t>=80 else "$15" if t>=60 else "$10" if t>=40 else "$5" if t>=20 else "")
    moved=int(pd.to_numeric(out["MovementVsOldStreamRank_v141"], errors="coerce").fillna(0).ne(0).sum())
    out["RankDiagnostic_v141"]="TRUE_HYBRID_MOVED_ROWS" if moved>0 else "WARNING_COLLAPSED_TO_OLD_STREAMRANK"
    # v143: rank-comparison columns must be first, then actual play/cost columns. No scoring/member logic changed.
    out["StreamRank_COMPARE_FIRST"] = out["OldStreamRank"]
    out["PctRank_COMPARE_FIRST"] = out["SingleRowHistoricalRank_v141"]
    out["HybridRank_COMPARE_FIRST"] = out["HybridFinalRank_v141"]
    front=[c for c in [
        "StreamRank_COMPARE_FIRST","PctRank_COMPARE_FIRST","HybridRank_COMPARE_FIRST",
        "PlayOrder","StreamKey","State","Game","Action","ActualMembersToPlay","ActualPlayCount",
        "RowCostDisplay","RunningPlayTotal","RunningCostDisplay","BudgetMarkerReached",
        "HybridFinalRank_v141","HybridScore_v141","OldPlaylistRank","OldStreamRank",
        "MovementVsOldStreamRank_v141","MovementLabel_v141","DynamicRank_v141","DynamicScore_v141",
        "SingleRow","RowPercentile","SingleRowWinnerCount_v141","SingleRowWinnerPct_v141",
        "SingleRowHistoricalRank_v141","DuePressureValue_v141","DuePressureRank_v141","RankDiagnostic_v141",
        "PredictedMember","Top2_pred","ThirdMember","Top1_Display","Top2_Display","Top3_Display"
    ] if c in out.columns]
    rest=[c for c in out.columns if c not in front]
    return out[front+rest]

def _v141_render_hybrid_verification_play_table(playlist):
    table=_v141_build_verification_play_table(playlist)
    if table is None or table.empty: return pd.DataFrame()
    st.divider()
    st.subheader("FINAL PLAY THIS TODAY — TRUE HYBRID RANK + ACTUAL COST")
    st.caption("Primary play screen. Use this order. Legacy StreamRank/v80/v89 tables are reference only below. Cost is calculated after ranking and never affects rank.")
    total=int(pd.to_numeric(table["ActualPlayCount"], errors="coerce").fillna(0).sum())
    moved=int(pd.to_numeric(table["MovementVsOldStreamRank_v141"], errors="coerce").fillna(0).ne(0).sum())
    play_flag_col=next((c for c in ["PLAY_FLAG","RecommendedStream","RecommendedByTopN","RecommendedByRowPct"] if c in table.columns), None)
    if play_flag_col:
        play_mask=table[play_flag_col].astype(str).str.strip().str.upper().isin(["1","TRUE","YES","Y","PLAY","PLAY_PRIMARY"])
        no_members_play_rows=int((play_mask & table["ActualMembersToPlay"].astype(str).str.strip().eq("")).sum())
    else:
        no_members_play_rows=int((table["Action"].ne("NO PLAY") & table["ActualMembersToPlay"].astype(str).str.strip().eq("")).sum())
    required_rank_cols=["HybridFinalRank_v141","HybridScore_v141","OldStreamRank","MovementVsOldStreamRank_v141","DynamicRank_v141","SingleRowHistoricalRank_v141","DuePressureRank_v141"]
    missing_rank_cols=[c for c in required_rank_cols if c not in table.columns]
    movement_pass=bool(moved>0 and not missing_rank_cols)
    play_extract_pass=bool(total>0 and no_members_play_rows==0)
    c1,c2,c3,c4=st.columns(4)
    c1.metric("Rows", len(table)); c2.metric("Rows moved vs old StreamRank", moved); c3.metric("Actual plays", total); c4.metric("Full-list cost", f"${total*0.25:,.2f}")
    vcols=st.columns(4)
    vcols[0].success("Hybrid movement check: PASS") if movement_pass else vcols[0].error("Hybrid movement check: FAIL")
    vcols[1].success("Actual play extraction: PASS") if play_extract_pass else vcols[1].error("Actual play extraction: FAIL")
    vcols[2].metric("Rows missing members", no_members_play_rows)
    vcols[3].metric("Rank columns missing", len(missing_rank_cols))
    if missing_rank_cols:
        st.warning("Missing rank verification columns: " + ", ".join(missing_rank_cols))
    cuts=[]
    for dollars in [5,10,15,20,25,30,35,40,50]:
        plays=int(dollars/0.25); sub=table[pd.to_numeric(table["RunningPlayTotal"], errors="coerce").le(plays)]
        cuts.append({"Budget":f"${dollars}","PlayCutoff":plays,"RowsIncluded":len(sub),"ActualPlaysUsed":int(sub["ActualPlayCount"].sum()) if not sub.empty else 0,"LastHybridRankIncluded":int(sub["HybridFinalRank_v141"].max()) if not sub.empty else ""})
    st.markdown("**Budget stopping guide — informational only, not part of ranking**")
    st.dataframe(pd.DataFrame(cuts), use_container_width=True, hide_index=True)
    st.markdown("**FINAL PLAY THIS TODAY — first 3 columns compare StreamRank vs PctRank vs HybridRank; play/cost columns follow immediately**")
    st.dataframe(table, use_container_width=True, hide_index=True, height=950)
    validation=pd.DataFrame([{
        "Build":"core389_northern_lights__2026-06-03_v145_ALL_78_STREAMS_VISIBLE_REPAIR",
        "Rows":len(table),"RowsMovedVsOldStreamRank":moved,"HybridMovementCheck":"PASS" if movement_pass else "FAIL",
        "ActualPlayExtractionCheck":"PASS" if play_extract_pass else "FAIL","RowsMissingActualMembersToPlay":no_members_play_rows,
        "TotalActualPlays":total,"TotalCostAt25c":round(total*0.25,2),"MissingRankColumns":"; ".join(missing_rank_cols)
    }])
    with st.expander("Validation summary", expanded=False):
        st.dataframe(validation, use_container_width=True, hide_index=True)
    st.session_state["v141_hybrid_verification_play_table"]=table
    st.download_button("Download FINAL PLAY THIS TODAY CSV", table.to_csv(index=False).encode("utf-8"), file_name="core389_v143_FINAL_PLAY_THIS_TODAY_rank_compare_first.csv", mime="text/csv", use_container_width=True, key="download_v143_final_play_this_today_csv")
    st.download_button("Download FINAL PLAY THIS TODAY TXT", table.to_csv(index=False).encode("utf-8"), file_name="core389_v143_FINAL_PLAY_THIS_TODAY_rank_compare_first.txt", mime="text/plain", use_container_width=True, key="download_v143_final_play_this_today_txt")
    st.download_button("Download v142 Validation Summary CSV", validation.to_csv(index=False).encode("utf-8"), file_name="core389_v143_validation_summary.csv", mime="text/csv", use_container_width=True, key="download_v143_validation_summary_csv")
    return table



