V157_DYNAMIC_DEPTH_NOTES = {46:"Row 46: Top1 won 70% (10 winners)", 53:"Row 53: Top2 needed 75% (8 winners)", 69:"Row 69: Top1 won 100% (5 winners)", 65:"Row 65: Top1 won 80% (5 winners)", 1:"Row 1: Top2 needed 80% (5 winners)"}

def _v157_norm_member(x):
    s = str(x).strip().replace(" ", "").replace("_", "")
    if s in {"25", "389", "3389"}: return "3389"
    if s in {"225", "3899"}: return "3899"
    if s in {"255", "3889"}: return "3889"
    return s

def _v157_first_col(df, names):
    for n in names:
        if n in df.columns: return n
    low = {c.lower(): c for c in df.columns}
    for n in names:
        if n.lower() in low: return low[n.lower()]
    return None

def _v157_num_series(df, names, default=0):
    c = _v157_first_col(df, names)
    if c is None: return pd.Series([default] * len(df), index=df.index)
    return pd.to_numeric(df[c], errors="coerce").fillna(default)

def _v157_str_series(df, names, default=""):
    c = _v157_first_col(df, names)
    if c is None: return pd.Series([default] * len(df), index=df.index, dtype="object")
    return df[c].astype(str)

def _v157_movement_bucket(v):
    try: v = int(float(v))
    except Exception: return "unknown"
    if v == 0: return "flat"
    av = abs(v); side = "promoted" if v > 0 else "demoted"
    if av <= 9: return side + "_1_9"
    if av <= 24: return side + "_10_24"
    if av <= 49: return side + "_25_49"
    return side + "_50_plus"

def _v157_add_keeper_flags_and_notes(table: pd.DataFrame) -> pd.DataFrame:
    """Add advisory flag/note columns beside member recommendations. Never removes rows or changes plays."""
    if table is None or not isinstance(table, pd.DataFrame) or table.empty: return table
    out = table.copy()
    dyn = _v157_num_series(out, ["DynamicRank", "DynamicRank_v141", "DynamicRank_v139", "HybridRank_COMPARE_FIRST"], default=np.nan)
    movement = _v157_num_series(out, ["Movement", "MovementVsOldStreamRank_v141", "MovementVsStream", "HybridVsOldStreamRankDelta_v139"], default=np.nan)
    out["DynamicSingleRowWins"] = dyn.map(lambda x: V157_DYNAMIC_RANK_WINNER_COUNTS.get(int(x), 0) if pd.notna(x) else 0).astype(int)
    out["MovementWins"] = movement.map(lambda x: V157_MOVEMENT_WINNER_COUNTS.get(int(x), 0) if pd.notna(x) else 0).astype(int)
    out["MovementWinnerRatePct"] = movement.map(lambda x: V157_MOVEMENT_WINNER_RATE_PCT.get(int(x), 0.0) if pd.notna(x) else 0.0).astype(float).round(3)
    out["MovementBucket_v157"] = movement.map(_v157_movement_bucket)
    rule_flags = pd.Series([[] for _ in range(len(out))], index=out.index, dtype="object")
    play_notes = pd.Series([[] for _ in range(len(out))], index=out.index, dtype="object")
    mask_scld2 = out["DynamicSingleRowWins"].le(2)
    mask_sclm0 = out["MovementWins"].eq(0)
    mask_mpt2 = out["MovementWinnerRatePct"].le(0.10)
    for idx in out.index[mask_scld2]:
        rule_flags.at[idx].append("SCL-D2"); play_notes.at[idx].append("CUT STREAM per SCL-D2: dynamic row has <=2 historical wins")
    for idx in out.index[mask_sclm0]:
        rule_flags.at[idx].append("SCL-M0"); play_notes.at[idx].append("CUT STREAM per SCL-M0: exact movement has 0 historical wins")
    for idx in out.index[mask_mpt2]:
        rule_flags.at[idx].append("MPT2"); play_notes.at[idx].append("PLAY TOP1 ONLY per MPT2: movement winner rate <=0.10%")
    for idx, val in dyn.items():
        try: rv = int(val)
        except Exception: continue
        if rv in V157_DYNAMIC_DEPTH_NOTES:
            rule_flags.at[idx].append("DNOTE-" + str(rv)); play_notes.at[idx].append(V157_DYNAMIC_DEPTH_NOTES[rv])
    consec = _v157_num_series(out, ["seed_consec_links", "SeedConsecLinks", "consec_links", "seed_links"], default=np.nan)
    seed_sum = _v157_num_series(out, ["seed_sum", "SeedSum"], default=np.nan)
    prior_neg = _v157_num_series(out, ["PriorNegativeStreak", "prior_negative_streak", "MovementPriorNegativeStreak"], default=np.nan)
    third = _v157_str_series(out, ["ThirdMember", "Top3", "Top3_Display"], default="").map(_v157_norm_member)
    sum_bucket = _v157_str_series(out, ["sum_bucket", "SumBucket", "seed_sum_bucket"], default="")
    mask_bucket_18_21 = sum_bucket.str.contains("18", na=False) | sum_bucket.str.contains("19", na=False) | sum_bucket.str.contains("20", na=False) | sum_bucket.str.contains("21", na=False) | seed_sum.between(18, 21, inclusive="both")
    candidate_masks = [
        ("MPT-C1", consec.eq(2) & out["MovementWins"].le(3), "Candidate Top1-only per MPT-C1: consec_links=2 + MovementWins<=3"),
        ("MPT-C2", third.eq("3899") & prior_neg.eq(1), "Candidate Top1-only per MPT-C2: ThirdMember=3899 + prior negative streak=1"),
        ("MPT-C3", seed_sum.eq(14), "Candidate Top1-only per MPT-C3: seed_sum=14"),
        ("MPT-C4", out["MovementBucket_v157"].eq("demoted_1_9") & mask_bucket_18_21, "Candidate Top1-only per MPT-C4: demoted 1-9 + sum bucket 18-21"),
    ]
    for rid, mask, note in candidate_masks:
        for idx in out.index[mask.fillna(False)]:
            rule_flags.at[idx].append(rid); play_notes.at[idx].append(note)
    out["RuleFlags"] = rule_flags.map(lambda xs: ", ".join(dict.fromkeys(xs)))
    out["PlayNote"] = play_notes.map(lambda xs: " | ".join(dict.fromkeys(xs)))
    out["RecommendedActionFlag"] = ""
    out.loc[mask_scld2 | mask_sclm0, "RecommendedActionFlag"] = "CUT REVIEW"
    out.loc[(out["RecommendedActionFlag"].eq("")) & mask_mpt2, "RecommendedActionFlag"] = "TOP1 ONLY REVIEW"
    out["v157FlagBuild"] = "v157_flags_notes_only_no_rows_removed_no_members_changed"
    return out

def _v157_rule_key_dataframe() -> pd.DataFrame:
    return pd.DataFrame(V157_RULE_KEY_ROWS)



# ================================
# v158 SEED / PRIOR-WINNER AWARE NOTES
# Additive only. Computes visible seed/prior-winner input status so seed-based notes do not require manual user lookup.
# Does not remove rows and does not alter member recommendations.
# ================================
def _v158_digits_from_any(value):
    import re
    s = str(value) if value is not None else ""
    digs = re.findall(r"\d", s)
    if len(digs) >= 4:
        return digs[:4]
    return []

def _v158_seed_sum_from_table(out: pd.DataFrame):
    # Prefer explicit seed-sum columns. Fall back to seed/result-like text columns.
    explicit = _v157_first_col(out, ["seed_sum", "SeedSum", "CurrentSeedSum", "PredictionSeedSum"])
    if explicit is not None:
        return pd.to_numeric(out[explicit], errors="coerce"), explicit
    for c in ["Seed", "PredictionSeed", "CurrentSeed", "LastSeed", "PrevSeed", "PreviousSeed", "SeedResult", "LastResult", "PrevResult", "PreviousResult"]:
        cc = _v157_first_col(out, [c])
        if cc is not None:
            vals = out[cc].map(lambda x: sum(int(d) for d in _v158_digits_from_any(x)) if len(_v158_digits_from_any(x)) >= 4 else np.nan)
            if vals.notna().any():
                return vals, cc + "(digit-derived)"
    return pd.Series([np.nan] * len(out), index=out.index), "missing"

def _v158_prior_member_from_table_or_session(out: pd.DataFrame):
    # Prefer explicit prior-winner columns if the app already generated them.
    c = _v157_first_col(out, ["PriorWinnerMember", "PriorCore389WinnerMember", "LastWinnerMember", "LastCore389Member"])
    if c is not None:
        return out[c].map(_v157_norm_member), c
    # Fall back to a session-state scalar if present.
    try:
        for key in ["PriorWinnerMember", "PriorCore389WinnerMember", "LastWinnerMember", "LastCore389Member", "v158_prior_winner_member"]:
            if key in st.session_state:
                val = _v157_norm_member(st.session_state.get(key))
                return pd.Series([val] * len(out), index=out.index), "session_state." + key
    except Exception:
        pass
    return pd.Series([""] * len(out), index=out.index, dtype="object"), "missing"

def _v158_add_seed_aware_notes(out: pd.DataFrame) -> pd.DataFrame:
    if out is None or not isinstance(out, pd.DataFrame) or out.empty:
        return out
    out = out.copy()
    seed_sum, seed_src = _v158_seed_sum_from_table(out)
    prior_member, prior_src = _v158_prior_member_from_table_or_session(out)
    out["SeedSumUsed_v158"] = seed_sum
    out["PriorWinnerMemberUsed_v158"] = prior_member
    out["SeedAwareStatus_v158"] = "seed_sum_source=" + str(seed_src) + "; prior_member_source=" + str(prior_src)
    if "PlayNote" not in out.columns: out["PlayNote"] = ""
    if "RuleFlags" not in out.columns: out["RuleFlags"] = ""
    # Existing candidate MPT-C3 becomes fully automatic when seed_sum is available.
    mask_seed14 = seed_sum.eq(14)
    for idx in out.index[mask_seed14.fillna(False)]:
        flag = "MPT-C3"
        note = "Candidate Top1-only per MPT-C3: app-computed seed_sum=14"
        oldf = str(out.at[idx, "RuleFlags"]).strip()
        oldn = str(out.at[idx, "PlayNote"]).strip()
        out.at[idx, "RuleFlags"] = (oldf + ", " + flag).strip(", ") if flag not in oldf.split(", ") else oldf
        out.at[idx, "PlayNote"] = (oldn + " | " + note).strip(" |") if note not in oldn else oldn
    # Do NOT add prior-member+seed-sum transition rules here; those have not been validated yet.
    # This column makes missing inputs visible, so the user can see whether the app is able to apply such future rules.
    return out



