def _v176_load_any(uploaded):
    if uploaded is None:
        return pd.DataFrame()
    try:
        name = str(getattr(uploaded, "name", "")).lower()
        if name.endswith(".csv"):
            return pd.read_csv(uploaded, dtype=str)
        if name.endswith((".txt", ".tsv")):
            raw = uploaded.getvalue() if hasattr(uploaded, "getvalue") else uploaded.read()
            try:
                return pd.read_csv(io.BytesIO(raw), sep="\t", dtype=str)
            except Exception:
                return pd.read_csv(io.BytesIO(raw), sep=None, engine="python", dtype=str)
        if name.endswith((".xlsx", ".xls")):
            return pd.read_excel(uploaded, dtype=str)
        return pd.read_csv(uploaded, dtype=str)
    except Exception as e:
        try:
            st.warning(f"v176 could not load file: {e}")
        except Exception:
            pass
        return pd.DataFrame()


def _v176_norm_col(c):
    return re.sub(r"[^a-z0-9]+", "", str(c).lower())


def _v176_column_map(df):
    if df is None or not isinstance(df, pd.DataFrame):
        return {}
    return {_v176_norm_col(c): c for c in df.columns}


def _v176_pick_col(df, candidates, contains_any=None):
    if df is None or df.empty:
        return None
    cmap = _v176_column_map(df)
    for cand in candidates:
        key = _v176_norm_col(cand)
        if key in cmap:
            return cmap[key]
    if contains_any:
        words = [_v176_norm_col(x) for x in contains_any]
        for c in df.columns:
            n = _v176_norm_col(c)
            if any(w in n for w in words):
                return c
    return None


def _v176_norm_result(x):
    digs = re.findall(r"\d", str(x))
    return "".join(digs[:4]) if len(digs) >= 4 else ""


def _v176_box_key(x):
    s = _v176_norm_result(x)
    return "".join(sorted(s)) if len(s) == 4 else ""


def _v176_to_member(x):
    s0 = str(x).strip()
    if s0 == "" or s0.lower() in {"nan", "none"}:
        return ""
    digs = re.findall(r"\d", s0)
    if not digs:
        return ""
    s = "".join(digs)
    if s in {"25", "389", "3389"}: return "3389"
    if s in {"225", "3899"}: return "3899"
    if s in {"255", "3889"}: return "3889"
    if len(s) >= 4:
        b = "".join(sorted(s[:4]))
        if b in V176_MEMBERS:
            return b
    return ""


def _v176_sum_bucket(x):
    try: x = int(x)
    except Exception: return ""
    if x <= 9: return "sum_00_09"
    if x <= 13: return "sum_10_13"
    if x <= 17: return "sum_14_17"
    if x <= 21: return "sum_18_21"
    return "sum_22_plus"


def _v176_spread_bucket(x):
    try: x = int(x)
    except Exception: return ""
    if x <= 2: return "spread_0_2"
    if x <= 4: return "spread_3_4"
    if x <= 6: return "spread_5_6"
    return "spread_7_plus"


def _v176_structure(digs):
    try:
        counts = sorted(pd.Series(digs).value_counts().tolist(), reverse=True)
    except Exception:
        return ""
    return { (1,1,1,1):"ABCD", (2,1,1):"AABC", (2,2):"AABB", (3,1):"AAAB", (4,):"AAAA" }.get(tuple(counts), "OTHER")


def _v176_add_seed_features(df, seed_col="seed"):
    out = df.copy()
    if seed_col not in out.columns:
        out[seed_col] = ""
    seeds = out[seed_col].astype(str).map(_v176_norm_result)
    seeds = seeds.where(seeds.str.len().eq(4), out[seed_col].astype(str).str.extract(r"(\d{4})", expand=False).fillna("0000"))
    digs = seeds.map(lambda s: [int(ch) for ch in str(s).zfill(4)[-4:]])
    out["seed"] = seeds
    out["sum"] = digs.map(sum); out["seed_sum"] = out["sum"]
    out["spread"] = digs.map(lambda d: max(d) - min(d)); out["seed_spread"] = out["spread"]
    out["sum_bucket"] = out["sum"].map(_v176_sum_bucket)
    out["spread_bucket"] = out["spread"].map(_v176_spread_bucket)
    out["even"] = digs.map(lambda d: sum(1 for x in d if x % 2 == 0))
    out["odd"] = digs.map(lambda d: sum(1 for x in d if x % 2 != 0))
    out["high"] = digs.map(lambda d: sum(1 for x in d if x >= 5))
    out["low"] = digs.map(lambda d: sum(1 for x in d if x <= 4))
    out["unique"] = digs.map(lambda d: len(set(d)))
    out["pair"] = digs.map(lambda d: int(len(set(d)) < 4))
    out["max_rep"] = digs.map(lambda d: max(pd.Series(d).value_counts().tolist()))
    out["consec_links"] = digs.map(lambda d: sum(1 for a,b in zip(sorted(set(d))[:-1], sorted(set(d))[1:]) if b-a == 1))
    out["parity_pattern"] = digs.map(lambda d: "".join("E" if x % 2 == 0 else "O" for x in d))
    out["highlow_pattern"] = digs.map(lambda d: "".join("H" if x >= 5 else "L" for x in d))
    out["structure"] = digs.map(_v176_structure)
    out["sorted_seed"] = digs.map(lambda d: "".join(str(x) for x in sorted(d)))
    out["first2"] = digs.map(lambda d: f"{d[0]}{d[1]}")
    out["last2"] = digs.map(lambda d: f"{d[2]}{d[3]}")
    for k in range(10):
        out[f"has{k}"] = digs.map(lambda d, kk=k: int(kk in d))
        out[f"cnt{k}"] = digs.map(lambda d, kk=k: int(sum(1 for x in d if x == kk)))
    out["seed_highlow_pattern"] = out["highlow_pattern"]
    out["seed_parity_pattern"] = out["parity_pattern"]
    out["seed_repeat_shape"] = out["structure"]
    out["seed_has9"] = out["has9"]
    out["seed_has0"] = out["has0"]
    out["seed_even_cnt"] = out["even"]
    out["seed_high_cnt"] = out["high"]
    out["seed_low_cnt"] = out["low"]
    return out


def _v176_prepare_history(df_raw):
    if df_raw is None or not isinstance(df_raw, pd.DataFrame) or df_raw.empty:
        return pd.DataFrame()
    df = df_raw.copy(); df.columns = [str(c).strip() for c in df.columns]
    date_col = _v176_pick_col(df, ["Date", "DrawDate", "draw_date"], ["date"])
    state_col = _v176_pick_col(df, ["State", "Jurisdiction"], ["state", "jurisdiction"])
    game_col = _v176_pick_col(df, ["Game"], ["game"])
    result_col = _v176_pick_col(df, ["Results", "Result", "Winning Numbers", "winning_numbers"], ["result", "winning"])
    if date_col is None or result_col is None:
        if df.shape[1] >= 4:
            date_col, state_col, game_col, result_col = df.columns[:4]
        else:
            return pd.DataFrame()
    out = pd.DataFrame()
    out["Date"] = pd.to_datetime(df[date_col], errors="coerce")
    out["State"] = df[state_col].astype(str) if state_col else ""
    out["Game"] = df[game_col].astype(str) if game_col else ""
    out["Result"] = df[result_col].map(_v176_norm_result)
    out = out[out["Date"].notna() & out["Result"].astype(str).str.len().eq(4)].copy()
    out["StreamKey"] = out["State"].astype(str).str.strip() + " | " + out["Game"].astype(str).str.strip()
    out["Box"] = out["Result"].map(_v176_box_key)
    out["Core389Member"] = out["Box"].where(out["Box"].isin(V176_MEMBERS), "")
    return out.sort_values(["StreamKey", "Date"]).reset_index(drop=True)


def _v176_build_transitions(hist):
    rows = []
    if hist is None or hist.empty:
        return pd.DataFrame()
    for stream, g in hist.groupby("StreamKey"):
        g = g.sort_values("Date").reset_index(drop=True)
        for i in range(1, len(g)):
            rows.append({
                "StreamKey": stream,
                "State": g.loc[i, "State"],
                "Game": g.loc[i, "Game"],
                "seed_date": g.loc[i-1, "Date"],
                "event_date": g.loc[i, "Date"],
                "seed": g.loc[i-1, "Result"],
                "Result": g.loc[i, "Result"],
                "next_member": g.loc[i, "Core389Member"] if g.loc[i, "Core389Member"] in V176_MEMBERS else "",
                "is_core389_hit": int(g.loc[i, "Core389Member"] in V176_MEMBERS),
            })
    out = pd.DataFrame(rows)
    if out.empty: return out
    out = _v176_add_seed_features(out, "seed")
    return out.sort_values(["event_date", "StreamKey"]).reset_index(drop=True)


def _v176_detect_member_col(df):
    if df is None or df.empty:
        return None, pd.Series(dtype=str), pd.DataFrame()
    candidates = [
        "TrueMember","WinningMember","WinnerMember","Winner","Core389Member","CapturedMember",
        "ActualMember","TargetMember","member","winning_member","winner_member","Box","Result","Results"
    ]
    rows = []
    best_col, best_count, best_members = None, -1, None
    for c in df.columns:
        n = _v176_norm_col(c)
        likely = any(_v176_norm_col(x) == n for x in candidates) or any(w in n for w in ["truemember","winningmember","winnermember","core389member","capturedmember","actualmember","targetmember"])
        if not likely:
            continue
        members = df[c].map(_v176_to_member)
        count = int(members.isin(V176_MEMBERS).sum())
        rows.append({"CandidateColumn": c, "DetectedCore389Members": count})
        if count > best_count:
            best_col, best_count, best_members = c, count, members
    # fallback: scan every column when no likely column worked
    if best_count <= 0:
        for c in df.columns:
            members = df[c].map(_v176_to_member)
            count = int(members.isin(V176_MEMBERS).sum())
            if count > best_count:
                best_col, best_count, best_members = c, count, members
        rows.append({"CandidateColumn": "FALLBACK_BEST_SCAN=" + str(best_col), "DetectedCore389Members": int(best_count)})
    if best_members is None:
        best_members = pd.Series([""] * len(df), index=df.index)
    return best_col, best_members, pd.DataFrame(rows)


def _v176_parse_conditions(trait_stack):
    parts = [p.strip() for p in re.split(r"\s+&&\s+", str(trait_stack)) if p.strip()]
    conds = []
    for p in parts:
        if "==" in p:
            col, val = p.split("==", 1)
        elif "=" in p:
            col, val = p.split("=", 1)
        else:
            continue
        conds.append((col.strip(), val.strip()))
    return conds


def _v176_condition_mask(df, conds):
    mask = pd.Series(True, index=df.index)
    missing = []
    for col, val in conds:
        aliases = [col]
        if col.startswith("seed_"):
            aliases.append(col.replace("seed_", ""))
        else:
            aliases.append("seed_" + col)
        real_col = next((c for c in aliases if c in df.columns), None)
        if real_col is None:
            missing.append(col); mask &= False; continue
        def fmt(x):
            if pd.isna(x): return ""
            s = str(x)
            try:
                f = float(s)
                if f.is_integer(): return str(int(f))
            except Exception:
                pass
            return s.strip()
        mask &= df[real_col].map(fmt).astype(str).str.strip().eq(str(val).strip())
    return mask, (";".join(missing) if missing else "")


def _v176_validate_separator(sep):
    if sep is None or not isinstance(sep, pd.DataFrame) or sep.empty:
        return pd.DataFrame([{"Check":"Separator loaded", "Status":"FAIL", "Detail":"No separator rows"}]), {}
    work = sep.copy(); work.columns = [str(c).strip() for c in work.columns]
    trait_col = _v176_pick_col(work, ["trait_stack", "TraitStack", "trait", "RuleTrait"], ["trait"])
    winner_col = _v176_pick_col(work, ["winner_member", "WinnerMember", "winning_member", "member"], ["winner", "member"])
    pair_col = _v176_pick_col(work, ["pair", "Pair"], ["pair"])
    members = work[winner_col].map(_v176_to_member) if winner_col else pd.Series([""]*len(work))
    member_counts = members.value_counts().reindex(V176_MEMBERS).fillna(0).astype(int).to_dict()
    pair_counts = work[pair_col].astype(str).value_counts().to_dict() if pair_col else {}
    checks = []
    checks.append({"Check":"Separator rows loaded", "Status":"PASS" if len(work)>0 else "FAIL", "Detail":str(len(work))})
    checks.append({"Check":"Trait stack column found", "Status":"PASS" if trait_col else "FAIL", "Detail":str(trait_col or "missing")})
    checks.append({"Check":"Winner member column found", "Status":"PASS" if winner_col else "FAIL", "Detail":str(winner_col or "missing")})
    checks.append({"Check":"Pair column found", "Status":"PASS" if pair_col else "WARN", "Detail":str(pair_col or "missing")})
    checks.append({"Check":"3389 rules", "Status":"PASS" if member_counts.get("3389",0)>0 else "FAIL", "Detail":str(member_counts.get("3389",0))})
    checks.append({"Check":"3899 rules", "Status":"PASS" if member_counts.get("3899",0)>0 else "FAIL", "Detail":str(member_counts.get("3899",0))})
    checks.append({"Check":"3889 rules", "Status":"PASS" if member_counts.get("3889",0)>0 else "FAIL", "Detail":str(member_counts.get("3889",0))})
    for pair_name in ["3389_vs_3899", "3389_vs_3889", "3899_vs_3889", "3899_vs_3389", "3889_vs_3389", "3889_vs_3899"]:
        if pair_col and any(pair_name in str(x) for x in work[pair_col].astype(str).unique()):
            checks.append({"Check":"Pair coverage " + pair_name, "Status":"PASS", "Detail":"present"})
    meta = {"trait_col": trait_col, "winner_col": winner_col, "pair_col": pair_col, "member_counts": member_counts, "pair_counts": pair_counts}
    return pd.DataFrame(checks), meta


def _v176_truth_audit(old_truth, transitions):
    core = transitions[transitions["is_core389_hit"] == 1].copy() if isinstance(transitions, pd.DataFrame) and not transitions.empty else pd.DataFrame()
    current_dist = core["next_member"].value_counts().reindex(V176_MEMBERS).fillna(0).astype(int) if not core.empty else pd.Series({m:0 for m in V176_MEMBERS})
    old_rows = old_cols = 0; old_max_date = "missing"; member_col = ""; detect = pd.DataFrame(); old_dist = pd.Series({m:0 for m in V176_MEMBERS})
    if old_truth is not None and isinstance(old_truth, pd.DataFrame) and not old_truth.empty:
        old = old_truth.copy(); old.columns = [str(c).strip() for c in old.columns]
        old_rows, old_cols = len(old), len(old.columns)
        member_col, old_members, detect = _v176_detect_member_col(old)
        old_dist = old_members[old_members.isin(V176_MEMBERS)].value_counts().reindex(V176_MEMBERS).fillna(0).astype(int)
        date_col = _v176_pick_col(old, ["Date", "date", "event_date", "EventDate", "DrawDate"], ["date"])
        if date_col:
            ds = pd.to_datetime(old[date_col], errors="coerce")
            old_max_date = str(ds.max().date()) if ds.notna().any() else "unknown"
        else:
            old_max_date = "unknown"
    current_max_date = str(pd.to_datetime(transitions["event_date"], errors="coerce").max().date()) if isinstance(transitions, pd.DataFrame) and not transitions.empty and "event_date" in transitions.columns else "unknown"
    dist_rows = []
    for m in V176_MEMBERS:
        dist_rows.append({"Member":m, "OldTruthCount":int(old_dist.get(m,0)), "CurrentHistoryCoreHitCount":int(current_dist.get(m,0)), "DeltaCount":int(current_dist.get(m,0))-int(old_dist.get(m,0))})
    meta = pd.DataFrame([{"OldTruthRows":int(old_rows), "OldTruthColumns":int(old_cols), "DetectedOldTruthMemberColumn":str(member_col or "NONE"), "OldTruthMaxDate":old_max_date, "CurrentTransitionRows":int(len(transitions)) if isinstance(transitions,pd.DataFrame) else 0, "CurrentCore389Hits":int(len(core)), "CurrentHistoryMaxEventDate":current_max_date, "AuditMode":"audit_only_no_auto_replace"}])
    checks = []
    checks.append({"Check":"Old truth file loaded", "Status":"PASS" if old_rows>0 else "FAIL", "Detail":str(old_rows)})
    checks.append({"Check":"Old truth member column detected", "Status":"PASS" if member_col else "FAIL", "Detail":str(member_col or "none")})
    checks.append({"Check":"Old truth member counts nonzero", "Status":"PASS" if int(sum(old_dist))>0 else "FAIL", "Detail":str(dict(old_dist))})
    checks.append({"Check":"Current history Core389 hits", "Status":"PASS" if len(core)>0 else "FAIL", "Detail":str(len(core))})
    return pd.DataFrame(dist_rows), meta, pd.DataFrame(checks), detect


def _v176_audit_separator(old_sep, transitions, min_support=5, weaken_delta=0.08, flip_margin=0.05):
    if old_sep is None or old_sep.empty or transitions is None or transitions.empty:
        return pd.DataFrame(), pd.DataFrame(), pd.DataFrame(), {}
    sep = old_sep.copy(); sep.columns = [str(c).strip() for c in sep.columns]
    parse_checks, meta = _v176_validate_separator(sep)
    trait_col = meta.get("trait_col") or "trait_stack"
    winner_col = meta.get("winner_col") or "winner_member"
    pair_col = meta.get("pair_col") or "pair"
    if trait_col not in sep.columns:
        return pd.DataFrame([{"Status":"PARSE_OR_SCHEMA_REVIEW", "EvalNote":"missing trait_stack"}]), pd.DataFrame(), parse_checks, meta
    if winner_col not in sep.columns:
        sep[winner_col] = ""
    if pair_col not in sep.columns:
        sep[pair_col] = ""
    core = transitions[transitions["is_core389_hit"] == 1].copy()
    rows=[]
    for idx, r in sep.iterrows():
        trait = str(r.get(trait_col, ""))
        old_member = _v176_to_member(r.get(winner_col, ""))
        old_support = pd.to_numeric(r.get("support", r.get("Support", "")), errors="coerce")
        old_rate = pd.to_numeric(r.get("winner_rate", r.get("WinnerRate", "")), errors="coerce")
        old_gap = pd.to_numeric(r.get("pair_gap", r.get("PairGap", "")), errors="coerce")
        conds = _v176_parse_conditions(trait)
        mask, missing = _v176_condition_mask(core, conds)
        sub = core[mask].copy()
        new_support = int(len(sub))
        counts = sub["next_member"].value_counts().reindex(V176_MEMBERS).fillna(0).astype(int).to_dict()
        if new_support > 0:
            rates = {m: counts.get(m,0)/new_support for m in V176_MEMBERS}
            new_best = max(rates, key=rates.get); new_best_rate = rates[new_best]; old_member_new_rate = rates.get(old_member, 0.0) if old_member else 0.0
        else:
            rates = {m:0.0 for m in V176_MEMBERS}; new_best=""; new_best_rate=0.0; old_member_new_rate=0.0
        delta_old = (float(old_rate)-old_member_new_rate) if pd.notna(old_rate) else None
        if missing:
            status="PARSE_OR_SCHEMA_REVIEW"; action="Do not change; parser could not verify rule."
        elif new_support < int(min_support):
            status="INSUFFICIENT_CURRENT_SUPPORT"; action="Do not change; not enough current support."
        elif old_member and new_best and new_best != old_member and (new_best_rate - old_member_new_rate) >= float(flip_margin):
            status="FLIPPED_REVIEW"; action="Candidate patch only after manual approval."
        elif delta_old is not None and delta_old >= float(weaken_delta):
            status="WEAKENED_REVIEW"; action="Keep production rule for now; monitor or test contribution."
        elif old_member and new_best == old_member:
            status="STILL_HOLDS"; action="Keep unchanged."
        else:
            status="REVIEW"; action="Manual review."
        rows.append({"RuleID": str(r.get("RuleID", r.get("rule_id", f"SEP_ROW_{idx+1}"))), "RuleRow":idx+1, "Pair":r.get(pair_col,""), "TraitStack":trait, "OldWinnerMember":old_member, "OldSupport":old_support if pd.notna(old_support) else "", "OldWinnerRate":old_rate if pd.notna(old_rate) else "", "OldPairGap":old_gap if pd.notna(old_gap) else "", "CurrentSupport":new_support, "CurrentBestMember":new_best, "CurrentBestRate":round(new_best_rate,4), "CurrentOldMemberRate":round(old_member_new_rate,4), "DeltaOldMemberRate":round(delta_old,4) if delta_old is not None else "", "Count_3389":counts.get("3389",0), "Count_3899":counts.get("3899",0), "Count_3889":counts.get("3889",0), "Status":status, "RecommendedAction":action, "EvalNote":missing})
    audit=pd.DataFrame(rows)
    summary=audit.groupby("Status").size().rename("RuleCount").reset_index().sort_values("RuleCount",ascending=False) if not audit.empty else pd.DataFrame()
    return audit, summary, parse_checks, meta


def _v176_make_proposed_changes(sep_audit):
    if sep_audit is None or not isinstance(sep_audit, pd.DataFrame) or sep_audit.empty:
        return pd.DataFrame()
    review = sep_audit[sep_audit["Status"].isin(["FLIPPED_REVIEW", "WEAKENED_REVIEW", "PARSE_OR_SCHEMA_REVIEW", "INSUFFICIENT_CURRENT_SUPPORT", "REVIEW"])].copy()
    if review.empty:
        return pd.DataFrame(columns=["Approve","RuleID","RuleRow","TraitStack","CurrentAction","ProposedAction","OldWinnerMember","ProposedWinnerMember","EvidenceSummary","Reason"])
    out = pd.DataFrame()
    out["Approve"] = "NO"
    out["RuleID"] = review.get("RuleID", "")
    out["RuleRow"] = review["RuleRow"]
    out["TraitStack"] = review["TraitStack"]
    out["CurrentAction"] = review["Status"]
    out["ProposedAction"] = review["Status"].map(lambda s: "CHANGE_WINNER_MEMBER" if s=="FLIPPED_REVIEW" else ("DISABLE_OR_MONITOR" if s=="WEAKENED_REVIEW" else "NO_CHANGE_REVIEW"))
    out["OldWinnerMember"] = review["OldWinnerMember"]
    out["ProposedWinnerMember"] = review["CurrentBestMember"]
    out["EvidenceSummary"] = review.apply(lambda r: f"old={r.get('OldWinnerMember')}@{r.get('OldWinnerRate')} support={r.get('OldSupport')} | current_best={r.get('CurrentBestMember')}@{r.get('CurrentBestRate')} support={r.get('CurrentSupport')}", axis=1)
    out["Reason"] = review["RecommendedAction"]
    return out


def _v176_patch_template(proposed=None):
    cols = ["Approve","RuleID","RuleRow","TraitStack","PatchAction","OldWinnerMember","NewWinnerMember","DisableRule","Reason","ApprovedBy","ApprovedDate"]
    if proposed is None or not isinstance(proposed, pd.DataFrame) or proposed.empty:
        return pd.DataFrame(columns=cols)
    p = proposed.head(250).copy()
    out = pd.DataFrame()
    out["Approve"] = "NO"
    out["RuleID"] = p.get("RuleID", "")
    out["RuleRow"] = p.get("RuleRow", "")
    out["TraitStack"] = p.get("TraitStack", "")
    out["PatchAction"] = p.get("ProposedAction", "")
    out["OldWinnerMember"] = p.get("OldWinnerMember", "")
    out["NewWinnerMember"] = p.get("ProposedWinnerMember", "")
    out["DisableRule"] = "NO"
    out["Reason"] = p.get("EvidenceSummary", "")
    out["ApprovedBy"] = ""
    out["ApprovedDate"] = ""
    return out[cols]


def _v176_apply_patch_preview(sep, patch):
    if sep is None or sep.empty or patch is None or patch.empty:
        return sep.copy() if isinstance(sep, pd.DataFrame) else pd.DataFrame(), pd.DataFrame([{"PatchStatus":"NO_PATCHES_ACTIVE", "Applied":0}])
    out = sep.copy(); out.columns = [str(c).strip() for c in out.columns]
    winner_col = _v176_pick_col(out, ["winner_member", "WinnerMember", "winning_member", "member"], ["winner", "member"]) or "winner_member"
    if winner_col not in out.columns: out[winner_col] = ""
    applied=[]
    p = patch.copy(); p.columns = [str(c).strip() for c in p.columns]
    for _, r in p.iterrows():
        approve = str(r.get("Approve", "")).strip().upper() in {"YES","Y","TRUE","1"}
        if not approve: continue
        rule_row = pd.to_numeric(r.get("RuleRow", ""), errors="coerce")
        if pd.isna(rule_row): continue
        idx = int(rule_row) - 1
        if idx < 0 or idx >= len(out): continue
        if str(r.get("DisableRule", "")).strip().upper() in {"YES","Y","TRUE","1"}:
            out.loc[out.index[idx], "PatchDisabled"] = 1
            applied.append({"RuleRow":idx+1,"PatchApplied":"DISABLE_RULE"})
        elif _v176_to_member(r.get("NewWinnerMember", "")) in V176_MEMBERS:
            out.loc[out.index[idx], winner_col] = _v176_to_member(r.get("NewWinnerMember"))
            out.loc[out.index[idx], "PatchUpdatedWinnerMember"] = 1
            applied.append({"RuleRow":idx+1,"PatchApplied":"CHANGE_WINNER_MEMBER","NewWinnerMember":_v176_to_member(r.get("NewWinnerMember"))})
    patched = out[out.get("PatchDisabled",0).astype(str)!="1"].copy() if "PatchDisabled" in out.columns else out
    return patched, pd.DataFrame(applied) if applied else pd.DataFrame([{"PatchStatus":"NO_APPROVED_PATCH_ROWS", "Applied":0}])


def _v176_notes(truth_meta, truth_dist, truth_checks, sep_checks, sep_summary, sep_audit, proposed):
    lines=[]
    lines.append("CORE389 SUPPORT AUDIT LAB — v176")
    lines.append("Mode: AUDIT + PATCH PROPOSAL ONLY. No production files were replaced automatically.")
    lines.append("")
    lines.append("AUDIT TRUST STATUS")
    for label, df in [("Truth checks", truth_checks), ("Separator parse checks", sep_checks)]:
        if isinstance(df,pd.DataFrame) and not df.empty:
            bad = df[df["Status"].isin(["FAIL"])]
            lines.append(f"- {label}: {'PASS' if bad.empty else 'FAIL'}")
            for _,r in df.iterrows(): lines.append(f"  - {r.get('Check')}: {r.get('Status')} ({r.get('Detail','')})")
    lines.append("")
    if isinstance(truth_meta,pd.DataFrame) and not truth_meta.empty:
        lines.append("TRUTH / HISTORY EVIDENCE")
        for k,v in truth_meta.iloc[0].to_dict().items(): lines.append(f"- {k}: {v}")
    if isinstance(truth_dist,pd.DataFrame) and not truth_dist.empty:
        lines.append(""); lines.append("MEMBER DISTRIBUTION CHECK")
        for _,r in truth_dist.iterrows(): lines.append(f"- {r['Member']}: old={r['OldTruthCount']} current={r['CurrentHistoryCoreHitCount']} delta={r['DeltaCount']}")
    if isinstance(sep_summary,pd.DataFrame) and not sep_summary.empty:
        lines.append(""); lines.append("SEPARATOR RULE STATUS SUMMARY")
        for _,r in sep_summary.iterrows(): lines.append(f"- {r['Status']}: {r['RuleCount']} rules")
    if isinstance(proposed,pd.DataFrame):
        lines.append(""); lines.append(f"PROPOSED REVIEW/PATCH ITEMS: {len(proposed)}")
    if isinstance(sep_audit,pd.DataFrame) and not sep_audit.empty:
        focus = sep_audit[sep_audit["Status"].isin(["FLIPPED_REVIEW","WEAKENED_REVIEW","PARSE_OR_SCHEMA_REVIEW","INSUFFICIENT_CURRENT_SUPPORT"])].head(50)
        lines.append(""); lines.append("TOP REVIEW ITEMS")
        if focus.empty: lines.append("- None.")
        for _,r in focus.iterrows():
            lines.append(f"- Rule {r.get('RuleRow')} [{r.get('Status')}]: {r.get('TraitStack')} | old={r.get('OldWinnerMember')}@{r.get('OldWinnerRate')} | current best={r.get('CurrentBestMember')}@{r.get('CurrentBestRate')} | action={r.get('RecommendedAction')}")
    return "\n".join(lines)


