    if st.button("Run Trusted Support Audit — no replacement", type="primary", use_container_width=True, key="v176_run_audit"):
        hist_raw = _v176_load_any(hist_up) if hist_up is not None else (hist_default.copy() if isinstance(hist_default,pd.DataFrame) else pd.DataFrame())
        old_truth = _v176_load_any(truth_up) if truth_up is not None else (_v171_upload_to_df(truth_file_obj, ensure_truth) if truth_file_obj is not None else pd.DataFrame())
        old_sep = _v176_load_any(sep_up) if sep_up is not None else (_v171_upload_to_df(lib_file_obj, ensure_library) if lib_file_obj is not None else pd.DataFrame())
