# ============================================================
# v179 CALIBRATED SUPPORT AUDIT — PAIRWISE + ROLLING SUPPORT
# ============================================================
# Additive override only. Does NOT change daily engine, weights, ZLT, B2, RTE, SCL,
# printable logic, or production support files. It recalibrates the audit so it does
# not treat ~20 new wins as proof that hundreds of rules died.
# Key fixes:
# - audit each separator in the same pairwise universe style used by the deep separator builder
# - compare Old Truth universe, Full Current universe, and Equal-Size Rolling Current universe
# - use New-Wins/extra-history as warning context only, not a lifecycle killer
# - only proposes lifecycle movement; never deletes rules; inactive rules remain re-auditable

V179_BUILD_MARKER = "BUILD: core389_northern_lights__2026-06-16_v220_WINNER_FIT_AUDIT_LITE"


def _v181_norm_member(x):
    try:
        return _v176_to_member(x)
    except Exception:
        try:
            return normalize_member(x)
        except Exception:
            return ""


def _v181_prepare_truth_like_events(df: pd.DataFrame) -> pd.DataFrame:
    """Normalize old Truth/current transitions into the same event-like schema for rule evaluation."""
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return pd.DataFrame()
    out = df.copy()
    out.columns = [str(c).strip() for c in out.columns]

    # Current transition tables already have next_member and seed features.
    if "next_member" not in out.columns:
        member_col = _v176_pick_col(out, [
            "next_member", "NextMember", "WinningMember", "TrueMember", "WinnerMember",
            "winner_member", "Core389Member", "ActualMember", "CapturedMember", "Member"
        ], ["member", "winner", "true"])
        if member_col:
            out["next_member"] = out[member_col].map(_v181_norm_member)
        else:
            out["next_member"] = ""
    else:
        out["next_member"] = out["next_member"].map(_v181_norm_member)

    if "is_core389_hit" not in out.columns:
        out["is_core389_hit"] = out["next_member"].isin(V176_MEMBERS).astype(int)

    # Normalize date for sorting/window comparison.
    if "event_date" not in out.columns:
        date_col = _v176_pick_col(out, ["event_date", "EventDate", "Date", "date", "DrawDate", "draw_date"], ["date"])
        if date_col:
            out["event_date"] = pd.to_datetime(out[date_col], errors="coerce")
        else:
            out["event_date"] = pd.NaT
    else:
        out["event_date"] = pd.to_datetime(out["event_date"], errors="coerce")

    # Normalize seed, then add missing features used by separator trait stacks.
    if "seed" not in out.columns:
        seed_col = _v176_pick_col(out, ["seed", "Seed", "PrevSeed", "PreviousResult", "PrevResult", "LastResult", "feat_seed"], ["seed", "prev"])
        out["seed"] = out[seed_col] if seed_col else ""
    if "seed" in out.columns:
        try:
            out = _v174_add_deep_compat_features(out, "seed") if "_v174_add_deep_compat_features" in globals() else enrich_seed_features(out, "seed")
        except Exception:
            try:
                out = enrich_seed_features(out, "seed")
            except Exception:
                pass

    return out[out["next_member"].isin(V176_MEMBERS)].copy().reset_index(drop=True)


def _v181_pair_members(pair_text, fallback_member=""):
    """Return the exact two members named by a separator pair.

    v181 fix: the previous regex could read 3899/3889 as partial 389 tokens,
    which allowed impossible third-member flips such as a 3899_vs_3889 rule
    proposing 3389. This parser only accepts exact Core389 member tokens and
    common short aliases, then preserves pair order.
    """
    s = str(pair_text or "").strip()
    found = []

    # Prefer explicit 4-digit members. Negative lookarounds prevent partial matches.
    for tok in re.findall(r"(?<!\d)(3389|3899|3889)(?!\d)", s):
        m = _v181_norm_member(tok)
        if m in V176_MEMBERS and m not in found:
            found.append(m)

    # Fallback for compact/legacy pair forms like 25_vs_225 or 225>255.
    if len(found) < 2:
        alias_map = {"25": "3389", "225": "3899", "255": "3889"}
        for tok in re.findall(r"(?<!\d)(25|225|255)(?!\d)", s):
            m = alias_map.get(tok, "")
            if m in V176_MEMBERS and m not in found:
                found.append(m)

    if len(found) >= 2:
        return found[:2]

    fb = _v181_norm_member(fallback_member)
    if fb in V176_MEMBERS:
        # Ambiguous pair: return old winner + the other two, but mark later as ambiguous.
        # The evaluator will still never choose outside this returned set.
        return [fb] + [m for m in V176_MEMBERS if m != fb]
    return V176_MEMBERS[:]


def _v181_eval_rule(dataset: pd.DataFrame, trait: str, old_member: str, pair_members=None, min_support=1) -> dict:
    """Evaluate one separator rule strictly inside its pair universe.

    v181 fix: best_member/rates are calculated only over pair_members, never all
    three Core389 members. This blocks invalid third-member flips.
    """
    eval_members = [m for m in (pair_members or V176_MEMBERS) if m in V176_MEMBERS]
    if not eval_members:
        eval_members = V176_MEMBERS[:]
    if dataset is None or not isinstance(dataset, pd.DataFrame) or dataset.empty:
        return {"support":0, "best_member":"", "best_rate":0.0, "old_rate":0.0, "counts":{m:0 for m in V176_MEMBERS}, "missing":"empty_dataset", "eval_members":"|".join(eval_members)}
    work = dataset.copy()
    work = work[work["next_member"].isin(eval_members)].copy()
    conds = _v176_parse_conditions(str(trait))
    mask, missing = _v176_condition_mask(work, conds)
    sub = work[mask].copy()
    support = int(len(sub))
    counts_all = sub["next_member"].value_counts().reindex(V176_MEMBERS).fillna(0).astype(int).to_dict()
    counts_pair = {m: int(counts_all.get(m, 0)) for m in eval_members}
    invalid_third_count = int(sum(counts_all.get(m, 0) for m in V176_MEMBERS if m not in eval_members))
    if support:
        rates = {m: counts_pair.get(m, 0)/support for m in eval_members}
        best = max(rates, key=rates.get)
        best_rate = float(rates.get(best, 0.0))
        old_rate = float(rates.get(old_member, 0.0)) if old_member in eval_members else 0.0
    else:
        best=""; best_rate=0.0; old_rate=0.0
    return {"support":support, "best_member":best, "best_rate":best_rate, "old_rate":old_rate, "counts":counts_all, "pair_counts":counts_pair, "missing":missing, "eval_members":"|".join(eval_members), "invalid_third_count":invalid_third_count}


def _v181_make_rolling_universe(current_events: pd.DataFrame, old_n: int) -> pd.DataFrame:
    if current_events is None or not isinstance(current_events, pd.DataFrame) or current_events.empty:
        return pd.DataFrame()
    cur = current_events.copy()
    if "event_date" in cur.columns and pd.to_datetime(cur["event_date"], errors="coerce").notna().any():
        cur = cur.assign(_sort_date=pd.to_datetime(cur["event_date"], errors="coerce")).sort_values(["_sort_date"] + (["stream"] if "stream" in cur.columns else [])).drop(columns=["_sort_date"], errors="ignore")
    if old_n and old_n > 0 and len(cur) > old_n:
        return cur.tail(int(old_n)).copy().reset_index(drop=True)
    return cur.copy().reset_index(drop=True)


def _v181_audit_separator_calibrated(old_sep, old_truth, transitions, min_support=5, weaken_delta=0.08, flip_margin=0.05):
    """Pairwise calibrated separator audit.

    The old v176 audit recalculated current rate on all three members together, which can overstate drift.
    This version mirrors the original deep separator builder's pairwise comparison style.
    """
    if old_sep is None or not isinstance(old_sep, pd.DataFrame) or old_sep.empty or transitions is None or transitions.empty:
        return pd.DataFrame(), pd.DataFrame(), pd.DataFrame(), {}
    sep = old_sep.copy(); sep.columns = [str(c).strip() for c in sep.columns]
    parse_checks, meta = _v176_validate_separator(sep)
    trait_col = meta.get("trait_col") or "trait_stack"
    winner_col = meta.get("winner_col") or "winner_member"
    pair_col = meta.get("pair_col") or "pair"
    rate_col = _v176_pick_col(sep, ["winner_rate", "WinnerRate", "rate"], ["winner", "rate"])
    support_col = _v176_pick_col(sep, ["support", "Support"], ["support"])
    if trait_col not in sep.columns:
        return pd.DataFrame([{"Status":"PARSE_OR_SCHEMA_REVIEW", "EvalNote":"missing trait_stack"}]), pd.DataFrame(), parse_checks, meta
    if winner_col not in sep.columns:
        sep[winner_col] = ""
    if pair_col not in sep.columns:
        sep[pair_col] = ""

    old_events = _v181_prepare_truth_like_events(old_truth)
    current_events = _v181_prepare_truth_like_events(transitions)
    old_n = int(len(old_events)) if isinstance(old_events, pd.DataFrame) else 0
    rolling_events = _v181_make_rolling_universe(current_events, old_n)
    new_extra_n = max(0, int(len(current_events)) - old_n)
    new_tail_events = current_events.tail(new_extra_n).copy() if new_extra_n > 0 else pd.DataFrame()

    rows=[]
    for idx, r in sep.iterrows():
        trait = str(r.get(trait_col, ""))
        old_member = _v181_norm_member(r.get(winner_col, ""))
        pair_members = _v181_pair_members(r.get(pair_col, ""), old_member)
        file_support = pd.to_numeric(r.get(support_col, "") if support_col else "", errors="coerce")
        file_rate = pd.to_numeric(r.get(rate_col, "") if rate_col else "", errors="coerce")

        old_eval = _v181_eval_rule(old_events, trait, old_member, pair_members, min_support)
        full_eval = _v181_eval_rule(current_events, trait, old_member, pair_members, min_support)
        roll_eval = _v181_eval_rule(rolling_events, trait, old_member, pair_members, min_support)
        new_eval = _v181_eval_rule(new_tail_events, trait, old_member, pair_members, min_support) if not new_tail_events.empty else {"support":0,"best_member":"","best_rate":0.0,"old_rate":0.0,"counts":{m:0 for m in V176_MEMBERS},"missing":"no_incremental_window"}

        # Use recalculated old rate when available. Fall back to file rate if old truth cannot reproduce it.
        old_rate_ref = old_eval["old_rate"] if old_eval["support"] >= int(min_support) else (float(file_rate) if pd.notna(file_rate) else 0.0)
        old_support_ref = old_eval["support"] if old_eval["support"] else (int(file_support) if pd.notna(file_support) else 0)
        full_old_rate = full_eval["old_rate"]
        roll_old_rate = roll_eval["old_rate"]
        full_best = full_eval["best_member"]
        full_best_rate = full_eval["best_rate"]
        roll_best = roll_eval["best_member"]
        roll_best_rate = roll_eval["best_rate"]
        pairwise_valid = (full_best in pair_members or full_best == "") and (roll_best in pair_members or roll_best == "")
        pairwise_error = "" if pairwise_valid else f"PAIRWISE_ERROR_best_outside_pair full={full_best} rolling={roll_best} pair={pair_members}"

        delta_full = old_rate_ref - full_old_rate
        delta_roll = old_rate_ref - roll_old_rate
        missing = "; ".join([x for x in [old_eval.get("missing",""), full_eval.get("missing",""), roll_eval.get("missing",""), pairwise_error] if x])

        # Calibrated lifecycle status: full + rolling must agree before demotion.
        if pairwise_error:
            status="PAIRWISE_AUDIT_ERROR_BLOCKED"; action="Blocked: audit attempted a member outside the rule pair; do not patch."
        elif missing and "missing_col" in missing:
            status="PARSE_OR_SCHEMA_REVIEW"; action="Do not change; parser could not verify rule."
        elif full_eval["support"] < int(min_support) and roll_eval["support"] < int(min_support):
            status="INSUFFICIENT_CURRENT_SUPPORT"; action="Preserve and re-audit later; do not deactivate from low support alone."
        elif old_member and full_best and roll_best and full_best != old_member and roll_best != old_member and full_best_rate >= 0.60 and roll_best_rate >= 0.60 and (full_best_rate - full_old_rate) >= float(flip_margin):
            status="FLIPPED_REVIEW_CONFIRMED"; action="Manual review only; candidate patch after production-context test."
        elif full_old_rate >= 0.70 or roll_old_rate >= 0.70:
            status="STILL_HOLDS_STRONG"; action="Keep active; old member remains strong in full or rolling universe."
        elif full_old_rate >= 0.60 or roll_old_rate >= 0.60:
            status="STILL_HOLDS_MODERATE"; action="Keep active as a moderate vote; do not treat as a decision-maker."
        elif (full_old_rate < 0.55 and roll_old_rate < 0.55 and full_eval["support"] >= 15 and roll_eval["support"] >= 15):
            status="WEAK_BOTH_WINDOWS_REVIEW"; action="Candidate for weight reduction/inactive only after contribution test confirms no value."
        elif delta_full >= float(weaken_delta) or delta_roll >= float(weaken_delta):
            status="WEAKENED_MONITOR"; action="Monitor; not enough evidence for retirement."
        elif old_member and (full_best == old_member or roll_best == old_member):
            status="STILL_HOLDS"; action="Keep unchanged."
        else:
            status="REVIEW"; action="Manual review if high impact; otherwise preserve."

        rows.append({
            "RuleID": str(r.get("RuleID", r.get("rule_id", f"SEP_ROW_{idx+1}"))),
            "RuleRow":idx+1,
            "Pair":r.get(pair_col,""),
            "PairMembers":" vs ".join(pair_members),
            "TraitStack":trait,
            "OldWinnerMember":old_member,
            "FileOldSupport":int(file_support) if pd.notna(file_support) else "",
            "FileOldWinnerRate":float(file_rate) if pd.notna(file_rate) else "",
            "OldRecalcSupport":old_eval["support"],
            "OldRecalcOldMemberRate":round(old_eval["old_rate"],4),
            "FullCurrentSupport":full_eval["support"],
            "FullCurrentBestMember":full_best,
            "FullCurrentBestRate":round(full_best_rate,4),
            "FullCurrentOldMemberRate":round(full_old_rate,4),
            "RollingSupport":roll_eval["support"],
            "RollingBestMember":roll_best,
            "RollingBestRate":round(roll_best_rate,4),
            "RollingOldMemberRate":round(roll_old_rate,4),
            "NewExtraSupport":new_eval.get("support",0),
            "NewExtraBestMember":new_eval.get("best_member",""),
            "NewExtraBestRate":round(float(new_eval.get("best_rate",0.0)),4),
            "NewExtraOldMemberRate":round(float(new_eval.get("old_rate",0.0)),4),
            "DeltaFullOldMemberRate":round(delta_full,4),
            "DeltaRollingOldMemberRate":round(delta_roll,4),
            "CountFull_3389":full_eval["counts"].get("3389",0),
            "CountFull_3899":full_eval["counts"].get("3899",0),
            "CountFull_3889":full_eval["counts"].get("3889",0),
            "Status":status,
            "RecommendedAction":action,
            "EvalNote":missing,
        })
    audit=pd.DataFrame(rows)
    summary=audit.groupby("Status").size().rename("RuleCount").reset_index().sort_values("RuleCount",ascending=False) if not audit.empty else pd.DataFrame()
    meta.update({"old_truth_events":old_n, "current_core_events":int(len(current_events)), "rolling_events":int(len(rolling_events)), "new_extra_events":int(new_extra_n), "audit_method":"v181_pairwise_full_plus_rolling"})
    extra_checks = pd.DataFrame([
        {"Check":"Audit calibration method", "Status":"PASS", "Detail":"Pairwise support + old/full/rolling comparison"},
        {"Check":"Old Truth event count", "Status":"PASS" if old_n>0 else "FAIL", "Detail":str(old_n)},
        {"Check":"Current Core389 hit count", "Status":"PASS" if len(current_events)>0 else "FAIL", "Detail":str(len(current_events))},
        {"Check":"New extra Core389 hits vs old truth", "Status":"INFO", "Detail":str(new_extra_n)},
        {"Check":"Lifecycle safety", "Status":"PASS", "Detail":"New-extra-only results are warning context; rules are not retired from incremental window alone."},
        {"Check":"Pairwise third-member flip block", "Status":"PASS", "Detail":"v181: best_member is restricted to the two members named in PairMembers; invalid third-member flips are blocked."},
    ])
    parse_checks = pd.concat([parse_checks, extra_checks], ignore_index=True)
    return audit, summary, parse_checks, meta


def _v181_separator_contribution_audit(old_sep, old_truth, transitions, sep_audit=None, max_rules=1000):
    """Conservative contribution audit.

    Keeps leave-one-rule-out as context, but lifecycle uses pairwise calibrated rate audit too.
    This prevents overlapping rules from being mass-retired simply because removing one rule
    rarely changes the final separator-only prediction.
    """
    contrib, details = _v177_separator_contribution_audit(old_sep, transitions, max_rules=max_rules)
    if contrib is None or not isinstance(contrib, pd.DataFrame) or contrib.empty:
        return contrib, details
    if isinstance(sep_audit, pd.DataFrame) and not sep_audit.empty:
        merge_cols = [c for c in ["RuleID","RuleRow","Status","FullCurrentOldMemberRate","RollingOldMemberRate","FullCurrentSupport","RollingSupport","PairMembers"] if c in sep_audit.columns]
        if "RuleRow" in merge_cols:
            contrib = contrib.merge(sep_audit[merge_cols].drop_duplicates("RuleRow"), on="RuleRow", how="left", suffixes=("", "_RateAudit"))
    # Reclassify with calibrated rates + contribution. Keep 60/40 as a vote, 70+ as strong.
    recs=[]; tiers=[]
    for _, r in contrib.iterrows():
        net = pd.to_numeric(r.get("LOO_NetContribution",0), errors="coerce")
        helped = pd.to_numeric(r.get("LOO_Helped",0), errors="coerce")
        harmed = pd.to_numeric(r.get("LOO_Harmed",0), errors="coerce")
        fires = pd.to_numeric(r.get("FiredEvents",0), errors="coerce")
        full_rate = pd.to_numeric(r.get("FullCurrentOldMemberRate", np.nan), errors="coerce")
        roll_rate = pd.to_numeric(r.get("RollingOldMemberRate", np.nan), errors="coerce")
        best_rate = max([x for x in [full_rate, roll_rate] if pd.notna(x)] or [pd.to_numeric(r.get("DirectAccuracy",0), errors="coerce")])
        status = str(r.get("Status", ""))
        if status == "FLIPPED_REVIEW_CONFIRMED":
            life="MANUAL_REVIEW_FLIP_CONFIRMED"; tier="REVIEW_ONLY_NO_AUTO_CHANGE"
        elif pd.notna(net) and net > 0:
            life="KEEP_CONTRIBUTES"; tier="CONTRIBUTING_KEEP_ACTIVE"
        elif pd.notna(best_rate) and best_rate >= 0.70 and fires >= 10:
            life="ACTIVE_STRONG"; tier="FULL_WEIGHT_70_PLUS"
        elif pd.notna(best_rate) and best_rate >= 0.60 and fires >= 10:
            life="ACTIVE_MODERATE"; tier="MODERATE_VOTE_60_69"
        elif pd.notna(best_rate) and best_rate >= 0.55 and fires >= 10:
            life="WEAK_MONITOR"; tier="WEAK_VOTE_55_59"
        elif (pd.notna(net) and net < 0 and pd.notna(harmed) and harmed >= 2 and pd.notna(best_rate) and best_rate < 0.55):
            life="INACTIVE_CANDIDATE_AFTER_REVIEW"; tier="PRESERVE_INACTIVE_REAUDIT"
        elif fires >= 15 and pd.notna(best_rate) and best_rate < 0.55:
            life="WEAK_BOTH_WINDOWS_MONITOR"; tier="POSSIBLE_INACTIVE_NEEDS_REVIEW"
        else:
            life="LOW_SUPPORT_OR_NEUTRAL_MONITOR"; tier="PRESERVE_MONITOR"
        recs.append(life); tiers.append(tier)
    contrib["LifecycleRecommendation_v179"] = recs
    contrib["WeightTierSuggestion_v179"] = tiers
    # Keep old columns but make visible recommendation the calibrated one.
    contrib["LifecycleRecommendation"] = contrib["LifecycleRecommendation_v179"]
    contrib["WeightTierSuggestion"] = contrib["WeightTierSuggestion_v179"]
    return contrib, details


def _v181_make_proposed_changes(sep_audit, contrib=None):
    if sep_audit is None or not isinstance(sep_audit, pd.DataFrame) or sep_audit.empty:
        base = pd.DataFrame()
    else:
        review_statuses = ["FLIPPED_REVIEW_CONFIRMED", "WEAK_BOTH_WINDOWS_REVIEW", "PARSE_OR_SCHEMA_REVIEW", "INSUFFICIENT_CURRENT_SUPPORT", "REVIEW"]
        review = sep_audit[sep_audit["Status"].isin(review_statuses)].copy()
        base = pd.DataFrame()
        if not review.empty:
            base["Approve"] = "NO"
            base["RuleID"] = review.get("RuleID", "")
            base["RuleRow"] = review["RuleRow"]
            base["TraitStack"] = review["TraitStack"]
            base["CurrentAction"] = review["Status"]
            def _pa(s):
                if s == "FLIPPED_REVIEW_CONFIRMED": return "CHANGE_WINNER_MEMBER_REVIEW_ONLY"
                if s == "WEAK_BOTH_WINDOWS_REVIEW": return "WEAKEN_OR_INACTIVE_REVIEW_ONLY"
                return "NO_CHANGE_REVIEW"
            base["ProposedAction"] = review["Status"].map(_pa)
            base["OldWinnerMember"] = review["OldWinnerMember"]
            base["ProposedWinnerMember"] = review.get("FullCurrentBestMember", "")
            base["EvidenceSummary"] = review.apply(lambda r: f"pair={r.get('PairMembers')} | old_recalc={r.get('OldRecalcOldMemberRate')} support={r.get('OldRecalcSupport')} | full_old_rate={r.get('FullCurrentOldMemberRate')} support={r.get('FullCurrentSupport')} | rolling_old_rate={r.get('RollingOldMemberRate')} support={r.get('RollingSupport')} | new_extra_old_rate={r.get('NewExtraOldMemberRate')} support={r.get('NewExtraSupport')}", axis=1)
            base["Reason"] = review["RecommendedAction"]
    if contrib is None or not isinstance(contrib, pd.DataFrame) or contrib.empty:
        return base
    c = contrib.copy()
    review_life = ["MANUAL_REVIEW_FLIP_CONFIRMED", "INACTIVE_CANDIDATE_AFTER_REVIEW", "WEAK_BOTH_WINDOWS_MONITOR", "KEEP_CONTRIBUTES", "ACTIVE_MODERATE"]
    c = c[c["LifecycleRecommendation"].isin(review_life)].copy()
    out = pd.DataFrame()
    if not c.empty:
        out["Approve"] = "NO"
        out["RuleID"] = c["RuleID"]
        out["RuleRow"] = c["RuleRow"]
        out["TraitStack"] = c["TraitStack"]
        out["CurrentAction"] = c["LifecycleRecommendation"]
        def action_for(life):
            if life == "MANUAL_REVIEW_FLIP_CONFIRMED": return "MANUAL_REVIEW_CHANGE_WINNER"
            if life == "INACTIVE_CANDIDATE_AFTER_REVIEW": return "MOVE_TO_INACTIVE_AFTER_APPROVAL"
            if life == "WEAK_BOTH_WINDOWS_MONITOR": return "MONITOR_OR_REDUCE_WEIGHT"
            if life == "ACTIVE_MODERATE": return "KEEP_ACTIVE_MODERATE_VOTE"
            return "KEEP_ACTIVE_CONTRIBUTES"
        out["ProposedAction"] = c["LifecycleRecommendation"].map(action_for)
        out["OldWinnerMember"] = c["OldWinnerMember"]
        out["ProposedWinnerMember"] = c["OldWinnerMember"]
        out["EvidenceSummary"] = c.apply(lambda r: f"fires={r.get('FiredEvents')} direct_acc={r.get('DirectAccuracy')} full_rate={r.get('FullCurrentOldMemberRate')} rolling_rate={r.get('RollingOldMemberRate')} helped={r.get('LOO_Helped')} harmed={r.get('LOO_Harmed')} net={r.get('LOO_NetContribution')} tier={r.get('WeightTierSuggestion')}", axis=1)
        out["Reason"] = "v179 calibrated pairwise + rolling + contribution audit; preserve forever, do not delete."
    if base.empty:
        return out
    if out.empty:
        return base
    merged = pd.concat([base, out], ignore_index=True)
    return merged.drop_duplicates(subset=["RuleRow", "ProposedAction"], keep="first")


def _v181_notes(truth_meta, truth_dist, truth_checks, sep_checks, sep_summary, sep_audit, proposed, contrib=None):
    lines=[]
    lines.append("CORE389 SUPPORT AUDIT LAB — v179")
    lines.append("Mode: CALIBRATED AUDIT + LIFECYCLE PROPOSAL ONLY. No production files were replaced automatically.")
    lines.append("Calibration: pairwise separator support, old Truth vs full current vs equal-size rolling current. New-extra-only evidence is warning context only.")
    lines.append("")
    if isinstance(truth_checks, pd.DataFrame):
        lines.append("TRUTH CHECKS")
        for _, r in truth_checks.iterrows():
            lines.append(f"- {r.get('Check')}: {r.get('Status')} ({r.get('Detail')})")
        lines.append("")
    if isinstance(sep_checks, pd.DataFrame):
        lines.append("SEPARATOR / AUDIT CALIBRATION CHECKS")
        for _, r in sep_checks.iterrows():
            lines.append(f"- {r.get('Check')}: {r.get('Status')} ({r.get('Detail')})")
        lines.append("")
    if isinstance(truth_meta, pd.DataFrame) and not truth_meta.empty:
        lines.append("TRUTH / HISTORY EVIDENCE")
        for k, v in truth_meta.iloc[0].to_dict().items():
            lines.append(f"- {k}: {v}")
        lines.append("")
    if isinstance(truth_dist, pd.DataFrame) and not truth_dist.empty:
        lines.append("MEMBER DISTRIBUTION CHECK")
        for _, r in truth_dist.iterrows():
            lines.append(f"- {r.get('Member')}: old={r.get('OldTruthCount')} current={r.get('CurrentHistoryCoreHitCount')} delta={r.get('DeltaCount')}")
        lines.append("")
    if isinstance(sep_summary, pd.DataFrame) and not sep_summary.empty:
        lines.append("CALIBRATED SEPARATOR STATUS SUMMARY")
        for _, r in sep_summary.iterrows():
            lines.append(f"- {r.get('Status')}: {int(r.get('RuleCount',0))} rules")
        lines.append("")
    if isinstance(contrib, pd.DataFrame) and not contrib.empty:
        lines.append("CONTRIBUTION / LIFECYCLE SUMMARY")
        summ = contrib.groupby("LifecycleRecommendation").size().rename("RuleCount").reset_index().sort_values("RuleCount", ascending=False)
        for _, r in summ.iterrows():
            lines.append(f"- {r['LifecycleRecommendation']}: {int(r['RuleCount'])} rules")
        lines.append("")
        lines.append("TOP POSITIVE CONTRIBUTORS")
        for _, r in contrib.sort_values(["LOO_NetContribution", "LOO_Helped"], ascending=[False, False]).head(20).iterrows():
            lines.append(f"- {r.get('RuleID')} row {r.get('RuleRow')}: net={r.get('LOO_NetContribution')} helped={r.get('LOO_Helped')} harmed={r.get('LOO_Harmed')} fires={r.get('FiredEvents')} direct_acc={r.get('DirectAccuracy')} full_rate={r.get('FullCurrentOldMemberRate')} rolling_rate={r.get('RollingOldMemberRate')} | {r.get('TraitStack')}")
        lines.append("")
    if isinstance(proposed, pd.DataFrame):
        lines.append(f"PROPOSED REVIEW/PATCH ITEMS: {len(proposed)}")
        lines.append("These are review proposals only. Apply by approved overlay; do not overwrite the production separator.")
    lines.append("")
    lines.append("RULE PRESERVATION POLICY")
    lines.append("- No separator rule is deleted by audit.")
    lines.append("- Weak/dead rules move to inactive/weak libraries only after approved overlay and remain eligible for future reactivation audits.")
    lines.append("- New-extra-only evidence does not deactivate rules.")
    return "\n".join(lines)



# ================================
# v182 AUDIT CLOCK / UPLOAD-ONLY PRODUCTION SUPPORT GOVERNANCE
# ================================
def _v182_date_today():
    try:
        return pd.Timestamp.today().normalize()
    except Exception:
        return pd.Timestamp.now().normalize()

def _v182_parse_audit_status_upload(uploaded):
    """Load optional audit_status CSV/JSON/TXT exported by this app."""
    if uploaded is None:
        return {}
    try:
        raw = _v105_upload_bytes(uploaded)
        name = _v105_upload_name(uploaded, "audit_status.json").lower()
        txt = raw.decode("utf-8", errors="ignore") if isinstance(raw, (bytes, bytearray)) else str(raw)
        if name.endswith(".json"):
            import json
            obj = json.loads(txt)
            return obj if isinstance(obj, dict) else {}
        df = pd.read_csv(io.BytesIO(raw)) if not name.endswith(".txt") else pd.read_csv(io.StringIO(txt), sep=None, engine="python")
        if isinstance(df, pd.DataFrame) and not df.empty:
            row = df.iloc[0].to_dict()
            return {str(k): ("" if pd.isna(v) else v) for k, v in row.items()}
    except Exception:
        return {}
    return {}

def _v182_core389_hit_count(hist_df):
    try:
        if hist_df is None or not isinstance(hist_df, pd.DataFrame) or hist_df.empty:
            return 0
        h = hist_df.copy()
        if "Core389Member" in h.columns:
            return int(h["Core389Member"].astype(str).str.strip().isin(MEMBERS + ["25","225","255"]).sum())
        if "Result" in h.columns:
            return int(h["Result"].apply(result_to_core389_member).astype(str).str.strip().isin(MEMBERS).sum())
    except Exception:
        pass
    return 0

def _v182_status_dict_to_df(status: dict) -> pd.DataFrame:
    if not isinstance(status, dict) or not status:
        return pd.DataFrame()
    return pd.DataFrame([{k: v for k, v in status.items()}])

def _v182_json_bytes(status: dict) -> bytes:
    import json
    return json.dumps(status, indent=2, default=str).encode("utf-8")

def _v182_compute_audit_clock(status: dict, hist_df=None) -> tuple[pd.DataFrame, str]:
    today = _v182_date_today()
    last_raw = status.get("LastAuditDate") or status.get("AuditDate") or status.get("audit_date") or ""
    last_dt = pd.to_datetime(last_raw, errors="coerce") if last_raw else pd.NaT
    audit_hits = pd.to_numeric(pd.Series([status.get("AuditCore389Hits") or status.get("CurrentCore389Hits") or status.get("AuditHitCount") or np.nan]), errors="coerce").iloc[0]
    current_hits = _v182_core389_hit_count(hist_df)
    days = None if pd.isna(last_dt) else int((today - pd.Timestamp(last_dt).normalize()).days)
    new_hits = None if pd.isna(audit_hits) else int(current_hits - int(audit_hits))
    next_due = "" if pd.isna(last_dt) else (pd.Timestamp(last_dt).normalize() + pd.Timedelta(days=90)).date().isoformat()
    if pd.isna(last_dt):
        audit_status = "NO AUDIT STAMP LOADED"
    elif days is not None and days >= 90:
        audit_status = "RED — AUDIT DUE"
    elif new_hits is not None and new_hits >= 25:
        audit_status = "YELLOW — EARLY AUDIT RECOMMENDED BY NEW WINS"
    elif days is not None and days >= 75:
        audit_status = "YELLOW — AUDIT WINDOW APPROACHING"
    else:
        audit_status = "GREEN — AUDIT NOT YET NEEDED"
    rows = [
        {"Metric":"Last Audit Date", "Value": "" if pd.isna(last_dt) else pd.Timestamp(last_dt).date().isoformat()},
        {"Metric":"Next 90-Day Audit Due", "Value": next_due},
        {"Metric":"Days Since Audit", "Value": "" if days is None else days},
        {"Metric":"Core389 Hits At Audit", "Value": "" if pd.isna(audit_hits) else int(audit_hits)},
        {"Metric":"Current Core389 Hits In Loaded History", "Value": current_hits},
        {"Metric":"New Core389 Wins Since Audit", "Value": "" if new_hits is None else new_hits},
        {"Metric":"Audit Trigger", "Value": "90 days OR 25+ new Core389 wins"},
        {"Metric":"Audit Status", "Value": audit_status},
        {"Metric":"Production Support Rule", "Value": "Daily engine uses sidebar-uploaded Truth/Separator only"},
    ]
    return pd.DataFrame(rows), audit_status

def _v182_make_audit_stamp(truth_meta=None, sep_audit=None, contrib=None, hist_df=None, decision="NO_PATCH_FREEZE_PRODUCTION") -> dict:
    today = _v182_date_today().date().isoformat()
    current_hits = _v182_core389_hit_count(hist_df)
    truth_rows = ""
    try:
        if isinstance(truth_meta, pd.DataFrame) and not truth_meta.empty and "Metric" in truth_meta.columns and "Value" in truth_meta.columns:
            m = dict(zip(truth_meta["Metric"].astype(str), truth_meta["Value"]))
            truth_rows = m.get("OldTruthRows", m.get("CurrentCore389Hits", ""))
    except Exception:
        pass
    sep_rules = int(len(sep_audit)) if isinstance(sep_audit, pd.DataFrame) else ""
    contrib_rules = int(len(contrib)) if isinstance(contrib, pd.DataFrame) else ""
    return {
        "AuditSystemVersion": "v182_AUDIT_CLOCK_UPLOAD_ONLY_SUPPORT_FREEZE",
        "LastAuditDate": today,
        "NextAuditDueDate": (pd.Timestamp(today) + pd.Timedelta(days=90)).date().isoformat(),
        "AuditCore389Hits": int(current_hits),
        "TruthRowsAtAudit": truth_rows,
        "SeparatorRulesAudited": sep_rules,
        "ContributionRulesAudited": contrib_rules,
        "ProductionDecision": decision,
        "TruthProductionSource": "sidebar uploaded Truth only",
        "SeparatorProductionSource": "sidebar uploaded Separator only",
        "PatchApplied": "NO",
        "AutoReplaceAllowed": "NO",
        "GeneratedSupportAutoActivation": "NO",
        "Notes": "Production Truth/Separator remain unchanged. Future accepted changes must be downloaded and re-uploaded in the sidebar. Re-audit at 90 days or 25+ new Core389 wins."
    }

def _v182_render_audit_clock_panel(hist_df=None):
    st.subheader("v182 Truth/Separator Audit Clock — upload-only production lock")
    st.caption("Production support is intentionally boring: the daily engine only uses the Truth and Separator files uploaded in the sidebar. Generated files are download/re-upload only.")
    up = st.file_uploader("Optional: upload prior audit_status.json/csv to restore the 90-day audit clock", type=["json","csv","txt"], key="v182_audit_status_upload")
    uploaded_status = _v182_parse_audit_status_upload(up)
    session_status = st.session_state.get("v182_audit_status", {})
    status = uploaded_status or session_status
    clock, audit_status = _v182_compute_audit_clock(status, hist_df)
    if not status:
        st.warning("No audit stamp loaded yet. After tonight's audit/freeze, download audit_status.json and keep it with your production Truth/Separator files.")
    elif str(audit_status).startswith("GREEN"):
        st.success(audit_status)
    elif str(audit_status).startswith("YELLOW"):
        st.warning(audit_status)
    else:
        st.error(audit_status)
    if isinstance(clock, pd.DataFrame) and not clock.empty:
        st.dataframe(clock, use_container_width=True, hide_index=True)
    if status:
        c1, c2 = st.columns(2)
        with c1:
            st.download_button("Download audit_status.json", _v182_json_bytes(status), "core389_audit_status_v182.json", "application/json", use_container_width=True, key="v182_dl_audit_status_json")
        with c2:
            st.download_button("Download audit_status.csv", _v176_csv_bytes(_v182_status_dict_to_df(status)), "core389_audit_status_v182.csv", "text/csv", use_container_width=True, key="v182_dl_audit_status_csv")

def _v181_render_support_audit_lab(hist_default=None, truth_file_obj=None, lib_file_obj=None):
    st.divider()
    st.subheader("v181 Support Audit Lab — pairwise-safe calibrated audit")
    st.caption("Audit/revise only. Production Truth/Separator are not replaced. Rules are preserved forever; weak rules can move to inactive libraries and be re-audited later.")
    st.info("v181 fixes the third-member flip bug and preserves the v179 overreaction protection: it uses original-style pairwise support and compares old Truth, full current, and equal-size rolling current. New-extra-only evidence is context, not a rule killer.")
    c1,c2,c3 = st.columns(3)
    with c1:
        hist_up = st.file_uploader("Audit history override optional", type=["csv","txt","tsv","xlsx","xls"], key="v181_hist_upload")
    with c2:
        truth_up = st.file_uploader("Truth override optional", type=["csv","txt","tsv","xlsx","xls"], key="v181_truth_upload")
    with c3:
        sep_up = st.file_uploader("Separator override optional", type=["csv","txt","tsv","xlsx","xls"], key="v181_sep_upload")
    patch_up = st.file_uploader("Optional approved patch overlay CSV/TXT", type=["csv","txt","tsv","xlsx","xls"], key="v181_patch_upload")
