# ================================
# v146 WALK-FORWARD WINNER COMMONALITY SUMMARY
# Additive reporting only. Does not change ranking, stream selection, member picks, depth, rescues, or scoring.
# ================================
def _v146_numeric_rank(df, *cols):
    for c in cols:
        if isinstance(df, pd.DataFrame) and c in df.columns:
            return pd.to_numeric(df[c], errors="coerce")
    return pd.Series(np.nan, index=df.index if isinstance(df, pd.DataFrame) else [])

def _v146_winner_flag(df: pd.DataFrame) -> pd.Series:
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return pd.Series(dtype=bool)
    top1 = pd.to_numeric(df.get("Top1_Correct", 0), errors="coerce").fillna(0).eq(1)
    needed = pd.to_numeric(df.get("Needed_Top2", 0), errors="coerce").fillna(0).eq(1)
    miss = pd.to_numeric(df.get("Miss", 0), errors="coerce").fillna(0).eq(1)
    if "PlayType" in df.columns:
        top2_played = df["PlayType"].astype(str).isin(["TOP1_TOP2", "TOP1_TOP2_TOP3"])
        top3_played = df["PlayType"].astype(str).eq("TOP1_TOP2_TOP3")
        return top1 | (needed & top2_played) | (miss & top3_played)
    return top1 | needed

def _v146_bucket_movement(x):
    try:
        v = float(x)
    except Exception:
        return "unknown"
    if pd.isna(v): return "unknown"
    if v <= -40: return "moved up 40+"
    if v <= -21: return "moved up 21-40"
    if v <= -11: return "moved up 11-20"
    if v <= -1: return "moved up 1-10"
    if v == 0: return "unchanged"
    if v <= 10: return "moved down 1-10"
    if v <= 20: return "moved down 11-20"
    if v <= 40: return "moved down 21-40"
    return "moved down 40+"

def _v146_render_winner_commonality_panel(res: pd.DataFrame):
    if res is None or not isinstance(res, pd.DataFrame) or res.empty:
        return
    st.subheader("v146 Winner Commonality / Movement Analysis")
    st.caption("Additive analysis only: finds traits shared by captured winners. It does not change rank, stream reduction, play depth, members, rescues, or scoring.")
    out = res.copy()
    out["v146_WinnerCaptured"] = _v146_winner_flag(out)
    winners = out[out["v146_WinnerCaptured"]].copy()
    if winners.empty:
        st.info("No captured winners available in the current Walk-forward Lab output.")
        return
    out["v146_StreamRank"] = _v146_numeric_rank(out, "StreamRank_COMPARE_FIRST", "StreamRank", "rank")
    out["v146_PctRank"] = _v146_numeric_rank(out, "PctRank_COMPARE_FIRST", "SingleRowHistoricalRank_v139", "SingleRow", "RowPercentile")
    out["v146_HybridRank"] = _v146_numeric_rank(out, "HybridRank_COMPARE_FIRST", "HybridFinalRank_v139", "FinalDynamicStreamRank_v135", "DynamicOrder")
    out["v146_MovementVsStream"] = out["v146_HybridRank"] - out["v146_StreamRank"]
    out["v146_MovementBucket"] = out["v146_MovementVsStream"].map(_v146_bucket_movement)
    winners = out[out["v146_WinnerCaptured"]].copy()

    c1, c2, c3, c4 = st.columns(4)
    c1.metric("Captured winners analyzed", f"{len(winners):,}")
    c2.metric("Median StreamRank", "" if winners["v146_StreamRank"].dropna().empty else int(winners["v146_StreamRank"].median()))
    c3.metric("Median PctRank", "" if winners["v146_PctRank"].dropna().empty else int(winners["v146_PctRank"].median()))
    c4.metric("Median HybridRank", "" if winners["v146_HybridRank"].dropna().empty else int(winners["v146_HybridRank"].median()))

    if winners["v146_MovementBucket"].ne("unknown").any():
        movement = winners.groupby("v146_MovementBucket", dropna=False).size().reset_index(name="CapturedWinnerCount")
        movement["CapturedWinnerPct"] = (movement["CapturedWinnerCount"] / len(winners) * 100).round(2)
        order = ["moved up 40+","moved up 21-40","moved up 11-20","moved up 1-10","unchanged","moved down 1-10","moved down 11-20","moved down 21-40","moved down 40+","unknown"]
        movement["_order"] = movement["v146_MovementBucket"].map({v:i for i,v in enumerate(order)}).fillna(999)
        movement = movement.sort_values("_order").drop(columns=["_order"])
        st.write("**Captured winners by Hybrid movement vs StreamRank**")
        st.dataframe(movement, use_container_width=True, hide_index=True)
    else:
        st.info("Movement buckets need HybridRank and StreamRank columns in the Walk-forward result. This run can still report other commonalities.")

    for label, col in [
        ("PlayType", "PlayType"),
        ("RecommendedStream", "RecommendedStream"),
        ("StreamTier", "StreamTier"),
        ("SingleRow", "SingleRow"),
        ("RowBucket10", "RowBucket10"),
    ]:
        if col in winners.columns:
            t = winners.groupby(col, dropna=False).size().reset_index(name="CapturedWinnerCount")
            t["CapturedWinnerPct"] = (t["CapturedWinnerCount"] / len(winners) * 100).round(2)
            t = t.sort_values(["CapturedWinnerCount"], ascending=False).head(25)
            st.write(f"**Top captured-winner commonalities by {label}**")
            st.dataframe(t, use_container_width=True, hide_index=True)

    st.session_state["v146_winner_commonality_events"] = winners
    st.download_button(
        "Download v146 Winner Commonality Events CSV",
        winners.to_csv(index=False).encode("utf-8"),
        file_name="core389_v146_winner_commonality_events.csv",
        mime="text/csv",
        use_container_width=True,
        key="download_v146_winner_commonality_events_csv",
    )
    st.download_button(
        "Download v146 Winner Commonality Events TXT",
        winners.to_csv(index=False, sep="\t").encode("utf-8"),
        file_name="core389_v146_winner_commonality_events.txt",
        mime="text/plain",
        use_container_width=True,
        key="download_v146_winner_commonality_events_txt",
    )


# v153: Full-universe winner vs non-winner trait mining.
# Additive analysis only: does not change ranking, scoring, stream reduction, play depth, member logic, or rescue logic.
def _v153_safe_numeric(s):
    try:
        return pd.to_numeric(s, errors="coerce")
    except Exception:
        return pd.Series(dtype=float)


def _v153_bin_numeric(series: pd.Series, col: str) -> pd.Series:
    vals = pd.to_numeric(series, errors="coerce")
    if vals.dropna().empty:
        return vals.astype(object).where(vals.notna(), "missing")
    # Rank-like columns: lower is better, so fixed operational buckets are easier to audit.
    lower_col = str(col).lower()
    if any(k in lower_col for k in ["rank", "playorder", "singlerow", "streamrank", "hybridrank", "pctrank"]):
        bins = [-float("inf"), 5, 10, 20, 30, 40, 50, 60, 78, float("inf")]
        labels = ["001-005", "006-010", "011-020", "021-030", "031-040", "041-050", "051-060", "061-078", "079+"]
        return pd.cut(vals, bins=bins, labels=labels, include_lowest=True).astype(object).where(vals.notna(), "missing")
    if "movement" in lower_col:
        return vals.map(_v146_bucket_movement if "_v146_bucket_movement" in globals() else lambda x: "unknown")
    # General numeric columns: use quartiles when useful; otherwise exact values.
    uniq = vals.dropna().nunique()
    if uniq <= 12:
        return vals.astype("Int64").astype(str).where(vals.notna(), "missing")
    try:
        q = pd.qcut(vals.rank(method="first"), q=4, labels=["Q1_low", "Q2", "Q3", "Q4_high"])
        return q.astype(object).where(vals.notna(), "missing")
    except Exception:
        return vals.round(2).astype(str).where(vals.notna(), "missing")


def _v153_build_trait_comparison(res: pd.DataFrame):
    if res is None or not isinstance(res, pd.DataFrame) or res.empty:
        empty_cols = ["TraitColumn", "TraitValue", "WinnerCount", "WinnerPct", "NonWinnerCount", "NonWinnerPct", "WinnerMinusNonWinnerPct", "WinnerLift", "SignalUse"]
        return pd.DataFrame(columns=empty_cols), pd.DataFrame(), pd.DataFrame(), pd.DataFrame()
    df = res.copy()
    if "Core389WinnerEvent" in df.columns:
        winner_mask = pd.to_numeric(df["Core389WinnerEvent"], errors="coerce").fillna(0).astype(int).eq(1)
    else:
        winner_mask = _v146_winner_flag(df) if "_v146_winner_flag" in globals() else pd.Series(False, index=df.index)
    df["v153_Core389Winner"] = winner_mask
    df["v153_NonWinner"] = ~winner_mask
    if "PlayType" in df.columns:
        top2_played = df["PlayType"].astype(str).isin(["TOP1_TOP2", "TOP1_TOP2_TOP3"])
        top3_played = df["PlayType"].astype(str).eq("TOP1_TOP2_TOP3")
    else:
        top2_played = pd.Series(False, index=df.index)
        top3_played = pd.Series(False, index=df.index)
    top1 = pd.to_numeric(df.get("Top1_Correct", 0), errors="coerce").fillna(0).astype(int).eq(1)
    needed = pd.to_numeric(df.get("Needed_Top2", 0), errors="coerce").fillna(0).astype(int).eq(1)
    miss = pd.to_numeric(df.get("Miss", 0), errors="coerce").fillna(0).astype(int).eq(1)
    df["v153_OperationalCaptured"] = winner_mask & (top1 | (needed & top2_played) | (miss & top3_played))
    df["v153_OperationalMissed"] = winner_mask & ~df["v153_OperationalCaptured"]

    candidate_cols = [
        "v152_MovementBucket", "v152_MovementVsStream", "v152_StreamRank", "v152_PctRank", "v152_HybridRank",
        "StreamRank_COMPARE_FIRST", "PctRank_COMPARE_FIRST", "HybridRank_COMPARE_FIRST",
        "KeptStreamFlag", "KeptStreamAdvisory", "RecommendedStream", "StreamTier", "SingleRow", "RowBucket10", "RowPercentile",
        "PlayType", "RowPlayType", "RowPlayTypeReason", "Top2Decision", "Top2Zone", "Top2RiskScore", "Top3Rescue", "Top3RescueScore", "Top3RescueReasons",
        "PredictedMember", "Top2_pred", "ThirdMember", "RecommendedPlay", "TrueMember",
        "seed_sum", "seed_spread", "seed_even_cnt", "seed_high_cnt", "seed_low_cnt", "seed_has9", "seed_has0",
        "seed_parity_pattern", "seed_highlow_pattern", "seed_repeat_shape", "sum_bucket", "spread_bucket",
        "structure", "unique", "max_rep", "consec_links", "pair", "even", "odd", "high", "low", "parity_pattern", "highlow_pattern",
        "ModelConfidenceScore", "UniversalFamilyScore", "RowStrengthScore", "FamilyHitDensityScore", "MissOutlierRiskScore",
    ]
    rows = []
    total_w = int(winner_mask.sum())
    total_nw = int((~winner_mask).sum())
    for col in candidate_cols:
        if col not in df.columns:
            continue
        vals = df[col]
        if pd.api.types.is_numeric_dtype(vals) or col.lower().endswith("rank") or "Rank" in col or "Score" in col or "movement" in col.lower():
            trait_vals = _v153_bin_numeric(vals, col)
        else:
            trait_vals = vals.astype(str).replace({"nan": "missing", "None": "missing", "": "missing"}).fillna("missing")
        tmp = pd.DataFrame({"TraitColumn": col, "TraitValue": trait_vals.astype(str), "Winner": winner_mask.values})
        # Avoid huge one-off text blobs, but keep rescue reasons because those are actionable.
        if col not in ["Top3RescueReasons", "RowPlayTypeReason"] and tmp["TraitValue"].nunique(dropna=False) > 75:
            continue
        grp = tmp.groupby(["TraitColumn", "TraitValue", "Winner"], dropna=False).size().reset_index(name="Count")
        piv = grp.pivot_table(index=["TraitColumn", "TraitValue"], columns="Winner", values="Count", fill_value=0, aggfunc="sum").reset_index()
        if True not in piv.columns: piv[True] = 0
        if False not in piv.columns: piv[False] = 0
        piv = piv.rename(columns={True: "WinnerCount", False: "NonWinnerCount"})
        piv["WinnerPct"] = (piv["WinnerCount"] / total_w * 100).round(3) if total_w else 0.0
        piv["NonWinnerPct"] = (piv["NonWinnerCount"] / total_nw * 100).round(3) if total_nw else 0.0
        piv["WinnerMinusNonWinnerPct"] = (piv["WinnerPct"] - piv["NonWinnerPct"]).round(3)
        piv["WinnerLift"] = ((piv["WinnerPct"] + 0.001) / (piv["NonWinnerPct"] + 0.001)).round(3)
        def use_label(r):
            if r["WinnerCount"] >= 3 and r["WinnerMinusNonWinnerPct"] >= 5:
                return "WINNER_COMMON_SIGNAL"
            if r["NonWinnerCount"] >= 20 and r["WinnerPct"] <= 1 and r["NonWinnerPct"] >= 5:
                return "POSSIBLE_EXCLUSION_SIGNAL"
            if r["WinnerCount"] >= 1 and r["WinnerPct"] <= 5 and r["WinnerLift"] >= 2:
                return "RARE_WINNER_RESCUE_SIGNAL"
            if r["WinnerCount"] == 0 and r["NonWinnerCount"] >= 10:
                return "NEGATED_RARE_OR_AVOID_SIGNAL"
            return "WATCHLIST"
        piv["SignalUse"] = piv.apply(use_label, axis=1)
        rows.append(piv)
    compare = pd.concat(rows, ignore_index=True) if rows else pd.DataFrame()
    if not compare.empty:
        compare = compare.sort_values(["SignalUse", "WinnerMinusNonWinnerPct", "WinnerCount"], ascending=[True, False, False]).reset_index(drop=True)

    winners = df[winner_mask].copy()
    nonwinners = df[~winner_mask].copy()
    missed = df[df["v153_OperationalMissed"]].copy()
    return compare, winners, nonwinners, missed


def _v153_render_winner_nonwinner_trait_panel(res: pd.DataFrame):
    if res is None or not isinstance(res, pd.DataFrame) or res.empty:
        return
    st.subheader("v153 Winner vs Non-Winner Trait Mining")
    st.caption("Full-universe comparison only. This does not change ranking, stream inclusion, play depth, member logic, rescues, or scoring.")
    compare, winners, nonwinners, missed = _v153_build_trait_comparison(res)
    c1, c2, c3, c4 = st.columns(4)
    c1.metric("Winner rows", f"{len(winners):,}")
    c2.metric("Non-winner rows", f"{len(nonwinners):,}")
    c3.metric("Operational missed winners", f"{len(missed):,}")
    c4.metric("Traits compared", f"{len(compare):,}")
    if compare.empty:
        st.info("No comparable trait table could be generated from the current walk-forward output.")
        return
    # Show actionable slices first.
    for title, sigs in [
        ("Winner-common / rescue-leaning signals", ["WINNER_COMMON_SIGNAL", "RARE_WINNER_RESCUE_SIGNAL"]),
        ("Possible exclusion / avoid-extra-play signals", ["POSSIBLE_EXCLUSION_SIGNAL", "NEGATED_RARE_OR_AVOID_SIGNAL"]),
        ("Watchlist traits", ["WATCHLIST"]),
    ]:
        sub = compare[compare["SignalUse"].isin(sigs)].copy()
        if not sub.empty:
            st.write(f"**{title}**")
            st.dataframe(sub.head(100), use_container_width=True, hide_index=True)
    # Member-specific view for winner rows.
    if not winners.empty and "TrueMember" in winners.columns:
        member_cols = [c for c in ["TrueMember", "v152_MovementBucket", "ThirdMember", "Top3Rescue", "Top3RescueReasons", "PlayType", "KeptStreamFlag", "RecommendedStream"] if c in winners.columns]
        if member_cols:
            wmem = winners.groupby(member_cols, dropna=False).size().reset_index(name="WinnerCount").sort_values("WinnerCount", ascending=False).head(100)
            st.write("**Winner member traits / movement / rescue view**")
            st.dataframe(wmem, use_container_width=True, hide_index=True)
    st.session_state["v153_trait_compare"] = compare
    st.session_state["v153_winner_rows"] = winners
    st.session_state["v153_nonwinner_rows"] = nonwinners
    st.session_state["v153_missed_winner_rows"] = missed
    d1, d2, d3, d4 = st.columns(4)
    with d1:
        st.download_button("Download v153 Trait Compare CSV", compare.to_csv(index=False).encode("utf-8"), "trait_compare__core389_northern_lights_v156_SINGLE_PASS_FAST_CHECKPOINT.csv", "text/csv", use_container_width=True, key="dl_v153_trait_compare_csv")
        st.download_button("Download v153 Trait Compare TXT", compare.to_csv(index=False, sep="\t").encode("utf-8"), "trait_compare__core389_northern_lights_v156_SINGLE_PASS_FAST_CHECKPOINT.txt", "text/plain", use_container_width=True, key="dl_v153_trait_compare_txt")
    with d2:
        st.download_button("Download v153 Winner Rows CSV", winners.to_csv(index=False).encode("utf-8"), "winner_rows__core389_northern_lights_v156_SINGLE_PASS_FAST_CHECKPOINT.csv", "text/csv", use_container_width=True, key="dl_v153_winner_rows_csv")
        st.download_button("Download v153 Winner Rows TXT", winners.to_csv(index=False, sep="\t").encode("utf-8"), "winner_rows__core389_northern_lights_v156_SINGLE_PASS_FAST_CHECKPOINT.txt", "text/plain", use_container_width=True, key="dl_v153_winner_rows_txt")
    with d3:
        st.download_button("Download v153 Non-Winner Rows CSV", nonwinners.to_csv(index=False).encode("utf-8"), "nonwinner_rows__core389_northern_lights_v156_SINGLE_PASS_FAST_CHECKPOINT.csv", "text/csv", use_container_width=True, key="dl_v153_nonwinner_rows_csv")
        st.download_button("Download v153 Non-Winner Rows TXT", nonwinners.to_csv(index=False, sep="\t").encode("utf-8"), "nonwinner_rows__core389_northern_lights_v156_SINGLE_PASS_FAST_CHECKPOINT.txt", "text/plain", use_container_width=True, key="dl_v153_nonwinner_rows_txt")
    with d4:
        st.download_button("Download v153 Missed Winner Rows CSV", missed.to_csv(index=False).encode("utf-8"), "missed_winner_rows__core389_northern_lights_v156_SINGLE_PASS_FAST_CHECKPOINT.csv", "text/csv", use_container_width=True, key="dl_v153_missed_rows_csv")
        st.download_button("Download v153 Missed Winner Rows TXT", missed.to_csv(index=False, sep="\t").encode("utf-8"), "missed_winner_rows__core389_northern_lights_v156_SINGLE_PASS_FAST_CHECKPOINT.txt", "text/plain", use_container_width=True, key="dl_v153_missed_rows_txt")



# v154: internal separator-history/rule-source utilities for Walk-forward Lab.
# These utilities do not change the member scoring formula. They only make the rule source
# explicit and available to Walk-forward without requiring Daily Prediction to run first.
_V154_RULE_COLS = ["pair", "trait_stack", "winner_member", "winner_rate", "support", "pair_gap", "stack_size"]

def v154_empty_rules() -> pd.DataFrame:
    return pd.DataFrame(columns=_V154_RULE_COLS)

def v154_standardize_rules(df: pd.DataFrame, source_mode: str = "UNKNOWN", source_cutoff_date=None, asof_date=None) -> pd.DataFrame:
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        out = v154_empty_rules()
    else:
        out = df.copy()
    for c in _V154_RULE_COLS:
        if c not in out.columns:
            out[c] = 0 if c in ["winner_rate", "support", "pair_gap", "stack_size"] else ""
    out = out[_V154_RULE_COLS + [c for c in out.columns if c not in _V154_RULE_COLS]].copy()
    out["winner_member"] = out["winner_member"].map(normalize_member)
    out = out[out["winner_member"].isin(MEMBERS)].copy()
    out["trait_stack"] = out["trait_stack"].astype(str)
    out = out[out["trait_stack"].str.strip().ne("")].copy()
    if out.empty:
        return v154_empty_rules()
    out["winner_rate"] = pd.to_numeric(out["winner_rate"], errors="coerce").fillna(0.0)
    out["support"] = pd.to_numeric(out["support"], errors="coerce").fillna(0).astype(int)
    out["pair_gap"] = pd.to_numeric(out.get("pair_gap", 0), errors="coerce").fillna(0.0)
    out["stack_size"] = pd.to_numeric(out.get("stack_size", 1), errors="coerce").fillna(1).astype(int)
    out["RuleSourceMode"] = source_mode
    if source_cutoff_date is not None:
        out["SourceCutoffDate"] = pd.to_datetime(source_cutoff_date, errors="coerce")
    elif "SourceCutoffDate" not in out.columns:
        out["SourceCutoffDate"] = pd.NaT
    else:
        out["SourceCutoffDate"] = pd.to_datetime(out["SourceCutoffDate"], errors="coerce")
    if asof_date is not None:
        out["AsOfDate"] = pd.to_datetime(asof_date, errors="coerce")
    elif "AsOfDate" not in out.columns:
        out["AsOfDate"] = pd.NaT
    else:
        out["AsOfDate"] = pd.to_datetime(out["AsOfDate"], errors="coerce")
    return out.drop_duplicates(subset=["trait_stack", "winner_member", "RuleSourceMode", "AsOfDate"], keep="last").reset_index(drop=True)

def v154_load_promoted_library_rules(lib_file_obj) -> pd.DataFrame:
    if lib_file_obj is None:
        return v154_empty_rules()
    lib_df = ensure_library(load_upload(lib_file_obj))
    return v154_standardize_rules(lib_df, source_mode="PROMOTED_LIBRARY_FIXED")

def v154_load_truth_rules_static(truth_file_obj, min_rate: float, min_support: int) -> pd.DataFrame:
    if truth_file_obj is None:
        return v154_empty_rules()
    t = ensure_truth(load_upload(truth_file_obj))
    t = enrich_seed_features(t, "seed")
    mined = deep_mine_separators(t, min_rate, min_support)
    cutoff = pd.to_datetime(t.get("Date"), errors="coerce").max() if "Date" in t.columns else pd.NaT
    return v154_standardize_rules(mined, source_mode="TRUTH_MINED_STATIC_FULL_FILE", source_cutoff_date=cutoff)

def v154_build_date_valid_truth_separator_history(truth_file_obj, target_dates, min_rate: float, min_support: int, max_dates: int = 0) -> pd.DataFrame:
    """Build blind, date-valid truth-mined separator snapshots.
    For each target PredictionDate, only truth rows with Date < PredictionDate are mined.
    max_dates=0 means all target dates. This is a prep utility and may be slow by design.
    """
    if truth_file_obj is None:
        return pd.DataFrame()
    truth_df = ensure_truth(load_upload(truth_file_obj))
    truth_df = enrich_seed_features(truth_df, "seed")
    if "Date" not in truth_df.columns:
        raise ValueError("FULL TRUTH file must contain Date for date-valid separator-history building.")
    truth_df["Date"] = pd.to_datetime(truth_df["Date"], errors="coerce").dt.normalize()
    truth_df = truth_df[truth_df["Date"].notna()].copy()
    dates = pd.to_datetime(pd.Series(list(target_dates)), errors="coerce").dropna().dt.normalize().drop_duplicates().sort_values().tolist()
    if max_dates and max_dates > 0:
        dates = dates[:int(max_dates)]
    parts = []
    for d in dates:
        train = truth_df[truth_df["Date"] < d].copy()
        if len(train) < int(min_support):
            continue
        mined = deep_mine_separators(train, min_rate, min_support)
        if mined is None or mined.empty:
            continue
        cutoff = train["Date"].max()
        snap = v154_standardize_rules(mined, source_mode="TRUTH_DATE_VALID_BLIND", source_cutoff_date=cutoff, asof_date=d)
        snap["PredictionDate"] = pd.to_datetime(d)
        snap["TrainingRows"] = int(len(train))
        parts.append(snap)
    return pd.concat(parts, ignore_index=True) if parts else pd.DataFrame()

def v154_rules_for_prediction_date(pred_date, separator_history: pd.DataFrame, fallback_rules: pd.DataFrame) -> pd.DataFrame:
    pred = pd.to_datetime(pred_date, errors="coerce")
    pieces = []
    if isinstance(fallback_rules, pd.DataFrame) and not fallback_rules.empty:
        fr = fallback_rules.copy()
        # Fixed promoted library rules are allowed as a locked user-supplied rulebook.
        # Any date-stamped fallback rules are constrained to SourceCutoffDate < prediction date.
        if "SourceCutoffDate" in fr.columns and pd.notna(pred):
            sc = pd.to_datetime(fr["SourceCutoffDate"], errors="coerce")
            fixed_mask = fr.get("RuleSourceMode", "").astype(str).eq("PROMOTED_LIBRARY_FIXED") if "RuleSourceMode" in fr.columns else pd.Series([True]*len(fr), index=fr.index)
            dated_ok = sc.isna() | (sc < pred)
            fr = fr[fixed_mask | dated_ok].copy()
        pieces.append(fr)
    if isinstance(separator_history, pd.DataFrame) and not separator_history.empty and pd.notna(pred):
        sh = separator_history.copy()
        if "PredictionDate" in sh.columns:
            sh["PredictionDate"] = pd.to_datetime(sh["PredictionDate"], errors="coerce").dt.normalize()
            hit = sh[sh["PredictionDate"].eq(pred.normalize())].copy()
            if not hit.empty:
                pieces.append(hit)
        elif "SourceCutoffDate" in sh.columns:
            sh["SourceCutoffDate"] = pd.to_datetime(sh["SourceCutoffDate"], errors="coerce")
            eligible = sh[sh["SourceCutoffDate"] < pred].copy()
            if not eligible.empty:
                pieces.append(eligible)
    if not pieces:
        return v154_empty_rules()
    out = pd.concat(pieces, ignore_index=True)
    return v154_standardize_rules(out, source_mode="MIXED_DATE_VALID")

def v154_build_walkforward_base_rules(lib_file_obj, truth_file_obj, truth_min_rate: float, truth_min_support: int, mode: str) -> tuple[pd.DataFrame, pd.DataFrame, str]:
    """Return fallback/base rules, static truth rules, and readable source label."""
    base_parts = []
    lib_rules = v154_load_promoted_library_rules(lib_file_obj)
    if not lib_rules.empty:
        base_parts.append(lib_rules)
    static_truth_rules = v154_empty_rules()
    if mode == "Fixed library + static full-truth mined rules (NOT BLIND)":
        static_truth_rules = v154_load_truth_rules_static(truth_file_obj, truth_min_rate, truth_min_support)
        if not static_truth_rules.empty:
            base_parts.append(static_truth_rules)
    base = pd.concat(base_parts, ignore_index=True) if base_parts else v154_empty_rules()
    label = mode
    return base, static_truth_rules, label


# v155: production-rulebook validation reporting.
# This is intentionally NOT labeled strict blind when static full-truth/promoted rules are used.
def _v155_period_validation_table(res: pd.DataFrame) -> pd.DataFrame:
    if res is None or not isinstance(res, pd.DataFrame) or res.empty or "Date" not in res.columns:
        return pd.DataFrame()
    out = res.copy()
    out["Date"] = pd.to_datetime(out["Date"], errors="coerce")
    out = out[out["Date"].notna()].copy()
    if out.empty:
        return pd.DataFrame()
    out["PeriodYear"] = out["Date"].dt.year.astype(str)
    out["PeriodMonth"] = out["Date"].dt.strftime("%Y-%m")
    out["PeriodQuarter"] = out["Date"].dt.to_period("Q").astype(str)
    rows = []
    def _summ(label_col: str, period_type: str):
        for p, g in out.groupby(label_col, dropna=False):
            total = int(len(g))
            core = int(pd.to_numeric(g.get("Core389WinnerEvent", 0), errors="coerce").fillna(0).sum())
            top1 = int(pd.to_numeric(g.get("Top1_Correct", 0), errors="coerce").fillna(0).sum())
            top2 = int(pd.to_numeric(g.get("Needed_Top2", 0), errors="coerce").fillna(0).sum())
            miss = int(pd.to_numeric(g.get("Miss", 0), errors="coerce").fillna(0).sum())
            plays = 0
            if "ActualBoxPlay" in g.columns:
                plays = int(g["ActualBoxPlay"].fillna("").astype(str).apply(lambda x: 0 if not x.strip() else len([z for z in re.split(r"\s*\+\s*", x) if z.strip()])).sum())
            elif "RecommendedPlay" in g.columns:
                plays = int(g["RecommendedPlay"].fillna("").astype(str).apply(lambda x: 0 if not x.strip() else len([z for z in re.split(r"\s*\+\s*", re.sub(r"\*", "", x)) if z.strip()])).sum())
            captured = top1 + top2
            rows.append({
                "PeriodType": period_type,
                "Period": str(p),
                "EvaluatedRows": total,
                "Core389WinnerEvents": core,
                "Top1": top1,
                "NeededTop2": top2,
                "Miss": miss,
                "CapturePctOfCoreEvents": round((captured / core * 100), 2) if core else 0.0,
                "Top1PctOfCoreEvents": round((top1 / core * 100), 2) if core else 0.0,
                "Top2BurdenPctOfCoreEvents": round((top2 / core * 100), 2) if core else 0.0,
                "OperationalPlays": plays,
                "PlaysPerCoreEvent": round((plays / core), 3) if core else None,
                "RowsPerCoreEvent": round((total / core), 3) if core else None,
            })
    _summ("PeriodYear", "Year")
    _summ("PeriodQuarter", "Quarter")
    _summ("PeriodMonth", "Month")
    return pd.DataFrame(rows)

