# =====================================================================
# v91 ROW CADENCE INTERNAL ENGINE MODULE

# =====================================================================
# v92 ROW CADENCE EMBEDDED INTERNAL ENGINE
# =====================================================================
# Additive only. This module does not modify existing playlist generation,
# member scoring, straight generation, or lab logic. It creates auditable
# row-cadence profiles and optional soft-downgrade/debug annotations.
#
# v92 changes from v91:
# - Embeds the current ranked-per-event cadence source directly in the app.
# - Upload remains optional and overrides the embedded baseline when supplied.
# - Shows the cadence source max date, staleness age, daily playlist source max date,
#   and the prediction/as-of date used for annotation.
# - Automatically attempts to pull the canonical daily playlist from this app session.
# - Row cadence remains keyed ONLY by SingleRow. Stream cadence remains NOT computed.

V92_ROW_CADENCE_BUILD = "v129_DAILY_AUTODETECT_AND_WF_SLOT_FIX__2026-05-31"
V92_ROW_CLUSTER_GAP_MAX_DEFAULT = 7
V92_ROW_PRE_CUSHION_DEFAULT = 2
V92_ROW_POST_CUSHION_DEFAULT = 2
V92_CADENCE_STALE_AFTER_DAYS = 60
V92_EMBEDDED_RANKED_SOURCE_NAME = "all_3_members_ranked_per_event__core389_v5(3).txt"
V92_EMBEDDED_RANKED_SOURCE_NOTE = "Embedded baseline built from uploaded all_3_members_ranked_per_event__core389_v5(3).txt; upload a newer ranked-per-event file to override."
V92_EMBEDDED_RANKED_PER_EVENT_GZ_B64_CHUNKS = ['', '', '']


def v92_load_any_table(uploaded_file) -> pd.DataFrame:
    """Load CSV/TXT/TSV with delimiter sniffing. Keeps all fields as strings first."""
    raw = _v105_upload_bytes(uploaded_file)
    name = _v105_upload_name(uploaded_file)
    seps = [",", "	", "|", ";"]
    if name.endswith(".tsv"):
        seps = ["	", ",", "|", ";"]
    if name.endswith(".txt"):
        seps = ["	", ",", "|", ";"]
    best = None
    best_score = -1
    for sep in seps:
        try:
            d = pd.read_csv(io.BytesIO(raw), sep=sep, dtype=str, low_memory=False, encoding="utf-8-sig", on_bad_lines="skip")
            d = d.dropna(how="all").copy()
            if d.empty:
                continue
            score = d.shape[1] * 100 + min(len(d), 100)
            if score > best_score:
                best = d
                best_score = score
        except Exception:
            continue
    if best is None:
        best = pd.read_csv(io.BytesIO(raw), sep=None, engine="python", dtype=str, encoding="utf-8-sig", on_bad_lines="skip")
        best = best.dropna(how="all").copy()
    best.columns = [str(c).replace("﻿", "").strip() for c in best.columns]
    return best


@st.cache_data(show_spinner=False)
def v92_load_embedded_ranked_per_event() -> pd.DataFrame:
    """Load embedded ranked-per-event cadence baseline. No external file needed."""
    import base64
    import gzip
    payload = "".join(V92_EMBEDDED_RANKED_PER_EVENT_GZ_B64_CHUNKS)
    raw = gzip.decompress(base64.b64decode(payload.encode("ascii")))
    d = pd.read_csv(io.BytesIO(raw), dtype=str, low_memory=False, encoding="utf-8-sig", on_bad_lines="skip")
    d = d.dropna(how="all").copy()
    d.columns = [str(c).replace("﻿", "").strip() for c in d.columns]
    return d


def v92_prepare_ranked_row_events(ranked_df: pd.DataFrame) -> pd.DataFrame:
    """Deduplicate all_3_members_ranked_per_event to one winner event per EventIndex/date/row."""
    d = ranked_df.copy()
    d.columns = [str(c).strip() for c in d.columns]
    required = ["Date", "StreamKey", "SingleRow"]
    missing = [c for c in required if c not in d.columns]
    if missing:
        raise ValueError(f"Ranked-per-event file is missing required columns for row cadence: {missing}")
    d["Date"] = pd.to_datetime(d["Date"], errors="coerce")
    d["SingleRow"] = pd.to_numeric(d["SingleRow"], errors="coerce")
    d = d[d["Date"].notna() & d["SingleRow"].notna()].copy()
    d["SingleRow"] = d["SingleRow"].astype(int)
    base_keys = [c for c in [
        "EventIndex", "Date", "StreamKey", "SingleRow", "StreamRank", "RowPercentile", "seed", "Result",
        "TrueMember", "PredictedMember", "Top2_pred", "ThirdMember", "PlayType", "Top2Decision",
        "RowVolatilityRate", "RowPlayTypeReason"
    ] if c in d.columns]
    if "EventIndex" in d.columns:
        out = d[base_keys].drop_duplicates(subset=[c for c in ["EventIndex", "Date", "StreamKey", "SingleRow"] if c in d.columns]).copy()
    else:
        out = d[base_keys].drop_duplicates().copy()
    out = out.sort_values(["Date", "SingleRow", "StreamKey"]).reset_index(drop=True)
    out["BUILD"] = V92_ROW_CADENCE_BUILD
    return out


def v92_gap_classes(gaps, cluster_gap_max: int):
    classes = ["normal"] * len(gaps)
    for i, g in enumerate(gaps):
        if g <= cluster_gap_max:
            classes[i] = "cluster_continuation"
    if len(gaps) >= 4:
        s = pd.Series(gaps, dtype="float64")
        q1, q3 = s.quantile(0.25), s.quantile(0.75)
        high_cut = q3 + 1.5 * (q3 - q1)
        for i, g in enumerate(gaps):
            if g > high_cut:
                classes[i] = "extreme_drought"
    normal = [g for g, c in zip(gaps, classes) if c == "normal"]
    return classes, normal


def v92_cluster_dates(dates, cluster_gap_max: int):
    dates = sorted(pd.to_datetime(pd.Series(dates)).dropna().unique())
    if not dates:
        return []
    clusters = [[dates[0]]]
    for dt in dates[1:]:
        gap = int((dt - clusters[-1][-1]).days)
        if gap <= cluster_gap_max:
            clusters[-1].append(dt)
        else:
            clusters.append([dt])
    return clusters


def v92_build_row_cadence_outputs(row_events: pd.DataFrame, cluster_gap_max: int, post_cushion: int, pre_cushion: int):
    summary_rows, event_rows, cluster_rows, window_rows = [], [], [], []
    max_date = row_events["Date"].max()
    for row, g in row_events.groupby("SingleRow", dropna=False):
        g = g.sort_values("Date")
        dates = list(g["Date"])
        gaps = [int((dates[i] - dates[i-1]).days) for i in range(1, len(dates))]
        gap_classes, normal_gaps = v92_gap_classes(gaps, cluster_gap_max)
        clusters = v92_cluster_dates(dates, cluster_gap_max)

        last_dt = None
        for _, r in g.iterrows():
            gap = None if last_dt is None else int((r["Date"] - last_dt).days)
            event_rows.append({
                "BUILD": V92_ROW_CADENCE_BUILD,
                "SingleRow": int(row),
                "Date": r["Date"].date().isoformat(),
                "GapFromPriorRowHitDays": gap,
                "StreamKey_AUDIT_ONLY_NOT_CADENCE_KEY": r.get("StreamKey", ""),
                "TrueMember": r.get("TrueMember", ""),
                "Result": r.get("Result", ""),
                "PredictedMember": r.get("PredictedMember", ""),
                "Top2_pred": r.get("Top2_pred", ""),
                "PlayType": r.get("PlayType", ""),
            })
            last_dt = r["Date"]

        for idx, cl in enumerate(clusters, start=1):
            cluster_rows.append({
                "BUILD": V92_ROW_CADENCE_BUILD,
                "SingleRow": int(row),
                "ClusterID": idx,
                "ClusterStart": cl[0].date().isoformat(),
                "ClusterEnd": cl[-1].date().isoformat(),
                "HitsInCluster": len(cl),
                "ClusterHitDates": "|".join(x.date().isoformat() for x in cl),
            })

        for i in range(len(clusters) - 1):
            prev_end = clusters[i][-1]
            next_start = clusters[i + 1][0]
            inactive_start = prev_end + pd.Timedelta(days=post_cushion)
            inactive_end = next_start - pd.Timedelta(days=pre_cushion)
            inactive_days = max(int((inactive_end - inactive_start).days) + 1, 0)
            if inactive_days > 0:
                window_rows.append({
                    "BUILD": V92_ROW_CADENCE_BUILD,
                    "SingleRow": int(row),
                    "FromClusterID": i + 1,
                    "ToClusterID": i + 2,
                    "PreviousClusterEnd": prev_end.date().isoformat(),
                    "NextClusterStart": next_start.date().isoformat(),
                    "RawGapDays_BetweenClusterEndAndNextStart": int((next_start - prev_end).days),
                    "PostClusterCushionDays": post_cushion,
                    "PreNextClusterCushionDays": pre_cushion,
                    "InactiveWindowStart": inactive_start.date().isoformat(),
                    "InactiveWindowEnd": inactive_end.date().isoformat(),
                    "InactiveCalendarDays": inactive_days,
                    "RuleLabel": f"ROW_{int(row)}_INACTIVE_CLUSTER_WINDOW_POST{post_cushion}_PRE{pre_cushion}",
                })

        min_normal = min(normal_gaps) if normal_gaps else (min(gaps) if gaps else None)
        median_normal = float(pd.Series(normal_gaps).median()) if normal_gaps else None
        max_cluster_len = max([len(c) for c in clusters]) if clusters else 0
        last_hit = max(dates) if dates else pd.NaT
        current_gap = int((max_date - last_hit).days) if pd.notna(last_hit) else None
        playable_after = max(min_normal - post_cushion, 0) if min_normal is not None else None
        if playable_after is None:
            current_status = "INSUFFICIENT_ROW_CADENCE"
        elif current_gap >= playable_after:
            current_status = "ACTIVE_NOW_BY_MIN_NORMAL"
        else:
            current_status = "COOLDOWN_NOW_BY_MIN_NORMAL"
        summary_rows.append({
            "BUILD": V92_ROW_CADENCE_BUILD,
            "SingleRow": int(row),
            "Wins": int(len(g)),
            "FirstHitDate": min(dates).date().isoformat() if dates else "",
            "LastHitDate": last_hit.date().isoformat() if pd.notna(last_hit) else "",
            "CadenceSourceMaxDate": max_date.date().isoformat() if pd.notna(max_date) else "",
            "CurrentGapFromLastHit_AsOfCadenceSourceMaxDate": current_gap,
            "RawGapSequenceDays": "|".join(map(str, gaps)),
            "GapClassSequence": "|".join(gap_classes),
            "NormalGapsUsed": "|".join(map(str, normal_gaps)),
            "ClusterContinuationGapsIgnored": "|".join(str(g) for g, c in zip(gaps, gap_classes) if c == "cluster_continuation"),
            "ExtremeDroughtGapsIgnored": "|".join(str(g) for g, c in zip(gaps, gap_classes) if c == "extreme_drought"),
            "MinNormalGapDays": min_normal,
            "MedianNormalGapDays": median_normal,
            "MaxClusterLength": max_cluster_len,
            "ClusterCount": len(clusters),
            "CushionPostClusterDays": post_cushion,
            "CushionPreNextClusterDays": pre_cushion,
            "PlayableAfterDays_MinNormalMinusPostCushion": playable_after,
            "SuggestedCurrentStatus_AsOfCadenceSourceMaxDate": current_status,
            "StreamsSeenInRowEvents_AUDIT_ONLY_NOT_CADENCE_KEY": " || ".join(sorted(set(g["StreamKey"].astype(str)))) if "StreamKey" in g.columns else "",
            "Member3389Wins": int((g.get("TrueMember", pd.Series(dtype=str)).astype(str) == "3389").sum()) if "TrueMember" in g.columns else 0,
            "Member3899Wins": int((g.get("TrueMember", pd.Series(dtype=str)).astype(str) == "3899").sum()) if "TrueMember" in g.columns else 0,
            "Member3889Wins": int((g.get("TrueMember", pd.Series(dtype=str)).astype(str) == "3889").sum()) if "TrueMember" in g.columns else 0,
        })

    summary = pd.DataFrame(summary_rows).sort_values(["Wins", "SingleRow"], ascending=[False, True]) if summary_rows else pd.DataFrame()
    events_out = pd.DataFrame(event_rows).sort_values(["SingleRow", "Date"]) if event_rows else pd.DataFrame()
    clusters_out = pd.DataFrame(cluster_rows).sort_values(["SingleRow", "ClusterID"]) if cluster_rows else pd.DataFrame()
    windows_out = pd.DataFrame(window_rows).sort_values(["SingleRow", "InactiveWindowStart"]) if window_rows else pd.DataFrame()
    return summary, events_out, clusters_out, windows_out


def v92_blind_row_status(row_events: pd.DataFrame, row_value, as_of_date, cluster_gap_max: int, post_cushion: int):
    try:
        row_int = int(float(row_value))
    except Exception:
        return {
            "RowCadenceStatus": "NO_SINGLE_ROW",
            "RowCadenceReason": "SingleRow missing or invalid",
            "RowMinNormalGap": None,
            "RowGapSinceLastHit": None,
            "RowPlayableAfterDays": None,
            "RowPriorHitCount": 0,
        }
    as_of = pd.to_datetime(as_of_date, errors="coerce")
    if pd.isna(as_of):
        as_of = pd.Timestamp.today().normalize()
    prior = row_events[(row_events["SingleRow"] == row_int) & (row_events["Date"] < as_of)].sort_values("Date")
    if prior.empty:
        return {
            "RowCadenceStatus": "NO_PRIOR_ROW_HISTORY",
            "RowCadenceReason": f"No prior cadence hits for row {row_int} before {as_of.date().isoformat()}",
            "RowMinNormalGap": None,
            "RowGapSinceLastHit": None,
            "RowPlayableAfterDays": None,
            "RowPriorHitCount": 0,
        }
    prior_dates = list(prior["Date"])
    gap_since = int((as_of - prior_dates[-1]).days)
    if len(prior_dates) < 2:
        return {
            "RowCadenceStatus": "INSUFFICIENT_PRIOR_ROW_GAPS",
            "RowCadenceReason": f"Only one prior row hit; gap_since_last={gap_since}; no hard action",
            "RowMinNormalGap": None,
            "RowGapSinceLastHit": gap_since,
            "RowPlayableAfterDays": None,
            "RowPriorHitCount": len(prior_dates),
        }
    gaps = [int((prior_dates[i] - prior_dates[i-1]).days) for i in range(1, len(prior_dates))]
    classes, normal = v92_gap_classes(gaps, cluster_gap_max)
    min_normal = min(normal) if normal else min(gaps)
    playable_after = max(min_normal - post_cushion, 0)
    cooldown = gap_since < playable_after
    return {
        "RowCadenceStatus": "COOLDOWN_SOFT_DOWNGRADE" if cooldown else "ACTIVE_BY_ROW_CADENCE",
        "RowCadenceReason": f"prior_hits={len(prior_dates)}; gap_since_last={gap_since}; min_normal_gap={min_normal}; post_cushion={post_cushion}; playable_after={playable_after}; gaps={'|'.join(map(str, gaps))}; classes={'|'.join(classes)}",
        "RowMinNormalGap": min_normal,
        "RowGapSinceLastHit": gap_since,
        "RowPlayableAfterDays": playable_after,
        "RowPriorHitCount": len(prior_dates),
    }


def v92_annotate_playlist_with_row_cadence(playlist_df: pd.DataFrame, row_events: pd.DataFrame, as_of_date, cluster_gap_max: int, post_cushion: int, hard_preview: bool = False) -> pd.DataFrame:
    d = playlist_df.copy()
    if "SingleRow" not in d.columns:
        raise ValueError("Playlist/replay file must include SingleRow for row cadence annotation.")
    d["SingleRow"] = pd.to_numeric(d["SingleRow"], errors="coerce")
    if "Date" in d.columns:
        dates = pd.to_datetime(d["Date"], errors="coerce")
        dates = dates.fillna(pd.to_datetime(as_of_date))
    else:
        dates = pd.Series([pd.to_datetime(as_of_date)] * len(d), index=d.index)
    out_rows = []
    for idx, r in d.iterrows():
        status = v92_blind_row_status(row_events, r.get("SingleRow"), dates.loc[idx], cluster_gap_max, post_cushion)
        out_rows.append(status)
    status_df = pd.DataFrame(out_rows, index=d.index)
    out = pd.concat([d, status_df], axis=1)
    out["RowCooldownFlag"] = out["RowCadenceStatus"].eq("COOLDOWN_SOFT_DOWNGRADE").astype(int)
    out["RowCadenceSoftAction"] = out["RowCooldownFlag"].map({1: "SOFT_DOWNGRADE_ONLY_DO_NOT_DELETE", 0: "NO_ROW_CADENCE_DOWNGRADE"})
    out["StreamCadenceStatus"] = "NOT_COMPUTED_IN_V92_ROW_ONLY_MODULE"
    out["StreamCadenceReason"] = "Row cadence and stream cadence are intentionally separate. This module does not compute stream cadence."
    out["CombinedCadenceDecision"] = "ROW_ONLY_SOFT_DEBUG"
    out["EliminatedByCadence"] = 0
    out["CadenceEliminationSource"] = "NONE_SOFT_ONLY"
    if hard_preview:
        out["HardSuppressionPreview_PlayAfterRowCadence"] = (out["RowCooldownFlag"] == 0).astype(int)
        out["HardSuppressionPreview_WouldSuppress"] = out["RowCooldownFlag"]
    else:
        out["HardSuppressionPreview_PlayAfterRowCadence"] = "DISABLED"
        out["HardSuppressionPreview_WouldSuppress"] = "DISABLED"
    out["BUILD"] = V92_ROW_CADENCE_BUILD
    return out


def v92_download_pair(label: str, df: pd.DataFrame, base_name: str):
    if df is None or df.empty:
        st.caption(f"{label}: no rows to download yet.")
        return
    csv_bytes = df.to_csv(index=False).encode("utf-8")
    txt_bytes = df.to_csv(index=False, sep="	").encode("utf-8")
    c1, c2 = st.columns(2)
    with c1:
        st.download_button(
            f"Download {label} CSV",
            data=csv_bytes,
            file_name=f"{base_name}.csv",
            mime="text/csv",
            key=f"v92_dl_csv_{base_name}",
            **_v103_download_kwargs(),
        )
    with c2:
        st.download_button(
            f"Download {label} TXT",
            data=txt_bytes,
            file_name=f"{base_name}.txt",
            mime="text/plain",
            key=f"v92_dl_txt_{base_name}",
            **_v103_download_kwargs(),
        )


def v92_date_summary_for_df(df: pd.DataFrame):
    if not isinstance(df, pd.DataFrame) or df.empty or "Date" not in df.columns:
        return None, None
    vals = pd.to_datetime(df["Date"], errors="coerce")
    if vals.notna().sum() == 0:
        return None, None
    return vals.min(), vals.max()


def v92_build_cadence_from_source(ranked_df: pd.DataFrame, source_label: str, cluster_gap_max: int, post_cushion: int, pre_cushion: int):
    row_events_v92 = v92_prepare_ranked_row_events(ranked_df)
    summary_v92, events_v92, clusters_v92, windows_v92 = v92_build_row_cadence_outputs(
        row_events_v92,
        int(cluster_gap_max),
        int(post_cushion),
        int(pre_cushion),
    )
    row_events_v92["CadenceSourceLabel"] = source_label
    for obj in [summary_v92, events_v92, clusters_v92, windows_v92]:
        if isinstance(obj, pd.DataFrame) and not obj.empty:
            obj["CadenceSourceLabel"] = source_label
    return row_events_v92, summary_v92, events_v92, clusters_v92, windows_v92



# ================================
# v100 ROW CADENCE REPLAY / SURVIVAL LAB
# ================================
def v100_play_count_from_playtype(play_type) -> int:
    s = str(play_type or "").strip().upper()
    if s == "TOP1_TOP2_TOP3":
        return 3
    if s == "TOP1_TOP2":
        return 2
    if s == "TOP1_ONLY":
        return 1
    return 1

def v100_member_survived_after_cadence(row) -> bool:
    """If cadence suppresses the stream/row, the winner cannot survive that event."""
    return int(row.get("WouldSuppressByCadence", 0) or 0) == 0

def v100_build_row_cadence_replay_from_lab(
    lab_df: pd.DataFrame,
    row_events: pd.DataFrame,
    cluster_gap_max: int = 7,
    post_cushion: int = 2,
    suppress_on_cooldown: bool = True,
    lost_win_value: float = 250.0,
) -> tuple[pd.DataFrame, pd.DataFrame]:
    """
    Uses the app's own walk-forward lab output as the replay source.

    This intentionally does NOT rebuild ranking/scoring in a separate formula.
    It consumes the exact lab_results rows already produced by the app:
    history -> seed selection -> scoring -> row ranking -> PlayType.

    Scope:
    - Tests winner-event survival across the historical Core389 hit universe.
    - Does not claim all-stream daily savings unless a full daily replay table exists.
    """
    if lab_df is None or not isinstance(lab_df, pd.DataFrame) or lab_df.empty:
        raise ValueError("Run Walk-forward Lab first. Cadence Replay needs st.session_state['lab_results'].")
    need = ["Date", "StreamKey", "SingleRow", "TrueMember"]
    missing = [c for c in need if c not in lab_df.columns]
    if missing:
        raise ValueError(f"Lab results missing required columns for cadence replay: {missing}")
    if row_events is None or not isinstance(row_events, pd.DataFrame) or row_events.empty:
        raise ValueError("Row cadence event source is empty.")

    work = lab_df.copy()
    work["Date"] = pd.to_datetime(work["Date"], errors="coerce")
    work = work[work["Date"].notna()].copy()
    work["SingleRow"] = pd.to_numeric(work["SingleRow"], errors="coerce")

    status_rows = []
    for _, r in work.iterrows():
        status_rows.append(
            v92_blind_row_status(
                row_events,
                r.get("SingleRow"),
                r.get("Date"),
                int(cluster_gap_max),
                int(post_cushion),
            )
        )
    status_df = pd.DataFrame(status_rows, index=work.index)

    out = pd.concat([work, status_df], axis=1)
    out["RecommendedPlay_before"] = out.get("RecommendedPlay", "").astype(str)
    out["PlayType_before"] = out.get("PlayType", "").astype(str)
    out["PlaysBeforeCadence"] = out["PlayType_before"].apply(v100_play_count_from_playtype)
    out["WouldSuppressByCadence"] = out["RowCadenceStatus"].eq("COOLDOWN_SOFT_DOWNGRADE").astype(int) if suppress_on_cooldown else 0
    out["RecommendedPlay_after"] = out.apply(
        lambda r: "" if int(r["WouldSuppressByCadence"]) == 1 else str(r.get("RecommendedPlay_before", "")),
        axis=1,
    )
    out["PlaysAfterCadence"] = out.apply(
        lambda r: 0 if int(r["WouldSuppressByCadence"]) == 1 else int(r.get("PlaysBeforeCadence", 0)),
        axis=1,
    )
    out["PlaysSavedByCadence"] = out["PlaysBeforeCadence"] - out["PlaysAfterCadence"]
    out["WinnerSurvived"] = out.apply(lambda r: int(v100_member_survived_after_cadence(r)), axis=1)
    out["WouldLoseWinner"] = (1 - out["WinnerSurvived"]).astype(int)
    out["LostWinValue_250"] = out["WouldLoseWinner"].astype(float) * float(lost_win_value)
    out["CadenceReplayScope"] = "WINNER_EVENT_REPLAY_FROM_APP_WALKFORWARD_OUTPUT"
    out["BUILD"] = "core389_northern_lights__2026-06-03_v145_ALL_78_STREAMS_VISIBLE_REPAIR"

    front = [
        "Date", "StreamKey", "SingleRow",
        "RecommendedPlay_before", "RowCadenceStatus", "RowCadenceReason",
        "WouldSuppressByCadence", "RecommendedPlay_after",
        "TrueMember", "Result", "WinnerSurvived", "WouldLoseWinner", "LostWinValue_250",
        "PlayType_before", "PlaysBeforeCadence", "PlaysAfterCadence", "PlaysSavedByCadence",
        "RowMinNormalGap", "RowGapSinceLastHit", "RowPlayableAfterDays", "RowPriorHitCount",
        "CadenceReplayScope", "BUILD",
    ]
    out = out[[c for c in front if c in out.columns] + [c for c in out.columns if c not in front]]

    total_events = int(len(out))
    wins_retained = int(out["WinnerSurvived"].sum()) if total_events else 0
    wins_lost = int(out["WouldLoseWinner"].sum()) if total_events else 0
    plays_before = int(out["PlaysBeforeCadence"].sum()) if total_events else 0
    plays_after = int(out["PlaysAfterCadence"].sum()) if total_events else 0
    plays_saved = int(out["PlaysSavedByCadence"].sum()) if total_events else 0
    suppressed_events = int(out["WouldSuppressByCadence"].sum()) if total_events else 0

    summary = pd.DataFrame([{
        "ReplayScope": "WINNER_EVENT_REPLAY_FROM_APP_WALKFORWARD_OUTPUT",
        "TotalWinnerEvents": total_events,
        "WinsRetained": wins_retained,
        "WinsRetainedPct": round(wins_retained / total_events * 100, 2) if total_events else 0.0,
        "WinsLost": wins_lost,
        "WinsLostPct": round(wins_lost / total_events * 100, 2) if total_events else 0.0,
        "CadenceSuppressedWinnerEvents": suppressed_events,
        "PlaysBeforeCadence_OnWinnerEvents": plays_before,
        "PlaysAfterCadence_OnWinnerEvents": plays_after,
        "PlaysSaved_OnWinnerEvents": plays_saved,
        "LostWinValue_250_Total": float(out["LostWinValue_250"].sum()) if total_events else 0.0,
        "ClusterContinuationGapDays": int(cluster_gap_max),
        "PostClusterCushionDays": int(post_cushion),
        "SuppressOnCooldown": bool(suppress_on_cooldown),
        "ImportantLimitation": "This tests winner-event survival. Full non-winner daily stream savings requires a full daily all-stream replay table.",
        "BUILD": "core389_northern_lights__2026-06-03_v145_ALL_78_STREAMS_VISIBLE_REPAIR",
    }])
    return out, summary

def v100_cadence_replay_tab_ui():
    st.subheader("Full History Row Cadence Replay")
    st.info(
        "This uses the app's own Walk-forward Lab output, so it does not invent a second scoring/ranking formula. "
        "Run Walk-forward Lab first, then run this replay. Row cadence is tested as a separate suppression layer."
    )

    lab_df = st.session_state.get("lab_results")
    if not isinstance(lab_df, pd.DataFrame) or lab_df.empty:
        st.warning("Run Walk-forward Lab first. This tab needs the app-created lab_results table.")
        return

    c1, c2, c3, c4 = st.columns(4)
    with c1:
        cluster_gap_max = st.number_input("Cluster continuation gap ≤ days", min_value=0, max_value=30, value=7, step=1, key="v100_replay_cluster_gap")
    with c2:
        post_cushion = st.number_input("Post-cluster cushion days", min_value=0, max_value=30, value=2, step=1, key="v100_replay_post_cushion")
    with c3:
        lost_value = st.number_input("Lost win value", min_value=0.0, max_value=10000.0, value=250.0, step=10.0, key="v100_replay_lost_value")
    with c4:
        suppress = st.checkbox("Test hard suppression of cooldown rows", value=True, key="v100_replay_suppress")

    st.caption(
        f"Lab source available: rows={len(lab_df)} | "
        f"date range={pd.to_datetime(lab_df['Date'], errors='coerce').min().date() if 'Date' in lab_df.columns else 'n/a'} to "
        f"{pd.to_datetime(lab_df['Date'], errors='coerce').max().date() if 'Date' in lab_df.columns else 'n/a'}"
    )

    if st.button("Run v108 Row Cadence Replay", type="primary", use_container_width=True, key="v100_run_cadence_replay"):
        try:
            ranked_df = v92_load_embedded_ranked_per_event()
            row_events, _, _, _, _ = v92_build_cadence_from_source(
                ranked_df,
                V92_EMBEDDED_RANKED_SOURCE_NAME,
                int(cluster_gap_max),
                int(post_cushion),
                V92_ROW_PRE_CUSHION_DEFAULT,
            )
            replay, summary = v100_build_row_cadence_replay_from_lab(
                lab_df,
                row_events,
                int(cluster_gap_max),
                int(post_cushion),
                bool(suppress),
                float(lost_value),
            )
            st.session_state["v100_row_cadence_replay"] = replay
            st.session_state["v100_row_cadence_replay_summary"] = summary
            st.success("v100 row cadence replay complete.")
        except Exception as e:
            st.error(f"Cadence replay failed: {e}")

    summary = st.session_state.get("v100_row_cadence_replay_summary")
    replay = st.session_state.get("v100_row_cadence_replay")
    if isinstance(summary, pd.DataFrame) and not summary.empty:
        st.dataframe(summary, use_container_width=True, hide_index=True)
        if isinstance(replay, pd.DataFrame) and not replay.empty:
            st.dataframe(replay, use_container_width=True, hide_index=True)
            v92_download_pair("v100 Row Cadence Replay Summary", summary, "core389_v100_row_cadence_replay_summary")
            v92_download_pair("v100 Row Cadence Replay Per Event", replay, "core389_v100_row_cadence_replay_per_event")

st.divider()
st.info("v202 trim: legacy v108-v112 miner/staged/preview UI panels are disabled in this build to reduce Streamlit rerun/render load. Core daily/WF functions remain available.")

# ================================
# v123 OVERRIDES: exact Daily schema crosswalk + robust rule parser + session scanner
# ================================
def _v123_truthy_str(x):
    s = str(x).strip()
    if s.lower() in {"true","1","yes","y"}:
        return "True"
    if s.lower() in {"false","0","no","n","nan","none",""}:
        return "False"
    return s

def _v123_cut_rank_bands(out):
    rv = None
    for c in ["BlindRollingRank","rank","StreamRank","PlaylistRank"]:
        if c in out.columns:
            rv = pd.to_numeric(out[c], errors="coerce")
            break
    if rv is None:
        rv = pd.Series(999, index=out.index)
    out["BRankBand10"] = pd.cut(
        rv, bins=[0,10,20,30,40,50,60,70,78],
        labels=["BR_01_10","BR_11_20","BR_21_30","BR_31_40","BR_41_50","BR_51_60","BR_61_70","BR_71_78"],
        include_lowest=True
    ).astype(str)
    edges = [0,5,10,15,20,25,30,35,40,45,50,55,60,65,70,75,78]
    labs = [f"BR_{edges[i]+1:02d}_{edges[i+1]:02d}" for i in range(len(edges)-1)]
    out["BRankBand5"] = pd.cut(rv, bins=edges, labels=labs, include_lowest=True).astype(str)
    return out

def _v123_add_daily_crosswalk_features(df):
    out = df.copy()

    # Daily column aliases to mined names.
    alias_pairs = {
        "seed": "PrevResult",
        "LastResult": "PrevResult",
        "seed_parity_pattern": "seed_parity",
        "parity_pattern": "seed_parity",
        "seed_highlow_pattern": "seed_highlow",
        "highlow_pattern": "seed_highlow",
        "seed_repeat_shape": "seed_shape",
        "structure": "seed_shape",
        "sum_bucket": "seed_sum_bucket",
        "spread_bucket": "seed_spread_bucket",
        "rank": "BlindRollingRank",
        "StreamRank": "BlindRollingRank",
    }
    for src, dst_col in alias_pairs.items():
        if src in out.columns and dst_col not in out.columns:
            out[dst_col] = out[src]

    # Normalize boolean-ish digit fields.
    for d in "0123456789":
        srcs = [f"has{d}", f"seed_has{d}", f"seed_inc2_{d}"]
        val = None
        for s in srcs:
            if s in out.columns:
                val = out[s]
                break
        if val is not None:
            out[f"seed_inc2_{d}"] = val.map(_v123_truthy_str)
            if f"seed_has{d}" not in out.columns:
                out[f"seed_has{d}"] = out[f"seed_inc2_{d}"]

    # Seed source and derived fields.
    seed_col = None
    for c in ["PrevResult","seed","LastResult","Seed","Result"]:
        if c in out.columns:
            seed_col = c
            break
    if seed_col is None:
        out["PrevResult"] = "0000"
        seed_col = "PrevResult"

    def _digits(x):
        ds = re.findall(r"\d", str(x))
        return ds[-4:] if len(ds) >= 4 else list(str(x).zfill(4)[-4:])

    sd = [_digits(x) for x in out[seed_col]]
    sd_int = []
    for row in sd:
        try: sd_int.append([int(x) for x in row])
        except Exception: sd_int.append([0,0,0,0])
    seed_sums = pd.Series([sum(x) for x in sd_int], index=out.index)

    if "seed_sum" in out.columns:
        ss = pd.to_numeric(out["seed_sum"], errors="coerce").fillna(seed_sums).astype(int)
    else:
        ss = seed_sums.astype(int)

    out["seed_sum_exact2"] = ss.astype(str)
    out["seed_sum_parity2"] = np.where(ss % 2 == 0, "sum_even", "sum_odd")
    out["seed_sum_mod5_2"] = (ss % 5).astype(str)
    out["seed_sum_end2"] = (ss % 10).astype(str)

    if "seed_sum_bucket" not in out.columns:
        out["seed_sum_bucket"] = pd.cut(
            ss, bins=[-1,9,13,17,21,99],
            labels=["sum_0_9","sum_10_13","sum_14_17","sum_18_21","sum_22_plus"]
        ).astype(str)

    if "seed_spread_bucket" not in out.columns:
        spreads = []
        for row in sd_int:
            try: spreads.append(max(row)-min(row))
            except Exception: spreads.append(0)
        out["seed_spread_bucket"] = pd.cut(
            pd.Series(spreads, index=out.index), bins=[-1,2,4,6,9],
            labels=["spread_0_2","spread_3_4","spread_5_6","spread_7_plus"]
        ).astype(str)

    if "seed_parity" not in out.columns:
        out["seed_parity"] = ["".join("E" if int(x)%2==0 else "O" for x in row) for row in sd]
    if "seed_highlow" not in out.columns:
        out["seed_highlow"] = ["".join("H" if int(x)>=5 else "L" for x in row) for row in sd]
    if "seed_shape" not in out.columns:
        def _struct(row):
            counts = sorted([list(row).count(d) for d in set(row)], reverse=True)
            if counts == [4]: return "quad"
            if counts == [3,1]: return "triple"
            if counts == [2,2]: return "double_double"
            if counts == [2,1,1]: return "single_pair"
            return "all_unique"
        out["seed_shape"] = [_struct(row) for row in sd]

    # Prior buckets crosswalk from real Daily output.
    # Historical mining used prior stream rate. Daily's closest live field is hit_density.
    if "PriorRateBucket" not in out.columns:
        hd = pd.to_numeric(out["hit_density"], errors="coerce").fillna(0) if "hit_density" in out.columns else pd.Series(0, index=out.index)
        out["PriorRateBucket"] = pd.cut(
            hd, bins=[-1,0,0.3389,0.005,0.0075,0.01,0.015,0.02,1],
            labels=["pr_0","pr_0_025","pr_389_05","pr_05_075","pr_075_1","pr_1_15","pr_15_2","pr_2plus"],
            include_lowest=True
        ).astype(str)

    if "PriorHitsBucket" not in out.columns:
        rh = pd.to_numeric(out["RowModelHits"], errors="coerce").fillna(0) if "RowModelHits" in out.columns else pd.Series(0, index=out.index)
        out["PriorHitsBucket"] = pd.cut(
            rh, bins=[-1,0,1,2,4,7,12,9999],
            labels=["ph_0","ph_1","ph_2","ph_3_4","ph_5_7","ph_8_12","ph_13plus"],
            include_lowest=True
        ).astype(str)

    out = _v123_cut_rank_bands(out)

    # Member aliases.
    for c in ["TrueMember","PredictedMember","Top2_pred","ThirdMember"]:
        if c not in out.columns:
            out[c] = ""
        out[c] = out[c].fillna("").map(_v121_member)

    out["top1_member2"] = out["PredictedMember"].replace({"3389":"25","3899":"225","3889":"255"})
    out["top2_member2"] = out["Top2_pred"].replace({"3389":"25","3899":"225","3889":"255"})
    out["top3_member2"] = out["ThirdMember"].replace({"3389":"25","3899":"225","3889":"255"})
    out["top12_pair2"] = out["top1_member2"].astype(str) + "_" + out["top2_member2"].astype(str)
    out["top_order2"] = out["top1_member2"].astype(str) + "_" + out["top2_member2"].astype(str) + "_" + out["top3_member2"].astype(str)

    return out

# Override old feature builder with v123 crosswalk.
def _v121_add_features(df):
    return _v123_add_daily_crosswalk_features(df)

def _v123_parse_embedded_or_uploaded_rules(rules):
    if rules is None or not isinstance(rules, pd.DataFrame) or rules.empty:
        return pd.DataFrame()
    out_rows = []
    for idx, r in rules.iterrows():
        raw_rule = str(r.get("Rule", r.get("AppliedRule", ""))).strip()
        action = str(r.get("ReductionAction", "")).strip()
        step = r.get("Step", r.get("ReductionStep", idx+1))
        if raw_rule.startswith("REDUCE_"):
            raw_rule = raw_rule[len("REDUCE_"):]
        m = re.search(r"_TO_([0123])\s*$", raw_rule)
        if m:
            action = f"SET_DEPTH_{int(m.group(1))}"
            raw_rule = raw_rule[:m.start()]
        if not action:
            action = "SET_DEPTH_0"
        out_rows.append({"Step": step, "Rule": raw_rule, "ReductionAction": action})
    return pd.DataFrame(out_rows)

def _v121_apply_reduction_stack(df, reduction_rules):
    out = _v121_add_features(df)
    depth = _v121_initial_depth(out).copy()
    rules = _v123_parse_embedded_or_uploaded_rules(reduction_rules)
    log_rows = []

    if rules.empty:
        out["v121_Depth"] = depth
        out["v121_Action"] = np.where(depth==0, "NO_PLAY", np.where(depth==1, "PLAY_TOP1", np.where(depth==2, "PLAY_TOP2", "PLAY_TOP3")))
        return out, pd.DataFrame()

    for idx, r in rules.iterrows():
        rule = str(r.get("Rule", ""))
        action = str(r.get("ReductionAction", "SET_DEPTH_0"))
        m = re.search(r"([0123])", action)
        if not m:
            new_depth = 0
        else:
            new_depth = int(m.group(1))
        mask = _v121_rule_mask(out, rule) & (depth > new_depth)
        affected = int(mask.sum())
        before_plays = int(depth.sum())
        if affected > 0:
            depth.loc[mask] = new_depth
        log_rows.append({
            "Step": int(float(r.get("Step", idx+1))) if str(r.get("Step", idx+1)).replace(".0","").isdigit() else idx+1,
            "Rule": rule,
            "ReductionAction": f"SET_DEPTH_{new_depth}",
            "RowsAffected": affected,
            "PlayCountBefore": before_plays,
            "PlayCountAfter": int(depth.sum()),
            "PlaysReduced": before_plays - int(depth.sum()),
        })

    out["v121_Depth"] = depth
    out["v121_Action"] = np.where(depth==0, "NO_PLAY", np.where(depth==1, "PLAY_TOP1", np.where(depth==2, "PLAY_TOP2", "PLAY_TOP3")))
    return out, pd.DataFrame(log_rows)

def _v123_find_daily_stream_table_in_session():
    best_key = None
    best_df = pd.DataFrame()
    required = {"StreamKey","PredictedMember","Top2_pred","ThirdMember"}
    for k, v in list(st.session_state.items()):
        if isinstance(v, pd.DataFrame) and not v.empty:
            cols = set(map(str, v.columns))
            score = len(required & cols)
            if "StreamRank" in cols or "rank" in cols: score += 1
            if "RowPercentile" in cols or "SingleRow" in cols: score += 1
            if 50 <= len(v) <= 200: score += 2
            if score >= 5 and score > (len(set(map(str,best_df.columns)) & required) if isinstance(best_df,pd.DataFrame) and not best_df.empty else -1):
                best_key = k
                best_df = v.copy()
    return best_key, best_df





# ================================
# v126 WALKFORWARD UPLOAD LOADER FIX
# Fixes Run Walkforward bug where Streamlit internal UUID was treated as file type.
# ================================
import io as _v126_io

def _v126_read_uploaded_table(uploaded, default_sep=None):
    """
    Robust reader for Streamlit UploadedFile.
    Uses uploaded.name for extension only and uploaded.getvalue()/read() for bytes.
    Never treats the internal file id as a filename.
    """
    if uploaded is None:
        return pd.DataFrame()

    name = str(getattr(uploaded, "name", "") or "").lower().strip()
    try:
        raw = uploaded.getvalue()
    except Exception:
        try:
            raw = uploaded.read()
        except Exception:
            raw = None

    if raw is None:
        return pd.DataFrame()

    bio = _v126_io.BytesIO(raw)

    try:
        if name.endswith((".xlsx", ".xls")):
            return pd.read_excel(bio)

        text = raw.decode("utf-8", errors="replace")
        sio = _v126_io.StringIO(text)

        if name.endswith(".tsv"):
            return pd.read_csv(sio, sep="\t", engine="python")
        if name.endswith(".csv"):
            return pd.read_csv(sio, engine="python")

        # TXT files may be comma, tab, pipe, or whitespace-ish.
        if name.endswith(".txt") or name == "":
            sample = text[:5000]
            if "\t" in sample:
                sep = "\t"
            elif "|" in sample and sample.count("|") > sample.count(","):
                sep = "|"
            else:
                sep = None
            sio = _v126_io.StringIO(text)
            return pd.read_csv(sio, sep=sep, engine="python")

        # If Streamlit supplied an internal UUID without extension, sniff content instead of failing.
        sample = text[:5000]
        if "\t" in sample:
            sep = "\t"
        elif "|" in sample and sample.count("|") > sample.count(","):
            sep = "|"
        else:
            sep = None
        sio = _v126_io.StringIO(text)
        return pd.read_csv(sio, sep=sep, engine="python")

    except Exception:
        # Last chance: use existing app loader if available.
        try:
            bio.seek(0)
            return pd.read_csv(bio, engine="python")
        except Exception:
            return pd.DataFrame()

# Override v121 generic loader too, so v124/v125/v126 panels use the safe reader.
