# ================================
# v124 LOCKED 264 HELPERS
# ================================
def _v124_parse_rescue_rules(rules):
    if rules is None or not isinstance(rules, pd.DataFrame) or rules.empty:
        return pd.DataFrame()
    rows = []
    for idx, r in rules.iterrows():
        rule = str(r.get("Rule", "")).strip()
        action = str(r.get("RescueAction", "")).strip()
        step = r.get("Step", idx+1)
        if not rule or not action:
            continue
        rows.append({"Step": step, "Rule": rule, "RescueAction": action})
    return pd.DataFrame(rows)

def _v124_apply_rescue_stack(df, rescue_rules):
    out = df.copy()
    if "v121_Depth" not in out.columns:
        out["v121_Depth"] = _v121_initial_depth(out)
    depth = pd.to_numeric(out["v121_Depth"], errors="coerce").fillna(0).astype(int).copy()
    rules = _v124_parse_rescue_rules(rescue_rules)
    logs = []
    if rules.empty:
        out["v124_Depth"] = depth
        out["v124_Action"] = np.where(depth==0, "NO_PLAY", np.where(depth==1, "PLAY_TOP1", np.where(depth==2, "PLAY_TOP2", "PLAY_TOP3")))
        return out, pd.DataFrame()
    for idx, r in rules.iterrows():
        rule = str(r.get("Rule", ""))
        action = str(r.get("RescueAction", ""))
        mt = re.search(r"TOP(\d)", action)
        if not mt:
            continue
        target_depth = int(mt.group(1))
        mask = _v121_rule_mask(out, rule) & (depth < target_depth)
        affected = int(mask.sum())
        before_plays = int(depth.sum())
        if affected > 0:
            depth.loc[mask] = target_depth
        logs.append({
            "Step": int(float(r.get("Step", idx+1))) if str(r.get("Step", idx+1)).replace(".0","").isdigit() else idx+1,
            "Rule": rule,
            "RescueAction": f"RAISE_TO_TOP{target_depth}",
            "RowsAffected": affected,
            "PlayCountBefore": before_plays,
            "PlayCountAfter": int(depth.sum()),
            "PlaysAdded": int(depth.sum()) - before_plays,
        })
    out["v124_Depth"] = depth
    out["v124_Action"] = np.where(depth==0, "NO_PLAY", np.where(depth==1, "PLAY_TOP1", np.where(depth==2, "PLAY_TOP2", "PLAY_TOP3")))
    return out, pd.DataFrame(logs)

def _v124_members_to_play(df):
    out = df.copy()
    def _members(row):
        d = int(row.get("v124_Depth", row.get("v121_Depth", 0)))
        vals = []
        if d >= 1: vals.append(row.get("PredictedMember", ""))
        if d >= 2: vals.append(row.get("Top2_pred", ""))
        if d >= 3: vals.append(row.get("ThirdMember", ""))
        vals = [str(x) for x in vals if str(x) not in {"", "nan", "None"}]
        return ",".join(vals)
    out["v124_MembersToPlay"] = out.apply(_members, axis=1)
    out["v124_PlayCount"] = pd.to_numeric(out["v124_Depth"], errors="coerce").fillna(0).astype(int)
    return out

def _v124_score_if_truth(df):
    out = df.copy()
    true = out.get("TrueMember", pd.Series("", index=out.index)).map(_v121_member)
    d = pd.to_numeric(out.get("v124_Depth", 0), errors="coerce").fillna(0).astype(int)
    top1 = out.get("PredictedMember", pd.Series("", index=out.index)).map(_v121_member)
    top2 = out.get("Top2_pred", pd.Series("", index=out.index)).map(_v121_member)
    top3 = out.get("ThirdMember", pd.Series("", index=out.index)).map(_v121_member)
    is_hit = true.isin(["3389","3899","3889"])
    cap = is_hit & (((d>=1)&top1.eq(true)) | ((d>=2)&top2.eq(true)) | ((d>=3)&top3.eq(true)))
    total_hits = int(is_hit.sum())
    captured = int(cap.sum())
    denom = out["Date"].nunique() if "Date" in out.columns and out["Date"].nunique() else None
    return pd.DataFrame([{
        "Rows": len(out),
        "TotalHits": total_hits,
        "CapturedHits": captured,
        "MissedHits": total_hits-captured,
        "CaptureRate": captured/total_hits if total_hits else None,
        "TotalPlays": int(d.sum()),
        "AvgPlaysPerDate": int(d.sum())/denom if denom else None,
        "Top1Rows": int((d==1).sum()),
        "Top2Rows": int((d==2).sum()),
        "Top3Rows": int((d==3).sum()),
        "NoPlayRows": int((d==0).sum()),
    }])

def _v124_run_engine(input_df, mode_label="daily"):
    # Step 1: v123 reduction stack
    reduced, reduction_log = _v121_apply_reduction_stack(input_df, pd.DataFrame(V124_EMBEDDED_REDUCTION_RULES))
    # Step 2: locked 264 rescue stack
    rescued, rescue_log = _v124_apply_rescue_stack(reduced, pd.DataFrame(V124_EMBEDDED_EXTENDED_RESCUE_RULES))
    final = _v124_members_to_play(rescued)
    final["v124_Mode"] = mode_label
    score = _v124_score_if_truth(final)
    return final, reduction_log, rescue_log, score

def _v124_find_session_table(kind="daily"):
    required = {"StreamKey","PredictedMember","Top2_pred","ThirdMember"}
    best_key, best_df, best_score = None, pd.DataFrame(), -1
    for k, v in list(st.session_state.items()):
        if not isinstance(v, pd.DataFrame) or v.empty:
            continue
        cols = set(map(str, v.columns))
        score = len(required & cols)
        if kind == "walkforward":
            if "TrueMember" in cols: score += 3
            if "Top1_Correct" in cols or "Needed_Top2" in cols or "Miss" in cols: score += 2
            if len(v) >= 250: score += 2
        else:
            if 50 <= len(v) <= 200: score += 3
            if "TrueMember" not in cols: score += 1
        if "StreamRank" in cols or "rank" in cols: score += 1
        if "RowPercentile" in cols or "SingleRow" in cols: score += 1
        if score > best_score and score >= 5:
            best_key, best_df, best_score = k, v.copy(), score
    return best_key, best_df

def _v124_row_percentile_probe(df):
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        return pd.DataFrame()
    if "v124_Depth" not in df.columns:
        return pd.DataFrame()
    rows = []
    base_score = _v124_score_if_truth(df)
    if base_score.empty:
        return pd.DataFrame()
    for col in ["SingleRow","RowPercentile","StreamRank","rank","RowBucket10"]:
        if col not in df.columns:
            continue
        vals = pd.to_numeric(df[col], errors="coerce")
        for thr in [5,10,15,20,25,30,35,40,45,50,55,60,65,70]:
            test = df.copy()
            d = pd.to_numeric(test["v124_Depth"], errors="coerce").fillna(0).astype(int)
            d.loc[~(vals <= thr)] = 0
            test["v124_Depth"] = d
            sc = _v124_score_if_truth(test)
            if not sc.empty:
                rec = sc.iloc[0].to_dict()
                rec["Probe"] = f"{col} <= {thr}"
                rec["Column"] = col
                rec["Threshold"] = thr
                rows.append(rec)
    return pd.DataFrame(rows)






