# ================================
# v131 DAILY BUDGET PLANNER — DISPLAY ONLY
# Does NOT modify prediction logic, depth, rescues, reductions, cadence, or captures.
# Shows the full final playlist on screen in SingleRow / RowPercentile order with running play count and $0.25 cost.
# ================================
def _v131_daily_budget_planner(final_df: pd.DataFrame) -> pd.DataFrame:
    if final_df is None or not isinstance(final_df, pd.DataFrame) or final_df.empty:
        return pd.DataFrame()

    out = final_df.copy()

    # Select final action/depth/member columns without changing existing engine columns.
    depth_col = next((c for c in ["v131_Depth", "v130_Depth", "v128_Depth", "v127_Depth", "v124_Depth", "v121_Depth"] if c in out.columns), None)
    play_col = next((c for c in ["v131_PlayCount", "v130_PlayCount", "v128_PlayCount", "v127_PlayCount", "v124_PlayCount", "v121_PlayCount"] if c in out.columns), None)
    action_col = next((c for c in ["v131_Action", "v130_Action", "v128_Action", "v127_Action", "v124_Action", "v121_Action"] if c in out.columns), None)
    members_col = next((c for c in ["v131_MembersToPlay", "v130_MembersToPlay", "v128_MembersToPlay", "v127_MembersToPlay", "v124_MembersToPlay", "v121_MembersToPlay"] if c in out.columns), None)

    if play_col is None and depth_col is not None:
        out["v131_Display_PlayCount"] = pd.to_numeric(out[depth_col], errors="coerce").fillna(0).astype(int)
        play_col = "v131_Display_PlayCount"
    elif play_col is not None:
        out["v131_Display_PlayCount"] = pd.to_numeric(out[play_col], errors="coerce").fillna(0).astype(int)
        play_col = "v131_Display_PlayCount"
    else:
        out["v131_Display_PlayCount"] = 0
        play_col = "v131_Display_PlayCount"

    if action_col is None:
        out["v131_Display_Action"] = np.where(
            out[play_col].eq(0), "NO_PLAY",
            np.where(out[play_col].eq(1), "PLAY_TOP1",
            np.where(out[play_col].eq(2), "PLAY_TOP2", "PLAY_TOP3"))
        )
        action_col = "v131_Display_Action"

    if members_col is None:
        members_col = "v131_Display_MembersToPlay"
        out[members_col] = ""

    # Rescue-added flag/depth display only.
    before_col = "v121_Depth" if "v121_Depth" in out.columns else None
    after_col = next((c for c in ["v127_Depth", "v124_Depth", depth_col] if c and c in out.columns), None)
    if before_col and after_col:
        out["v131_RescueAddedDepth"] = (
            pd.to_numeric(out[after_col], errors="coerce").fillna(0)
            - pd.to_numeric(out[before_col], errors="coerce").fillna(0)
        ).clip(lower=0).astype(int)
    else:
        out["v131_RescueAddedDepth"] = 0
    out["v131_RescueAddedFlag"] = np.where(out["v131_RescueAddedDepth"].gt(0), "YES", "")

    # Numeric order helpers. SingleRow is the practical row-percentile order used for this budget view.
    for c in ["SingleRow", "RowPercentile", "StreamRank", "rank", "PlaylistRank", "v79_FinalPlayRank"]:
        if c in out.columns:
            out[c + "_v131_num"] = pd.to_numeric(out[c], errors="coerce")

    sort_cols = []
    if "SingleRow_v131_num" in out.columns:
        sort_cols.append("SingleRow_v131_num")
    elif "RowPercentile_v131_num" in out.columns:
        sort_cols.append("RowPercentile_v131_num")
    elif "StreamRank_v131_num" in out.columns:
        sort_cols.append("StreamRank_v131_num")
    if "StreamRank_v131_num" in out.columns and "StreamRank_v131_num" not in sort_cols:
        sort_cols.append("StreamRank_v131_num")

    if sort_cols:
        out = out.sort_values(sort_cols, ascending=True, na_position="last").copy()
    else:
        out = out.copy()

    out["BudgetOrder"] = range(1, len(out) + 1)
    out["RunningPlayTotal"] = pd.to_numeric(out[play_col], errors="coerce").fillna(0).astype(int).cumsum()
    out["RunningCost_25c"] = out["RunningPlayTotal"] * 0.25
    out["RunningCost_25c_Display"] = out["RunningCost_25c"].map(lambda x: f"${x:,.2f}")

    # Budget marker for fast visual stopping.
    def _budget_marker(total):
        try:
            total = int(total)
        except Exception:
            return ""
        marks = []
        for plays, dollars in [(20,5),(40,10),(60,15),(80,20),(100,25),(120,30),(140,35),(160,40),(200,50)]:
            if total >= plays:
                marks.append(f"${dollars}")
        return marks[-1] if marks else ""

    out["BudgetMarkerReached"] = out["RunningPlayTotal"].map(_budget_marker)

    # Clean display columns, preserving available identifiers.
    display_cols = []
    for c in [
        "BudgetOrder", "SingleRow", "RowPercentile", "StreamRank", "rank",
        "State", "Game", "StreamKey",
        action_col, members_col, play_col,
        "RunningPlayTotal", "RunningCost_25c_Display", "BudgetMarkerReached",
        "v131_RescueAddedFlag", "v131_RescueAddedDepth",
        "PredictedMember", "Top2_pred", "ThirdMember"
    ]:
        if c in out.columns and c not in display_cols:
            display_cols.append(c)

    budget = out[display_cols].copy()

    # Rename selected engine-specific columns to stable v131 display names.
    rename_map = {
        action_col: "FinalAction",
        members_col: "MembersToPlay",
        play_col: "PlayCount",
        "RunningCost_25c_Display": "RunningCost_25c",
        "v131_RescueAddedFlag": "RescueAdded",
        "v131_RescueAddedDepth": "RescueAddedDepth",
    }
    budget = budget.rename(columns=rename_map)
    return budget

def _v131_render_daily_budget_planner(final_df: pd.DataFrame, key_prefix: str = "v131_daily_budget"):
    budget = _v131_daily_budget_planner(final_df)
    if budget is None or budget.empty:
        return pd.DataFrame()

    st.subheader("DAILY BUDGET PLANNER — FULL LIST ON SCREEN")
    st.caption(
        "Display-only. Ordered by SingleRow / RowPercentile strength. "
        "Use RunningPlayTotal and RunningCost_25c to decide how deep to play. "
        "This does not change reductions, rescues, cadence, or final engine output."
    )

    total_plays = int(pd.to_numeric(budget.get("PlayCount", pd.Series([], dtype=int)), errors="coerce").fillna(0).sum())
    st.info(f"Full v131 budget list shown on screen: {len(budget)} rows | {total_plays} plays | ${total_plays * 0.25:,.2f} at $0.25/play")

    # Show full list, not just head(250). For daily this is only ~78 rows.
    st.dataframe(budget, use_container_width=True, hide_index=True, height=900)

    try:
        _v125_download_button(
            "Download Daily Budget Planner CSV",
            budget,
            "core389_v131_daily_budget_planner_full_onscreen.csv",
            key_prefix + "_csv_dl",
        )
    except Exception:
        st.download_button(
            "Download Daily Budget Planner CSV",
            budget.to_csv(index=False).encode("utf-8"),
            file_name="core389_v131_daily_budget_planner_full_onscreen.csv",
            mime="text/csv",
            use_container_width=True,
            key=key_prefix + "_csv_dl_fallback",
        )
    return budget


