# ============================================================
# v175 SUPPORT AUDIT LAB — NO AUTO-REPLACE
# ============================================================
# Additive only. This section audits production Truth/Separator files against
# newly uploaded history. It does NOT replace active support files or alter the
# daily engine. It produces evidence-backed audit reports and proposed changes.

V175_BUILD_MARKER = "BUILD: core389_northern_lights__2026-06-16_v220_WINNER_FIT_AUDIT_LITE"
V175_MEMBERS = ["3389", "3899", "3889"]


def _v175_to_csv_bytes(df):
    try:
        return df.to_csv(index=False).encode("utf-8")
    except Exception:
        return b""


def _v175_load_any(uploaded):
    if uploaded is None:
        return pd.DataFrame()
    try:
        name = str(getattr(uploaded, "name", "")).lower()
        if name.endswith(".csv"):
            return pd.read_csv(uploaded, dtype=str)
        if name.endswith((".txt", ".tsv")):
            raw = uploaded.getvalue() if hasattr(uploaded, "getvalue") else uploaded.read()
            try:
                return pd.read_csv(io.BytesIO(raw), sep="\t", dtype=str)
            except Exception:
                return pd.read_csv(io.BytesIO(raw), sep=None, engine="python", dtype=str)
        if name.endswith((".xlsx", ".xls")):
            return pd.read_excel(uploaded, dtype=str)
        return pd.read_csv(uploaded, dtype=str)
    except Exception as e:
        try:
            st.warning(f"v175 could not load file: {e}")
        except Exception:
            pass
        return pd.DataFrame()


def _v175_norm_result(x):
    digs = re.findall(r"\d", str(x))
    return "".join(digs[:4]) if len(digs) >= 4 else ""


def _v175_box_key(x):
    s = _v175_norm_result(x)
    return "".join(sorted(s)) if len(s) == 4 else ""


def _v175_to_member(x):
    s = re.sub(r"\D", "", str(x)).zfill(4)[-4:]
    if s in {"3389", "3899", "3889"}:
        return s
    b = _v175_box_key(s)
    return b if b in set(V175_MEMBERS) else ""


def _v175_sum_bucket(x):
    try:
        x = int(x)
    except Exception:
        return ""
    if x <= 9:
        return "sum_00_09"
    if x <= 13:
        return "sum_10_13"
    if x <= 17:
        return "sum_14_17"
    if x <= 21:
        return "sum_18_21"
    return "sum_22_plus"


def _v175_spread_bucket(x):
    try:
        x = int(x)
    except Exception:
        return ""
    if x <= 2:
        return "spread_0_2"
    if x <= 4:
        return "spread_3_4"
    if x <= 6:
        return "spread_5_6"
    return "spread_7_plus"


def _v175_structure(digs):
    try:
        counts = sorted(pd.Series(digs).value_counts().tolist(), reverse=True)
    except Exception:
        return ""
    if counts == [1, 1, 1, 1]: return "ABCD"
    if counts == [2, 1, 1]: return "AABC"
    if counts == [2, 2]: return "AABB"
    if counts == [3, 1]: return "AAAB"
    if counts == [4]: return "AAAA"
    return "OTHER"


def _v175_add_seed_features(df, seed_col="seed"):
    out = df.copy()
    if seed_col not in out.columns:
        out[seed_col] = ""
    seeds = out[seed_col].astype(str).map(_v175_norm_result)
    seeds = seeds.where(seeds.str.len().eq(4), out[seed_col].astype(str).str.extract(r"(\d{4})", expand=False).fillna("0000"))
    digs = seeds.map(lambda s: [int(ch) for ch in str(s).zfill(4)[-4:]])
    out["seed"] = seeds
    out["sum"] = digs.map(sum)
    out["seed_sum"] = out["sum"]
    out["spread"] = digs.map(lambda d: max(d) - min(d))
    out["seed_spread"] = out["spread"]
    out["sum_bucket"] = out["sum"].map(_v175_sum_bucket)
    out["spread_bucket"] = out["spread"].map(_v175_spread_bucket)
    out["even"] = digs.map(lambda d: sum(1 for x in d if x % 2 == 0))
    out["odd"] = digs.map(lambda d: sum(1 for x in d if x % 2 != 0))
    out["high"] = digs.map(lambda d: sum(1 for x in d if x >= 5))
    out["low"] = digs.map(lambda d: sum(1 for x in d if x <= 4))
    out["unique"] = digs.map(lambda d: len(set(d)))
    out["pair"] = digs.map(lambda d: int(len(set(d)) < 4))
    out["max_rep"] = digs.map(lambda d: max(pd.Series(d).value_counts().tolist()))
    out["consec_links"] = digs.map(lambda d: sum(1 for a,b in zip(sorted(set(d))[:-1], sorted(set(d))[1:]) if b-a == 1))
    out["parity_pattern"] = digs.map(lambda d: "".join("E" if x % 2 == 0 else "O" for x in d))
    out["highlow_pattern"] = digs.map(lambda d: "".join("H" if x >= 5 else "L" for x in d))
    out["structure"] = digs.map(_v175_structure)
    out["sorted_seed"] = digs.map(lambda d: "".join(str(x) for x in sorted(d)))
    out["first2"] = digs.map(lambda d: f"{d[0]}{d[1]}")
    out["last2"] = digs.map(lambda d: f"{d[2]}{d[3]}")
    for k in range(10):
        out[f"has{k}"] = digs.map(lambda d, kk=k: int(kk in d))
        out[f"cnt{k}"] = digs.map(lambda d, kk=k: int(sum(1 for x in d if x == kk)))
    # aliases used by newer app/rules
    out["seed_highlow_pattern"] = out["highlow_pattern"]
    out["seed_parity_pattern"] = out["parity_pattern"]
    out["seed_repeat_shape"] = out["structure"]
    out["seed_has9"] = out["has9"]
    out["seed_has0"] = out["has0"]
    out["seed_even_cnt"] = out["even"]
    out["seed_high_cnt"] = out["high"]
    out["seed_low_cnt"] = out["low"]
    return out


def _v175_prepare_history(df_raw):
    if df_raw is None or not isinstance(df_raw, pd.DataFrame) or df_raw.empty:
        return pd.DataFrame()
    df = df_raw.copy()
    df.columns = [str(c).strip() for c in df.columns]
    lower = {c.lower(): c for c in df.columns}
    date_col = lower.get("date") or lower.get("drawdate") or next((c for c in df.columns if "date" in c.lower()), None)
    state_col = lower.get("state") or lower.get("jurisdiction") or next((c for c in df.columns if "state" in c.lower() or "jurisdiction" in c.lower()), None)
    game_col = lower.get("game") or next((c for c in df.columns if "game" in c.lower()), None)
    result_col = lower.get("results") or lower.get("result") or lower.get("winning numbers") or lower.get("winning_numbers") or next((c for c in df.columns if "result" in c.lower()), None)
    if date_col is None or result_col is None:
        if df.shape[1] >= 4:
            date_col, state_col, game_col, result_col = df.columns[:4]
        else:
            return pd.DataFrame()
    out = pd.DataFrame()
    out["Date"] = pd.to_datetime(df[date_col], errors="coerce")
    out["State"] = df[state_col].astype(str) if state_col else ""
    out["Game"] = df[game_col].astype(str) if game_col else ""
    out["Result"] = df[result_col].map(_v175_norm_result)
    out = out[out["Date"].notna() & out["Result"].astype(str).str.len().eq(4)].copy()
    out["StreamKey"] = out["State"].astype(str).str.strip() + " | " + out["Game"].astype(str).str.strip()
    out["Box"] = out["Result"].map(_v175_box_key)
    out["Core389Member"] = out["Box"].where(out["Box"].isin(V175_MEMBERS), "")
    return out.sort_values(["StreamKey", "Date"]).reset_index(drop=True)


def _v175_build_transitions(hist):
    rows = []
    if hist is None or hist.empty:
        return pd.DataFrame()
    for stream, g in hist.groupby("StreamKey"):
        g = g.sort_values("Date").reset_index(drop=True)
        for i in range(1, len(g)):
            rows.append({
                "StreamKey": stream,
                "State": g.loc[i, "State"],
                "Game": g.loc[i, "Game"],
                "seed_date": g.loc[i-1, "Date"],
                "event_date": g.loc[i, "Date"],
                "seed": g.loc[i-1, "Result"],
                "Result": g.loc[i, "Result"],
                "next_member": g.loc[i, "Core389Member"] if g.loc[i, "Core389Member"] in V175_MEMBERS else "",
                "is_core389_hit": int(g.loc[i, "Core389Member"] in V175_MEMBERS),
            })
    out = pd.DataFrame(rows)
    if out.empty:
        return out
    out = _v175_add_seed_features(out, "seed")
    return out.sort_values(["event_date", "StreamKey"]).reset_index(drop=True)


def _v175_split_pair(pair_text):
    s = str(pair_text)
    found = re.findall(r"0?0?25|0?225|0?255", s)
    members = []
    for x in found:
        m = _v175_to_member(x)
        if m in V175_MEMBERS and m not in members:
            members.append(m)
    return members[:2]


def _v175_parse_conditions(trait_stack):
    parts = [p.strip() for p in re.split(r"\s+&&\s+", str(trait_stack)) if p.strip()]
    conds = []
    for p in parts:
        if "==" in p:
            col, val = p.split("==", 1)
        elif "=" in p:
            col, val = p.split("=", 1)
        else:
            continue
        conds.append((col.strip(), val.strip()))
    return conds


def _v175_condition_mask(df, conds):
    mask = pd.Series(True, index=df.index)
    for col, val in conds:
        col_aliases = [col]
        if col.startswith("seed_"):
            col_aliases.append(col.replace("seed_", ""))
        else:
            col_aliases.append("seed_" + col)
        real_col = next((c for c in col_aliases if c in df.columns), None)
        if real_col is None:
            return pd.Series(False, index=df.index), f"missing column: {col}"
        cur = df[real_col].map(lambda x: "" if pd.isna(x) else (str(int(float(x))) if str(x).replace('.0','').lstrip('-').isdigit() and str(x).endswith('.0') else str(x)))
        mask &= cur.astype(str).str.strip().eq(str(val).strip())
    return mask, ""


def _v175_audit_separator(old_sep, transitions, min_support=5, weaken_delta=0.08, flip_margin=0.05):
    if old_sep is None or old_sep.empty or transitions is None or transitions.empty:
        return pd.DataFrame(), pd.DataFrame()
    sep = old_sep.copy()
    sep.columns = [str(c).strip() for c in sep.columns]
    if "trait_stack" not in sep.columns:
        return pd.DataFrame([{"AuditError": "Separator file missing trait_stack column"}]), pd.DataFrame()
    if "winner_member" not in sep.columns:
        sep["winner_member"] = ""
    core = transitions[transitions["is_core389_hit"] == 1].copy()
    rows = []
    for idx, r in sep.iterrows():
        trait = str(r.get("trait_stack", ""))
        old_member = _v175_to_member(r.get("winner_member", ""))
        old_support = pd.to_numeric(pd.Series([r.get("support", None)]), errors="coerce").iloc[0]
        old_rate = pd.to_numeric(pd.Series([r.get("winner_rate", None)]), errors="coerce").iloc[0]
        old_gap = pd.to_numeric(pd.Series([r.get("pair_gap", None)]), errors="coerce").iloc[0]
        pair_members = _v175_split_pair(r.get("pair", ""))
        test_df = core.copy()
        if len(pair_members) == 2:
            test_df = test_df[test_df["next_member"].isin(pair_members)].copy()
        conds = _v175_parse_conditions(trait)
        mask, err = _v175_condition_mask(test_df, conds)
        sub = test_df[mask].copy() if err == "" else pd.DataFrame()
        counts = {m: int((sub.get("next_member", pd.Series(dtype=str)) == m).sum()) for m in V175_MEMBERS}
        if len(pair_members) == 2:
            counts = {m: counts[m] for m in pair_members}
        new_support = int(len(sub))
        if new_support > 0:
            new_rates = {m: counts.get(m, 0) / new_support for m in counts}
            new_best = max(new_rates, key=lambda k: new_rates[k])
            new_best_rate = float(new_rates[new_best])
            old_member_new_rate = float(new_rates.get(old_member, 0.0)) if old_member else 0.0
        else:
            new_rates = {m: 0.0 for m in counts}
            new_best = ""
            new_best_rate = 0.0
            old_member_new_rate = 0.0
        old_rate_f = float(old_rate) if pd.notna(old_rate) else None
        delta_old_member = (old_member_new_rate - old_rate_f) if old_rate_f is not None else None
        if err:
            status = "PARSE_OR_SCHEMA_REVIEW"
            action = "Do not change; rule could not be evaluated against current history."
        elif new_support < int(min_support):
            status = "INSUFFICIENT_CURRENT_SUPPORT"
            action = "Keep existing rule; not enough current support to revise."
        elif old_member and new_best and new_best != old_member and (new_best_rate - old_member_new_rate) >= float(flip_margin):
            status = "FLIPPED_REVIEW"
            action = "Do not auto-replace; review possible member flip."
        elif old_rate_f is not None and old_member_new_rate < max(0.0, old_rate_f - float(weaken_delta)):
            status = "WEAKENED_REVIEW"
            action = "Keep for now; mark weakened and monitor before revision."
        elif old_member and new_best == old_member:
            status = "STILL_HOLDS"
            action = "Keep unchanged."
        else:
            status = "REVIEW"
            action = "Manual review."
        rows.append({
            "RuleRow": int(idx) + 1,
            "Pair": r.get("pair", ""),
            "TraitStack": trait,
            "OldWinnerMember": old_member,
            "OldSupport": old_support if pd.notna(old_support) else "",
            "OldWinnerRate": old_rate if pd.notna(old_rate) else "",
            "OldPairGap": old_gap if pd.notna(old_gap) else "",
            "CurrentSupport": new_support,
            "CurrentBestMember": new_best,
            "CurrentBestRate": round(new_best_rate, 4),
            "CurrentOldMemberRate": round(old_member_new_rate, 4),
            "DeltaOldMemberRate": round(delta_old_member, 4) if delta_old_member is not None else "",
            "Count_3389": counts.get("3389", 0),
            "Count_3899": counts.get("3899", 0),
            "Count_3889": counts.get("3889", 0),
            "Status": status,
            "RecommendedAction": action,
            "EvalNote": err,
        })
    audit = pd.DataFrame(rows)
    summary = audit.groupby("Status").size().rename("RuleCount").reset_index().sort_values("RuleCount", ascending=False) if not audit.empty else pd.DataFrame()
    return audit, summary


def _v175_truth_audit(old_truth, transitions):
    rows = []
    if transitions is None or transitions.empty:
        return pd.DataFrame(), pd.DataFrame()
    core = transitions[transitions["is_core389_hit"] == 1].copy()
    current_dist = core["next_member"].value_counts().reindex(V175_MEMBERS).fillna(0).astype(int)
    if old_truth is not None and isinstance(old_truth, pd.DataFrame) and not old_truth.empty:
        old = old_truth.copy()
        old.columns = [str(c).strip() for c in old.columns]
        tcol = next((c for c in ["TrueMember", "WinningMember", "Core389Member", "member", "winner"] if c in old.columns), None)
        if tcol:
            old_members = old[tcol].map(_v175_to_member)
            old_core = old[old_members.isin(V175_MEMBERS)].copy()
            old_dist = old_members[old_members.isin(V175_MEMBERS)].value_counts().reindex(V175_MEMBERS).fillna(0).astype(int)
        else:
            old_core = pd.DataFrame()
            old_dist = pd.Series({m:0 for m in V175_MEMBERS})
        date_col = next((c for c in ["Date", "date", "event_date"] if c in old.columns), None)
        old_max_date = str(pd.to_datetime(old[date_col], errors="coerce").max().date()) if date_col and pd.to_datetime(old[date_col], errors="coerce").notna().any() else "unknown"
        old_rows = len(old)
        old_cols = len(old.columns)
    else:
        old_dist = pd.Series({m:0 for m in V175_MEMBERS})
        old_max_date = "missing"
        old_rows = 0
        old_cols = 0
    current_max_date = str(pd.to_datetime(transitions["event_date"], errors="coerce").max().date()) if "event_date" in transitions.columns else "unknown"
    for m in V175_MEMBERS:
        rows.append({
            "Member": m,
            "OldTruthCount": int(old_dist.get(m,0)),
            "CurrentHistoryCoreHitCount": int(current_dist.get(m,0)),
            "DeltaCount": int(current_dist.get(m,0)) - int(old_dist.get(m,0)),
        })
    meta = pd.DataFrame([{
        "OldTruthRows": int(old_rows),
        "OldTruthColumns": int(old_cols),
        "OldTruthMaxDate": old_max_date,
        "CurrentHistoryRows": int(len(transitions) + 1),
        "CurrentTransitionRows": int(len(transitions)),
        "CurrentCore389Hits": int(len(core)),
        "CurrentHistoryMaxEventDate": current_max_date,
        "AuditMode": "audit_only_no_auto_replace",
    }])
    return pd.DataFrame(rows), meta


def _v175_make_notes(truth_meta, truth_dist, sep_summary, sep_audit):
    lines = []
    lines.append("CORE389 SUPPORT AUDIT LAB — v175")
    lines.append("Mode: AUDIT ONLY. No Truth/Separator files were replaced automatically.")
    lines.append("")
    if isinstance(truth_meta, pd.DataFrame) and not truth_meta.empty:
        m = truth_meta.iloc[0].to_dict()
        lines.append("TRUTH / HISTORY EVIDENCE")
        for k,v in m.items():
            lines.append(f"- {k}: {v}")
        lines.append("")
    if isinstance(truth_dist, pd.DataFrame) and not truth_dist.empty:
        lines.append("MEMBER DISTRIBUTION CHECK")
        for _, r in truth_dist.iterrows():
            lines.append(f"- {r['Member']}: old={r['OldTruthCount']} current={r['CurrentHistoryCoreHitCount']} delta={r['DeltaCount']}")
        lines.append("")
    if isinstance(sep_summary, pd.DataFrame) and not sep_summary.empty:
        lines.append("SEPARATOR RULE STATUS SUMMARY")
        for _, r in sep_summary.iterrows():
            lines.append(f"- {r['Status']}: {r['RuleCount']} rules")
        lines.append("")
    if isinstance(sep_audit, pd.DataFrame) and not sep_audit.empty:
        focus = sep_audit[sep_audit["Status"].isin(["FLIPPED_REVIEW", "WEAKENED_REVIEW", "PARSE_OR_SCHEMA_REVIEW", "INSUFFICIENT_CURRENT_SUPPORT"])].head(50)
        lines.append("TOP REVIEW ITEMS")
        if focus.empty:
            lines.append("- No high-priority review items in the first audit pass.")
        else:
            for _, r in focus.iterrows():
                lines.append(f"- Rule {r['RuleRow']} [{r['Status']}]: {r['TraitStack']} | old={r['OldWinnerMember']}@{r['OldWinnerRate']} | current best={r['CurrentBestMember']}@{r['CurrentBestRate']} | action={r['RecommendedAction']}")
    return "\n".join(lines).encode("utf-8")


def _v175_render_support_audit_lab():
    st.divider()
    with st.expander("v175 Support Audit Lab — audit/revise, no auto-replace", expanded=True):
        st.caption("This lab retests existing production Truth/Separator evidence against updated history. It does not alter the daily engine or replace active files.")
        c1, c2, c3 = st.columns(3)
        with c1:
            hist_up = st.file_uploader("Upload latest full history", type=["csv","txt","tsv","xlsx","xls"], key="v175_hist_upload")
        with c2:
            truth_up = st.file_uploader("Upload current production Truth file", type=["csv","txt","tsv","xlsx","xls"], key="v175_truth_upload")
        with c3:
            sep_up = st.file_uploader("Upload current production Separator file", type=["csv","txt","tsv","xlsx","xls"], key="v175_sep_upload")

        with st.expander("Audit thresholds", expanded=False):
            min_support = st.number_input("Minimum current support to consider revising a rule", min_value=1, value=5, step=1, key="v175_min_support")
            weaken_delta = st.slider("Weakened threshold: old-member rate drop", 0.01, 0.30, 0.08, 0.01, key="v175_weaken_delta")
            flip_margin = st.slider("Flip threshold: new best beats old member by", 0.01, 0.30, 0.05, 0.01, key="v175_flip_margin")

        if st.button("Run Support Audit — do not replace files", type="primary", use_container_width=True, key="v175_run_audit"):
            hist_raw = _v175_load_any(hist_up)
            old_truth = _v175_load_any(truth_up)
            old_sep = _v175_load_any(sep_up)
            hist = _v175_prepare_history(hist_raw)
            transitions = _v175_build_transitions(hist)
            truth_dist, truth_meta = _v175_truth_audit(old_truth, transitions)
            sep_audit, sep_summary = _v175_audit_separator(old_sep, transitions, min_support=min_support, weaken_delta=weaken_delta, flip_margin=flip_margin)
            notes = _v175_make_notes(truth_meta, truth_dist, sep_summary, sep_audit)
            st.session_state["v175_truth_dist"] = truth_dist
            st.session_state["v175_truth_meta"] = truth_meta
            st.session_state["v175_sep_audit"] = sep_audit
            st.session_state["v175_sep_summary"] = sep_summary
            st.session_state["v175_audit_notes"] = notes
            st.success("Support audit complete. No files were replaced or activated.")

        truth_meta = st.session_state.get("v175_truth_meta")
        truth_dist = st.session_state.get("v175_truth_dist")
        sep_summary = st.session_state.get("v175_sep_summary")
        sep_audit = st.session_state.get("v175_sep_audit")
        notes = st.session_state.get("v175_audit_notes")
        if isinstance(truth_meta, pd.DataFrame) and not truth_meta.empty:
            st.subheader("Truth / History Audit Meta")
            st.dataframe(truth_meta, use_container_width=True, hide_index=True)
        if isinstance(truth_dist, pd.DataFrame) and not truth_dist.empty:
            st.subheader("Member Distribution Audit")
            st.dataframe(truth_dist, use_container_width=True, hide_index=True)
        if isinstance(sep_summary, pd.DataFrame) and not sep_summary.empty:
            st.subheader("Separator Status Summary")
            st.dataframe(sep_summary, use_container_width=True, hide_index=True)
        if isinstance(sep_audit, pd.DataFrame) and not sep_audit.empty:
            st.subheader("Separator Rule Audit Detail")
            st.dataframe(sep_audit, use_container_width=True, hide_index=True, height=650)
            review = sep_audit[sep_audit["Status"].isin(["FLIPPED_REVIEW", "WEAKENED_REVIEW", "PARSE_OR_SCHEMA_REVIEW", "INSUFFICIENT_CURRENT_SUPPORT"])].copy()
            st.download_button("Download Separator Audit CSV", _v175_to_csv_bytes(sep_audit), "core389_v175_separator_rule_audit.csv", "text/csv", use_container_width=True, key="v175_sep_audit_csv")
            st.download_button("Download Proposed Review Items CSV", _v175_to_csv_bytes(review), "core389_v175_proposed_review_items.csv", "text/csv", use_container_width=True, key="v175_review_csv")
        if isinstance(notes, (bytes, bytearray)) and len(notes):
            st.download_button("Download Human-Readable Audit Notes TXT", notes, "core389_v175_support_audit_notes.txt", "text/plain", use_container_width=True, key="v175_notes_txt")

